import { PublicCard } from '../../../types';

export const mcatCards: PublicCard[] = [
  // --- Biology & Biochemistry ---
  { id: 'dc-mcat-0001', deck_id: 'deck-mcat', sort_order: 1, front: "Michaelis-Menten Equation", back: "v = Vmax[S] / (Km + [S]). Describes enzyme kinetics: Km is the substrate concentration at half-maximal velocity; lower Km indicates higher enzyme affinity for substrate." , front_translations: {"es":"Equación de Michaelis-Menten","de":"Michaelis-Menten-Gleichung","fr":"Équation de Michaelis-Menten","tr":"Michaelis-Menten Denklemi","nl":"Michaelis-Menten-vergelijking","ru":"Уравнение Михаэлиса-Ментен","zh":"米氏方程","pt_BR":"Equação de Michaelis-Menten","pt_PT":"Equação de Michaelis-Menten"}, back_translations: {"es":"v = Vmax[S] / (Km + [S]). Descreve a cinética enzimática: Km es a concentración de substrato en la metade de la velocidad máxima; un Km más bajo indica mayor afinidad de la enzima por el substrato.","de":"v = Vmax[S] / (Km + [S]). Beschreibt die Enzymkinetik: Km ist die Substratkonzentration bei halbmaximaler Geschwindigkeit; ein niedrigerer Km zeigt eine höhere Enzymaffinität zum Substrat an.","fr":"v = Vmax[S] / (Km + [S]). Décrit la cinétique enzymatique : Km est la concentration de substrat à la moitié de la vitesse maximale ; un Km plus bas indique une affinité plus élevée de l'enzyme pour le substrat.","tr":"v = Vmax[S] / (Km + [S]). Enzim kinetiğini tanımlar: Km, yarı-maksimum hızdaki substrat konsantrasyonudur; düşük Km, enzimin substrata daha yüksek afinitesini gösterir.","nl":"v = Vmax[S] / (Km + [S]). Beschrijft enzymkinetiek: Km is de substraatconcentratie bij halfmaximale snelheid; een lagere Km duidt op een hogere enzymaffiniteit voor het substraat.","ru":"v = Vmax[S] / (Km + [S]). Описывает кинетику ферментов: Km — концентрация субстрата при половине максимальной скорости; более низкий Km указывает на более высокое сродство фермента к субстрату.","zh":"v = Vmax[S] / (Km + [S])。描述酶动力学：Km 是半最大速度时的底物浓度；Km 越低表示酶对底物的亲和力越高。","pt_BR":"v = Vmax[S] / (Km + [S]). Descreve a cinética enzimática: Km é a concentração de substrato na metade da velocidade máxima; um Km mais baixo indica maior afinidade da enzima pelo substrato.","pt_PT":"v = Vmax[S] / (Km + [S]). Descreve a cinética enzimática: Km é a concentração de substrato a metade da velocidade máxima; um Km mais baixo indica maior afinidade da enzima pelo substrato."}},
  { id: 'dc-mcat-0002', deck_id: 'deck-mcat', sort_order: 2, front: "Vmax and Enzyme Concentration", back: "Vmax is directly proportional to the total enzyme concentration [E]T. Adding more enzyme increases Vmax but does not change Km. Competitive inhibitors increase apparent Km; non-competitive inhibitors decrease Vmax." , front_translations: {"es":"Vmax y Concentración Enzimática","de":"Vmax und Enzymkonzentration","fr":"Vmax et concentration enzymatique","tr":"Vmax ve Enzim Konsantrasyonu","nl":"Vmax en enzymconcentratie","ru":"Vmax и концентрация фермента","zh":"Vmax 与酶浓度","pt_BR":"Vmax e Concentração Enzimática","pt_PT":"Vmax e Concentração Enzimática"}, back_translations: {"es":"Vmax es directamente proporcional a la concentración total de enzima [Y]T. Adicionar más enzima aumenta Vmax, pero no altera Km. Inibidores competitivos aumentan el Km aparente; inibidores no competitivos disminuyen Vmax.","de":"Vmax ist direkt proportional zur gesamten Enzymkonzentration [E]T. Mehr Enzym erhöht Vmax, ändert aber nicht Km. Kompetitive Inhibitoren erhöhen den scheinbaren Km; nicht-kompetitive Inhibitoren verringern Vmax.","fr":"Vmax est directement proportionnel à la concentration totale d'enzyme [E]T. Ajouter plus d'enzyme augmente Vmax mais ne change pas Km. Les inhibiteurs compétitifs augmentent le Km apparent ; les inhibiteurs non compétitifs diminuent Vmax.","tr":"Vmax, toplam enzim konsantrasyonuna [E]T doğrudan orantılıdır. Daha fazla enzim eklemek Vmax'ı artırır ancak Km'yi değiştirmez. Kompetitif inhibitörler görünür Km'yi artırır; non-kompetitif inhibitörler Vmax'ı azaltır.","nl":"Vmax is recht evenredig met de totale enzymconcentratie [E]T. Meer enzym verhoogt Vmax maar verandert Km niet. Competitieve remmers verhogen de schijnbare Km; niet-competitieve remmers verlagen Vmax.","ru":"Vmax прямо пропорциональна общей концентрации фермента [E]T. Добавление фермента увеличивает Vmax, но не изменяет Km. Конкурентные ингибиторы увеличивают кажущийся Km; неконкурентные ингибиторы снижают Vmax.","zh":"Vmax 与总酶浓度 [E]T 成正比。增加酶的量会提高 Vmax，但不改变 Km。竞争性抑制剂增加表观 Km；非竞争性抑制剂降低 Vmax。","pt_BR":"Vmax é diretamente proporcional à concentração total de enzima [E]T. Adicionar mais enzima aumenta Vmax, mas não altera Km. Inibidores competitivos aumentam o Km aparente; inibidores não competitivos diminuem Vmax.","pt_PT":"Vmax é diretamente proporcional à concentração total de enzima [E]T. Adicionar mais enzima aumenta Vmax, mas não altera Km. Inibidores competitivos aumentam o Km aparente; inibidores não competitivos diminuem Vmax."}},
  { id: 'dc-mcat-0003', deck_id: 'deck-mcat', sort_order: 3, front: "Competitive Inhibition (Kinetics)", back: "Increases apparent Km (reduces apparent affinity); Vmax is unchanged because inhibitor can be outcompeted by excess substrate. On a Lineweaver-Burk plot, the x-intercept shifts but y-intercept stays the same." , front_translations: {"es":"Inibición Competitiva (Cinética)","de":"Kompetitive Hemmung (Kinetik)","fr":"Inhibition compétitive (cinétique)","tr":"Kompetitif İnhibisyon (Kinetik)","nl":"Competitieve remming (kinetiek)","ru":"Конкурентное ингибирование (кинетика)","zh":"竞争性抑制（动力学）","pt_BR":"Inibição Competitiva (Cinética)","pt_PT":"Inibição Competitiva (Cinética)"}, back_translations: {"es":"Aumenta el Km aparente (reduce a afinidad aparente); Vmax no muda porque el inibidor puede ser superado por exceso de substrato. No gráfico de Lineweaver-Burk, el intercepto en x muda, pero el intercepto en y permanece el mismo.","de":"Erhöht den scheinbaren Km (reduziert die scheinbare Affinität); Vmax bleibt unverändert, da der Inhibitor durch Substratüberschuss verdrängt werden kann. Im Lineweaver-Burk-Diagramm verschiebt sich der x-Achsenabschnitt, aber der y-Achsenabschnitt bleibt gleich.","fr":"Augmente le Km apparent (réduit l'affinité apparente) ; Vmax reste inchangé car l'inhibiteur peut être surpassé par un excès de substrat. Sur un diagramme de Lineweaver-Burk, l'intersection avec l'axe x change mais celle avec l'axe y reste la même.","tr":"Görünür Km'yi artırır (görünür afiniteyi azaltır); Vmax değişmez çünkü inhibitör aşırı substrat ile yarıştan çıkarılabilir. Lineweaver-Burk grafiğinde x-kesişimi kayar ama y-kesişimi aynı kalır.","nl":"Verhoogt de schijnbare Km (vermindert schijnbare affiniteit); Vmax blijft ongewijzigd omdat de remmer kan worden verdrongen door overmaat substraat. Op een Lineweaver-Burk-plot verschuift het x-snijpunt maar het y-snijpunt blijft gelijk.","ru":"Увеличивает кажущийся Km (снижает кажущееся сродство); Vmax не изменяется, так как ингибитор может быть вытеснен избытком субстрата. На графике Лайнуивера-Бёрка точка пересечения с осью x смещается, а точка пересечения с осью y остаётся прежней.","zh":"增加表观 Km（降低表观亲和力）；Vmax 不变，因为过量底物可以竞争掉抑制剂。在 Lineweaver-Burk 图上，x 轴截距移动，但 y 轴截距不变。","pt_BR":"Aumenta o Km aparente (reduz a afinidade aparente); Vmax não muda porque o inibidor pode ser superado por excesso de substrato. No gráfico de Lineweaver-Burk, o intercepto em x muda, mas o intercepto em y permanece o mesmo.","pt_PT":"Aumenta o Km aparente (reduz a afinidade aparente); Vmax não muda porque o inibidor pode ser superado por excesso de substrato. No gráfico de Lineweaver-Burk, o intercepto em x muda, mas o intercepto em y permanece o mesmo."}},
  { id: 'dc-mcat-0004', deck_id: 'deck-mcat', sort_order: 4, front: "Non-Competitive Inhibition (Kinetics)", back: "Inhibitor binds allosteric site regardless of substrate; decreases Vmax but Km is unchanged. Cannot be overcome by adding more substrate. On a Lineweaver-Burk plot, y-intercept increases but x-intercept stays the same." , front_translations: {"es":"Inibición No Competitiva (Cinética)","de":"Nicht-kompetitive Hemmung (Kinetik)","fr":"Inhibition non compétitive (cinétique)","tr":"Non-kompetitif İnhibisyon (Kinetik)","nl":"Niet-competitieve remming (kinetiek)","ru":"Неконкурентное ингибирование (кинетика)","zh":"非竞争性抑制（动力学）","pt_BR":"Inibição Não Competitiva (Cinética)","pt_PT":"Inibição Não Competitiva (Cinética)"}, back_translations: {"es":"El inibidor se liga al sítio alostérico independentemente del substrato; disminuye Vmax, pero Km permanece inalterado. No puede ser superado adicionando más substrato. No gráfico de Lineweaver-Burk, el intercepto en y aumenta, pero el intercepto en x permanece el mismo.","de":"Der Inhibitor bindet an eine allosterische Stelle unabhängig vom Substrat; verringert Vmax, aber Km bleibt unverändert. Kann nicht durch Zugabe von mehr Substrat überwunden werden. Im Lineweaver-Burk-Diagramm steigt der y-Achsenabschnitt, aber der x-Achsenabschnitt bleibt gleich.","fr":"L'inhibiteur se lie au site allostérique indépendamment du substrat ; diminue Vmax mais Km reste inchangé. Ne peut pas être surmonté en ajoutant plus de substrat. Sur un diagramme de Lineweaver-Burk, l'intersection avec l'axe y augmente mais celle avec l'axe x reste la même.","tr":"İnhibitör, substrattan bağımsız olarak allosterik bölgeye bağlanır; Vmax'ı düşürür ama Km değişmez. Daha fazla substrat ekleyerek aşılamaz. Lineweaver-Burk grafiğinde y-kesişimi artar ama x-kesişimi aynı kalır.","nl":"De remmer bindt aan een allosterische plaats ongeacht het substraat; verlaagt Vmax maar Km blijft ongewijzigd. Kan niet worden overwonnen door meer substraat toe te voegen. Op een Lineweaver-Burk-plot stijgt het y-snijpunt maar het x-snijpunt blijft gelijk.","ru":"Ингибитор связывается с аллостерическим сайтом независимо от субстрата; снижает Vmax, но Km не изменяется. Не может быть преодолено добавлением субстрата. На графике Лайнуивера-Бёрка точка пересечения с осью y увеличивается, а с осью x остаётся прежней.","zh":"抑制剂无论底物是否存在均结合于变构位点；降低 Vmax 但 Km 不变。无法通过增加底物来克服。在 Lineweaver-Burk 图上，y 轴截距增大，但 x 轴截距不变。","pt_BR":"O inibidor se liga ao sítio alostérico independentemente do substrato; diminui Vmax, mas Km permanece inalterado. Não pode ser superado adicionando mais substrato. No gráfico de Lineweaver-Burk, o intercepto em y aumenta, mas o intercepto em x permanece o mesmo.","pt_PT":"O inibidor liga-se ao sítio alostérico independentemente do substrato; diminui Vmax, mas Km permanece inalterado. Não pode ser superado adicionando mais substrato. No gráfico de Lineweaver-Burk, o intercepto em y aumenta, mas o intercepto em x permanece o mesmo."}},
  { id: 'dc-mcat-0005', deck_id: 'deck-mcat', sort_order: 5, front: "Feedback Inhibition", back: "A regulatory mechanism where the end product of a metabolic pathway inhibits an enzyme earlier in the pathway, usually the first committed step. Common in amino acid biosynthesis; prevents overproduction of a product." , front_translations: {"es":"Inibición por Retroalimentación","de":"Rückkopplungshemmung","fr":"Inhibition par rétroaction","tr":"Geri Bildirim İnhibisyonu","nl":"Feedbackremming","ru":"Ингибирование по типу обратной связи","zh":"反馈抑制","pt_BR":"Inibição por Retroalimentação","pt_PT":"Inibição por Retroalimentação"}, back_translations: {"es":"Un mecanismo regulatório en el qual el producto final de una via metabólica inibe una enzima en el início de la via, generalmente a primera etapa comprometida. Comum en la biossíntese de aminoácidos; previene a superprodución de un producto.","de":"Ein Regulationsmechanismus, bei dem das Endprodukt eines Stoffwechselwegs ein Enzym am Anfang des Weges hemmt, meist den ersten irreversiblen Schritt. Häufig bei der Aminosäurebiosynthese; verhindert Überproduktion eines Produkts.","fr":"Un mécanisme de régulation où le produit final d'une voie métabolique inhibe une enzyme plus tôt dans la voie, généralement la première étape engagée. Courant dans la biosynthèse des acides aminés ; empêche la surproduction d'un produit.","tr":"Bir metabolik yolun son ürününün, yolun başındaki bir enzimi inhibe ettiği düzenleyici mekanizma; genellikle ilk bağlanmış adımı inhibe eder. Amino asit biyosentezinde yaygındır; bir ürünün aşırı üretimini önler.","nl":"Een regulerend mechanisme waarbij het eindproduct van een metabole route een enzym eerder in de route remt, meestal de eerste gecommitteerde stap. Komt veel voor bij aminozuurbiosynthese; voorkomt overproductie van een product.","ru":"Регуляторный механизм, при котором конечный продукт метаболического пути ингибирует фермент на ранней стадии пути, обычно на первом необратимом этапе. Распространён в биосинтезе аминокислот; предотвращает перепроизводство продукта.","zh":"一种调节机制，代谢途径的终产物抑制途径前端的酶，通常是第一个关键步骤。常见于氨基酸生物合成中；防止产物过量生成。","pt_BR":"Um mecanismo regulatório no qual o produto final de uma via metabólica inibe uma enzima no início da via, geralmente a primeira etapa comprometida. Comum na biossíntese de aminoácidos; previne a superprodução de um produto.","pt_PT":"Um mecanismo regulatório no qual o produto final de uma via metabólica inibe uma enzima no início da via, geralmente a primeira etapa comprometida. Comum na biossíntese de aminoácidos; previne a superprodução de um produto."}},
  { id: 'dc-mcat-0006', deck_id: 'deck-mcat', sort_order: 6, front: "Cell Signaling: G-Protein Coupled Receptor (GPCR)", back: "A ligand binds the receptor, activating a G-protein (GDP → GTP exchange). The G-protein activates/inhibits effectors (adenylyl cyclase, phospholipase C). Key second messengers: cAMP, IP₃, DAG, Ca²⁺." , front_translations: {"es":"Sinalización Celular: Receptor Acoplado a la Proteína G (GPCR)","de":"Zellsignalübertragung: G-Protein-gekoppelter Rezeptor (GPCR)","fr":"Signalisation cellulaire : récepteur couplé aux protéines G (GPCR)","tr":"Hücre Sinyalizasyonu: G-Proteini Kuplajlı Reseptör (GPCR)","nl":"Celsignalering: G-proteïne-gekoppelde receptor (GPCR)","ru":"Клеточная сигнализация: рецептор, сопряжённый с G-белком (GPCR)","zh":"细胞信号传导：G 蛋白偶联受体 (GPCR)","pt_BR":"Sinalização Celular: Receptor Acoplado à Proteína G (GPCR)","pt_PT":"Sinalização Celular: Receptor Acoplado à Proteína G (GPCR)"}, back_translations: {"es":"Un ligante se liga al receptor, ativando una proteína G (troca GDP → GTP). La proteína G ativa/inibe efetores (adenilato ciclase, fosfolipase C). Segundos mensageros principales: cAMP, IP₃, DAG, Ca²⁺.","de":"Ein Ligand bindet an den Rezeptor und aktiviert ein G-Protein (GDP → GTP-Austausch). Das G-Protein aktiviert/hemmt Effektoren (Adenylatcyclase, Phospholipase C). Wichtige sekundäre Botenstoffe: cAMP, IP₃, DAG, Ca²⁺.","fr":"Un ligand se lie au récepteur, activant une protéine G (échange GDP → GTP). La protéine G active/inhibe des effecteurs (adénylate cyclase, phospholipase C). Seconds messagers clés : cAMP, IP₃, DAG, Ca²⁺.","tr":"Bir ligand reseptöre bağlanarak G-proteinini aktive eder (GDP → GTP değişimi). G-proteini, efektörleri (adenilat siklaz, fosfolipaz C) aktive/inhibe eder. Önemli ikincil haberciler: cAMP, IP₃, DAG, Ca²⁺.","nl":"Een ligand bindt aan de receptor en activeert een G-proteïne (GDP → GTP-uitwisseling). Het G-proteïne activeert/remt effectoren (adenylcyclase, fosfolipase C). Belangrijke second messengers: cAMP, IP₃, DAG, Ca²⁺.","ru":"Лиганд связывается с рецептором, активируя G-белок (обмен GDP → GTP). G-белок активирует/ингибирует эффекторы (аденилатциклазу, фосфолипазу C). Ключевые вторичные мессенджеры: cAMP, IP₃, DAG, Ca²⁺.","zh":"配体与受体结合，激活 G 蛋白（GDP → GTP 交换）。G 蛋白激活/抑制效应器（腺苷酸环化酶、磷脂酶 C）。关键第二信使：cAMP、IP₃、DAG、Ca²⁺。","pt_BR":"Um ligante se liga ao receptor, ativando uma proteína G (troca GDP → GTP). A proteína G ativa/inibe efetores (adenilato ciclase, fosfolipase C). Segundos mensageiros principais: cAMP, IP₃, DAG, Ca²⁺.","pt_PT":"Um ligando liga-se ao receptor, ativando uma proteína G (troca GDP → GTP). A proteína G ativa/inibe efetores (adenilato ciclase, fosfolipase C). Segundos mensageiros principais: cAMP, IP₃, DAG, Ca²⁺."}},
  { id: 'dc-mcat-0007', deck_id: 'deck-mcat', sort_order: 7, front: "Receptor Tyrosine Kinase (RTK)", back: "A transmembrane receptor that dimerizes and autophosphorylates tyrosine residues upon ligand binding. Activates downstream cascades (RAS-MAPK, PI3K-Akt). Important in growth factor signaling (EGF, insulin receptor)." , front_translations: {"es":"Receptor Tirosina Quinase (RTK)","de":"Rezeptortyrosinkinase (RTK)","fr":"Récepteur à activité tyrosine kinase (RTK)","tr":"Reseptör Tirozin Kinaz (RTK)","nl":"Receptortyrosinekinase (RTK)","ru":"Рецепторная тирозинкиназа (RTK)","zh":"受体酪氨酸激酶 (RTK)","pt_BR":"Receptor Tirosina Quinase (RTK)","pt_PT":"Recetor Tirosina Cinase (RTK)"}, back_translations: {"es":"Un receptor transmembrana que dimeriza y autofosforila resíduos de tirosina após a enlace del ligante. Ativa cascatas a jusante (RAS-MAPK, PI3K-Akt). Importante en la sinalización de fatores de crecimiento (EGF, receptor de insulina).","de":"Ein Transmembranrezeptor, der bei Ligandenbindung dimerisiert und Tyrosinreste autophosphoryliert. Aktiviert nachgeschaltete Kaskaden (RAS-MAPK, PI3K-Akt). Wichtig in der Wachstumsfaktorsignalübertragung (EGF, Insulinrezeptor).","fr":"Un récepteur transmembranaire qui se dimérise et s'autophosphoryle sur des résidus tyrosine lors de la liaison du ligand. Active des cascades en aval (RAS-MAPK, PI3K-Akt). Important dans la signalisation des facteurs de croissance (EGF, récepteur de l'insuline).","tr":"Ligand bağlanması üzerine dimerize olan ve tirozin kalıntılarını otofosforile eden bir transmembran reseptör. Alt akış kaskadlarını aktive eder (RAS-MAPK, PI3K-Akt). Büyüme faktörü sinyalizasyonunda önemlidir (EGF, insülin reseptörü).","nl":"Een transmembraanreceptor die dimeriseert en tyrosineresiduen autofosforyleert bij ligandbinding. Activeert stroomafwaartse cascades (RAS-MAPK, PI3K-Akt). Belangrijk in groeifactorsignalering (EGF, insulinereceptor).","ru":"Трансмембранный рецептор, который димеризуется и аутофосфорилирует остатки тирозина при связывании лиганда. Активирует нисходящие каскады (RAS-MAPK, PI3K-Akt). Важен в сигнализации факторов роста (EGF, рецептор инсулина).","zh":"一种跨膜受体，在配体结合后二聚化并自磷酸化酪氨酸残基。激活下游级联反应（RAS-MAPK、PI3K-Akt）。在生长因子信号传导中至关重要（EGF、胰岛素受体）。","pt_BR":"Um receptor transmembrana que dimeriza e autofosforila resíduos de tirosina após a ligação do ligante. Ativa cascatas a jusante (RAS-MAPK, PI3K-Akt). Importante na sinalização de fatores de crescimento (EGF, receptor de insulina).","pt_PT":"Um recetor transmembranar que dimeriza e autofosforila resíduos de tirosina após a ligação do ligando. Ativa cascatas a jusante (RAS-MAPK, PI3K-Akt). Importante na sinalização de fatores de crescimento (EGF, recetor de insulina)."}},
  { id: 'dc-mcat-0008', deck_id: 'deck-mcat', sort_order: 8, front: "Protein Structure: Primary to Quaternary", back: "1°: amino acid sequence. 2°: α-helix and β-sheet from backbone H-bonds. 3°: 3D folding from R-group interactions (hydrophobic, disulfide, ionic, H-bonds). 4°: multiple subunit assembly (e.g., hemoglobin)." , front_translations: {"es":"Estrutura Proteica: Primária a Quaternária","de":"Proteinstruktur: Primär- bis Quartärstruktur","fr":"Structure des protéines : du primaire au quaternaire","tr":"Protein Yapısı: Birincilden Dördüncül Yapıya","nl":"Eiwitstructuur: primair tot quaternair","ru":"Структура белка: от первичной до четвертичной","zh":"蛋白质结构：一级到四级","pt_BR":"Estrutura Proteica: Primária a Quaternária","pt_PT":"Estrutura Proteica: Primária a Quaternária"}, back_translations: {"es":"1°: secuencia de aminoácidos. 2°: α-hélice y hoja β por enlaces H de la cadeia principal. 3°: dobramento 3D por interacciones de grupos R (hidrofóbicas, dissulfeto, ionicas, enlaces H). 4°: montaje de múltiplas subunidades (ex.: hemoglobina).","de":"1°: Aminosäuresequenz. 2°: α-Helix und β-Faltblatt durch Wasserstoffbrücken im Rückgrat. 3°: 3D-Faltung durch R-Gruppen-Wechselwirkungen (hydrophob, Disulfid, ionisch, H-Brücken). 4°: Zusammenlagerung mehrerer Untereinheiten (z. B. Hämoglobin).","fr":"1° : séquence d'acides aminés. 2° : hélice α et feuillet β par liaisons H du squelette. 3° : repliement 3D par interactions des groupes R (hydrophobes, disulfures, ioniques, liaisons H). 4° : assemblage de plusieurs sous-unités (ex. : hémoglobine).","tr":"1°: amino asit dizisi. 2°: omurga H-bağlarından α-heliks ve β-tabaka. 3°: R-grubu etkileşimlerinden 3B katlanma (hidrofobik, disülfid, iyonik, H-bağları). 4°: çoklu alt birim düzeni (ör. hemoglobin).","nl":"1°: aminozuurvolgorde. 2°: α-helix en β-sheet door waterstofbruggen in de ruggengraat. 3°: 3D-vouwing door R-groep-interacties (hydrofoob, disulfide, ionisch, H-bruggen). 4°: assemblage van meerdere subeenheden (bijv. hemoglobine).","ru":"1°: аминокислотная последовательность. 2°: α-спираль и β-лист за счёт водородных связей основной цепи. 3°: трёхмерная укладка за счёт взаимодействий R-групп (гидрофобные, дисульфидные, ионные, водородные связи). 4°: сборка из нескольких субъединиц (напр., гемоглобин).","zh":"1°：氨基酸序列。2°：主链氢键形成的 α-螺旋和 β-折叠。3°：R 基团相互作用的三维折叠（疏水、二硫键、离子键、氢键）。4°：多亚基组装（如血红蛋白）。","pt_BR":"1°: sequência de aminoácidos. 2°: α-hélice e folha β por ligações H da cadeia principal. 3°: dobramento 3D por interações de grupos R (hidrofóbicas, dissulfeto, iônicas, ligações H). 4°: montagem de múltiplas subunidades (ex.: hemoglobina).","pt_PT":"1°: sequência de aminoácidos. 2°: α-hélice e folha β por ligações H da cadeia principal. 3°: enrolamento 3D por interações de grupos R (hidrofóbicas, dissulfureto, iónicas, ligações H). 4°: montagem de múltiplas subunidades (ex.: hemoglobina)."}},
  { id: 'dc-mcat-0009', deck_id: 'deck-mcat', sort_order: 9, front: "Membrane Transport: Simple Diffusion", back: "Passive movement of small, nonpolar molecules (O₂, CO₂, ethanol) directly through the lipid bilayer down their concentration gradient. No protein, no energy required. Rate is proportional to concentration gradient." , front_translations: {"es":"Transporte de Membrana: Difusão Simples","de":"Membrantransport: Einfache Diffusion","fr":"Transport membranaire : diffusion simple","tr":"Membran Taşınımı: Basit Difüzyon","nl":"Membraantransport: eenvoudige diffusie","ru":"Мембранный транспорт: простая диффузия","zh":"膜运输：简单扩散","pt_BR":"Transporte de Membrana: Difusão Simples","pt_PT":"Transporte de Membrana: Difusão Simples"}, back_translations: {"es":"Movimento passivo de moléculas pequeñas y apolares (El₂, CO₂, etanol) directamente a través de la bicamada lipídica a favor del gradiente de concentración. Sin proteína, sin energía necesaria. La taxa es proporcional al gradiente de concentración.","de":"Passive Bewegung kleiner, unpolarer Moleküle (O₂, CO₂, Ethanol) direkt durch die Lipiddoppelschicht entlang ihres Konzentrationsgradienten. Kein Protein, keine Energie erforderlich. Die Rate ist proportional zum Konzentrationsgradienten.","fr":"Mouvement passif de petites molécules non polaires (O₂, CO₂, éthanol) directement à travers la bicouche lipidique selon leur gradient de concentration. Aucune protéine ni énergie requise. La vitesse est proportionnelle au gradient de concentration.","tr":"Küçük, polar olmayan moleküllerin (O₂, CO₂, etanol) konsantrasyon gradyanı boyunca doğrudan lipit çift tabakası üzerinden pasif hareketi. Protein veya enerji gerekmez. Hız, konsantrasyon gradyanı ile orantılıdır.","nl":"Passieve beweging van kleine, apolaire moleculen (O₂, CO₂, ethanol) rechtstreeks door de lipide dubbellaag langs hun concentratiegradiënt. Geen eiwit, geen energie nodig. De snelheid is evenredig met de concentratiegradiënt.","ru":"Пассивное перемещение малых неполярных молекул (O₂, CO₂, этанол) непосредственно через липидный бислой по градиенту концентрации. Не требуется белок или энергия. Скорость пропорциональна градиенту концентрации.","zh":"小型非极性分子（O₂、CO₂、乙醇）沿浓度梯度直接通过脂双层的被动运动。无需蛋白质或能量。速率与浓度梯度成正比。","pt_BR":"Movimento passivo de moléculas pequenas e apolares (O₂, CO₂, etanol) diretamente através da bicamada lipídica a favor do gradiente de concentração. Sem proteína, sem energia necessária. A taxa é proporcional ao gradiente de concentração.","pt_PT":"Movimento passivo de moléculas pequenas e apolares (O₂, CO₂, etanol) diretamente através da bicamada lipídica a favor do gradiente de concentração. Sem proteína, sem energia necessária. A taxa é proporcional ao gradiente de concentração."}},
  { id: 'dc-mcat-0010', deck_id: 'deck-mcat', sort_order: 10, front: "Membrane Transport: Facilitated Diffusion", back: "Passive transport of larger or polar molecules via protein channels or carriers, down their concentration gradient. No ATP required. Examples: glucose uptake by GLUT transporters, ion movement through channels." , front_translations: {"es":"Transporte de Membrana: Difusão Facilitada","de":"Membrantransport: Erleichterte Diffusion","fr":"Transport membranaire : diffusion facilitée","tr":"Membran Taşınımı: Kolaylaştırılmış Difüzyon","nl":"Membraantransport: gefaciliteerde diffusie","ru":"Мембранный транспорт: облегчённая диффузия","zh":"膜运输：协助扩散","pt_BR":"Transporte de Membrana: Difusão Facilitada","pt_PT":"Transporte de Membrana: Difusão Facilitada"}, back_translations: {"es":"Transporte passivo de moléculas mayores o polares via canais o carreadores proteicos, a favor del gradiente de concentración. Sin ATP necesario. Exemplos: captación de glicose por transportadores GLUT, movimiento de iones por canais.","de":"Passiver Transport größerer oder polarer Moleküle über Proteinkanäle oder Carrier entlang des Konzentrationsgradienten. Kein ATP erforderlich. Beispiele: Glukoseaufnahme durch GLUT-Transporter, Ionenbewegung durch Kanäle.","fr":"Transport passif de molécules plus grandes ou polaires via des canaux ou transporteurs protéiques, selon leur gradient de concentration. Pas d'ATP requis. Exemples : absorption du glucose par les transporteurs GLUT, mouvement des ions à travers des canaux.","tr":"Büyük veya polar moleküllerin protein kanalları veya taşıyıcılar aracılığıyla konsantrasyon gradyanı boyunca pasif taşınımı. ATP gerekmez. Örnekler: GLUT taşıyıcılarıyla glikoz alımı, kanallardan iyon hareketi.","nl":"Passief transport van grotere of polaire moleculen via eiwitkanalen of carriers, langs hun concentratiegradiënt. Geen ATP nodig. Voorbeelden: glucoseopname door GLUT-transporters, ionenbeweging door kanalen.","ru":"Пассивный транспорт крупных или полярных молекул через белковые каналы или переносчики по градиенту концентрации. ATP не требуется. Примеры: поглощение глюкозы транспортёрами GLUT, движение ионов через каналы.","zh":"较大或极性分子通过蛋白质通道或载体沿浓度梯度的被动运输。不需要 ATP。例如：GLUT 转运蛋白摄取葡萄糖、离子通过通道的运动。","pt_BR":"Transporte passivo de moléculas maiores ou polares via canais ou carreadores proteicos, a favor do gradiente de concentração. Sem ATP necessário. Exemplos: captação de glicose por transportadores GLUT, movimento de íons por canais.","pt_PT":"Transporte passivo de moléculas maiores ou polares via canais ou transportadores proteicos, a favor do gradiente de concentração. Sem ATP necessário. Exemplos: captação de glicose por transportadores GLUT, movimento de iões por canais."}},
  { id: 'dc-mcat-0011', deck_id: 'deck-mcat', sort_order: 11, front: "Glycolysis (Steps Overview)", back: "10-step pathway in the cytoplasm. Investment phase: 2 ATP consumed. Payoff phase: 4 ATP produced. Net: 2 ATP, 2 NADH, 2 pyruvate per glucose. Key regulatory enzyme: PFK-1 (inhibited by ATP, citrate; activated by AMP, ADP)." , front_translations: {"es":"Glicólise (Visão Geral de las Etapas)","de":"Glykolyse (Schritte im Überblick)","fr":"Glycolyse (vue d'ensemble des étapes)","tr":"Glikoliz (Adımlara Genel Bakış)","nl":"Glycolyse (overzicht van stappen)","ru":"Гликолиз (обзор этапов)","zh":"糖酵解（步骤概述）","pt_BR":"Glicólise (Visão Geral das Etapas)","pt_PT":"Glicólise (Visão Geral das Etapas)"}, back_translations: {"es":"Via de 10 etapas en el citoplasma. Fase de inversión: 2 ATP consumidos. Fase de retorno: 4 ATP producidos. Saldo: 2 ATP, 2 NADH, 2 piruvatos por glicose. Enzima reguladora chave: PFK-1 (inibida por ATP, citrato; ativada por AMP, ADP).","de":"10-stufiger Weg im Zytoplasma. Investitionsphase: 2 ATP verbraucht. Ertragsphase: 4 ATP produziert. Netto: 2 ATP, 2 NADH, 2 Pyruvat pro Glukose. Wichtiges regulatorisches Enzym: PFK-1 (gehemmt durch ATP, Citrat; aktiviert durch AMP, ADP).","fr":"Voie en 10 étapes dans le cytoplasme. Phase d'investissement : 2 ATP consommés. Phase de gain : 4 ATP produits. Bilan net : 2 ATP, 2 NADH, 2 pyruvates par glucose. Enzyme régulatrice clé : PFK-1 (inhibée par ATP, citrate ; activée par AMP, ADP).","tr":"Sitoplazmada 10 adımlık yol. Yatırım fazı: 2 ATP harcanır. Kazanç fazı: 4 ATP üretilir. Net: glikoz başına 2 ATP, 2 NADH, 2 piruvat. Anahtar düzenleyici enzim: PFK-1 (ATP, sitrat ile inhibe; AMP, ADP ile aktive edilir).","nl":"10-staps route in het cytoplasma. Investeringsfase: 2 ATP verbruikt. Opbrengstfase: 4 ATP geproduceerd. Netto: 2 ATP, 2 NADH, 2 pyruvaat per glucose. Belangrijk regulerend enzym: PFK-1 (geremd door ATP, citraat; geactiveerd door AMP, ADP).","ru":"10-стадийный путь в цитоплазме. Фаза затрат: 2 ATP потребляются. Фаза отдачи: 4 ATP производятся. Итого: 2 ATP, 2 NADH, 2 пирувата на глюкозу. Ключевой регуляторный фермент: PFK-1 (ингибируется ATP, цитратом; активируется AMP, ADP).","zh":"细胞质中的 10 步途径。投入阶段：消耗 2 ATP。收获阶段：产生 4 ATP。净产出：每分子葡萄糖 2 ATP、2 NADH、2 丙酮酸。关键调节酶：PFK-1（被 ATP、柠檬酸抑制；被 AMP、ADP 激活）。","pt_BR":"Via de 10 etapas no citoplasma. Fase de investimento: 2 ATP consumidos. Fase de retorno: 4 ATP produzidos. Saldo: 2 ATP, 2 NADH, 2 piruvatos por glicose. Enzima reguladora chave: PFK-1 (inibida por ATP, citrato; ativada por AMP, ADP).","pt_PT":"Via de 10 etapas no citoplasma. Fase de investimento: 2 ATP consumidos. Fase de retorno: 4 ATP produzidos. Saldo: 2 ATP, 2 NADH, 2 piruvatos por glicose. Enzima reguladora chave: PFK-1 (inibida por ATP, citrato; ativada por AMP, ADP)."}},
  { id: 'dc-mcat-0012', deck_id: 'deck-mcat', sort_order: 12, front: "Pyruvate Decarboxylation", back: "Pyruvate (3C) is converted to acetyl-CoA (2C) + CO₂ + NADH in the mitochondrial matrix by pyruvate dehydrogenase complex. Irreversible step linking glycolysis to the Krebs cycle. Inhibited by its own products (NADH, acetyl-CoA)." , front_translations: {"es":"Descarboxilación del Piruvato","de":"Pyruvatdecarboxylierung","fr":"Décarboxylation du pyruvate","tr":"Piruvat Dekarboksilasyonu","nl":"Pyruvaatdecarboxylering","ru":"Декарбоксилирование пирувата","zh":"丙酮酸脱羧","pt_BR":"Descarboxilação do Piruvato","pt_PT":"Descarboxilação do Piruvato"}, back_translations: {"es":"El piruvato (3C) es convertido en acetil-CoA (2C) + CO₂ + NADH en la matriz mitocondrial por el complexo piruvato desidrogenase. Etapa irreversible ligando a glicólise al ciclo de Krebs. Inibido por sus propios productos (NADH, acetil-CoA).","de":"Pyruvat (3C) wird in der mitochondrialen Matrix durch den Pyruvatdehydrogenase-Komplex zu Acetyl-CoA (2C) + CO₂ + NADH umgewandelt. Irreversibler Schritt, der Glykolyse mit dem Krebs-Zyklus verbindet. Gehemmt durch eigene Produkte (NADH, Acetyl-CoA).","fr":"Le pyruvate (3C) est converti en acétyl-CoA (2C) + CO₂ + NADH dans la matrice mitochondriale par le complexe pyruvate déshydrogénase. Étape irréversible reliant la glycolyse au cycle de Krebs. Inhibé par ses propres produits (NADH, acétyl-CoA).","tr":"Piruvat (3C), mitokondri matriksinde piruvat dehidrojenaz kompleksi tarafından asetil-CoA (2C) + CO₂ + NADH'ye dönüştürülür. Glikolizi Krebs döngüsüne bağlayan geri dönüşümsüz adım. Kendi ürünleri (NADH, asetil-CoA) tarafından inhibe edilir.","nl":"Pyruvaat (3C) wordt omgezet in acetyl-CoA (2C) + CO₂ + NADH in de mitochondriale matrix door het pyruvaatdehydrogenasecomplex. Onomkeerbare stap die glycolyse met de Krebs-cyclus verbindt. Geremd door eigen producten (NADH, acetyl-CoA).","ru":"Пируват (3C) превращается в ацетил-CoA (2C) + CO₂ + NADH в митохондриальном матриксе комплексом пируватдегидрогеназы. Необратимый шаг, связывающий гликолиз с циклом Кребса. Ингибируется собственными продуктами (NADH, ацетил-CoA).","zh":"丙酮酸（3C）在线粒体基质中由丙酮酸脱氢酶复合体转化为乙酰 CoA（2C）+ CO₂ + NADH。连接糖酵解与 Krebs 循环的不可逆步骤。受自身产物（NADH、乙酰 CoA）抑制。","pt_BR":"O piruvato (3C) é convertido em acetil-CoA (2C) + CO₂ + NADH na matriz mitocondrial pelo complexo piruvato desidrogenase. Etapa irreversível ligando a glicólise ao ciclo de Krebs. Inibido por seus próprios produtos (NADH, acetil-CoA).","pt_PT":"O piruvato (3C) é convertido em acetil-CoA (2C) + CO₂ + NADH na matriz mitocondrial pelo complexo piruvato desidrogenase. Etapa irreversível que liga a glicólise ao ciclo de Krebs. Inibido pelos seus próprios produtos (NADH, acetil-CoA)."}},
  { id: 'dc-mcat-0013', deck_id: 'deck-mcat', sort_order: 13, front: "TCA Cycle (Krebs Cycle) Yield", back: "Per acetyl-CoA turn: 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. Per glucose (two turns): 6 NADH, 2 FADH₂, 2 GTP. Occurs in the mitochondrial matrix; all intermediates regenerate oxaloacetate." , front_translations: {"es":"Rendimento del Ciclo TCA (Ciclo de Krebs)","de":"TCA-Zyklus (Krebs-Zyklus) Ertrag","fr":"Rendement du cycle TCA (cycle de Krebs)","tr":"TCA Döngüsü (Krebs Döngüsü) Verimi","nl":"TCA-cyclus (Krebs-cyclus) opbrengst","ru":"Выход цикла TCA (цикл Кребса)","zh":"TCA 循环（Krebs 循环）产出","pt_BR":"Rendimento do Ciclo TCA (Ciclo de Krebs)","pt_PT":"Rendimento do Ciclo TCA (Ciclo de Krebs)"}, back_translations: {"es":"Por volta de acetil-CoA: 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. Por glicose (de los voltas): 6 NADH, 2 FADH₂, 2 GTP. Ocorre en la matriz mitocondrial; todos los intermediários regeneram oxaloacetato.","de":"Pro Acetyl-CoA-Umdrehung: 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. Pro Glukose (zwei Umdrehungen): 6 NADH, 2 FADH₂, 2 GTP. Findet in der mitochondrialen Matrix statt; alle Intermediate regenerieren Oxalacetat.","fr":"Par tour d'acétyl-CoA : 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. Par glucose (deux tours) : 6 NADH, 2 FADH₂, 2 GTP. Se déroule dans la matrice mitochondriale ; tous les intermédiaires régénèrent l'oxaloacétate.","tr":"Her asetil-CoA dönüşünde: 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. Her glikoz için (iki dönüş): 6 NADH, 2 FADH₂, 2 GTP. Mitokondri matriksinde gerçekleşir; tüm ara ürünler oksaloasetatı yeniler.","nl":"Per acetyl-CoA-ronde: 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. Per glucose (twee rondes): 6 NADH, 2 FADH₂, 2 GTP. Vindt plaats in de mitochondriale matrix; alle tussenproducten regenereren oxaalacetaat.","ru":"На один оборот ацетил-CoA: 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. На глюкозу (два оборота): 6 NADH, 2 FADH₂, 2 GTP. Происходит в митохондриальном матриксе; все интермедиаты регенерируют оксалоацетат.","zh":"每轮乙酰 CoA：3 NADH、1 FADH₂、1 GTP (ATP)、2 CO₂。每分子葡萄糖（两轮）：6 NADH、2 FADH₂、2 GTP。发生在线粒体基质中；所有中间体再生草酰乙酸。","pt_BR":"Por volta de acetil-CoA: 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. Por glicose (duas voltas): 6 NADH, 2 FADH₂, 2 GTP. Ocorre na matriz mitocondrial; todos os intermediários regeneram oxaloacetato.","pt_PT":"Por volta de acetil-CoA: 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. Por glicose (duas voltas): 6 NADH, 2 FADH₂, 2 GTP. Ocorre na matriz mitocondrial; todos os intermediários regeneram oxaloacetato."}},
  { id: 'dc-mcat-0014', deck_id: 'deck-mcat', sort_order: 14, front: "Electron Transport Chain (ETC)", back: "Located in the inner mitochondrial membrane. NADH enters at Complex I (4H⁺ pumped), FADH₂ at Complex II (0H⁺). Complexes I, III, IV pump H⁺ into the intermembrane space. O₂ is the final electron acceptor (→ H₂O)." , front_translations: {"es":"Cadeia de Transporte de Elétrons (ETC)","de":"Elektronentransportkette (ETC)","fr":"Chaîne de transport des électrons (ETC)","tr":"Elektron Taşıma Zinciri (ETC)","nl":"Elektronentransportketen (ETC)","ru":"Электрон-транспортная цепь (ETC)","zh":"电子传递链 (ETC)","pt_BR":"Cadeia de Transporte de Elétrons (ETC)","pt_PT":"Cadeia de Transporte de Eletrões (ETC)"}, back_translations: {"es":"Localizada en la membrana mitocondrial interna. NADH entra en el Complexo I (4H⁺ bombeados), FADH₂ en el Complexo II (0H⁺). Complexos I, III, IV bombeiam H⁺ para el espacio intermembranar. El₂ es el aceptor final de electrones (→ H₂El).","de":"Befindet sich in der inneren Mitochondrienmembran. NADH tritt bei Komplex I ein (4H⁺ gepumpt), FADH₂ bei Komplex II (0H⁺). Komplexe I, III, IV pumpen H⁺ in den Intermembranraum. O₂ ist der finale Elektronenakzeptor (→ H₂O).","fr":"Située dans la membrane mitochondriale interne. Le NADH entre au Complexe I (4H⁺ pompés), le FADH₂ au Complexe II (0H⁺). Les Complexes I, III, IV pompent les H⁺ dans l'espace intermembranaire. O₂ est l'accepteur final d'électrons (→ H₂O).","tr":"İç mitokondri zarında bulunur. NADH Kompleks I'de girer (4H⁺ pompalanır), FADH₂ Kompleks II'de (0H⁺). Kompleks I, III, IV H⁺'yi zarlar arası boşluğa pompalar. O₂ son elektron alıcısıdır (→ H₂O).","nl":"Gelegen in het binnenste mitochondriale membraan. NADH treedt in bij Complex I (4H⁺ gepompt), FADH₂ bij Complex II (0H⁺). Complexen I, III, IV pompen H⁺ naar de intermembraanruimte. O₂ is de uiteindelijke elektronenacceptor (→ H₂O).","ru":"Расположена во внутренней мембране митохондрий. NADH входит в Комплекс I (перекачивается 4H⁺), FADH₂ — в Комплекс II (0H⁺). Комплексы I, III, IV перекачивают H⁺ в межмембранное пространство. O₂ — конечный акцептор электронов (→ H₂O).","zh":"位于线粒体内膜。NADH 在复合体 I 进入（泵出 4H⁺），FADH₂ 在复合体 II（0H⁺）。复合体 I、III、IV 将 H⁺ 泵入膜间隙。O₂ 是最终电子受体（→ H₂O）。","pt_BR":"Localizada na membrana mitocondrial interna. NADH entra no Complexo I (4H⁺ bombeados), FADH₂ no Complexo II (0H⁺). Complexos I, III, IV bombeiam H⁺ para o espaço intermembranar. O₂ é o aceptor final de elétrons (→ H₂O).","pt_PT":"Localizada na membrana mitocondrial interna. NADH entra no Complexo I (4H⁺ bombeados), FADH₂ no Complexo II (0H⁺). Complexos I, III, IV bombeiam H⁺ para o espaço intermembranar. O₂ é o aceitador final de eletrões (→ H₂O)."}},
  { id: 'dc-mcat-0015', deck_id: 'deck-mcat', sort_order: 15, front: "ATP Synthase (Complex V)", back: "Uses the proton gradient (chemiosmosis) established by the ETC to synthesize ATP as protons flow back into the matrix. Approximately 2.5 ATP per NADH and 1.5 ATP per FADH₂ by current estimates." , front_translations: {"es":"ATP Sintase (Complexo V)","de":"ATP-Synthase (Komplex V)","fr":"ATP synthase (Complexe V)","tr":"ATP Sentaz (Kompleks V)","nl":"ATP-synthase (Complex V)","ru":"АТФ-синтаза (Комплекс V)","zh":"ATP 合酶（复合体 V）","pt_BR":"ATP Sintase (Complexo V)","pt_PT":"ATP Sintase (Complexo V)"}, back_translations: {"es":"Usa el gradiente de protones (quimiosmose) estabelecido por la ETC para sintetizar ATP conforme los protones fluem de volta para a matriz. Aproximadamente 2,5 ATP por NADH y 1,5 ATP por FADH₂ por las estimativas atuais.","de":"Nutzt den Protonengradienten (Chemiosmose), der durch die ETC aufgebaut wurde, um ATP zu synthetisieren, wenn Protonen zurück in die Matrix fließen. Ungefähr 2,5 ATP pro NADH und 1,5 ATP pro FADH₂ nach aktuellen Schätzungen.","fr":"Utilise le gradient de protons (chimiosmose) établi par l'ETC pour synthétiser l'ATP lorsque les protons retournent dans la matrice. Environ 2,5 ATP par NADH et 1,5 ATP par FADH₂ selon les estimations actuelles.","tr":"ETC tarafından oluşturulan proton gradyanını (kemiozmoz) kullanarak protonlar matrikse geri akarken ATP sentezler. Güncel tahminlere göre NADH başına yaklaşık 2,5 ATP ve FADH₂ başına 1,5 ATP.","nl":"Gebruikt de protongradiënt (chemiosmose) opgebouwd door de ETC om ATP te synthetiseren terwijl protonen terugstromen naar de matrix. Ongeveer 2,5 ATP per NADH en 1,5 ATP per FADH₂ volgens huidige schattingen.","ru":"Использует протонный градиент (хемиосмос), созданный ETC, для синтеза ATP при возвращении протонов в матрикс. Приблизительно 2,5 ATP на NADH и 1,5 ATP на FADH₂ по современным оценкам.","zh":"利用 ETC 建立的质子梯度（化学渗透）在质子回流到基质时合成 ATP。按目前估计，每个 NADH 约产生 2.5 ATP，每个 FADH₂ 约产生 1.5 ATP。","pt_BR":"Usa o gradiente de prótons (quimiosmose) estabelecido pela ETC para sintetizar ATP conforme os prótons fluem de volta para a matriz. Aproximadamente 2,5 ATP por NADH e 1,5 ATP por FADH₂ pelas estimativas atuais.","pt_PT":"Usa o gradiente de protões (quimiosmose) estabelecido pela ETC para sintetizar ATP conforme os protões fluem de volta para a matriz. Aproximadamente 2,5 ATP por NADH e 1,5 ATP por FADH₂ pelas estimativas atuais."}},
  { id: 'dc-mcat-0016', deck_id: 'deck-mcat', sort_order: 16, front: "Fatty Acid Beta-Oxidation", back: "Each cycle of β-oxidation cleaves a 2-carbon unit from an acyl-CoA, yielding acetyl-CoA, 1 NADH, and 1 FADH₂. Occurs in the mitochondrial matrix. Long-chain fatty acids require carnitine shuttle to enter mitochondria." , front_translations: {"es":"Beta-Oxidación de Ácidos Graxos","de":"Fettsäure-Beta-Oxidation","fr":"Bêta-oxydation des acides gras","tr":"Yağ Asidi Beta-Oksidasyonu","nl":"Vetzuur-bèta-oxidatie","ru":"Бета-окисление жирных кислот","zh":"脂肪酸 β-氧化","pt_BR":"Beta-Oxidação de Ácidos Graxos","pt_PT":"Beta-Oxidação de Ácidos Gordos"}, back_translations: {"es":"Cada ciclo de β-oxidación cliva una unidad de 2 carbonos de un acil-CoA, produciendo acetil-CoA, 1 NADH y 1 FADH₂. Ocorre en la matriz mitocondrial. Ácidos grasos de cadeia ancha requieren a lançadera de carnitina para entrar en la mitocondria.","de":"Jeder Zyklus der β-Oxidation spaltet eine 2-Kohlenstoff-Einheit von einem Acyl-CoA ab und liefert Acetyl-CoA, 1 NADH und 1 FADH₂. Findet in der mitochondrialen Matrix statt. Langkettige Fettsäuren benötigen den Carnitin-Shuttle zum Eintritt in die Mitochondrien.","fr":"Chaque cycle de β-oxydation clive une unité à 2 carbones d'un acyl-CoA, produisant de l'acétyl-CoA, 1 NADH et 1 FADH₂. Se déroule dans la matrice mitochondriale. Les acides gras à longue chaîne nécessitent la navette carnitine pour entrer dans les mitochondries.","tr":"Her β-oksidasyon döngüsü bir açil-CoA'dan 2 karbonluk bir birim kopararak asetil-CoA, 1 NADH ve 1 FADH₂ verir. Mitokondri matriksinde gerçekleşir. Uzun zincirli yağ asitleri mitokondriye girmek için karnitin taşıyıcısına ihtiyaç duyar.","nl":"Elke cyclus van β-oxidatie splitst een 2-koolstofeenheid af van een acyl-CoA, wat acetyl-CoA, 1 NADH en 1 FADH₂ oplevert. Vindt plaats in de mitochondriale matrix. Langketige vetzuren hebben de carnitineshuttle nodig om de mitochondriën binnen te komen.","ru":"Каждый цикл β-окисления отщепляет 2-углеродную единицу от ацил-CoA, давая ацетил-CoA, 1 NADH и 1 FADH₂. Происходит в митохондриальном матриксе. Длинноцепочечные жирные кислоты для входа в митохондрии требуют карнитинового челнока.","zh":"每轮 β-氧化从酰基 CoA 切下一个 2 碳单元，生成乙酰 CoA、1 NADH 和 1 FADH₂。发生在线粒体基质中。长链脂肪酸需要肉碱穿梭系统才能进入线粒体。","pt_BR":"Cada ciclo de β-oxidação cliva uma unidade de 2 carbonos de um acil-CoA, produzindo acetil-CoA, 1 NADH e 1 FADH₂. Ocorre na matriz mitocondrial. Ácidos graxos de cadeia longa requerem a lançadeira de carnitina para entrar na mitocôndria.","pt_PT":"Cada ciclo de β-oxidação cliva uma unidade de 2 carbonos de um acil-CoA, produzindo acetil-CoA, 1 NADH e 1 FADH₂. Ocorre na matriz mitocondrial. Ácidos gordos de cadeia longa requerem a lançadeira de carnitina para entrar na mitocôndria."}},
  { id: 'dc-mcat-0017', deck_id: 'deck-mcat', sort_order: 17, front: "Ketogenesis", back: "In fasting/starvation, excess acetyl-CoA (from fat breakdown) is converted to ketone bodies (acetoacetate, β-hydroxybutyrate, acetone) in the liver. Exported as fuel for brain and muscle when glucose is scarce." , front_translations: {"es":"Cetogenese","de":"Ketogenese","fr":"Cétogenèse","tr":"Ketojenez","nl":"Ketogenese","ru":"Кетогенез","zh":"酮体生成","pt_BR":"Cetogênese","pt_PT":"Cetogénese"}, back_translations: {"es":"No jejum/inanición, el exceso de acetil-CoA (de la degradación de gorduras) es convertido en cuerpos cetonicos (acetoacetato, β-hidroxibutirato, acetona) en el hígado. Exportados como combustible para el cerebro y músculos cuando a glicose es escassa.","de":"Beim Fasten/Hungern wird überschüssiges Acetyl-CoA (aus dem Fettabbau) in der Leber in Ketonkörper umgewandelt (Acetoacetat, β-Hydroxybutyrat, Aceton). Wird als Brennstoff für Gehirn und Muskeln exportiert, wenn Glukose knapp ist.","fr":"En jeûne/famine, l'excès d'acétyl-CoA (de la dégradation des graisses) est converti en corps cétoniques (acétoacétate, β-hydroxybutyrate, acétone) dans le foie. Exportés comme carburant pour le cerveau et les muscles lorsque le glucose est rare.","tr":"Açlık/uzun süreli açlıkta, fazla asetil-CoA (yağ yıkımından) karaciğerde keton cisimlerine dönüştürülür (asetoasetat, β-hidroksibutirat, aseton). Glikoz yetersiz olduğunda beyin ve kas için yakıt olarak ihraç edilir.","nl":"Bij vasten/uithongering wordt overtollig acetyl-CoA (uit vetafbraak) omgezet in ketonlichamen (acetoacetaat, β-hydroxybutyraat, aceton) in de lever. Geëxporteerd als brandstof voor hersenen en spieren wanneer glucose schaars is.","ru":"При голодании избыток ацетил-CoA (от расщепления жиров) превращается в кетоновые тела (ацетоацетат, β-гидроксибутират, ацетон) в печени. Экспортируются как топливо для мозга и мышц при дефиците глюкозы.","zh":"禁食/饥饿时，过量的乙酰 CoA（来自脂肪分解）在肝脏中转化为酮体（乙酰乙酸、β-羟基丁酸、丙酮）。在葡萄糖匮乏时作为大脑和肌肉的燃料输出。","pt_BR":"No jejum/inanição, o excesso de acetil-CoA (da degradação de gorduras) é convertido em corpos cetônicos (acetoacetato, β-hidroxibutirato, acetona) no fígado. Exportados como combustível para o cérebro e músculos quando a glicose é escassa.","pt_PT":"No jejum/inanição, o excesso de acetil-CoA (da degradação de gorduras) é convertido em corpos cetónicos (acetoacetato, β-hidroxibutirato, acetona) no fígado. Exportados como combustível para o cérebro e músculos quando a glicose é escassa."}},
  { id: 'dc-mcat-0018', deck_id: 'deck-mcat', sort_order: 18, front: "Gluconeogenesis", back: "Synthesis of glucose from non-carbohydrate precursors (lactate, glycerol, alanine, oxaloacetate) in the liver and kidney cortex. Occurs during fasting. Essentially the reverse of glycolysis, with 3 unique bypass enzymes." , front_translations: {"es":"Gliconeogenese","de":"Glukoneogenese","fr":"Néoglucogenèse","tr":"Glukoneogenez","nl":"Gluconeogenese","ru":"Глюконеогенез","zh":"糖异生","pt_BR":"Gliconeogênese","pt_PT":"Gliconeogénese"}, back_translations: {"es":"Síntese de glicose a partir de precursores no carboidratos (lactato, glicerol, alanina, oxaloacetato) en el hígado y córtex renal. Ocorre durante el jejum. Essencialmente el reverso de la glicólise, con 3 enzimas de desvio únicas.","de":"Synthese von Glukose aus Nicht-Kohlenhydrat-Vorstufen (Laktat, Glycerol, Alanin, Oxalacetat) in Leber und Nierenrinde. Tritt beim Fasten auf. Im Wesentlichen die Umkehrung der Glykolyse mit 3 einzigartigen Bypass-Enzymen.","fr":"Synthèse de glucose à partir de précurseurs non glucidiques (lactate, glycérol, alanine, oxaloacétate) dans le foie et le cortex rénal. Se produit pendant le jeûne. Essentiellement l'inverse de la glycolyse, avec 3 enzymes de contournement uniques.","tr":"Karaciğer ve böbrek korteksinde karbonhidrat olmayan öncülerden (laktat, gliserol, alanin, oksaloasetat) glikoz sentezi. Açlıkta gerçekleşir. Esasen glikolizin tersi olup 3 benzersiz baypas enzimi içerir.","nl":"Synthese van glucose uit niet-koolhydraatprecursoren (lactaat, glycerol, alanine, oxaalacetaat) in de lever en nierschors. Treedt op tijdens vasten. In wezen het omgekeerde van glycolyse, met 3 unieke bypass-enzymen.","ru":"Синтез глюкозы из неуглеводных предшественников (лактат, глицерол, аланин, оксалоацетат) в печени и корковом веществе почек. Происходит при голодании. По сути обратный гликолиз с 3 уникальными обходными ферментами.","zh":"在肝脏和肾皮质中由非碳水化合物前体（乳酸、甘油、丙氨酸、草酰乙酸）合成葡萄糖。禁食期间发生。本质上是糖酵解的逆过程，具有 3 种独特的旁路酶。","pt_BR":"Síntese de glicose a partir de precursores não carboidratos (lactato, glicerol, alanina, oxaloacetato) no fígado e córtex renal. Ocorre durante o jejum. Essencialmente o reverso da glicólise, com 3 enzimas de desvio únicas.","pt_PT":"Síntese de glicose a partir de precursores não glicídicos (lactato, glicerol, alanina, oxaloacetato) no fígado e córtex renal. Ocorre durante o jejum. Essencialmente o reverso da glicólise, com 3 enzimas de desvio únicas."}},
  { id: 'dc-mcat-0019', deck_id: 'deck-mcat', sort_order: 19, front: "Glycogen Synthesis and Breakdown", back: "Glycogenesis: glucose-6-P → glycogen (liver and muscle); insulin stimulates, glucagon inhibits. Glycogenolysis: glycogen → glucose-1-P (glucagon and epinephrine stimulate). Liver glycogen maintains blood glucose; muscle for local use." , front_translations: {"es":"Síntese y Degradación del Glicogenio","de":"Glykogensynthese und -abbau","fr":"Synthèse et dégradation du glycogène","tr":"Glikojen Sentezi ve Yıkımı","nl":"Glycogeensynthese en -afbraak","ru":"Синтез и распад гликогена","zh":"糖原合成与分解","pt_BR":"Síntese e Degradação do Glicogênio","pt_PT":"Síntese e Degradação do Glicogénio"}, back_translations: {"es":"Glicogenese: glicose-6-P → glicogenio (hígado y músculo); insulina estimula, glucagon inibe. Glicogenólise: glicogenio → glicose-1-P (glucagon y epinefrina estimulan). Glicogenio hepático mantiene a glicemia; muscular para uso local.","de":"Glykogenese: Glukose-6-P → Glykogen (Leber und Muskel); Insulin stimuliert, Glukagon hemmt. Glykogenolyse: Glykogen → Glukose-1-P (Glukagon und Adrenalin stimulieren). Leberglykogen hält den Blutzucker aufrecht; Muskelglykogen für lokalen Verbrauch.","fr":"Glycogenèse : glucose-6-P → glycogène (foie et muscle) ; l'insuline stimule, le glucagon inhibe. Glycogénolyse : glycogène → glucose-1-P (le glucagon et l'épinéphrine stimulent). Le glycogène hépatique maintient la glycémie ; le musculaire pour usage local.","tr":"Glikojenez: glikoz-6-P → glikojen (karaciğer ve kas); insülin uyarır, glukagon inhibe eder. Glikojenoliz: glikojen → glikoz-1-P (glukagon ve epinefrin uyarır). Karaciğer glikojeni kan glikozunu korur; kas glikojeni yerel kullanım içindir.","nl":"Glycogenese: glucose-6-P → glycogeen (lever en spier); insuline stimuleert, glucagon remt. Glycogenolyse: glycogeen → glucose-1-P (glucagon en epinefrine stimuleren). Leverglycogeen handhaaft bloedglucose; spierglycogeen voor lokaal gebruik.","ru":"Гликогенез: глюкоза-6-Ф → гликоген (печень и мышцы); инсулин стимулирует, глюкагон ингибирует. Гликогенолиз: гликоген → глюкоза-1-Ф (глюкагон и адреналин стимулируют). Гликоген печени поддерживает уровень глюкозы в крови; мышечный — для местного использования.","zh":"糖原合成：葡萄糖-6-磷酸 → 糖原（肝脏和肌肉）；胰岛素刺激，胰高血糖素抑制。糖原分解：糖原 → 葡萄糖-1-磷酸（胰高血糖素和肾上腺素刺激）。肝糖原维持血糖；肌糖原供局部使用。","pt_BR":"Glicogênese: glicose-6-P → glicogênio (fígado e músculo); insulina estimula, glucagon inibe. Glicogenólise: glicogênio → glicose-1-P (glucagon e epinefrina estimulam). Glicogênio hepático mantém a glicemia; muscular para uso local.","pt_PT":"Glicogénese: glicose-6-P → glicogénio (fígado e músculo); insulina estimula, glucagom inibe. Glicogenólise: glicogénio → glicose-1-P (glucagom e epinefrina estimulam). Glicogénio hepático mantém a glicemia; muscular para uso local."}},
  { id: 'dc-mcat-0020', deck_id: 'deck-mcat', sort_order: 20, front: "Amino Acid Catabolism", back: "Amino groups are removed by transamination (to α-ketoglutarate, forming glutamate) or oxidative deamination. NH₃ is toxic; converted to urea (urea cycle) in the liver. Carbon skeletons enter TCA as various intermediates." , front_translations: {"es":"Catabolismo de Aminoácidos","de":"Aminosäurekatabolismus","fr":"Catabolisme des acides aminés","tr":"Amino Asit Katabolizması","nl":"Aminozuurkatabolisme","ru":"Катаболизм аминокислот","zh":"氨基酸分解代谢","pt_BR":"Catabolismo de Aminoácidos","pt_PT":"Catabolismo de Aminoácidos"}, back_translations: {"es":"Grupos amino son removidos por transaminación (para α-cetoglutarato, formando glutamato) o desaminación oxidativa. NH₃ es tóxico; convertido en ureia (ciclo de la ureia) en el hígado. Esqueletos de carbono entram en el TCA como vários intermediários.","de":"Aminogruppen werden durch Transaminierung (auf α-Ketoglutarat, bildet Glutamat) oder oxidative Desaminierung entfernt. NH₃ ist toxisch; wird in der Leber zu Harnstoff umgewandelt (Harnstoffzyklus). Kohlenstoffskelette treten als verschiedene Intermediate in den TCA-Zyklus ein.","fr":"Les groupes aminés sont retirés par transamination (vers l'α-cétoglutarate, formant du glutamate) ou par désamination oxydative. NH₃ est toxique ; converti en urée (cycle de l'urée) dans le foie. Les squelettes carbonés entrent dans le TCA comme divers intermédiaires.","tr":"Amino grupları transaminasyon (α-ketoglutarata, glutamat oluşturarak) veya oksidatif deaminasyon ile uzaklaştırılır. NH₃ toksiktir; karaciğerde üreye dönüştürülür (üre döngüsü). Karbon iskeletleri çeşitli ara ürünler olarak TCA'ya girer.","nl":"Aminogroepen worden verwijderd door transaminering (naar α-ketoglutaraat, vormt glutamaat) of oxidatieve deaminering. NH₃ is giftig; omgezet in ureum (ureumcyclus) in de lever. Koolstofskeletten treden als diverse tussenproducten in de TCA-cyclus.","ru":"Аминогруппы удаляются путём трансаминирования (на α-кетоглутарат с образованием глутамата) или окислительного дезаминирования. NH₃ токсичен; превращается в мочевину (цикл мочевины) в печени. Углеродные скелеты входят в цикл TCA как различные интермедиаты.","zh":"氨基通过转氨作用（转移到 α-酮戊二酸形成谷氨酸）或氧化脱氨去除。NH₃ 有毒；在肝脏中转化为尿素（尿素循环）。碳骨架以各种中间体形式进入 TCA 循环。","pt_BR":"Grupos amino são removidos por transaminação (para α-cetoglutarato, formando glutamato) ou desaminação oxidativa. NH₃ é tóxico; convertido em ureia (ciclo da ureia) no fígado. Esqueletos de carbono entram no TCA como vários intermediários.","pt_PT":"Grupos amino são removidos por transaminação (para α-cetoglutarato, formando glutamato) ou desaminação oxidativa. NH₃ é tóxico; convertido em ureia (ciclo da ureia) no fígado. Esqueletos de carbono entram no TCA como vários intermediários."}},
  { id: 'dc-mcat-0021', deck_id: 'deck-mcat', sort_order: 21, front: "DNA Replication: Key Enzymes", back: "Helicase: unwinds double helix. Primase: synthesizes RNA primers. DNA polymerase III: extends primers 5'→3'. DNA polymerase I: removes RNA primers, fills gaps. Ligase: joins Okazaki fragments on lagging strand." , front_translations: {"es":"Replicación del DNA: Enzimas-Chave","de":"DNA-Replikation: Schlüsselenzyme","fr":"Réplication de l'ADN : enzymes clés","tr":"DNA Replikasyonu: Anahtar Enzimler","nl":"DNA-replicatie: sleutelenzymen","ru":"Репликация ДНК: ключевые ферменты","zh":"DNA 复制：关键酶","pt_BR":"Replicação do DNA: Enzimas-Chave","pt_PT":"Replicação do DNA: Enzimas-Chave"}, back_translations: {"es":"Helicase: desenrola a dupla hélice. Primase: sintetiza primers de RNA. DNA polimerase III: estende primers 5'→3'. DNA polimerase I: elimina primers de RNA, preenche lacunas. Ligase: une fragmentos de Okazaki en la fita tardia.","de":"Helikase: entwindet die Doppelhelix. Primase: synthetisiert RNA-Primer. DNA-Polymerase III: verlängert Primer 5'→3'. DNA-Polymerase I: entfernt RNA-Primer, füllt Lücken. Ligase: verbindet Okazaki-Fragmente am Folgestrang.","fr":"Hélicase : déroule la double hélice. Primase : synthétise les amorces ARN. ADN polymérase III : prolonge les amorces 5'→3'. ADN polymérase I : retire les amorces ARN, comble les lacunes. Ligase : joint les fragments d'Okazaki sur le brin retardé.","tr":"Helikaz: çift sarmalı açar. Primaz: RNA primerlerini sentezler. DNA polimeraz III: primerleri 5'→3' yönünde uzatır. DNA polimeraz I: RNA primerlerini kaldırır, boşlukları doldurur. Ligaz: geciken iplikte Okazaki fragmentlerini birleştirir.","nl":"Helicase: ontrolt de dubbele helix. Primase: synthetiseert RNA-primers. DNA-polymerase III: verlengt primers 5'→3'. DNA-polymerase I: verwijdert RNA-primers, vult gaten. Ligase: verbindt Okazaki-fragmenten op de achterblijvende streng.","ru":"Хеликаза: раскручивает двойную спираль. Праймаза: синтезирует РНК-праймеры. ДНК-полимераза III: удлиняет праймеры 5'→3'. ДНК-полимераза I: удаляет РНК-праймеры, заполняет пробелы. Лигаза: соединяет фрагменты Оказаки на отстающей цепи.","zh":"解旋酶：解开双螺旋。引物酶：合成 RNA 引物。DNA 聚合酶 III：沿 5'→3' 延伸引物。DNA 聚合酶 I：去除 RNA 引物并填补缺口。连接酶：连接滞后链上的冈崎片段。","pt_BR":"Helicase: desenrola a dupla hélice. Primase: sintetiza primers de RNA. DNA polimerase III: estende primers 5'→3'. DNA polimerase I: remove primers de RNA, preenche lacunas. Ligase: une fragmentos de Okazaki na fita tardia.","pt_PT":"Helicase: desenrola a dupla hélice. Primase: sintetiza primers de RNA. DNA polimerase III: estende primers 5'→3'. DNA polimerase I: remove primers de RNA, preenche lacunas. Ligase: une fragmentos de Okazaki na cadeia atrasada."}},
  { id: 'dc-mcat-0022', deck_id: 'deck-mcat', sort_order: 22, front: "Transcription: Key Features in Eukaryotes", back: "RNA polymerase II transcribes mRNA; requires general transcription factors and promoter (TATA box ~25 bp upstream). Pre-mRNA processing: 5' 7-methylguanosine cap, 3' poly-A tail, splicing of introns by spliceosome." , front_translations: {"es":"Transcrición: Características Principais en Eucariotos","de":"Transkription: Schlüsselmerkmale bei Eukaryoten","fr":"Transcription : caractéristiques clés chez les eucaryotes","tr":"Transkripsiyon: Ökaryotlarda Temel Özellikler","nl":"Transcriptie: belangrijke kenmerken bij eukaryoten","ru":"Транскрипция: ключевые особенности у эукариот","zh":"转录：真核生物的关键特征","pt_BR":"Transcrição: Características Principais em Eucariotos","pt_PT":"Transcrição: Características Principais em Eucariotas"}, back_translations: {"es":"La RNA polimerase II transcreve mRNA; requiere fatores gerais de transcrición y promotor (TATA box ~25 pb a montante). Processamento del pré-mRNA: cap 5' 7-metilguanosina, cauda 3' poli-A, splicing de íntrons por el spliceossomo.","de":"RNA-Polymerase II transkribiert mRNA; benötigt allgemeine Transkriptionsfaktoren und Promotor (TATA-Box ~25 bp stromaufwärts). Prä-mRNA-Prozessierung: 5'-7-Methylguanosin-Kappe, 3'-Poly-A-Schwanz, Spleißen der Introns durch Spleißosom.","fr":"L'ARN polymérase II transcrit l'ARNm ; nécessite des facteurs généraux de transcription et un promoteur (boîte TATA ~25 pb en amont). Maturation du pré-ARNm : coiffe 5' 7-méthylguanosine, queue 3' poly-A, épissage des introns par le splicéosome.","tr":"RNA polimeraz II mRNA'yı transkripsiyonlar; genel transkripsiyon faktörleri ve promotör (TATA kutusu ~25 bp yukarı akış) gerektirir. Pre-mRNA işleme: 5' 7-metilguanozin şapka, 3' poli-A kuyruk, splaysozom ile intronların çıkarılması.","nl":"RNA-polymerase II transcribeert mRNA; vereist algemene transcriptiefactoren en promotor (TATA-box ~25 bp stroomopwaarts). Pre-mRNA-verwerking: 5' 7-methylguanosinecap, 3' poly-A-staart, splitsing van intronen door spliceosome.","ru":"РНК-полимераза II транскрибирует мРНК; требуются общие факторы транскрипции и промотор (ТАТА-бокс ~25 п.н. выше). Процессинг пре-мРНК: 5'-кэп 7-метилгуанозин, 3'-поли-А-хвост, сплайсинг интронов сплайсосомой.","zh":"RNA 聚合酶 II 转录 mRNA；需要通用转录因子和启动子（TATA 框位于上游约 25 bp）。前体 mRNA 加工：5' 7-甲基鸟苷帽、3' 多聚 A 尾、剪接体剪切内含子。","pt_BR":"A RNA polimerase II transcreve mRNA; requer fatores gerais de transcrição e promotor (TATA box ~25 pb a montante). Processamento do pré-mRNA: cap 5' 7-metilguanosina, cauda 3' poli-A, splicing de íntrons pelo spliceossomo.","pt_PT":"A RNA polimerase II transcreve mRNA; requer fatores gerais de transcrição e promotor (TATA box ~25 pb a montante). Processamento do pré-mRNA: cap 5' 7-metilguanosina, cauda 3' poli-A, splicing de intrões pelo spliceossoma."}},
  { id: 'dc-mcat-0023', deck_id: 'deck-mcat', sort_order: 23, front: "Translation: Initiation, Elongation, Termination", back: "Initiation: small ribosomal subunit binds mRNA at AUG (start codon), initiator Met-tRNA, large subunit joins. Elongation: A-site (aminoacyl), P-site (peptidyl), E-site (exit); peptidyl transferase forms peptide bond. Termination: stop codon recognized by release factor." , front_translations: {"es":"Tradución: Iniciación, Elongación, Terminación","de":"Translation: Initiation, Elongation, Termination","fr":"Traduction : initiation, élongation, terminaison","tr":"Translasyon: Başlama, Uzama, Sonlanma","nl":"Translatie: initiatie, elongatie, terminatie","ru":"Трансляция: инициация, элонгация, терминация","zh":"翻译：起始、延伸、终止","pt_BR":"Tradução: Iniciação, Elongação, Terminação","pt_PT":"Tradução: Iniciação, Elongação, Terminação"}, back_translations: {"es":"Iniciación: subunidad ribossomica menor se liga al mRNA en el AUG (códon de início), Met-tRNA iniciador, subunidad mayor se junta. Elongación: sítio A (aminoacil), sítio P (peptidil), sítio Y (saída); peptidil transferase forma enlace peptídica. Terminación: códon de parada reconhecido por el fator de liberación.","de":"Initiation: kleine ribosomale Untereinheit bindet mRNA am AUG (Startcodon), Initiator-Met-tRNA, große Untereinheit verbindet sich. Elongation: A-Stelle (Aminoacyl), P-Stelle (Peptidyl), E-Stelle (Exit); Peptidyltransferase bildet Peptidbindung. Termination: Stoppcodon wird von Freisetzungsfaktor erkannt.","fr":"Initiation : la petite sous-unité ribosomale se lie à l'ARNm au AUG (codon d'initiation), ARNt initiateur Met, la grande sous-unité se joint. Élongation : site A (aminoacyl), site P (peptidyl), site E (sortie) ; peptidyl transférase forme la liaison peptidique. Terminaison : codon stop reconnu par le facteur de libération.","tr":"Başlama: küçük ribozomal alt birim mRNA'ya AUG'da (başlangıç kodonu) bağlanır, başlatıcı Met-tRNA, büyük alt birim katılır. Uzama: A-bölgesi (aminoaçil), P-bölgesi (peptidil), E-bölgesi (çıkış); peptidil transferaz peptit bağı oluşturur. Sonlanma: durdurma kodonu salım faktörü tarafından tanınır.","nl":"Initiatie: kleine ribosomale subeenheid bindt mRNA bij AUG (startcodon), initiator Met-tRNA, grote subeenheid voegt zich. Elongatie: A-site (aminoacyl), P-site (peptidyl), E-site (exit); peptidyltransferase vormt peptidebinding. Terminatie: stopcodon herkend door releasefactor.","ru":"Инициация: малая рибосомная субъединица связывается с мРНК у AUG (стартовый кодон), инициаторная Met-тРНК, присоединяется большая субъединица. Элонгация: А-сайт (аминоацил), Р-сайт (пептидил), Е-сайт (выход); пептидилтрансфераза образует пептидную связь. Терминация: стоп-кодон распознаётся фактором высвобождения.","zh":"起始：核糖体小亚基在 AUG（起始密码子）处结合 mRNA，起始 Met-tRNA，大亚基加入。延伸：A 位（氨酰基）、P 位（肽酰基）、E 位（退出）；肽基转移酶形成肽键。终止：终止密码子被释放因子识别。","pt_BR":"Iniciação: subunidade ribossômica menor se liga ao mRNA no AUG (códon de início), Met-tRNA iniciador, subunidade maior se junta. Elongação: sítio A (aminoacil), sítio P (peptidil), sítio E (saída); peptidil transferase forma ligação peptídica. Terminação: códon de parada reconhecido pelo fator de liberação.","pt_PT":"Iniciação: subunidade ribossómica menor liga-se ao mRNA no AUG (codão de início), Met-tRNA iniciador, subunidade maior junta-se. Elongação: sítio A (aminoacil), sítio P (peptidil), sítio E (saída); peptidil transferase forma ligação peptídica. Terminação: codão de paragem reconhecido pelo fator de libertação."}},
  { id: 'dc-mcat-0024', deck_id: 'deck-mcat', sort_order: 24, front: "DNA Repair Mechanisms", back: "Nucleotide excision repair (NER): removes bulky lesions (UV-induced pyrimidine dimers). Base excision repair (BER): removes damaged/modified bases. Mismatch repair (MMR): corrects replication errors. NHEJ and HR repair double-strand breaks." , front_translations: {"es":"Mecanismos de Reparo del DNA","de":"DNA-Reparaturmechanismen","fr":"Mécanismes de réparation de l'ADN","tr":"DNA Onarım Mekanizmaları","nl":"DNA-reparatiemechanismen","ru":"Механизмы репарации ДНК","zh":"DNA修复机制","pt_BR":"Mecanismos de Reparo do DNA","pt_PT":"Mecanismos de Reparação do DNA"}, back_translations: {"es":"Reparo por excisão de nucleotídeos (NER): elimina lesões volumosas (dímeros de pirimidina induzidos por UV). Reparo por excisão de bases (BER): elimina bases danificadas/modificadas. Reparo de mau pareamento (MMR): corrige erros de replicación. NHEJ y HR reparam quebras de fita dupla.","de":"Nukleotidexzisionsreparatur (NER): entfernt sperrige Läsionen (UV-induzierte Pyrimidindimere). Basenexzisionsreparatur (BER): entfernt beschädigte/modifizierte Basen. Mismatch-Reparatur (MMR): korrigiert Replikationsfehler. NHEJ und HR reparieren Doppelstrangbrüche.","fr":"Réparation par excision de nucléotides (NER) : élimine les lésions volumineuses (dimères de pyrimidine induits par les UV). Réparation par excision de bases (BER) : élimine les bases endommagées/modifiées. Réparation des mésappariements (MMR) : corrige les erreurs de réplication. NHEJ et HR réparent les cassures double-brin.","tr":"Nükleotid eksizyon onarımı (NER): büyük lezyonları kaldırır (UV kaynaklı pirimidin dimerleri). Baz eksizyon onarımı (BER): hasarlı/değiştirilmiş bazları kaldırır. Uyumsuzluk onarımı (MMR): replikasyon hatalarını düzeltir. NHEJ ve HR çift zincir kırıklarını onarır.","nl":"Nucleotide-excisiereparatie (NER): verwijdert omvangrijke laesies (UV-geïnduceerde pyrimidinedimeren). Base-excisiereparatie (BER): verwijdert beschadigde/gemodificeerde basen. Mismatch-reparatie (MMR): corrigeert replicatiefouten. NHEJ en HR repareren dubbelstrengsbreuken.","ru":"Эксцизионная репарация нуклеотидов (NER): удаляет объёмные повреждения (УФ-индуцированные пиримидиновые димеры). Эксцизионная репарация оснований (BER): удаляет повреждённые/модифицированные основания. Репарация ошибочных спариваний (MMR): исправляет ошибки репликации. NHEJ и HR восстанавливают двуцепочечные разрывы.","zh":"核苷酸切除修复（NER）：去除大体积损伤（紫外线诱导的嘧啶二聚体）。碱基切除修复（BER）：去除受损/修饰碱基。错配修复（MMR）：纠正复制错误。NHEJ和HR修复双链断裂。","pt_BR":"Reparo por excisão de nucleotídeos (NER): remove lesões volumosas (dímeros de pirimidina induzidos por UV). Reparo por excisão de bases (BER): remove bases danificadas/modificadas. Reparo de mau pareamento (MMR): corrige erros de replicação. NHEJ e HR reparam quebras de fita dupla.","pt_PT":"Reparação por excisão de nucleótidos (NER): remove lesões volumosas (dímeros de pirimidina induzidos por UV). Reparação por excisão de bases (BER): remove bases danificadas/modificadas. Reparação de emparelhamentos incorretos (MMR): corrige erros de replicação. NHEJ e HR reparam quebras de cadeia dupla."}},
  { id: 'dc-mcat-0025', deck_id: 'deck-mcat', sort_order: 25, front: "Cell Cycle Checkpoints", back: "G1/S checkpoint (restriction point): checks DNA integrity and cell size; regulated by CDK4/6-cyclin D and p53/p21. G2/M checkpoint: checks DNA replication completion. M checkpoint (spindle checkpoint): ensures kinetochore-microtubule attachment." , front_translations: {"es":"Pontos de Verificación del Ciclo Celular","de":"Zellzyklus-Kontrollpunkte","fr":"Points de contrôle du cycle cellulaire","tr":"Hücre Döngüsü Kontrol Noktaları","nl":"Celcyclus-checkpoints","ru":"Контрольные точки клеточного цикла","zh":"细胞周期检查点","pt_BR":"Pontos de Verificação do Ciclo Celular","pt_PT":"Pontos de Controlo do Ciclo Celular"}, back_translations: {"es":"Ponto de verificación G1/S (punto de restrición): verifica a integridad del DNA y el tamaño celular; regulado por CDK4/6-ciclina D y p53/p21. Ponto de verificación G2/M: verifica a conclusão de la replicación del DNA. Ponto de verificación M (punto de verificación del fuso): garantiza a enlace cinetócoro-microtúbulo.","de":"G1/S-Kontrollpunkt (Restriktionspunkt): überprüft DNA-Integrität und Zellgröße; reguliert durch CDK4/6-Cyclin D und p53/p21. G2/M-Kontrollpunkt: überprüft den Abschluss der DNA-Replikation. M-Kontrollpunkt (Spindelkontrollpunkt): stellt die Kinetochor-Mikrotubuli-Anheftung sicher.","fr":"Point de contrôle G1/S (point de restriction) : vérifie l'intégrité de l'ADN et la taille cellulaire ; régulé par CDK4/6-cycline D et p53/p21. Point de contrôle G2/M : vérifie l'achèvement de la réplication de l'ADN. Point de contrôle M (point de contrôle du fuseau) : assure l'attachement kinétochore-microtubule.","tr":"G1/S kontrol noktası (kısıtlama noktası): DNA bütünlüğünü ve hücre boyutunu kontrol eder; CDK4/6-siklin D ve p53/p21 tarafından düzenlenir. G2/M kontrol noktası: DNA replikasyonunun tamamlanmasını kontrol eder. M kontrol noktası (iğ kontrol noktası): kinetokor-mikrotübül bağlantısını sağlar.","nl":"G1/S-checkpoint (restrictiepunt): controleert DNA-integriteit en celgrootte; gereguleerd door CDK4/6-cycline D en p53/p21. G2/M-checkpoint: controleert de voltooiing van DNA-replicatie. M-checkpoint (spindelcheckpoint): zorgt voor kinetochoor-microtubulus-aanhechting.","ru":"Контрольная точка G1/S (точка рестрикции): проверяет целостность ДНК и размер клетки; регулируется CDK4/6-циклин D и p53/p21. Контрольная точка G2/M: проверяет завершение репликации ДНК. Контрольная точка M (контрольная точка веретена): обеспечивает прикрепление кинетохоров к микротрубочкам.","zh":"G1/S检查点（限制点）：检查DNA完整性和细胞大小；由CDK4/6-细胞周期蛋白D和p53/p21调控。G2/M检查点：检查DNA复制是否完成。M检查点（纺锤体检查点）：确保着丝粒-微管连接。","pt_BR":"Ponto de verificação G1/S (ponto de restrição): verifica a integridade do DNA e o tamanho celular; regulado por CDK4/6-ciclina D e p53/p21. Ponto de verificação G2/M: verifica a conclusão da replicação do DNA. Ponto de verificação M (ponto de verificação do fuso): garante a ligação cinetócoro-microtúbulo.","pt_PT":"Ponto de controlo G1/S (ponto de restrição): verifica a integridade do DNA e o tamanho celular; regulado por CDK4/6-ciclina D e p53/p21. Ponto de controlo G2/M: verifica a conclusão da replicação do DNA. Ponto de controlo M (ponto de controlo do fuso): assegura a ligação cinetócoro-microtúbulo."}},
  { id: 'dc-mcat-0026', deck_id: 'deck-mcat', sort_order: 26, front: "Tumor Suppressors vs. Proto-Oncogenes", back: "Proto-oncogenes promote cell division; mutations → oncogenes (gain-of-function; dominant). Tumor suppressors inhibit division; mutations → loss-of-function (recessive; two-hit hypothesis). Key examples: RAS (oncogene), p53, Rb (tumor suppressors)." , front_translations: {"es":"Supressores Tumorais vs. Proto-Oncogenes","de":"Tumorsuppressoren vs. Proto-Onkogene","fr":"Suppresseurs de tumeurs vs. proto-oncogènes","tr":"Tümör Baskılayıcılar ve Proto-Onkogenler","nl":"Tumorsuppressoren vs. proto-oncogenen","ru":"Опухолевые супрессоры и протоонкогены","zh":"肿瘤抑制因子与原癌基因","pt_BR":"Supressores Tumorais vs. Proto-Oncogenes","pt_PT":"Supressores Tumorais vs. Proto-Oncogenes"}, back_translations: {"es":"Proto-oncogenes promueven a divisão celular; mutaciones → oncogenes (ganho de función; dominante). Supressores tumorais inibem a divisão; mutaciones → perda de función (recessivo; hipótese de los de los golpes). Exemplos-chave: RAS (oncogene), p53, Rb (supressores tumorais).","de":"Proto-Onkogene fördern die Zellteilung; Mutationen → Onkogene (Funktionsgewinn; dominant). Tumorsuppressoren hemmen die Teilung; Mutationen → Funktionsverlust (rezessiv; Zwei-Treffer-Hypothese). Wichtige Beispiele: RAS (Onkogen), p53, Rb (Tumorsuppressoren).","fr":"Les proto-oncogènes favorisent la division cellulaire ; mutations → oncogènes (gain de fonction ; dominant). Les suppresseurs de tumeurs inhibent la division ; mutations → perte de fonction (récessif ; hypothèse des deux coups). Exemples clés : RAS (oncogène), p53, Rb (suppresseurs de tumeurs).","tr":"Proto-onkogenler hücre bölünmesini teşvik eder; mutasyonlar → onkogenler (fonksiyon kazanımı; dominant). Tümör baskılayıcılar bölünmeyi inhibe eder; mutasyonlar → fonksiyon kaybı (resesif; iki vuruş hipotezi). Önemli örnekler: RAS (onkogen), p53, Rb (tümör baskılayıcılar).","nl":"Proto-oncogenen bevorderen celdeling; mutaties → oncogenen (gain-of-function; dominant). Tumorsuppressoren remmen deling; mutaties → verlies van functie (recessief; two-hit-hypothese). Belangrijke voorbeelden: RAS (oncogen), p53, Rb (tumorsuppressoren).","ru":"Протоонкогены стимулируют деление клеток; мутации → онкогены (приобретение функции; доминантные). Опухолевые супрессоры подавляют деление; мутации → потеря функции (рецессивные; гипотеза двух ударов). Ключевые примеры: RAS (онкоген), p53, Rb (опухолевые супрессоры).","zh":"原癌基因促进细胞分裂；突变→癌基因（功能获得性；显性）。肿瘤抑制因子抑制分裂；突变→功能丧失（隐性；二次打击假说）。关键实例：RAS（癌基因），p53、Rb（肿瘤抑制因子）。","pt_BR":"Proto-oncogenes promovem a divisão celular; mutações → oncogenes (ganho de função; dominante). Supressores tumorais inibem a divisão; mutações → perda de função (recessivo; hipótese dos dois golpes). Exemplos-chave: RAS (oncogene), p53, Rb (supressores tumorais).","pt_PT":"Proto-oncogenes promovem a divisão celular; mutações → oncogenes (ganho de função; dominante). Supressores tumorais inibem a divisão; mutações → perda de função (recessivo; hipótese dos dois golpes). Exemplos-chave: RAS (oncogene), p53, Rb (supressores tumorais)."}},
  { id: 'dc-mcat-0027', deck_id: 'deck-mcat', sort_order: 27, front: "Meiosis I vs. Meiosis II", back: "Meiosis I (reductive): homologous chromosomes separate; crossing over occurs in prophase I; results in two haploid cells (each with sister chromatids). Meiosis II (equational): sister chromatids separate; similar to mitosis; results in 4 haploid cells." , front_translations: {"es":"Meiose I vs. Meiose II","de":"Meiose I vs. Meiose II","fr":"Méiose I vs. Méiose II","tr":"Mayoz I ve Mayoz II","nl":"Meiose I vs. Meiose II","ru":"Мейоз I и Мейоз II","zh":"减数分裂I与减数分裂II","pt_BR":"Meiose I vs. Meiose II","pt_PT":"Meiose I vs. Meiose II"}, back_translations: {"es":"Meiose I (reducional): cromossomos homólogos se separan; crossing-over ocurre en la prófase I; resulta en de los células haploides (cada una con cromátides-irmãs). Meiose II (equacional): cromátides-irmãs se separan; semelhante a la mitose; resulta en 4 células haploides.","de":"Meiose I (reduktiv): homologe Chromosomen trennen sich; Crossing-over erfolgt in der Prophase I; Ergebnis sind zwei haploide Zellen (jeweils mit Schwesterchromatiden). Meiose II (äquational): Schwesterchromatiden trennen sich; ähnlich der Mitose; Ergebnis sind 4 haploide Zellen.","fr":"Méiose I (réductionnelle) : les chromosomes homologues se séparent ; le crossing-over se produit en prophase I ; donne deux cellules haploïdes (chacune avec des chromatides sœurs). Méiose II (équationnelle) : les chromatides sœurs se séparent ; similaire à la mitose ; donne 4 cellules haploïdes.","tr":"Mayoz I (indirgemeli): homolog kromozomlar ayrılır; krossing-over profaz I'de gerçekleşir; iki haploid hücre oluşur (her biri kardeş kromatidli). Mayoz II (eşitleme): kardeş kromatidler ayrılır; mitoza benzer; 4 haploid hücre oluşur.","nl":"Meiose I (reductief): homologe chromosomen scheiden; crossing-over vindt plaats in profase I; resulteert in twee haploïde cellen (elk met zusterchromatiden). Meiose II (equationeel): zusterchromatiden scheiden; vergelijkbaar met mitose; resulteert in 4 haploïde cellen.","ru":"Мейоз I (редукционный): гомологичные хромосомы расходятся; кроссинговер происходит в профазе I; образуются две гаплоидные клетки (каждая с сестринскими хроматидами). Мейоз II (эквационный): сестринские хроматиды расходятся; аналогичен митозу; образуются 4 гаплоидные клетки.","zh":"减数分裂I（减数型）：同源染色体分离；交叉互换发生在前期I；产生两个单倍体细胞（各含姐妹染色单体）。减数分裂II（等数型）：姐妹染色单体分离；类似有丝分裂；产生4个单倍体细胞。","pt_BR":"Meiose I (reducional): cromossomos homólogos se separam; crossing-over ocorre na prófase I; resulta em duas células haploides (cada uma com cromátides-irmãs). Meiose II (equacional): cromátides-irmãs se separam; semelhante à mitose; resulta em 4 células haploides.","pt_PT":"Meiose I (reducional): cromossomas homólogos separam-se; crossing-over ocorre na prófase I; resulta em duas células haploides (cada uma com cromatídeos-irmãos). Meiose II (equacional): cromatídeos-irmãos separam-se; semelhante à mitose; resulta em 4 células haploides."}},
  { id: 'dc-mcat-0028', deck_id: 'deck-mcat', sort_order: 28, front: "Linked Genes and Recombination Frequency", back: "Genes on the same chromosome are linked and tend to be inherited together. Recombination frequency = (recombinant offspring / total offspring) × 100%. 1% recombination ≈ 1 centimorgan (cM) of genetic distance." , front_translations: {"es":"Genes Ligados y Frequencia de Recombinación","de":"Gekoppelte Gene und Rekombinationsfrequenz","fr":"Gènes liés et fréquence de recombinaison","tr":"Bağlı Genler ve Rekombinasyon Frekansı","nl":"Gekoppelde genen en recombinatiefrequentie","ru":"Сцепленные гены и частота рекомбинации","zh":"连锁基因与重组频率","pt_BR":"Genes Ligados e Frequência de Recombinação","pt_PT":"Genes Ligados e Frequência de Recombinação"}, back_translations: {"es":"Genes en el mismo cromossomo son ligados y tendem a ser herdados juntos. Frequencia de recombinación = (descendentes recombinantes / descendentes totais) × 100%. 1% de recombinación ≈ 1 centimorgan (cM) de distancia genética.","de":"Gene auf demselben Chromosom sind gekoppelt und werden tendenziell zusammen vererbt. Rekombinationsfrequenz = (rekombinante Nachkommen / Gesamtnachkommen) × 100 %. 1 % Rekombination ≈ 1 Centimorgan (cM) genetischer Abstand.","fr":"Les gènes situés sur le même chromosome sont liés et tendent à être hérités ensemble. Fréquence de recombinaison = (descendants recombinants / descendants totaux) × 100 %. 1 % de recombinaison ≈ 1 centimorgan (cM) de distance génétique.","tr":"Aynı kromozom üzerindeki genler bağlıdır ve birlikte kalıtılma eğilimindedir. Rekombinasyon frekansı = (rekombinant yavrular / toplam yavrular) × %100. %1 rekombinasyon ≈ 1 santimorganık (cM) genetik mesafe.","nl":"Genen op hetzelfde chromosoom zijn gekoppeld en worden doorgaans samen overgeërfd. Recombinatiefrequentie = (recombinante nakomelingen / totale nakomelingen) × 100%. 1% recombinatie ≈ 1 centimorgan (cM) genetische afstand.","ru":"Гены на одной хромосоме сцеплены и наследуются вместе. Частота рекомбинации = (рекомбинантное потомство / общее потомство) × 100%. 1% рекомбинации ≈ 1 сантиморган (cM) генетического расстояния.","zh":"位于同一条染色体上的基因是连锁的，倾向于一起遗传。重组频率 =（重组后代/总后代）× 100%。1%重组 ≈ 1厘摩（cM）的遗传距离。","pt_BR":"Genes no mesmo cromossomo são ligados e tendem a ser herdados juntos. Frequência de recombinação = (descendentes recombinantes / descendentes totais) × 100%. 1% de recombinação ≈ 1 centimorgan (cM) de distância genética.","pt_PT":"Genes no mesmo cromossoma são ligados e tendem a ser herdados juntos. Frequência de recombinação = (descendentes recombinantes / descendentes totais) × 100%. 1% de recombinação ≈ 1 centimorgan (cM) de distância genética."}},
  { id: 'dc-mcat-0029', deck_id: 'deck-mcat', sort_order: 29, front: "Eukaryotic Gene Expression Regulation", back: "Transcriptional level: enhancers, silencers, transcription factors. Post-transcriptional: alternative splicing, RNA stability. Translational: ribosome availability, initiation factors. Post-translational: phosphorylation, ubiquitination, glycosylation." , front_translations: {"es":"Regulación de la Expresión Genica en Eucariotos","de":"Regulation der eukaryotischen Genexpression","fr":"Régulation de l'expression des gènes eucaryotes","tr":"Ökaryotik Gen İfadesi Düzenlemesi","nl":"Regulatie van eukaryotische genexpressie","ru":"Регуляция экспрессии генов у эукариот","zh":"真核生物基因表达调控","pt_BR":"Regulação da Expressão Gênica em Eucariotos","pt_PT":"Regulação da Expressão Génica em Eucariotas"}, back_translations: {"es":"Nible transcricional: enhancers, silenciadores, fatores de transcrición. Pós-transcricional: splicing alternativo, estabilidad del RNA. Traducional: disponibilidad de ribossomos, fatores de iniciación. Pós-traducional: fosforilación, ubiquitinación, glicosilación.","de":"Transkriptionsebene: Enhancer, Silencer, Transkriptionsfaktoren. Posttranskriptionell: alternatives Spleißen, RNA-Stabilität. Translationsebene: Ribosomenverfügbarkeit, Initiationsfaktoren. Posttranslational: Phosphorylierung, Ubiquitinierung, Glykosylierung.","fr":"Niveau transcriptionnel : amplificateurs, silenceurs, facteurs de transcription. Post-transcriptionnel : épissage alternatif, stabilité de l'ARN. Traductionnel : disponibilité des ribosomes, facteurs d'initiation. Post-traductionnel : phosphorylation, ubiquitination, glycosylation.","tr":"Transkripsiyon düzeyi: güçlendiriciler, susturucular, transkripsiyon faktörleri. Post-transkripsiyonel: alternatif kırpma, RNA stabilitesi. Translasyon düzeyi: ribozom erişilebilirliği, başlatma faktörleri. Post-translasyonel: fosforilasyon, ubikuitinasyon, glikozilasyon.","nl":"Transcriptieniveau: enhancers, silencers, transcriptiefactoren. Post-transcriptioneel: alternatieve splicing, RNA-stabiliteit. Translationeel: ribosomale beschikbaarheid, initiatiefactoren. Post-translationeel: fosforylering, ubiquitinatie, glycosylering.","ru":"Транскрипционный уровень: энхансеры, сайленсеры, транскрипционные факторы. Посттранскрипционный: альтернативный сплайсинг, стабильность РНК. Трансляционный: доступность рибосом, факторы инициации. Посттрансляционный: фосфорилирование, убиквитинирование, гликозилирование.","zh":"转录水平：增强子、沉默子、转录因子。转录后：选择性剪接、RNA稳定性。翻译水平：核糖体可用性、起始因子。翻译后：磷酸化、泛素化、糖基化。","pt_BR":"Nível transcricional: enhancers, silenciadores, fatores de transcrição. Pós-transcricional: splicing alternativo, estabilidade do RNA. Traducional: disponibilidade de ribossomos, fatores de iniciação. Pós-traducional: fosforilação, ubiquitinação, glicosilação.","pt_PT":"Nível transcricional: enhancers, silenciadores, fatores de transcrição. Pós-transcricional: splicing alternativo, estabilidade do RNA. Traducional: disponibilidade de ribossomas, fatores de iniciação. Pós-traducional: fosforilação, ubiquitinação, glicosilação."}},
  { id: 'dc-mcat-0030', deck_id: 'deck-mcat', sort_order: 30, front: "Virus Replication Cycle", back: "Attachment → penetration → uncoating → replication/transcription → assembly → release. DNA viruses replicate in nucleus; RNA viruses (mostly) in cytoplasm. Retroviruses use reverse transcriptase to make DNA from RNA." , front_translations: {"es":"Ciclo de Replicación Viral","de":"Virusreplikationszyklus","fr":"Cycle de réplication virale","tr":"Virüs Replikasyon Döngüsü","nl":"Virusreplicatiecyclus","ru":"Цикл репликации вируса","zh":"病毒复制周期","pt_BR":"Ciclo de Replicação Viral","pt_PT":"Ciclo de Replicação Viral"}, back_translations: {"es":"Adsorción → penetración → desnudamento → replicación/transcrición → montaje → liberación. Vírus de DNA replicam en el núcleo; virus de RNA (generalmente) en el citoplasma. Retrovírus usam transcriptase reversa para sintetizar DNA a partir de RNA.","de":"Adsorption → Penetration → Uncoating → Replikation/Transkription → Zusammenbau → Freisetzung. DNA-Viren replizieren im Zellkern; RNA-Viren (meist) im Zytoplasma. Retroviren nutzen reverse Transkriptase, um DNA aus RNA herzustellen.","fr":"Attachement → pénétration → décapsidation → réplication/transcription → assemblage → libération. Les virus à ADN se répliquent dans le noyau ; les virus à ARN (principalement) dans le cytoplasme. Les rétrovirus utilisent la transcriptase inverse pour fabriquer de l'ADN à partir de l'ARN.","tr":"Tutunma → penetrasyon → soyunma → replikasyon/transkripsiyon → montaj → salınım. DNA virüsleri çekirdekte çoğalır; RNA virüsleri (çoğunlukla) sitoplazmada. Retrovirüsler RNA'dan DNA yapmak için ters transkriptaz kullanır.","nl":"Aanhechting → penetratie → ontmanteling → replicatie/transcriptie → assemblage → vrijlating. DNA-virussen repliceren in de kern; RNA-virussen (meestal) in het cytoplasma. Retrovirussen gebruiken reverse transcriptase om DNA te maken van RNA.","ru":"Прикрепление → проникновение → раздевание → репликация/транскрипция → сборка → высвобождение. ДНК-вирусы реплицируются в ядре; РНК-вирусы (в основном) в цитоплазме. Ретровирусы используют обратную транскриптазу для синтеза ДНК из РНК.","zh":"吸附→穿入→脱壳→复制/转录→组装→释放。DNA病毒在细胞核内复制；RNA病毒（大多数）在细胞质内复制。逆转录病毒利用逆转录酶从RNA合成DNA。","pt_BR":"Adsorção → penetração → desnudamento → replicação/transcrição → montagem → liberação. Vírus de DNA replicam no núcleo; vírus de RNA (geralmente) no citoplasma. Retrovírus usam transcriptase reversa para sintetizar DNA a partir de RNA.","pt_PT":"Adsorção → penetração → desnudamento → replicação/transcrição → montagem → libertação. Vírus de DNA replicam no núcleo; vírus de RNA (geralmente) no citoplasma. Retrovírus usam transcriptase reversa para sintetizar DNA a partir de RNA."}},
  { id: 'dc-mcat-0031', deck_id: 'deck-mcat', sort_order: 31, front: "Lac Operon (Inducible)", back: "Default state: repressor binds operator, blocking transcription. When lactose is present → allolactose binds repressor → repressor dissociates → genes transcribed. Also requires low glucose (catabolite repression via cAMP-CAP)." , front_translations: {"es":"Óperon Lac (Induzible)","de":"Lac-Operon (induzierbar)","fr":"Opéron Lac (inductible)","tr":"Lac Operonu (İndüklenebilir)","nl":"Lac-operon (induceerbaar)","ru":"Лактозный оперон (индуцибельный)","zh":"Lac操纵子（可诱导型）","pt_BR":"Óperon Lac (Induzível)","pt_PT":"Operão Lac (Indutível)"}, back_translations: {"es":"Estado padrão: repressor liga-se al operador, bloqueando a transcrición. Cuando lactose está presente → alolactose liga-se al repressor → repressor se dissocia → genes son transcritos. También requiere baja glicose (represión catabólica via cAMP-CAP).","de":"Standardzustand: Repressor bindet an den Operator und blockiert die Transkription. Bei Anwesenheit von Laktose → Allolaktose bindet den Repressor → Repressor löst sich → Gene werden transkribiert. Erfordert auch niedrige Glukose (Katabolitrepression über cAMP-CAP).","fr":"État par défaut : le répresseur se lie à l'opérateur, bloquant la transcription. En présence de lactose → l'allolactose se lie au répresseur → le répresseur se dissocie → les gènes sont transcrits. Nécessite aussi un faible taux de glucose (répression catabolique via cAMP-CAP).","tr":"Varsayılan durum: baskılayıcı operatöre bağlanır, transkripsiyonu engeller. Laktoz mevcut olduğunda → allolaktoz baskılayıcıya bağlanır → baskılayıcı ayrılır → genler transkripsiye edilir. Ayrıca düşük glukoz gerektirir (cAMP-CAP aracılığıyla katabolit baskılama).","nl":"Standaardtoestand: repressor bindt aan operator en blokkeert transcriptie. Wanneer lactose aanwezig is → allolactose bindt repressor → repressor dissocieert → genen worden getranscribeerd. Vereist ook lage glucose (katabolietrepressie via cAMP-CAP).","ru":"По умолчанию: репрессор связывается с оператором, блокируя транскрипцию. При наличии лактозы → аллолактоза связывается с репрессором → репрессор отсоединяется → гены транскрибируются. Также требуется низкий уровень глюкозы (катаболитная репрессия через cAMP-CAP).","zh":"默认状态：阻遏蛋白结合操纵基因，阻断转录。当乳糖存在时→别构乳糖结合阻遏蛋白→阻遏蛋白解离→基因被转录。还需要低葡萄糖（通过cAMP-CAP的分解代谢物抑制）。","pt_BR":"Estado padrão: repressor liga-se ao operador, bloqueando a transcrição. Quando lactose está presente → alolactose liga-se ao repressor → repressor se dissocia → genes são transcritos. Também requer baixa glicose (repressão catabólica via cAMP-CAP).","pt_PT":"Estado padrão: repressor liga-se ao operador, bloqueando a transcrição. Quando a lactose está presente → alolactose liga-se ao repressor → repressor dissocia-se → genes são transcritos. Também requer baixa glicose (repressão catabólica via cAMP-CAP)."}},
  { id: 'dc-mcat-0032', deck_id: 'deck-mcat', sort_order: 32, front: "Trp Operon (Repressible)", back: "When tryptophan is plentiful, it acts as a corepressor, binding the aporepressor to form an active repressor that blocks the operator. Also regulated by attenuation (ribosome stalling early in translation)." , front_translations: {"es":"Óperon Trp (Repressible)","de":"Trp-Operon (reprimierbar)","fr":"Opéron Trp (répressible)","tr":"Trp Operonu (Baskılanabilir)","nl":"Trp-operon (represseerbaar)","ru":"Триптофановый оперон (репрессибельный)","zh":"Trp操纵子（可抑制型）","pt_BR":"Óperon Trp (Repressível)","pt_PT":"Operão Trp (Repressível)"}, back_translations: {"es":"Cuando el triptofano es abundante, ele actúa como correpressor, ligando-se al aporrepressor para formar un repressor ativo que bloqueia el operador. También regulado por atenuación (parada del ribossomo en el início de la tradución).","de":"Wenn Tryptophan reichlich vorhanden ist, wirkt es als Corepressor, bindet den Aporepressor und bildet einen aktiven Repressor, der den Operator blockiert. Wird auch durch Attenuation reguliert (Ribosomenstillstand früh in der Translation).","fr":"Lorsque le tryptophane est abondant, il agit comme corépresseur, se liant à l'aporépresseur pour former un répresseur actif qui bloque l'opérateur. Également régulé par atténuation (blocage du ribosome en début de traduction).","tr":"Triptofan bol olduğunda, korepresör olarak görev yapar, aporepresöre bağlanarak operatörü bloke eden aktif bir represör oluşturur. Ayrıca attenüasyon ile düzenlenir (translasyonun başlarında ribozom durması).","nl":"Wanneer tryptofaan overvloedig is, werkt het als corepressor, bindt aan de aporepressor en vormt een actieve repressor die de operator blokkeert. Ook gereguleerd door attenuatie (ribosoomstilstand vroeg in de translatie).","ru":"Когда триптофана много, он действует как корепрессор, связываясь с апорепрессором и образуя активный репрессор, блокирующий оператор. Также регулируется аттенуацией (остановка рибосомы на раннем этапе трансляции).","zh":"当色氨酸充足时，它充当辅阻遏物，与脱辅基阻遏蛋白结合形成活性阻遏蛋白，阻断操纵基因。还通过衰减调节（翻译早期核糖体停滞）。","pt_BR":"Quando o triptofano é abundante, ele atua como correpressor, ligando-se ao aporrepressor para formar um repressor ativo que bloqueia o operador. Também regulado por atenuação (parada do ribossomo no início da tradução).","pt_PT":"Quando o triptofano é abundante, atua como correpressor, ligando-se ao aporrepressor para formar um repressor ativo que bloqueia o operador. Também regulado por atenuação (paragem do ribossoma no início da tradução)."}},
  { id: 'dc-mcat-0033', deck_id: 'deck-mcat', sort_order: 33, front: "Oxidative Phosphorylation", back: "ATP synthesis driven by the proton gradient established by the electron transport chain in the inner mitochondrial membrane. Produces ~34 ATP per glucose. Uncouplers (e.g., DNP) dissipate the gradient as heat (no ATP)." , front_translations: {"es":"Fosforilación Oxidativa","de":"Oxidative Phosphorylierung","fr":"Phosphorylation oxydative","tr":"Oksidatif Fosforilasyon","nl":"Oxidatieve fosforylering","ru":"Окислительное фосфорилирование","zh":"氧化磷酸化","pt_BR":"Fosforilação Oxidativa","pt_PT":"Fosforilação Oxidativa"}, back_translations: {"es":"Síntese de ATP impulsionada por el gradiente de protones estabelecido por la cadeia transportadora de electrones en la membrana interna mitocondrial. Produz ~34 ATP por glicose. Desacopladores (ex.: DNP) dissipam el gradiente como calor (sin ATP).","de":"ATP-Synthese, angetrieben durch den Protonengradienten, der von der Elektronentransportkette in der inneren Mitochondrienmembran aufgebaut wird. Produziert ~34 ATP pro Glukose. Entkoppler (z. B. DNP) zerstreuen den Gradienten als Wärme (kein ATP).","fr":"Synthèse d'ATP entraînée par le gradient de protons établi par la chaîne de transport des électrons dans la membrane interne mitochondriale. Produit ~34 ATP par glucose. Les découplants (p. ex. DNP) dissipent le gradient sous forme de chaleur (pas d'ATP).","tr":"İç mitokondri zarındaki elektron taşıma zinciri tarafından kurulan proton gradyanı ile yönlendirilen ATP sentezi. Glukoz başına ~34 ATP üretir. Eşleşme bozucular (örn. DNP) gradyanı ısı olarak dağıtır (ATP üretilmez).","nl":"ATP-synthese aangedreven door de protongradiënt opgebouwd door de elektronentransportketen in het binnenste mitochondriale membraan. Produceert ~34 ATP per glucose. Ontkoppelaars (bijv. DNP) verspreiden de gradiënt als warmte (geen ATP).","ru":"Синтез АТФ, движимый протонным градиентом, создаваемым электронной транспортной цепью на внутренней мембране митохондрий. Производит ~34 АТФ на молекулу глюкозы. Разобщители (напр., DNP) рассеивают градиент в виде тепла (без АТФ).","zh":"由线粒体内膜电子传递链建立的质子梯度驱动的ATP合成。每分子葡萄糖产生约34个ATP。解偶联剂（如DNP）将梯度以热量形式耗散（不产生ATP）。","pt_BR":"Síntese de ATP impulsionada pelo gradiente de prótons estabelecido pela cadeia transportadora de elétrons na membrana interna mitocondrial. Produz ~34 ATP por glicose. Desacopladores (ex.: DNP) dissipam o gradiente como calor (sem ATP).","pt_PT":"Síntese de ATP impulsionada pelo gradiente de protões estabelecido pela cadeia transportadora de eletrões na membrana interna mitocondrial. Produz ~34 ATP por glicose. Desacopladores (ex.: DNP) dissipam o gradiente como calor (sem ATP)."}},
  { id: 'dc-mcat-0034', deck_id: 'deck-mcat', sort_order: 34, front: "Glycolysis Net Products", back: "2 ATP, 2 NADH, and 2 pyruvate per glucose molecule. Occurs in the cytoplasm; does not require oxygen (anaerobic). Under anaerobic conditions, NADH is reoxidized to NAD⁺ by fermentation to allow glycolysis to continue." , front_translations: {"es":"Produtos Líquidos de la Glicólise","de":"Nettoprodukte der Glykolyse","fr":"Produits nets de la glycolyse","tr":"Glikolizin Net Ürünleri","nl":"Nettoproducten van glycolyse","ru":"Чистые продукты гликолиза","zh":"糖酵解净产物","pt_BR":"Produtos Líquidos da Glicólise","pt_PT":"Produtos Líquidos da Glicólise"}, back_translations: {"es":"2 ATP, 2 NADH y 2 piruvato por molécula de glicose. Ocorre en el citoplasma; no requiere oxígeno (anaeróbico). En condiciones anaeróbicas, el NADH es reoxidado a NAD⁺ por la fermentación para permitir a continuidad de la glicólise.","de":"2 ATP, 2 NADH und 2 Pyruvat pro Glukosemolekül. Findet im Zytoplasma statt; benötigt keinen Sauerstoff (anaerob). Unter anaeroben Bedingungen wird NADH durch Fermentation zu NAD⁺ reoxidiert, damit die Glykolyse fortgesetzt werden kann.","fr":"2 ATP, 2 NADH et 2 pyruvate par molécule de glucose. Se déroule dans le cytoplasme ; ne nécessite pas d'oxygène (anaérobie). En conditions anaérobies, le NADH est réoxydé en NAD⁺ par fermentation pour permettre la poursuite de la glycolyse.","tr":"Glukoz molekülü başına 2 ATP, 2 NADH ve 2 piruvat. Sitoplazmada gerçekleşir; oksijen gerektirmez (anaerobik). Anaerobik koşullarda, glikolizin devam edebilmesi için NADH fermentasyon yoluyla NAD⁺'ye yeniden oksitlenir.","nl":"2 ATP, 2 NADH en 2 pyruvaat per glucosemolecuul. Vindt plaats in het cytoplasma; vereist geen zuurstof (anaeroob). Onder anaerobe omstandigheden wordt NADH gereoxideerd tot NAD⁺ door fermentatie zodat glycolyse kan doorgaan.","ru":"2 АТФ, 2 НАДН и 2 пирувата на молекулу глюкозы. Происходит в цитоплазме; не требует кислорода (анаэробный). В анаэробных условиях НАДН реокисляется до НАД⁺ путём брожения, чтобы гликолиз мог продолжаться.","zh":"每分子葡萄糖产生2个ATP、2个NADH和2个丙酮酸。发生在细胞质中；不需要氧气（无氧）。在无氧条件下，NADH通过发酵被重新氧化为NAD⁺以使糖酵解继续进行。","pt_BR":"2 ATP, 2 NADH e 2 piruvato por molécula de glicose. Ocorre no citoplasma; não requer oxigênio (anaeróbico). Em condições anaeróbicas, o NADH é reoxidado a NAD⁺ pela fermentação para permitir a continuidade da glicólise.","pt_PT":"2 ATP, 2 NADH e 2 piruvato por molécula de glicose. Ocorre no citoplasma; não requer oxigénio (anaeróbico). Em condições anaeróbicas, o NADH é reoxidado a NAD⁺ pela fermentação para permitir a continuidade da glicólise."}},
  { id: 'dc-mcat-0035', deck_id: 'deck-mcat', sort_order: 35, front: "Pentose Phosphate Pathway", back: "An alternative glucose metabolism pathway in the cytoplasm with two phases: oxidative (produces NADPH and ribose-5-P) and non-oxidative (interconverts sugar phosphates). NADPH is essential for fatty acid synthesis and antioxidant defense (glutathione reduction)." , front_translations: {"es":"Via de las Pentoses-Fosfato","de":"Pentosephosphatweg","fr":"Voie des pentoses phosphates","tr":"Pentoz Fosfat Yolu","nl":"Pentosefosfaatroute","ru":"Пентозофосфатный путь","zh":"磷酸戊糖途径","pt_BR":"Via das Pentoses-Fosfato","pt_PT":"Via das Pentoses-Fosfato"}, back_translations: {"es":"Una via alternativa del metabolismo de la glicose en el citoplasma con de los fases: oxidativa (produce NADPH y ribose-5-P) y no oxidativa (interconverte fosfatos de açúcar). NADPH es esencial para a síntese de ácidos grasos y defesa antioxidante (reducción de la glutationa).","de":"Ein alternativer Glukosestoffwechselweg im Zytoplasma mit zwei Phasen: oxidativ (produziert NADPH und Ribose-5-P) und nicht-oxidativ (wandelt Zuckerphosphate ineinander um). NADPH ist essenziell für die Fettsäuresynthese und die antioxidative Abwehr (Glutathionreduktion).","fr":"Une voie alternative du métabolisme du glucose dans le cytoplasme avec deux phases : oxydative (produit NADPH et ribose-5-P) et non oxydative (interconvertit les sucres phosphates). Le NADPH est essentiel pour la synthèse des acides gras et la défense antioxydante (réduction du glutathion).","tr":"Sitoplazmada iki fazlı alternatif bir glukoz metabolizma yolu: oksidatif (NADPH ve riboz-5-P üretir) ve oksidatif olmayan (şeker fosfatları birbirine dönüştürür). NADPH, yağ asidi sentezi ve antioksidan savunma (glutatyon indirgemesi) için gereklidir.","nl":"Een alternatieve glucosemetabolismeroute in het cytoplasma met twee fasen: oxidatief (produceert NADPH en ribose-5-P) en niet-oxidatief (interconverteert suikerfosfaten). NADPH is essentieel voor vetzuursynthese en antioxidantafweer (glutathionreductie).","ru":"Альтернативный путь метаболизма глюкозы в цитоплазме с двумя фазами: окислительная (производит НАДФН и рибозо-5-фосфат) и неокислительная (взаимопревращение сахарофосфатов). НАДФН необходим для синтеза жирных кислот и антиоксидантной защиты (восстановление глутатиона).","zh":"细胞质中一条替代的葡萄糖代谢途径，分两个阶段：氧化阶段（产生NADPH和核糖-5-磷酸）和非氧化阶段（糖磷酸相互转化）。NADPH对脂肪酸合成和抗氧化防御（谷胱甘肽还原）至关重要。","pt_BR":"Uma via alternativa do metabolismo da glicose no citoplasma com duas fases: oxidativa (produz NADPH e ribose-5-P) e não oxidativa (interconverte fosfatos de açúcar). NADPH é essencial para a síntese de ácidos graxos e defesa antioxidante (redução da glutationa).","pt_PT":"Uma via alternativa do metabolismo da glicose no citoplasma com duas fases: oxidativa (produz NADPH e ribose-5-P) e não oxidativa (interconverte fosfatos de açúcar). NADPH é essencial para a síntese de ácidos gordos e defesa antioxidante (redução da glutationa)."}},
  // --- General Chemistry ---
  { id: 'dc-mcat-0036', deck_id: 'deck-mcat', sort_order: 36, front: "Henderson-Hasselbalch Equation", back: "pH = pKa + log([A⁻]/[HA]). Used to calculate pH of buffer solutions; at pH = pKa, concentrations of acid and conjugate base are equal. Critical for understanding blood buffers and titration curves." , front_translations: {"es":"Equación de Henderson-Hasselbalch","de":"Henderson-Hasselbalch-Gleichung","fr":"Équation de Henderson-Hasselbalch","tr":"Henderson-Hasselbalch Denklemi","nl":"Henderson-Hasselbalch-vergelijking","ru":"Уравнение Хендерсона — Хассельбальха","zh":"Henderson-Hasselbalch方程","pt_BR":"Equação de Henderson-Hasselbalch","pt_PT":"Equação de Henderson-Hasselbalch"}, back_translations: {"es":"pH = pKa + log([A⁻]/[HA]). Usada para calcular el pH de soluciones tampão; en pH = pKa, las concentraciones del ácido y de la base conjugada son iguais. Fundamental para entender tampões sanguíneos y curvas de titulación.","de":"pH = pKa + log([A⁻]/[HA]). Wird zur Berechnung des pH-Werts von Pufferlösungen verwendet; bei pH = pKa sind die Konzentrationen von Säure und konjugierter Base gleich. Wichtig für das Verständnis von Blutpuffern und Titrationskurven.","fr":"pH = pKa + log([A⁻]/[HA]). Utilisée pour calculer le pH des solutions tampons ; à pH = pKa, les concentrations de l'acide et de la base conjuguée sont égales. Essentielle pour comprendre les tampons sanguins et les courbes de titrage.","tr":"pH = pKa + log([A⁻]/[HA]). Tampon çözeltilerin pH'ını hesaplamak için kullanılır; pH = pKa olduğunda asit ve konjuge baz konsantrasyonları eşittir. Kan tamponlarını ve titrasyon eğrilerini anlamak için kritik öneme sahiptir.","nl":"pH = pKa + log([A⁻]/[HA]). Gebruikt om de pH van bufferoplossingen te berekenen; bij pH = pKa zijn de concentraties van zuur en geconjugeerde base gelijk. Cruciaal voor het begrijpen van bloedbuffers en titratiecurven.","ru":"pH = pKa + log([A⁻]/[HA]). Используется для расчёта pH буферных растворов; при pH = pKa концентрации кислоты и сопряжённого основания равны. Критически важно для понимания буферов крови и кривых титрования.","zh":"pH = pKa + log([A⁻]/[HA])。用于计算缓冲液的pH值；当pH = pKa时，酸和共轭碱的浓度相等。对理解血液缓冲系统和滴定曲线至关重要。","pt_BR":"pH = pKa + log([A⁻]/[HA]). Usada para calcular o pH de soluções tampão; em pH = pKa, as concentrações do ácido e da base conjugada são iguais. Fundamental para entender tampões sanguíneos e curvas de titulação.","pt_PT":"pH = pKa + log([A⁻]/[HA]). Usada para calcular o pH de soluções tampão; em pH = pKa, as concentrações do ácido e da base conjugada são iguais. Fundamental para compreender tampões sanguíneos e curvas de titulação."}},
  { id: 'dc-mcat-0037', deck_id: 'deck-mcat', sort_order: 37, front: "Buffer Systems in the Body", back: "Bicarbonate buffer: H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6.1; most important blood buffer; regulated by kidneys and lungs). Phosphate buffer: H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6.8; important intracellularly and in urine)." , front_translations: {"es":"Sistemas Tampão en el Corpo","de":"Puffersysteme im Körper","fr":"Systèmes tampons dans le corps","tr":"Vücuttaki Tampon Sistemleri","nl":"Buffersystemen in het lichaam","ru":"Буферные системы организма","zh":"体内缓冲系统","pt_BR":"Sistemas Tampão no Corpo","pt_PT":"Sistemas Tampão no Corpo"}, back_translations: {"es":"Tampão bicarbonato: H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6,1; tampão sanguíneo más importante; regulado por los riñones y pulmones). Tampão fosfato: H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6,8; importante intracelularmente y en la urina).","de":"Bikarbonatpuffer: H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6,1; wichtigster Blutpuffer; reguliert durch Nieren und Lungen). Phosphatpuffer: H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6,8; wichtig intrazellulär und im Urin).","fr":"Tampon bicarbonate : H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6,1 ; tampon sanguin le plus important ; régulé par les reins et les poumons). Tampon phosphate : H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6,8 ; important en intracellulaire et dans l'urine).","tr":"Bikarbonat tamponu: H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6,1; en önemli kan tamponu; böbrekler ve akciğerler tarafından düzenlenir). Fosfat tamponu: H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6,8; hücre içinde ve idrarda önemli).","nl":"Bicarbonaatbuffer: H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6,1; belangrijkste bloedbuffer; gereguleerd door nieren en longen). Fosfaatbuffer: H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6,8; belangrijk intracellulair en in urine).","ru":"Бикарбонатный буфер: H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6,1; важнейший буфер крови; регулируется почками и лёгкими). Фосфатный буфер: H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6,8; важен внутриклеточно и в моче).","zh":"碳酸氢盐缓冲液：H₂CO₃ ⇌ H⁺ + HCO₃⁻（pKa 6.1；最重要的血液缓冲液；由肾脏和肺调节）。磷酸盐缓冲液：H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻（pKa 6.8；在细胞内和尿液中很重要）。","pt_BR":"Tampão bicarbonato: H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6,1; tampão sanguíneo mais importante; regulado pelos rins e pulmões). Tampão fosfato: H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6,8; importante intracelularmente e na urina).","pt_PT":"Tampão bicarbonato: H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6,1; tampão sanguíneo mais importante; regulado pelos rins e pulmões). Tampão fosfato: H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6,8; importante intracelularmente e na urina)."}},
  { id: 'dc-mcat-0038', deck_id: 'deck-mcat', sort_order: 38, front: "Strong Acids and Bases", back: "Strong acids fully dissociate: HCl, HBr, HI, HNO₃, H₂SO₄ (1st dissociation), HClO₄. Strong bases: NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Weak acids/bases partially dissociate; have Ka or Kb < 1." , front_translations: {"es":"Ácidos y Bases Fortes","de":"Starke Säuren und Basen","fr":"Acides et bases forts","tr":"Kuvvetli Asitler ve Bazlar","nl":"Sterke zuren en basen","ru":"Сильные кислоты и основания","zh":"强酸和强碱","pt_BR":"Ácidos e Bases Fortes","pt_PT":"Ácidos e Bases Fortes"}, back_translations: {"es":"Ácidos fuertes dissociam completamente: HCl, HBr, HI, HNO₃, H₂SO₄ (1ª dissociación), HClO₄. Bases fuertes: NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Ácidos/bases débiles dissociam parcialmente; tienen Ka o Kb < 1.","de":"Starke Säuren dissoziieren vollständig: HCl, HBr, HI, HNO₃, H₂SO₄ (1. Dissoziation), HClO₄. Starke Basen: NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Schwache Säuren/Basen dissoziieren teilweise; haben Ka oder Kb < 1.","fr":"Les acides forts se dissocient complètement : HCl, HBr, HI, HNO₃, H₂SO₄ (1ère dissociation), HClO₄. Bases fortes : NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Les acides/bases faibles se dissocient partiellement ; Ka ou Kb < 1.","tr":"Kuvvetli asitler tamamen dissosiye olur: HCl, HBr, HI, HNO₃, H₂SO₄ (1. dissosiyasyon), HClO₄. Kuvvetli bazlar: NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Zayıf asitler/bazlar kısmen dissosiye olur; Ka veya Kb < 1.","nl":"Sterke zuren dissociëren volledig: HCl, HBr, HI, HNO₃, H₂SO₄ (1e dissociatie), HClO₄. Sterke basen: NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Zwakke zuren/basen dissociëren gedeeltelijk; hebben Ka of Kb < 1.","ru":"Сильные кислоты полностью диссоциируют: HCl, HBr, HI, HNO₃, H₂SO₄ (1-я диссоциация), HClO₄. Сильные основания: NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Слабые кислоты/основания частично диссоциируют; Ka или Kb < 1.","zh":"强酸完全电离：HCl、HBr、HI、HNO₃、H₂SO₄（第一级电离）、HClO₄。强碱：NaOH、KOH、Ca(OH)₂、Ba(OH)₂。弱酸/弱碱部分电离；Ka或Kb < 1。","pt_BR":"Ácidos fortes dissociam completamente: HCl, HBr, HI, HNO₃, H₂SO₄ (1ª dissociação), HClO₄. Bases fortes: NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Ácidos/bases fracos dissociam parcialmente; têm Ka ou Kb < 1.","pt_PT":"Ácidos fortes dissociam-se completamente: HCl, HBr, HI, HNO₃, H₂SO₄ (1.ª dissociação), HClO₄. Bases fortes: NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Ácidos/bases fracos dissociam-se parcialmente; têm Ka ou Kb < 1."}},
  { id: 'dc-mcat-0039', deck_id: 'deck-mcat', sort_order: 39, front: "Acid-Base Titration Curve", back: "At half-equivalence point: pH = pKa (half acid, half conjugate base). At equivalence point: stoichiometric neutralization. Strong acid + strong base: equivalence at pH 7. Weak acid + strong base: equivalence pH > 7 (hydrolysis of conjugate base)." , front_translations: {"es":"Curva de Titulación Ácido-Base","de":"Säure-Base-Titrationskurve","fr":"Courbe de titrage acide-base","tr":"Asit-Baz Titrasyon Eğrisi","nl":"Zuur-base-titratiecurve","ru":"Кривая кислотно-основного титрования","zh":"酸碱滴定曲线","pt_BR":"Curva de Titulação Ácido-Base","pt_PT":"Curva de Titulação Ácido-Base"}, back_translations: {"es":"No punto de media-equivalencia: pH = pKa (metade ácido, metade base conjugada). No punto de equivalencia: neutralización estequiométrica. Ácido fuerte + base fuerte: equivalencia en pH 7. Ácido débil + base fuerte: pH de equivalencia > 7 (hidrólise de la base conjugada).","de":"Am Halbäquivalenzpunkt: pH = pKa (halb Säure, halb konjugierte Base). Am Äquivalenzpunkt: stöchiometrische Neutralisation. Starke Säure + starke Base: Äquivalenz bei pH 7. Schwache Säure + starke Base: Äquivalenz-pH > 7 (Hydrolyse der konjugierten Base).","fr":"Au demi-point d'équivalence : pH = pKa (moitié acide, moitié base conjuguée). Au point d'équivalence : neutralisation stœchiométrique. Acide fort + base forte : équivalence à pH 7. Acide faible + base forte : pH d'équivalence > 7 (hydrolyse de la base conjuguée).","tr":"Yarı eşdeğerlik noktasında: pH = pKa (yarı asit, yarı konjuge baz). Eşdeğerlik noktasında: stokiyometrik nötralizasyon. Kuvvetli asit + kuvvetli baz: eşdeğerlik pH 7'de. Zayıf asit + kuvvetli baz: eşdeğerlik pH > 7 (konjuge bazın hidrolizi).","nl":"Bij het half-equivalentiepunt: pH = pKa (half zuur, half geconjugeerde base). Bij het equivalentiepunt: stoichiometrische neutralisatie. Sterk zuur + sterke base: equivalentie bij pH 7. Zwak zuur + sterke base: equivalentie-pH > 7 (hydrolyse van geconjugeerde base).","ru":"В точке полуэквивалентности: pH = pKa (половина кислоты, половина сопряжённого основания). В точке эквивалентности: стехиометрическая нейтрализация. Сильная кислота + сильное основание: эквивалентность при pH 7. Слабая кислота + сильное основание: pH эквивалентности > 7 (гидролиз сопряжённого основания).","zh":"半当量点：pH = pKa（一半是酸，一半是共轭碱）。当量点：化学计量中和。强酸+强碱：当量点pH为7。弱酸+强碱：当量点pH > 7（共轭碱水解）。","pt_BR":"No ponto de meia-equivalência: pH = pKa (metade ácido, metade base conjugada). No ponto de equivalência: neutralização estequiométrica. Ácido forte + base forte: equivalência em pH 7. Ácido fraco + base forte: pH de equivalência > 7 (hidrólise da base conjugada).","pt_PT":"No ponto de meia-equivalência: pH = pKa (metade ácido, metade base conjugada). No ponto de equivalência: neutralização estequiométrica. Ácido forte + base forte: equivalência a pH 7. Ácido fraco + base forte: pH de equivalência > 7 (hidrólise da base conjugada)."}},
  { id: 'dc-mcat-0040', deck_id: 'deck-mcat', sort_order: 40, front: "Electrochemistry: Standard Cell Potential", back: "E°cell = E°cathode - E°anode. Positive E°cell = spontaneous. ΔG° = -nFE°. n = moles of electrons transferred; F = 96,485 C/mol. At equilibrium, E = 0 and Q = K." , front_translations: {"es":"Eletroquímica: Potencial Padrão de la Célula","de":"Elektrochemie: Standard-Zellpotential","fr":"Électrochimie : potentiel standard de cellule","tr":"Elektrokimya: Standart Hücre Potansiyeli","nl":"Elektrochemie: standaard celpotentiaal","ru":"Электрохимия: стандартный потенциал ячейки","zh":"电化学：标准电池电位","pt_BR":"Eletroquímica: Potencial Padrão da Célula","pt_PT":"Eletroquímica: Potencial Padrão da Célula"}, back_translations: {"es":"Y°célula = Y°cátodo - Y°anodo. Y°célula positivo = espontaneo. ΔG° = -nFE°. n = mols de electrones transferidos; F = 96.485 C/mol. No equilíbrio, Y = 0 y Q = K.","de":"E°Zelle = E°Kathode - E°Anode. Positives E°Zelle = spontan. ΔG° = -nFE°. n = Mol übertragener Elektronen; F = 96.485 C/mol. Im Gleichgewicht E = 0 und Q = K.","fr":"E°cellule = E°cathode - E°anode. E°cellule positif = spontané. ΔG° = -nFE°. n = moles d'électrons transférés ; F = 96 485 C/mol. À l'équilibre, E = 0 et Q = K.","tr":"E°hücre = E°katot - E°anot. Pozitif E°hücre = kendiliğinden. ΔG° = -nFE°. n = transfer edilen elektron molleri; F = 96.485 C/mol. Dengede E = 0 ve Q = K.","nl":"E°cel = E°kathode - E°anode. Positieve E°cel = spontaan. ΔG° = -nFE°. n = mol overgedragen elektronen; F = 96.485 C/mol. Bij evenwicht: E = 0 en Q = K.","ru":"E°ячейки = E°катода - E°анода. Положительное E°ячейки = самопроизвольный процесс. ΔG° = -nFE°. n = моли перенесённых электронов; F = 96 485 Кл/моль. В равновесии E = 0 и Q = K.","zh":"E°电池 = E°阴极 - E°阳极。E°电池为正 = 自发反应。ΔG° = -nFE°。n = 转移电子的摩尔数；F = 96,485 C/mol。平衡时E = 0且Q = K。","pt_BR":"E°célula = E°cátodo - E°ânodo. E°célula positivo = espontâneo. ΔG° = -nFE°. n = mols de elétrons transferidos; F = 96.485 C/mol. No equilíbrio, E = 0 e Q = K.","pt_PT":"E°célula = E°cátodo - E°ânodo. E°célula positivo = espontâneo. ΔG° = -nFE°. n = moles de eletrões transferidos; F = 96.485 C/mol. No equilíbrio, E = 0 e Q = K."}},
  { id: 'dc-mcat-0041', deck_id: 'deck-mcat', sort_order: 41, front: "Nernst Equation (MCAT)", back: "E = E° - (0.0592/n)log(Q) at 25°C. Adjusts cell potential for non-standard concentrations. Q < 1 increases E (reaction driven forward); Q > 1 decreases E." , front_translations: {"es":"Equación de Nernst (MCAT)","de":"Nernst-Gleichung (MCAT)","fr":"Équation de Nernst (MCAT)","tr":"Nernst Denklemi (MCAT)","nl":"Nernst-vergelijking (MCAT)","ru":"Уравнение Нернста (MCAT)","zh":"Nernst方程（MCAT）","pt_BR":"Equação de Nernst (MCAT)","pt_PT":"Equação de Nernst (MCAT)"}, back_translations: {"es":"Y = Y° - (0,0592/n)log(Q) a 25 °C. Ajusta el potencial de la célula para concentraciones no padrão. Q < 1 aumenta Y (reacción impulsionada para frente); Q > 1 disminuye Y.","de":"E = E° - (0,0592/n)log(Q) bei 25 °C. Passt das Zellpotential für Nicht-Standardkonzentrationen an. Q < 1 erhöht E (Reaktion wird vorwärts getrieben); Q > 1 verringert E.","fr":"E = E° - (0,0592/n)log(Q) à 25 °C. Ajuste le potentiel de cellule pour des concentrations non standard. Q < 1 augmente E (réaction poussée vers l'avant) ; Q > 1 diminue E.","tr":"E = E° - (0,0592/n)log(Q), 25 °C'de. Standart dışı konsantrasyonlar için hücre potansiyelini ayarlar. Q < 1, E'yi artırır (reaksiyon ileri yönde ilerler); Q > 1, E'yi azaltır.","nl":"E = E° - (0,0592/n)log(Q) bij 25 °C. Past het celpotentiaal aan voor niet-standaardconcentraties. Q < 1 verhoogt E (reactie wordt voorwaarts gedreven); Q > 1 verlaagt E.","ru":"E = E° - (0,0592/n)log(Q) при 25 °C. Корректирует потенциал ячейки для нестандартных концентраций. Q < 1 увеличивает E (реакция идёт вперёд); Q > 1 уменьшает E.","zh":"E = E° - (0.0592/n)log(Q)，在25°C下。调整非标准浓度下的电池电位。Q < 1时E增大（反应正向进行）；Q > 1时E减小。","pt_BR":"E = E° - (0,0592/n)log(Q) a 25 °C. Ajusta o potencial da célula para concentrações não padrão. Q < 1 aumenta E (reação impulsionada para frente); Q > 1 diminui E.","pt_PT":"E = E° - (0,0592/n)log(Q) a 25 °C. Ajusta o potencial da célula para concentrações não padrão. Q < 1 aumenta E (reação impulsionada para a frente); Q > 1 diminui E."}},
  { id: 'dc-mcat-0042', deck_id: 'deck-mcat', sort_order: 42, front: "Colligative Properties", back: "Depend on the number of solute particles, not identity. Boiling point elevation: ΔTb = iKbm. Freezing point depression: ΔTf = iKfm. Osmotic pressure: π = iMRT. i = van 't Hoff factor (number of particles per formula unit)." , front_translations: {"es":"Propriedades Coligativas","de":"Kolligative Eigenschaften","fr":"Propriétés colligatives","tr":"Koligatif Özellikler","nl":"Colligatieve eigenschappen","ru":"Коллигативные свойства","zh":"依数性质","pt_BR":"Propriedades Coligativas","pt_PT":"Propriedades Coligativas"}, back_translations: {"es":"Dependem del número de partículas de soluto, no de la identidad. Elevación del punto de ebullición: ΔTb = iKbm. Depresión del punto de congelamento: ΔTf = iKfm. Presión osmótica: π = iMRT. i = fator de van 't Hoff (número de partículas por unidad de fórmula).","de":"Hängen von der Anzahl der gelösten Teilchen ab, nicht von deren Identität. Siedepunktserhöhung: ΔTb = iKbm. Gefrierpunktserniedrigung: ΔTf = iKfm. Osmotischer Druck: π = iMRT. i = Van-'t-Hoff-Faktor (Anzahl der Teilchen pro Formeleinheit).","fr":"Dépendent du nombre de particules de soluté, pas de leur identité. Élévation du point d'ébullition : ΔTb = iKbm. Abaissement du point de congélation : ΔTf = iKfm. Pression osmotique : π = iMRT. i = facteur de van 't Hoff (nombre de particules par unité de formule).","tr":"Çözünen parçacıkların sayısına bağlıdır, kimliğine değil. Kaynama noktası yükselmesi: ΔTb = iKbm. Donma noktası düşmesi: ΔTf = iKfm. Ozmotik basınç: π = iMRT. i = van 't Hoff faktörü (formül birimi başına parçacık sayısı).","nl":"Afhankelijk van het aantal opgeloste deeltjes, niet van de identiteit. Kookpuntverhoging: ΔTb = iKbm. Vriespuntverlaging: ΔTf = iKfm. Osmotische druk: π = iMRT. i = van 't Hoff-factor (aantal deeltjes per formule-eenheid).","ru":"Зависят от количества частиц растворённого вещества, а не от их природы. Повышение температуры кипения: ΔTb = iKbm. Понижение температуры замерзания: ΔTf = iKfm. Осмотическое давление: π = iMRT. i = фактор Вант-Гоффа (число частиц на формульную единицу).","zh":"取决于溶质粒子数量，而非种类。沸点升高：ΔTb = iKbm。凝固点降低：ΔTf = iKfm。渗透压：π = iMRT。i = 范特霍夫因子（每个化学式单位的粒子数）。","pt_BR":"Dependem do número de partículas de soluto, não da identidade. Elevação do ponto de ebulição: ΔTb = iKbm. Depressão do ponto de congelamento: ΔTf = iKfm. Pressão osmótica: π = iMRT. i = fator de van 't Hoff (número de partículas por unidade de fórmula).","pt_PT":"Dependem do número de partículas de soluto, não da identidade. Elevação do ponto de ebulição: ΔTb = iKbm. Depressão do ponto de congelação: ΔTf = iKfm. Pressão osmótica: π = iMRT. i = fator de van 't Hoff (número de partículas por unidade de fórmula)."}},
  { id: 'dc-mcat-0043', deck_id: 'deck-mcat', sort_order: 43, front: "Phase Changes and Heating Curve", back: "During a phase change, temperature remains constant while heat (= mL) is absorbed or released. The slope of the heating curve reflects specific heat capacity (q = mcΔT) of each phase. Greater slope = lower specific heat." , front_translations: {"es":"Mudanças de Fase y Curva de Aquecimento","de":"Phasenübergänge und Heizkurve","fr":"Changements de phase et courbe de chauffage","tr":"Faz Değişimleri ve Isıtma Eğrisi","nl":"Faseveranderingen en verwarmingscurve","ru":"Фазовые переходы и кривая нагревания","zh":"相变与加热曲线","pt_BR":"Mudanças de Fase e Curva de Aquecimento","pt_PT":"Mudanças de Fase e Curva de Aquecimento"}, back_translations: {"es":"Durante una cambio de fase, a temperatura permanece constante mientras calor (= mL) es absorbido o liberado. La inclinación de la curva de aquecimento reflete a capacidad calorífica específica (q = mcΔT) de cada fase. Maior inclinación = menor calor específico.","de":"Während eines Phasenübergangs bleibt die Temperatur konstant, während Wärme (= mL) aufgenommen oder freigesetzt wird. Die Steigung der Heizkurve spiegelt die spezifische Wärmekapazität (q = mcΔT) jeder Phase wider. Größere Steigung = geringere spezifische Wärme.","fr":"Lors d'un changement de phase, la température reste constante tandis que la chaleur (= mL) est absorbée ou libérée. La pente de la courbe de chauffage reflète la capacité thermique spécifique (q = mcΔT) de chaque phase. Pente plus grande = capacité thermique plus faible.","tr":"Faz değişimi sırasında, ısı (= mL) absorbe edilir veya serbest bırakılırken sıcaklık sabit kalır. Isıtma eğrisinin eğimi her fazın özgül ısı kapasitesini (q = mcΔT) yansıtır. Daha büyük eğim = daha düşük özgül ısı.","nl":"Tijdens een faseverandering blijft de temperatuur constant terwijl warmte (= mL) wordt geabsorbeerd of vrijgegeven. De helling van de verwarmingscurve weerspiegelt de soortelijke warmtecapaciteit (q = mcΔT) van elke fase. Grotere helling = lagere soortelijke warmte.","ru":"Во время фазового перехода температура остаётся постоянной, пока теплота (= mL) поглощается или выделяется. Наклон кривой нагревания отражает удельную теплоёмкость (q = mcΔT) каждой фазы. Больший наклон = меньшая удельная теплоёмкость.","zh":"相变过程中，温度保持不变，同时吸收或释放热量（= mL）。加热曲线的斜率反映每个相的比热容（q = mcΔT）。斜率越大 = 比热容越小。","pt_BR":"Durante uma mudança de fase, a temperatura permanece constante enquanto calor (= mL) é absorvido ou liberado. A inclinação da curva de aquecimento reflete a capacidade calorífica específica (q = mcΔT) de cada fase. Maior inclinação = menor calor específico.","pt_PT":"Durante uma mudança de fase, a temperatura permanece constante enquanto calor (= mL) é absorvido ou libertado. A inclinação da curva de aquecimento reflete a capacidade calorífica específica (q = mcΔT) de cada fase. Maior inclinação = menor calor específico."}},
  { id: 'dc-mcat-0044', deck_id: 'deck-mcat', sort_order: 44, front: "Ideal Gas Law and Deviations", back: "PV = nRT. Real gases deviate at high pressure (volume effect) and low temperature (attractive forces). Van der Waals equation: (P + a/V²)(V - b) = nRT. Gas with high a = strong intermolecular forces." , front_translations: {"es":"Ley de los Gases Ideais y Desvios","de":"Ideales Gasgesetz und Abweichungen","fr":"Loi des gaz parfaits et déviations","tr":"İdeal Gaz Yasası ve Sapmalar","nl":"Ideale gaswet en afwijkingen","ru":"Закон идеального газа и отклонения","zh":"理想气体定律与偏差","pt_BR":"Lei dos Gases Ideais e Desvios","pt_PT":"Lei dos Gases Ideais e Desvios"}, back_translations: {"es":"PV = nRT. Gases reais desviam en alta presión (efecto de volumen) y baja temperatura (fuerzas atrativas). Equación de Van der Waals: (P + a/V²)(V - b) = nRT. Gás con alto a = fuerzas intermoleculares fuertes.","de":"PV = nRT. Reale Gase weichen bei hohem Druck (Volumeneffekt) und niedriger Temperatur (Anziehungskräfte) ab. Van-der-Waals-Gleichung: (P + a/V²)(V - b) = nRT. Gas mit hohem a = starke intermolekulare Kräfte.","fr":"PV = nRT. Les gaz réels dévient à haute pression (effet de volume) et basse température (forces attractives). Équation de Van der Waals : (P + a/V²)(V - b) = nRT. Un gaz avec un a élevé = forces intermoléculaires fortes.","tr":"PV = nRT. Gerçek gazlar yüksek basınçta (hacim etkisi) ve düşük sıcaklıkta (çekim kuvvetleri) sapma gösterir. Van der Waals denklemi: (P + a/V²)(V - b) = nRT. Yüksek a değerine sahip gaz = güçlü moleküller arası kuvvetler.","nl":"PV = nRT. Reële gassen wijken af bij hoge druk (volume-effect) en lage temperatuur (aantrekkingskrachten). Van der Waals-vergelijking: (P + a/V²)(V - b) = nRT. Gas met hoge a = sterke intermoleculaire krachten.","ru":"PV = nRT. Реальные газы отклоняются при высоком давлении (эффект объёма) и низкой температуре (силы притяжения). Уравнение Ван-дер-Ваальса: (P + a/V²)(V - b) = nRT. Газ с высоким a = сильные межмолекулярные силы.","zh":"PV = nRT。真实气体在高压（体积效应）和低温（引力作用）下偏离理想行为。范德华方程：(P + a/V²)(V - b) = nRT。a值大的气体 = 分子间作用力强。","pt_BR":"PV = nRT. Gases reais desviam em alta pressão (efeito de volume) e baixa temperatura (forças atrativas). Equação de Van der Waals: (P + a/V²)(V - b) = nRT. Gás com alto a = forças intermoleculares fortes.","pt_PT":"PV = nRT. Gases reais desviam-se a alta pressão (efeito de volume) e baixa temperatura (forças atrativas). Equação de Van der Waals: (P + a/V²)(V - b) = nRT. Gás com alto a = forças intermoleculares fortes."}},
  { id: 'dc-mcat-0045', deck_id: 'deck-mcat', sort_order: 45, front: "Gibbs Free Energy and Spontaneity", back: "ΔG = ΔH - TΔS. Spontaneous when ΔG < 0. ΔG° = -RT ln K. If ΔG < 0: spontaneous; ΔG = 0: equilibrium; ΔG > 0: non-spontaneous. Exothermic (ΔH < 0) + entropy increase (ΔS > 0) = always spontaneous." , front_translations: {"es":"Energia Livre de Gibbs y Espontaneidad","de":"Gibbs-Energie und Spontaneität","fr":"Énergie libre de Gibbs et spontanéité","tr":"Gibbs Serbest Enerjisi ve Kendiliğindenlik","nl":"Gibbs vrije energie en spontaniteit","ru":"Энергия Гиббса и самопроизвольность","zh":"吉布斯自由能与自发性","pt_BR":"Energia Livre de Gibbs e Espontaneidade","pt_PT":"Energia Livre de Gibbs e Espontaneidade"}, back_translations: {"es":"ΔG = ΔH - TΔS. Espontaneo cuando ΔG < 0. ΔG° = -RT ln K. Se ΔG < 0: espontaneo; ΔG = 0: equilíbrio; ΔG > 0: no espontaneo. Exotérmico (ΔH < 0) + aumento de entropia (ΔS > 0) = siempre espontaneo.","de":"ΔG = ΔH - TΔS. Spontan wenn ΔG < 0. ΔG° = -RT ln K. Wenn ΔG < 0: spontan; ΔG = 0: Gleichgewicht; ΔG > 0: nicht spontan. Exotherm (ΔH < 0) + Entropiezunahme (ΔS > 0) = immer spontan.","fr":"ΔG = ΔH - TΔS. Spontané lorsque ΔG < 0. ΔG° = -RT ln K. Si ΔG < 0 : spontané ; ΔG = 0 : équilibre ; ΔG > 0 : non spontané. Exothermique (ΔH < 0) + augmentation d'entropie (ΔS > 0) = toujours spontané.","tr":"ΔG = ΔH - TΔS. ΔG < 0 olduğunda kendiliğinden. ΔG° = -RT ln K. ΔG < 0 ise: kendiliğinden; ΔG = 0: denge; ΔG > 0: kendiliğinden değil. Ekzotermik (ΔH < 0) + entropi artışı (ΔS > 0) = her zaman kendiliğinden.","nl":"ΔG = ΔH - TΔS. Spontaan wanneer ΔG < 0. ΔG° = -RT ln K. Als ΔG < 0: spontaan; ΔG = 0: evenwicht; ΔG > 0: niet-spontaan. Exotherm (ΔH < 0) + entropietoename (ΔS > 0) = altijd spontaan.","ru":"ΔG = ΔH - TΔS. Самопроизвольный при ΔG < 0. ΔG° = -RT ln K. Если ΔG < 0: самопроизвольный; ΔG = 0: равновесие; ΔG > 0: несамопроизвольный. Экзотермический (ΔH < 0) + увеличение энтропии (ΔS > 0) = всегда самопроизвольный.","zh":"ΔG = ΔH - TΔS。ΔG < 0时自发。ΔG° = -RT ln K。ΔG < 0：自发；ΔG = 0：平衡；ΔG > 0：非自发。放热（ΔH < 0）+ 熵增（ΔS > 0）= 总是自发。","pt_BR":"ΔG = ΔH - TΔS. Espontâneo quando ΔG < 0. ΔG° = -RT ln K. Se ΔG < 0: espontâneo; ΔG = 0: equilíbrio; ΔG > 0: não espontâneo. Exotérmico (ΔH < 0) + aumento de entropia (ΔS > 0) = sempre espontâneo.","pt_PT":"ΔG = ΔH - TΔS. Espontâneo quando ΔG < 0. ΔG° = -RT ln K. Se ΔG < 0: espontâneo; ΔG = 0: equilíbrio; ΔG > 0: não espontâneo. Exotérmico (ΔH < 0) + aumento de entropia (ΔS > 0) = sempre espontâneo."}},
  { id: 'dc-mcat-0046', deck_id: 'deck-mcat', sort_order: 46, front: "Radioactive Decay and Half-Life", back: "N = N₀(½)^(t/t½). After n half-lives, (½)ⁿ of the original remains. First-order process; ln 2 / λ = t½. MCAT relevant isotopes: ¹⁴C (dating), ¹³¹I (thyroid), ⁹⁹ᵐTc (imaging), ³H (tracers)." , front_translations: {"es":"Decaimento Radioativo y Meia-Vida","de":"Radioaktiver Zerfall und Halbwertszeit","fr":"Désintégration radioactive et demi-vie","tr":"Radyoaktif Bozunma ve Yarı Ömür","nl":"Radioactief verval en halfwaardetijd","ru":"Радиоактивный распад и период полураспада","zh":"放射性衰变与半衰期","pt_BR":"Decaimento Radioativo e Meia-Vida","pt_PT":"Decaimento Radioativo e Meia-Vida"}, back_translations: {"es":"N = N₀(½)^(t/t½). Após n meias-vidas, resta (½)ⁿ del original. Processo de primera ordem; ln 2 / λ = t½. Isótopos relevantes para el MCAT: ¹⁴C (datación), ¹³¹I (tireoide), ⁹⁹ᵐTc (imaje), ³H (traçadores).","de":"N = N₀(½)^(t/t½). Nach n Halbwertszeiten verbleibt (½)ⁿ des Originals. Prozess erster Ordnung; ln 2 / λ = t½. MCAT-relevante Isotope: ¹⁴C (Datierung), ¹³¹I (Schilddrüse), ⁹⁹ᵐTc (Bildgebung), ³H (Tracer).","fr":"N = N₀(½)^(t/t½). Après n demi-vies, (½)ⁿ de la quantité originale reste. Processus du premier ordre ; ln 2 / λ = t½. Isotopes pertinents pour le MCAT : ¹⁴C (datation), ¹³¹I (thyroïde), ⁹⁹ᵐTc (imagerie), ³H (traceurs).","tr":"N = N₀(½)^(t/t½). n yarı ömür sonrasında orijinalin (½)ⁿ'si kalır. Birinci dereceden süreç; ln 2 / λ = t½. MCAT ile ilgili izotoplar: ¹⁴C (tarihlendirme), ¹³¹I (tiroit), ⁹⁹ᵐTc (görüntüleme), ³H (izleyiciler).","nl":"N = N₀(½)^(t/t½). Na n halfwaardetijden blijft (½)ⁿ van het origineel over. Eerste-orde proces; ln 2 / λ = t½. MCAT-relevante isotopen: ¹⁴C (datering), ¹³¹I (schildklier), ⁹⁹ᵐTc (beeldvorming), ³H (tracers).","ru":"N = N₀(½)^(t/t½). После n периодов полураспада остаётся (½)ⁿ от исходного количества. Процесс первого порядка; ln 2 / λ = t½. Изотопы, актуальные для MCAT: ¹⁴C (датирование), ¹³¹I (щитовидная железа), ⁹⁹ᵐTc (визуализация), ³H (трассеры).","zh":"N = N₀(½)^(t/t½)。经过n个半衰期后，剩余原始量的(½)ⁿ。一级过程；ln 2 / λ = t½。MCAT相关同位素：¹⁴C（测年）、¹³¹I（甲状腺）、⁹⁹ᵐTc（成像）、³H（示踪剂）。","pt_BR":"N = N₀(½)^(t/t½). Após n meias-vidas, resta (½)ⁿ do original. Processo de primeira ordem; ln 2 / λ = t½. Isótopos relevantes para o MCAT: ¹⁴C (datação), ¹³¹I (tireoide), ⁹⁹ᵐTc (imagem), ³H (traçadores).","pt_PT":"N = N₀(½)^(t/t½). Após n meias-vidas, resta (½)ⁿ do original. Processo de primeira ordem; ln 2 / λ = t½. Isótopos relevantes para o MCAT: ¹⁴C (datação), ¹³¹I (tiroide), ⁹⁹ᵐTc (imagiologia), ³H (traçadores)."}},
  { id: 'dc-mcat-0047', deck_id: 'deck-mcat', sort_order: 47, front: "Le Chatelier's Principle (MCAT Applications)", back: "Increasing reactant concentration or decreasing product concentration shifts equilibrium right. Increasing pressure favors the side with fewer moles of gas. Increasing temperature favors the endothermic direction (shifts K)." , front_translations: {"es":"Princípio de Le Chatelier (Aplicaciones MCAT)","de":"Le-Chatelier-Prinzip (MCAT-Anwendungen)","fr":"Principe de Le Chatelier (applications MCAT)","tr":"Le Chatelier İlkesi (MCAT Uygulamaları)","nl":"Principe van Le Chatelier (MCAT-toepassingen)","ru":"Принцип Ле Шателье (применение на MCAT)","zh":"勒夏特列原理（MCAT应用）","pt_BR":"Princípio de Le Chatelier (Aplicações MCAT)","pt_PT":"Princípio de Le Chatelier (Aplicações MCAT)"}, back_translations: {"es":"Aumentar a concentración de reactivos o diminuir a de productos desloca el equilíbrio para a direita. Aumentar a presión favorece el lado con menos moles de gas. Aumentar a temperatura favorece a dirección endotérmica (desloca K).","de":"Erhöhung der Reaktantenkonzentration oder Verringerung der Produktkonzentration verschiebt das Gleichgewicht nach rechts. Druckerhöhung begünstigt die Seite mit weniger Gasmolen. Temperaturerhöhung begünstigt die endotherme Richtung (verschiebt K).","fr":"Augmenter la concentration des réactifs ou diminuer celle des produits déplace l'équilibre vers la droite. Augmenter la pression favorise le côté avec moins de moles de gaz. Augmenter la température favorise la direction endothermique (déplace K).","tr":"Reaktan konsantrasyonunu artırmak veya ürün konsantrasyonunu azaltmak dengeyi sağa kaydırır. Basıncı artırmak daha az mol gaza sahip tarafı destekler. Sıcaklığı artırmak endotermik yönü destekler (K'yı kaydırır).","nl":"Het verhogen van de reactantconcentratie of het verlagen van de productconcentratie verschuift het evenwicht naar rechts. Het verhogen van de druk begunstigt de zijde met minder mol gas. Het verhogen van de temperatuur begunstigt de endotherme richting (verschuift K).","ru":"Увеличение концентрации реагентов или уменьшение концентрации продуктов смещает равновесие вправо. Увеличение давления благоприятствует стороне с меньшим числом молей газа. Повышение температуры благоприятствует эндотермическому направлению (смещает K).","zh":"增加反应物浓度或减少产物浓度使平衡向右移动。增加压力有利于气体摩尔数较少的一侧。升高温度有利于吸热方向（改变K值）。","pt_BR":"Aumentar a concentração de reagentes ou diminuir a de produtos desloca o equilíbrio para a direita. Aumentar a pressão favorece o lado com menos moles de gás. Aumentar a temperatura favorece a direção endotérmica (desloca K).","pt_PT":"Aumentar a concentração de reagentes ou diminuir a de produtos desloca o equilíbrio para a direita. Aumentar a pressão favorece o lado com menos moles de gás. Aumentar a temperatura favorece a direção endotérmica (desloca K)."}},
  { id: 'dc-mcat-0048', deck_id: 'deck-mcat', sort_order: 48, front: "Rate-Determining Step", back: "The slowest elementary step in a reaction mechanism, determining the overall reaction rate. The rate law for the overall reaction reflects only the reactants in the rate-determining step, not the overall balanced equation." , front_translations: {"es":"Etapa Determinante de la Velocidad","de":"Geschwindigkeitsbestimmender Schritt","fr":"Étape cinétiquement déterminante","tr":"Hız Belirleyici Basamak","nl":"Snelheidsbepalende stap","ru":"Скорость-определяющая стадия","zh":"速率决定步骤","pt_BR":"Etapa Determinante da Velocidade","pt_PT":"Etapa Determinante da Velocidade"}, back_translations: {"es":"La etapa elementar más lenta en un mecanismo de reacción, determinando a velocidad global de la reacción. La ley de velocidad de la reacción global reflete solo los reactivos en la etapa determinante de la velocidad, no a ecuación balanceada global.","de":"Der langsamste Elementarschritt in einem Reaktionsmechanismus, der die Gesamtreaktionsgeschwindigkeit bestimmt. Das Geschwindigkeitsgesetz der Gesamtreaktion spiegelt nur die Reaktanten im geschwindigkeitsbestimmenden Schritt wider, nicht die gesamte ausgeglichene Gleichung.","fr":"L'étape élémentaire la plus lente dans un mécanisme réactionnel, déterminant la vitesse globale de la réaction. La loi de vitesse de la réaction globale ne reflète que les réactifs de l'étape cinétiquement déterminante, et non l'équation bilan globale.","tr":"Bir reaksiyon mekanizmasındaki en yavaş temel basamak olup genel reaksiyon hızını belirler. Genel reaksiyonun hız yasası, dengeli genel denklemdeki değil, yalnızca hız belirleyici basamaktaki reaktanları yansıtır.","nl":"De langzaamste elementaire stap in een reactiemechanisme, die de algehele reactiesnelheid bepaalt. De snelheidswet voor de algehele reactie weerspiegelt alleen de reactanten in de snelheidsbepalende stap, niet de algehele gebalanceerde vergelijking.","ru":"Самая медленная элементарная стадия в механизме реакции, определяющая общую скорость реакции. Закон скорости общей реакции отражает только реагенты скорость-определяющей стадии, а не общее сбалансированное уравнение.","zh":"反应机理中最慢的基元步骤，决定总反应速率。总反应的速率方程仅反映速率决定步骤中的反应物，而非总的平衡方程。","pt_BR":"A etapa elementar mais lenta em um mecanismo de reação, determinando a velocidade global da reação. A lei de velocidade da reação global reflete apenas os reagentes na etapa determinante da velocidade, não a equação balanceada global.","pt_PT":"A etapa elementar mais lenta num mecanismo de reação, determinando a velocidade global da reação. A lei de velocidade da reação global reflete apenas os reagentes na etapa determinante da velocidade, não a equação balanceada global."}},
  // --- Organic Chemistry ---
  { id: 'dc-mcat-0049', deck_id: 'deck-mcat', sort_order: 49, front: "SN2 Reaction (MCAT)", back: "Bimolecular; concerted mechanism; backside attack → inversion of configuration (Walden inversion). Rate = k[nucleophile][substrate]. Best with primary substrates, strong nucleophiles, polar aprotic solvents (DMSO, acetone)." , front_translations: {"es":"Reación SN2 (MCAT)","de":"SN2-Reaktion (MCAT)","fr":"Réaction SN2 (MCAT)","tr":"SN2 Reaksiyonu (MCAT)","nl":"SN2-reactie (MCAT)","ru":"Реакция SN2 (MCAT)","zh":"SN2反应（MCAT）","pt_BR":"Reação SN2 (MCAT)","pt_PT":"Reação SN2 (MCAT)"}, back_translations: {"es":"Bimolecular; mecanismo concertado; ataque por tras → inversão de configuración (inversão de Walden). Taxa = k[nucleófilo][substrato]. Melhor con substratos primários, nucleófilos fuertes, disolventes polares apróticos (DMSO, acetona).","de":"Bimolekular; konzertierter Mechanismus; Rückseitiger Angriff → Inversion der Konfiguration (Walden-Inversion). Geschwindigkeit = k[Nukleophil][Substrat]. Am besten mit primären Substraten, starken Nukleophilen, polar aprotischen Lösungsmitteln (DMSO, Aceton).","fr":"Bimoléculaire ; mécanisme concerté ; attaque dorsale → inversion de configuration (inversion de Walden). Vitesse = k[nucléophile][substrat]. Optimal avec substrats primaires, nucléophiles forts, solvants polaires aprotiques (DMSO, acétone).","tr":"Bimoleküler; uyumlu mekanizma; arkadan saldırı → konfigürasyon inversiyonu (Walden inversiyonu). Hız = k[nükleofil][substrat]. Birincil substratlar, güçlü nükleofiller, polar aprotik çözücülerle (DMSO, aseton) en iyi sonuç verir.","nl":"Bimoleculair; geconcerteerd mechanisme; aanval vanaf de achterkant → inversie van configuratie (Walden-inversie). Snelheid = k[nucleofiel][substraat]. Best met primaire substraten, sterke nucleofielen, polair aprotische oplosmiddelen (DMSO, aceton).","ru":"Бимолекулярная; согласованный механизм; атака с тыла → инверсия конфигурации (инверсия Вальдена). Скорость = k[нуклеофил][субстрат]. Лучше всего с первичными субстратами, сильными нуклеофилами, полярными апротонными растворителями (DMSO, ацетон).","zh":"双分子反应；协同机制；背面进攻→构型翻转（Walden翻转）。速率 = k[亲核试剂][底物]。最适用于伯底物、强亲核试剂、极性非质子溶剂（DMSO、丙酮）。","pt_BR":"Bimolecular; mecanismo concertado; ataque por trás → inversão de configuração (inversão de Walden). Taxa = k[nucleófilo][substrato]. Melhor com substratos primários, nucleófilos fortes, solventes polares apróticos (DMSO, acetona).","pt_PT":"Bimolecular; mecanismo concertado; ataque posterior → inversão de configuração (inversão de Walden). Taxa = k[nucleófilo][substrato]. Melhor com substratos primários, nucleófilos fortes, solventes polares apróticos (DMSO, acetona)."}},
  { id: 'dc-mcat-0050', deck_id: 'deck-mcat', sort_order: 50, front: "SN1 Reaction (MCAT)", back: "Unimolecular; two-step via carbocation intermediate. Rate = k[substrate]. Best with tertiary substrates, weak nucleophiles, polar protic solvents (water, alcohol). Produces racemic mixture (both enantiomers)." , front_translations: {"es":"Reación SN1 (MCAT)","de":"SN1-Reaktion (MCAT)","fr":"Réaction SN1 (MCAT)","tr":"SN1 Reaksiyonu (MCAT)","nl":"SN1-reactie (MCAT)","ru":"Реакция SN1 (MCAT)","zh":"SN1反应（MCAT）","pt_BR":"Reação SN1 (MCAT)","pt_PT":"Reação SN1 (MCAT)"}, back_translations: {"es":"Unimolecular; de los etapas via intermediário carbocátion. Taxa = k[substrato]. Melhor con substratos terciários, nucleófilos débiles, disolventes polares próticos (agua, álcool). Produz mistura racemica (ambos los enantiomeros).","de":"Unimolekular; zweistufig über Carbokation-Intermediat. Geschwindigkeit = k[Substrat]. Am besten mit tertiären Substraten, schwachen Nukleophilen, polar protischen Lösungsmitteln (Wasser, Alkohol). Erzeugt racemisches Gemisch (beide Enantiomere).","fr":"Unimoléculaire ; deux étapes via un intermédiaire carbocation. Vitesse = k[substrat]. Optimal avec substrats tertiaires, nucléophiles faibles, solvants polaires protiques (eau, alcool). Produit un mélange racémique (les deux énantiomères).","tr":"Unimoleküler; karbokation ara ürünü üzerinden iki aşamalı. Hız = k[substrat]. Tersiyer substratlar, zayıf nükleofiller, polar protik çözücülerle (su, alkol) en iyi sonuç verir. Rasemik karışım üretir (her iki enantiyomer).","nl":"Unimoleculair; tweestaps via carbokation-intermediair. Snelheid = k[substraat]. Best met tertiaire substraten, zwakke nucleofielen, polair protische oplosmiddelen (water, alcohol). Produceert racemisch mengsel (beide enantiomeren).","ru":"Унимолекулярная; двухстадийная через карбокатионный интермедиат. Скорость = k[субстрат]. Лучше всего с третичными субстратами, слабыми нуклеофилами, полярными протонными растворителями (вода, спирт). Образует рацемическую смесь (оба энантиомера).","zh":"单分子反应；经碳正离子中间体的两步反应。速率 = k[底物]。最适用于叔底物、弱亲核试剂、极性质子溶剂（水、醇）。产生外消旋混合物（两种对映体）。","pt_BR":"Unimolecular; duas etapas via intermediário carbocátion. Taxa = k[substrato]. Melhor com substratos terciários, nucleófilos fracos, solventes polares próticos (água, álcool). Produz mistura racêmica (ambos os enantiômeros).","pt_PT":"Unimolecular; duas etapas via intermediário carbocatião. Taxa = k[substrato]. Melhor com substratos terciários, nucleófilos fracos, solventes polares próticos (água, álcool). Produz mistura racémica (ambos os enantiómeros)."}},
  { id: 'dc-mcat-0051', deck_id: 'deck-mcat', sort_order: 51, front: "E2 Elimination", back: "Bimolecular; concerted; anti-periplanar geometry required (H and LG at 180°). Rate = k[base][substrate]. Strong, bulky base (KOtBu). Major product follows Zaitsev's rule (more substituted alkene) unless bulky base gives Hofmann product." , front_translations: {"es":"Eliminación Y2","de":"E2-Eliminierung","fr":"Élimination E2","tr":"E2 Eliminasyonu","nl":"E2-eliminatie","ru":"E2-элиминирование","zh":"E2消除反应","pt_BR":"Eliminação E2","pt_PT":"Eliminação E2"}, back_translations: {"es":"Bimolecular; concertado; geometría anti-periplanar necesaria (H y grupo de saída a 180°). Taxa = k[base][substrato]. Base fuerte y volumosa (KOtBu). Produto principal sigue a regra de Zaitsev (alceno más substituído), a menos que base volumosa forneça el producto de Hofmann.","de":"Bimolekular; konzertiert; anti-periplanare Geometrie erforderlich (H und Abgangsgruppe bei 180°). Geschwindigkeit = k[Base][Substrat]. Starke, sperrige Base (KOtBu). Hauptprodukt folgt der Zaitsev-Regel (höher substituiertes Alken), sofern keine sperrige Base das Hofmann-Produkt liefert.","fr":"Bimoléculaire ; concerté ; géométrie anti-périplanaire requise (H et groupe partant à 180°). Vitesse = k[base][substrat]. Base forte et encombrée (KOtBu). Le produit majoritaire suit la règle de Zaïtsev (alcène le plus substitué), sauf si une base encombrée donne le produit de Hofmann.","tr":"Bimoleküler; uyumlu; anti-periplanar geometri gereklidir (H ve ayrılan grup 180°'de). Hız = k[baz][substrat]. Güçlü, hacimli baz (KOtBu). Ana ürün Zaitsev kuralını izler (daha fazla sübstitüe alken), hacimli baz Hofmann ürünü vermedikçe.","nl":"Bimoleculair; geconcerteerd; anti-periplanaire geometrie vereist (H en vertrekkende groep op 180°). Snelheid = k[base][substraat]. Sterke, omvangrijke base (KOtBu). Hoofdproduct volgt de regel van Zaitsev (meer gesubstitueerd alkeen), tenzij omvangrijke base het Hofmann-product geeft.","ru":"Бимолекулярная; согласованная; необходима антиперипланарная геометрия (H и уходящая группа под 180°). Скорость = k[основание][субстрат]. Сильное объёмное основание (KOtBu). Основной продукт по правилу Зайцева (более замещённый алкен), если только объёмное основание не даёт продукт Гофмана.","zh":"双分子反应；协同反应；需要反式共面几何构型（H与离去基团成180°）。速率 = k[碱][底物]。强的体积大的碱（KOtBu）。主要产物遵循Zaitsev规则（取代度更高的烯烃），除非体积大的碱给出Hofmann产物。","pt_BR":"Bimolecular; concertado; geometria anti-periplanar necessária (H e grupo de saída a 180°). Taxa = k[base][substrato]. Base forte e volumosa (KOtBu). Produto principal segue a regra de Zaitsev (alceno mais substituído), a menos que base volumosa forneça o produto de Hofmann.","pt_PT":"Bimolecular; concertado; geometria anti-periplanar necessária (H e grupo de saída a 180°). Taxa = k[base][substrato]. Base forte e volumosa (KOtBu). Produto principal segue a regra de Zaitsev (alceno mais substituído), a menos que base volumosa forneça o produto de Hofmann."}},
  { id: 'dc-mcat-0052', deck_id: 'deck-mcat', sort_order: 52, front: "E1 Elimination", back: "Unimolecular; proceeds via carbocation intermediate (like SN1). Rate = k[substrate]. Follows Zaitsev's rule. Competes with SN1. Tertiary substrates, high temperature, and weak nucleophile/base favor E1." , front_translations: {"es":"Eliminación Y1","de":"E1-Eliminierung","fr":"Élimination E1","tr":"E1 Eliminasyonu","nl":"E1-eliminatie","ru":"E1-элиминирование","zh":"E1消除反应","pt_BR":"Eliminação E1","pt_PT":"Eliminação E1"}, back_translations: {"es":"Unimolecular; procede via intermediário carbocátion (como SN1). Taxa = k[substrato]. Segue a regra de Zaitsev. Compete con SN1. Substratos terciários, alta temperatura y nucleófilo/base débil favorecem Y1.","de":"Unimolekular; verläuft über Carbokation-Intermediat (wie SN1). Geschwindigkeit = k[Substrat]. Folgt der Zaitsev-Regel. Konkurriert mit SN1. Tertiäre Substrate, hohe Temperatur und schwache Nukleophile/Basen begünstigen E1.","fr":"Unimoléculaire ; procède via un intermédiaire carbocation (comme SN1). Vitesse = k[substrat]. Suit la règle de Zaïtsev. En compétition avec SN1. Les substrats tertiaires, haute température et nucléophile/base faible favorisent E1.","tr":"Unimoleküler; karbokation ara ürünü üzerinden ilerler (SN1 gibi). Hız = k[substrat]. Zaitsev kuralını izler. SN1 ile rekabet eder. Tersiyer substratlar, yüksek sıcaklık ve zayıf nükleofil/baz E1'i destekler.","nl":"Unimoleculair; verloopt via carbokation-intermediair (zoals SN1). Snelheid = k[substraat]. Volgt de regel van Zaitsev. Concurreert met SN1. Tertiaire substraten, hoge temperatuur en zwak nucleofiel/base bevorderen E1.","ru":"Унимолекулярная; протекает через карбокатионный интермедиат (как SN1). Скорость = k[субстрат]. Подчиняется правилу Зайцева. Конкурирует с SN1. Третичные субстраты, высокая температура и слабый нуклеофил/основание благоприятствуют E1.","zh":"单分子反应；经碳正离子中间体进行（类似SN1）。速率 = k[底物]。遵循Zaitsev规则。与SN1竞争。叔底物、高温和弱亲核试剂/碱有利于E1。","pt_BR":"Unimolecular; procede via intermediário carbocátion (como SN1). Taxa = k[substrato]. Segue a regra de Zaitsev. Compete com SN1. Substratos terciários, alta temperatura e nucleófilo/base fraco favorecem E1.","pt_PT":"Unimolecular; procede via intermediário carbocatião (como SN1). Taxa = k[substrato]. Segue a regra de Zaitsev. Compete com SN1. Substratos terciários, alta temperatura e nucleófilo/base fraco favorecem E1."}},
  { id: 'dc-mcat-0053', deck_id: 'deck-mcat', sort_order: 53, front: "Stereochemistry: R/S Configuration", back: "Assign priorities 1–4 by CIP rules (atomic number). If priority 1→2→3 is clockwise = R; counterclockwise = S. If the lowest priority (4) is facing you, reverse the designation. Chiral center: 4 different groups on carbon." , front_translations: {"es":"Estereoquímica: Configuración R/S","de":"Stereochemie: R/S-Konfiguration","fr":"Stéréochimie : Configuration R/S","tr":"Stereokimya: R/S Konfigürasyonu","nl":"Stereochemie: R/S-configuratie","ru":"Стереохимия: R/S-конфигурация","zh":"立体化学：R/S构型","pt_BR":"Estereoquímica: Configuração R/S","pt_PT":"Estereoquímica: Configuração R/S"}, back_translations: {"es":"Atribuir prioridades 1–4 por las regras CIP (número atómico). Se prioridad 1→2→3 es en el sentido horário = R; anti-horário = S. Se a menor prioridad (4) está voltada para voce, inverta a designación. Centro quiral: 4 grupos diferentes en el carbono.","de":"Prioritäten 1–4 nach CIP-Regeln (Ordnungszahl) zuweisen. Wenn Priorität 1→2→3 im Uhrzeigersinn = R; gegen den Uhrzeigersinn = S. Wenn die niedrigste Priorität (4) auf Sie zeigt, Bezeichnung umkehren. Chirales Zentrum: 4 verschiedene Gruppen am Kohlenstoff.","fr":"Attribuer les priorités 1–4 selon les règles CIP (numéro atomique). Si la priorité 1→2→3 est dans le sens horaire = R ; antihoraire = S. Si la priorité la plus basse (4) est face à vous, inverser la désignation. Centre chiral : 4 groupes différents sur le carbone.","tr":"CIP kurallarına göre (atom numarası) 1–4 öncelikleri atayın. Öncelik 1→2→3 saat yönündeyse = R; saat yönünün tersiyse = S. En düşük öncelik (4) size bakıyorsa, tanımlamayı tersine çevirin. Kiral merkez: karbon üzerinde 4 farklı grup.","nl":"Wijs prioriteiten 1–4 toe volgens CIP-regels (atoomnummer). Als prioriteit 1→2→3 met de klok mee = R; tegen de klok in = S. Als de laagste prioriteit (4) naar u toe wijst, keer de aanduiding om. Chiraal centrum: 4 verschillende groepen aan koolstof.","ru":"Присвойте приоритеты 1–4 по правилам CIP (атомный номер). Если приоритет 1→2→3 по часовой стрелке = R; против часовой = S. Если наименьший приоритет (4) направлен к вам, обозначение меняется на противоположное. Хиральный центр: 4 разные группы на углероде.","zh":"按CIP规则（原子序数）分配1–4优先级。若优先级1→2→3为顺时针 = R；逆时针 = S。若最低优先级（4）朝向你，则反转命名。手性中心：碳上有4个不同基团。","pt_BR":"Atribuir prioridades 1–4 pelas regras CIP (número atômico). Se prioridade 1→2→3 é no sentido horário = R; anti-horário = S. Se a menor prioridade (4) está voltada para você, inverta a designação. Centro quiral: 4 grupos diferentes no carbono.","pt_PT":"Atribuir prioridades 1–4 pelas regras CIP (número atómico). Se prioridade 1→2→3 é no sentido horário = R; anti-horário = S. Se a menor prioridade (4) está voltada para si, inverta a designação. Centro quiral: 4 grupos diferentes no carbono."}},
  { id: 'dc-mcat-0054', deck_id: 'deck-mcat', sort_order: 54, front: "Stereochemistry: Enantiomers vs. Diastereomers", back: "Enantiomers: non-superimposable mirror images; opposite configuration at all stereocenters. Diastereomers: stereoisomers that are not mirror images; different configuration at one or more (not all) stereocenters. Meso compounds are achiral despite stereocenters." , front_translations: {"es":"Estereoquímica: Enantiomeros vs. Diastereomeros","de":"Stereochemie: Enantiomere vs. Diastereomere","fr":"Stéréochimie : Énantiomères vs. Diastéréoisomères","tr":"Stereokimya: Enantiyomerler ve Diastereomerler","nl":"Stereochemie: Enantiomeren vs. Diastereomeren","ru":"Стереохимия: Энантиомеры и диастереомеры","zh":"立体化学：对映体与非对映体","pt_BR":"Estereoquímica: Enantiômeros vs. Diastereômeros","pt_PT":"Estereoquímica: Enantiómeros vs. Diastereómeros"}, back_translations: {"es":"Enantiomeros: imajes especulares no sobreponibles; configuración oposta en todos los estereocentros. Diastereomeros: estereoisomeros que no son imajes especulares; configuración diferente en un o más (no todos) estereocentros. Compostos meso son aquirais apesar de los estereocentros.","de":"Enantiomere: nicht deckungsgleiche Spiegelbilder; entgegengesetzte Konfiguration an allen Stereozentren. Diastereomere: Stereoisomere, die keine Spiegelbilder sind; unterschiedliche Konfiguration an einem oder mehreren (nicht allen) Stereozentren. Meso-Verbindungen sind achiral trotz Stereozentren.","fr":"Énantiomères : images miroir non superposables ; configuration opposée à tous les stéréocentres. Diastéréoisomères : stéréoisomères qui ne sont pas des images miroir ; configuration différente à un ou plusieurs (pas tous) stéréocentres. Les composés méso sont achiraux malgré les stéréocentres.","tr":"Enantiyomerler: üst üste gelemeyen ayna görüntüleri; tüm stereosenterlarda zıt konfigürasyon. Diastereomerler: ayna görüntüsü olmayan stereoizomerler; bir veya daha fazla (tümü değil) stereosenterde farklı konfigürasyon. Mezo bileşikler, stereosenterlara rağmen akiraldir.","nl":"Enantiomeren: niet-superponeerbare spiegelbeelden; tegengestelde configuratie bij alle stereocentra. Diastereomeren: stereo-isomeren die geen spiegelbeelden zijn; verschillende configuratie bij een of meer (niet alle) stereocentra. Mesoverbindingen zijn achiraal ondanks stereocentra.","ru":"Энантиомеры: несовместимые зеркальные отображения; противоположная конфигурация на всех стереоцентрах. Диастереомеры: стереоизомеры, не являющиеся зеркальными отображениями; различная конфигурация на одном или нескольких (не всех) стереоцентрах. Мезосоединения ахиральны несмотря на стереоцентры.","zh":"对映体：不可叠合的镜像；所有立体中心构型相反。非对映体：不是镜像的立体异构体；一个或多个（非全部）立体中心构型不同。内消旋化合物尽管有立体中心但不具手性。","pt_BR":"Enantiômeros: imagens especulares não sobreponíveis; configuração oposta em todos os estereocentros. Diastereômeros: estereoisômeros que não são imagens especulares; configuração diferente em um ou mais (não todos) estereocentros. Compostos meso são aquirais apesar dos estereocentros.","pt_PT":"Enantiómeros: imagens especulares não sobreponíveis; configuração oposta em todos os estereocentros. Diastereómeros: estereoisómeros que não são imagens especulares; configuração diferente em um ou mais (não todos) estereocentros. Compostos meso são aquirais apesar dos estereocentros."}},
  { id: 'dc-mcat-0055', deck_id: 'deck-mcat', sort_order: 55, front: "Carbohydrate Anomers (α vs. β)", back: "When monosaccharides cyclize, the anomeric carbon (C1 of aldoses) can adopt α (OH below the ring plane in Haworth) or β (OH above) configuration. β-glucose is more stable and is the monomer of cellulose; α-glucose forms starch and glycogen." , front_translations: {"es":"Anomeros de Carboidratos (α vs. β)","de":"Kohlenhydrat-Anomere (α vs. β)","fr":"Anomères des glucides (α vs. β)","tr":"Karbohidrat Anomerleri (α ve β)","nl":"Koolhydraat-anomeren (α vs. β)","ru":"Аномеры углеводов (α и β)","zh":"碳水化合物异头物（α与β）","pt_BR":"Anômeros de Carboidratos (α vs. β)","pt_PT":"Anómeros de Hidratos de Carbono (α vs. β)"}, back_translations: {"es":"Cuando monossacarídeos se ciclizam, el carbono anomérico (C1 de las aldoses) puede adotar configuración α (OH debajo del plano del anel en Haworth) o β (OH encima). La β-glicose es más estable y es el monomero de la celulose; a α-glicose forma amido y glicogenio.","de":"Wenn Monosaccharide zyklisieren, kann das anomere Kohlenstoffatom (C1 bei Aldosen) die α-Konfiguration (OH unterhalb der Ringebene in Haworth) oder β-Konfiguration (OH oberhalb) annehmen. β-Glucose ist stabiler und ist das Monomer der Cellulose; α-Glucose bildet Stärke und Glykogen.","fr":"Lorsque les monosaccharides se cyclisent, le carbone anomérique (C1 des aldoses) peut adopter la configuration α (OH en dessous du plan du cycle en Haworth) ou β (OH au-dessus). Le β-glucose est plus stable et constitue le monomère de la cellulose ; le α-glucose forme l'amidon et le glycogène.","tr":"Monosakkaritler halkalandığında, anomerik karbon (aldozların C1'i) α (Haworth'ta OH halka düzleminin altında) veya β (OH yukarıda) konfigürasyonunu alabilir. β-glukoz daha kararlıdır ve selülozun monomeridir; α-glukoz nişasta ve glikojen oluşturur.","nl":"Wanneer monosacchariden cycliseren, kan het anomere koolstofatoom (C1 van aldosen) de α-configuratie (OH onder het ringvlak in Haworth) of β-configuratie (OH erboven) aannemen. β-glucose is stabieler en is het monomeer van cellulose; α-glucose vormt zetmeel en glycogeen.","ru":"При циклизации моносахаридов аномерный углерод (C1 альдоз) может принять α-конфигурацию (OH ниже плоскости кольца в проекции Хеуорса) или β-конфигурацию (OH выше). β-глюкоза более стабильна и является мономером целлюлозы; α-глюкоза образует крахмал и гликоген.","zh":"单糖环化时，异头碳（醛糖的C1）可采用α构型（Haworth投影中OH在环平面下方）或β构型（OH在上方）。β-葡萄糖更稳定，是纤维素的单体；α-葡萄糖形成淀粉和糖原。","pt_BR":"Quando monossacarídeos se ciclizam, o carbono anomérico (C1 das aldoses) pode adotar configuração α (OH abaixo do plano do anel em Haworth) ou β (OH acima). A β-glicose é mais estável e é o monômero da celulose; a α-glicose forma amido e glicogênio.","pt_PT":"Quando os monossacáridos se ciclizam, o carbono anomérico (C1 das aldoses) pode adotar configuração α (OH abaixo do plano do anel em Haworth) ou β (OH acima). A β-glicose é mais estável e é o monómero da celulose; a α-glicose forma amido e glicogénio."}},
  { id: 'dc-mcat-0056', deck_id: 'deck-mcat', sort_order: 56, front: "Lipids: Phospholipid Structure", back: "A glycerophospholipid has: glycerol backbone + two fatty acid tails (ester bonds) + phosphate group + polar head group. Amphipathic: hydrophilic head (phosphate + head group) and hydrophobic tails. Forms bilayers spontaneously in water." , front_translations: {"es":"Lipídios: Estrutura de los Fosfolipídios","de":"Lipide: Phospholipid-Struktur","fr":"Lipides : Structure des phospholipides","tr":"Lipitler: Fosfolipit Yapısı","nl":"Lipiden: Fosfolipidestructuur","ru":"Липиды: Структура фосфолипидов","zh":"脂质：磷脂结构","pt_BR":"Lipídios: Estrutura dos Fosfolipídios","pt_PT":"Lípidos: Estrutura dos Fosfolípidos"}, back_translations: {"es":"Un glicerofosfolipídio tiene: esqueleto de glicerol + de los caudas de ácidos grasos (enlaces éster) + grupo fosfato + grupo polar de la cabeza. Anfipático: cabeza hidrofílica (fosfato + grupo de la cabeza) y caudas hidrofóbicas. Forma bicamadas espontaneamente en agua.","de":"Ein Glycerophospholipid hat: Glycerinrückgrat + zwei Fettsäureketten (Esterbindungen) + Phosphatgruppe + polare Kopfgruppe. Amphipathisch: hydrophiler Kopf (Phosphat + Kopfgruppe) und hydrophobe Schwänze. Bildet spontan Doppelschichten in Wasser.","fr":"Un glycérophospholipide possède : squelette glycérol + deux queues d'acides gras (liaisons ester) + groupe phosphate + groupe de tête polaire. Amphipathique : tête hydrophile (phosphate + groupe de tête) et queues hydrophobes. Forme spontanément des bicouches dans l'eau.","tr":"Bir gliserofosfolipit şunlara sahiptir: gliserol iskeleti + iki yağ asidi kuyruğu (ester bağları) + fosfat grubu + polar baş grubu. Amfipatik: hidrofilik baş (fosfat + baş grubu) ve hidrofobik kuyruklar. Suda kendiliğinden çift tabaka oluşturur.","nl":"Een glycerofosfolipide heeft: glycerolskelet + twee vetzuurstaarten (esterbindingen) + fosfaatgroep + polaire kopgroep. Amfipathisch: hydrofiele kop (fosfaat + kopgroep) en hydrofobe staarten. Vormt spontaan dubbellagen in water.","ru":"Глицерофосфолипид имеет: глицериновый остов + два хвоста жирных кислот (сложноэфирные связи) + фосфатная группа + полярная головная группа. Амфипатический: гидрофильная головка (фосфат + головная группа) и гидрофобные хвосты. Спонтанно образует бислои в воде.","zh":"甘油磷脂包含：甘油骨架 + 两条脂肪酸尾（酯键）+ 磷酸基团 + 极性头部基团。两亲性：亲水头部（磷酸 + 头部基团）和疏水尾部。在水中自发形成双分子层。","pt_BR":"Um glicerofosfolipídio tem: esqueleto de glicerol + duas caudas de ácidos graxos (ligações éster) + grupo fosfato + grupo polar da cabeça. Anfipático: cabeça hidrofílica (fosfato + grupo da cabeça) e caudas hidrofóbicas. Forma bicamadas espontaneamente em água.","pt_PT":"Um glicerofosfolípido tem: esqueleto de glicerol + duas caudas de ácidos gordos (ligações éster) + grupo fosfato + grupo polar da cabeça. Anfipático: cabeça hidrofílica (fosfato + grupo da cabeça) e caudas hidrofóbicas. Forma bicamadas espontaneamente em água."}},
  { id: 'dc-mcat-0057', deck_id: 'deck-mcat', sort_order: 57, front: "Amino Acid Classification", back: "Non-polar aliphatic: Gly, Ala, Val, Leu, Ile, Pro, Met. Aromatic: Phe, Tyr, Trp. Polar uncharged: Ser, Thr, Cys, Asn, Gln. Positively charged (+): Arg, Lys, His. Negatively charged (−): Asp, Glu. 20 standard amino acids." , front_translations: {"es":"Classificación de los Aminoácidos","de":"Aminosäure-Klassifizierung","fr":"Classification des acides aminés","tr":"Amino Asit Sınıflandırması","nl":"Aminozuurclassificatie","ru":"Классификация аминокислот","zh":"氨基酸分类","pt_BR":"Classificação dos Aminoácidos","pt_PT":"Classificação dos Aminoácidos"}, back_translations: {"es":"Apolares alifáticos: Gly, Ala, Val, Leu, Ile, Pro, Met. Aromáticos: Phe, Tyr, Trp. Polares sin carga: Ser, Thr, Cys, Asn, Gln. Carregados positivamente (+): Arg, Lys, His. Carregados negativamente (−): Asp, Glu. 20 aminoácidos padrão.","de":"Unpolar aliphatisch: Gly, Ala, Val, Leu, Ile, Pro, Met. Aromatisch: Phe, Tyr, Trp. Polar ungeladen: Ser, Thr, Cys, Asn, Gln. Positiv geladen (+): Arg, Lys, His. Negativ geladen (−): Asp, Glu. 20 Standardaminosäuren.","fr":"Non polaires aliphatiques : Gly, Ala, Val, Leu, Ile, Pro, Met. Aromatiques : Phe, Tyr, Trp. Polaires non chargés : Ser, Thr, Cys, Asn, Gln. Chargés positivement (+) : Arg, Lys, His. Chargés négativement (−) : Asp, Glu. 20 acides aminés standard.","tr":"Apolar alifatik: Gly, Ala, Val, Leu, Ile, Pro, Met. Aromatik: Phe, Tyr, Trp. Polar yüksüz: Ser, Thr, Cys, Asn, Gln. Pozitif yüklü (+): Arg, Lys, His. Negatif yüklü (−): Asp, Glu. 20 standart amino asit.","nl":"Niet-polair alifatisch: Gly, Ala, Val, Leu, Ile, Pro, Met. Aromatisch: Phe, Tyr, Trp. Polair ongeladen: Ser, Thr, Cys, Asn, Gln. Positief geladen (+): Arg, Lys, His. Negatief geladen (−): Asp, Glu. 20 standaard aminozuren.","ru":"Неполярные алифатические: Gly, Ala, Val, Leu, Ile, Pro, Met. Ароматические: Phe, Tyr, Trp. Полярные незаряженные: Ser, Thr, Cys, Asn, Gln. Положительно заряженные (+): Arg, Lys, His. Отрицательно заряженные (−): Asp, Glu. 20 стандартных аминокислот.","zh":"非极性脂肪族：Gly、Ala、Val、Leu、Ile、Pro、Met。芳香族：Phe、Tyr、Trp。极性不带电：Ser、Thr、Cys、Asn、Gln。带正电（+）：Arg、Lys、His。带负电（−）：Asp、Glu。20种标准氨基酸。","pt_BR":"Apolares alifáticos: Gly, Ala, Val, Leu, Ile, Pro, Met. Aromáticos: Phe, Tyr, Trp. Polares sem carga: Ser, Thr, Cys, Asn, Gln. Carregados positivamente (+): Arg, Lys, His. Carregados negativamente (−): Asp, Glu. 20 aminoácidos padrão.","pt_PT":"Apolares alifáticos: Gly, Ala, Val, Leu, Ile, Pro, Met. Aromáticos: Phe, Tyr, Trp. Polares sem carga: Ser, Thr, Cys, Asn, Gln. Carregados positivamente (+): Arg, Lys, His. Carregados negativamente (−): Asp, Glu. 20 aminoácidos padrão."}},
  { id: 'dc-mcat-0058', deck_id: 'deck-mcat', sort_order: 58, front: "Amino Acid: Isoelectric Point (pI)", back: "The pH at which an amino acid (or protein) has no net charge (zwitterionic). pI = (pKa1 + pKa2) / 2 for simple amino acids. For basic AA (Lys): pI uses pKa of the two most basic groups. At pH > pI, protein has net negative charge." , front_translations: {"es":"Aminoácido: Ponto Isoelétrico (pI)","de":"Aminosäure: Isoelektrischer Punkt (pI)","fr":"Acide aminé : Point isoélectrique (pI)","tr":"Amino Asit: İzoelektrik Nokta (pI)","nl":"Aminozuur: Iso-elektrisch punt (pI)","ru":"Аминокислота: Изоэлектрическая точка (pI)","zh":"氨基酸：等电点（pI）","pt_BR":"Aminoácido: Ponto Isoelétrico (pI)","pt_PT":"Aminoácido: Ponto Isoelétrico (pI)"}, back_translations: {"es":"El pH en el qual un aminoácido (o proteína) no tiene carga líquida (zwitterionico). pI = (pKa1 + pKa2) / 2 para aminoácidos simples. Para AA básicos (Lys): pI usa los pKa de los de los grupos más básicos. En pH > pI, a proteína tiene carga líquida negativa.","de":"Der pH-Wert, bei dem eine Aminosäure (oder ein Protein) keine Nettoladung hat (zwitterionisch). pI = (pKa1 + pKa2) / 2 für einfache Aminosäuren. Für basische AS (Lys): pI verwendet die pKa-Werte der zwei basischsten Gruppen. Bei pH > pI hat das Protein eine negative Nettoladung.","fr":"Le pH auquel un acide aminé (ou une protéine) n'a pas de charge nette (zwitterionique). pI = (pKa1 + pKa2) / 2 pour les acides aminés simples. Pour les AA basiques (Lys) : pI utilise les pKa des deux groupes les plus basiques. À pH > pI, la protéine a une charge nette négative.","tr":"Bir amino asidin (veya proteinin) net yükünün sıfır olduğu pH (zwitteriyonik). Basit amino asitler için pI = (pKa1 + pKa2) / 2. Bazik AA (Lys) için: pI en bazik iki grubun pKa'sını kullanır. pH > pI'da protein net negatif yüke sahiptir.","nl":"De pH waarbij een aminozuur (of eiwit) geen nettolading heeft (zwitterionisch). pI = (pKa1 + pKa2) / 2 voor eenvoudige aminozuren. Voor basische AZ (Lys): pI gebruikt de pKa van de twee meest basische groepen. Bij pH > pI heeft het eiwit een netto negatieve lading.","ru":"pH, при котором аминокислота (или белок) не имеет суммарного заряда (цвиттер-ион). pI = (pKa1 + pKa2) / 2 для простых аминокислот. Для основных АК (Lys): pI рассчитывается по pKa двух наиболее основных групп. При pH > pI белок имеет суммарный отрицательный заряд.","zh":"氨基酸（或蛋白质）净电荷为零时的pH（两性离子态）。简单氨基酸的pI =（pKa1 + pKa2）/ 2。碱性氨基酸（Lys）：pI使用两个最碱性基团的pKa。当pH > pI时，蛋白质带净负电荷。","pt_BR":"O pH no qual um aminoácido (ou proteína) não tem carga líquida (zwitteriônico). pI = (pKa1 + pKa2) / 2 para aminoácidos simples. Para AA básicos (Lys): pI usa os pKa dos dois grupos mais básicos. Em pH > pI, a proteína tem carga líquida negativa.","pt_PT":"O pH no qual um aminoácido (ou proteína) não tem carga líquida (zwitteriónico). pI = (pKa1 + pKa2) / 2 para aminoácidos simples. Para AA básicos (Lys): pI usa os pKa dos dois grupos mais básicos. Em pH > pI, a proteína tem carga líquida negativa."}},
  { id: 'dc-mcat-0059', deck_id: 'deck-mcat', sort_order: 59, front: "Nucleotides: Structure and Function", back: "Composed of a nitrogenous base, pentose sugar (ribose or deoxyribose), and 1–3 phosphate groups. Purines: adenine (A), guanine (G); 2 rings. Pyrimidines: cytosine (C), thymine (T/DNA only), uracil (U/RNA only); 1 ring." , front_translations: {"es":"Nucleotídeos: Estrutura y Función","de":"Nukleotide: Struktur und Funktion","fr":"Nucléotides : Structure et fonction","tr":"Nükleotidler: Yapı ve İşlev","nl":"Nucleotiden: Structuur en functie","ru":"Нуклеотиды: Структура и функция","zh":"核苷酸：结构与功能","pt_BR":"Nucleotídeos: Estrutura e Função","pt_PT":"Nucleótidos: Estrutura e Função"}, back_translations: {"es":"Composto por una base nitrogenada, açúcar pentose (ribose o desoxirribose) y 1–3 grupos fosfato. Purinas: adenina (A), guanina (G); 2 anéis. Pirimidinas: citosina (C), timina (T/solo DNA), uracila (U/solo RNA); 1 anel.","de":"Bestehend aus einer stickstoffhaltigen Base, Pentosezucker (Ribose oder Desoxyribose) und 1–3 Phosphatgruppen. Purine: Adenin (A), Guanin (G); 2 Ringe. Pyrimidine: Cytosin (C), Thymin (T/nur DNA), Uracil (U/nur RNA); 1 Ring.","fr":"Composé d'une base azotée, d'un sucre pentose (ribose ou désoxyribose) et de 1 à 3 groupes phosphate. Purines : adénine (A), guanine (G) ; 2 cycles. Pyrimidines : cytosine (C), thymine (T/ADN uniquement), uracile (U/ARN uniquement) ; 1 cycle.","tr":"Azotlu baz, pentoz şeker (riboz veya deoksiriboz) ve 1–3 fosfat grubundan oluşur. Pürinler: adenin (A), guanin (G); 2 halka. Pirimidinler: sitozin (C), timin (T/yalnızca DNA), urasil (U/yalnızca RNA); 1 halka.","nl":"Samengesteld uit een stikstofhoudende base, pentosesuiker (ribose of deoxyribose) en 1–3 fosfaatgroepen. Purinen: adenine (A), guanine (G); 2 ringen. Pyrimidinen: cytosine (C), thymine (T/alleen DNA), uracil (U/alleen RNA); 1 ring.","ru":"Состоят из азотистого основания, пентозного сахара (рибоза или дезоксирибоза) и 1–3 фосфатных групп. Пурины: аденин (A), гуанин (G); 2 кольца. Пиримидины: цитозин (C), тимин (T/только ДНК), урацил (U/только РНК); 1 кольцо.","zh":"由含氮碱基、戊糖（核糖或脱氧核糖）和1–3个磷酸基团组成。嘌呤：腺嘌呤（A）、鸟嘌呤（G）；2个环。嘧啶：胞嘧啶（C）、胸腺嘧啶（T/仅DNA）、尿嘧啶（U/仅RNA）；1个环。","pt_BR":"Composto por uma base nitrogenada, açúcar pentose (ribose ou desoxirribose) e 1–3 grupos fosfato. Purinas: adenina (A), guanina (G); 2 anéis. Pirimidinas: citosina (C), timina (T/apenas DNA), uracila (U/apenas RNA); 1 anel.","pt_PT":"Composto por uma base azotada, açúcar pentose (ribose ou desoxirribose) e 1–3 grupos fosfato. Purinas: adenina (A), guanina (G); 2 anéis. Pirimidinas: citosina (C), timina (T/apenas DNA), uracilo (U/apenas RNA); 1 anel."}},
  { id: 'dc-mcat-0060', deck_id: 'deck-mcat', sort_order: 60, front: "DNA vs. RNA: Structural Differences", back: "DNA: deoxyribose (no 2'-OH), bases A/T/G/C, double-stranded, stable. RNA: ribose (2'-OH makes it less stable), bases A/U/G/C, typically single-stranded. The 2'-OH makes RNA susceptible to hydrolysis under alkaline conditions." , front_translations: {"es":"DNA vs. RNA: Diferenças Estruturais","de":"DNA vs. RNA: Strukturelle Unterschiede","fr":"ADN vs. ARN : Différences structurelles","tr":"DNA ve RNA: Yapısal Farklar","nl":"DNA vs. RNA: Structurele verschillen","ru":"ДНК и РНК: Структурные различия","zh":"DNA与RNA：结构差异","pt_BR":"DNA vs. RNA: Diferenças Estruturais","pt_PT":"DNA vs. RNA: Diferenças Estruturais"}, back_translations: {"es":"DNA: desoxirribose (sin 2'-OH), bases A/T/G/C, dupla fita, estable. RNA: ribose (2'-OH torna-el menos estable), bases A/U/G/C, típicamente fita simples. El 2'-OH torna el RNA suscetible a la hidrólise en condiciones alcalinas.","de":"DNA: Desoxyribose (keine 2'-OH), Basen A/T/G/C, doppelsträngig, stabil. RNA: Ribose (2'-OH macht sie weniger stabil), Basen A/U/G/C, typischerweise einzelsträngig. Die 2'-OH-Gruppe macht RNA anfällig für Hydrolyse unter alkalischen Bedingungen.","fr":"ADN : désoxyribose (pas de 2'-OH), bases A/T/G/C, double brin, stable. ARN : ribose (le 2'-OH le rend moins stable), bases A/U/G/C, typiquement simple brin. Le 2'-OH rend l'ARN susceptible à l'hydrolyse en conditions alcalines.","tr":"DNA: deoksiriboz (2'-OH yok), bazlar A/T/G/C, çift sarmallı, kararlı. RNA: riboz (2'-OH daha az kararlı kılar), bazlar A/U/G/C, tipik olarak tek sarmallı. 2'-OH, RNA'yı alkali koşullarda hidrolize duyarlı kılar.","nl":"DNA: deoxyribose (geen 2'-OH), basen A/T/G/C, dubbelstrengs, stabiel. RNA: ribose (2'-OH maakt het minder stabiel), basen A/U/G/C, typisch enkelstrengs. De 2'-OH maakt RNA vatbaar voor hydrolyse onder alkalische omstandigheden.","ru":"ДНК: дезоксирибоза (нет 2'-OH), основания A/T/G/C, двуцепочечная, стабильная. РНК: рибоза (2'-OH делает менее стабильной), основания A/U/G/C, обычно одноцепочечная. 2'-OH делает РНК подверженной гидролизу в щелочных условиях.","zh":"DNA：脱氧核糖（无2'-OH），碱基A/T/G/C，双链，稳定。RNA：核糖（2'-OH使其不太稳定），碱基A/U/G/C，通常单链。2'-OH使RNA在碱性条件下容易水解。","pt_BR":"DNA: desoxirribose (sem 2'-OH), bases A/T/G/C, dupla fita, estável. RNA: ribose (2'-OH torna-o menos estável), bases A/U/G/C, tipicamente fita simples. O 2'-OH torna o RNA suscetível à hidrólise em condições alcalinas.","pt_PT":"DNA: desoxirribose (sem 2'-OH), bases A/T/G/C, cadeia dupla, estável. RNA: ribose (2'-OH torna-o menos estável), bases A/U/G/C, tipicamente cadeia simples. O 2'-OH torna o RNA suscetível à hidrólise em condições alcalinas."}},
  { id: 'dc-mcat-0061', deck_id: 'deck-mcat', sort_order: 61, front: "Aldol Condensation", back: "An enolizable carbonyl compound acts as a nucleophile (as its enolate) attacking another carbonyl compound, forming a β-hydroxy carbonyl (aldol addition), which can dehydrate to form an α,β-unsaturated carbonyl (aldol condensation)." , front_translations: {"es":"Condensación Aldólica","de":"Aldolkondensation","fr":"Condensation aldolique","tr":"Aldol Kondensasyonu","nl":"Aldolcondensatie","ru":"Альдольная конденсация","zh":"羟醛缩合反应","pt_BR":"Condensação Aldólica","pt_PT":"Condensação Aldólica"}, back_translations: {"es":"Un compuesto carbonílico enolizable actúa como nucleófilo (como su enolato) atacando outro compuesto carbonílico, formando un β-hidróxi carbonil (adición aldólica), que puede desidratar para formar un carbonil α,β-insaturado (condensación aldólica).","de":"Eine enolisierbare Carbonylverbindung wirkt als Nukleophil (als Enolat) und greift eine andere Carbonylverbindung an, wobei ein β-Hydroxycarbonyl entsteht (Aldoladdition), das zu einem α,β-ungesättigten Carbonyl dehydratisieren kann (Aldolkondensation).","fr":"Un composé carbonylé énolisable agit comme nucléophile (sous forme d'énolate) attaquant un autre composé carbonylé, formant un β-hydroxycarbonyle (addition aldolique), qui peut se déshydrater pour former un carbonyle α,β-insaturé (condensation aldolique).","tr":"Enolize olabilen bir karbonil bileşiği, nükleofil olarak (enolat formunda) başka bir karbonil bileşiğine saldırarak bir β-hidroksi karbonil oluşturur (aldol katılması), bu da dehidratasyonla α,β-doymamış karbonil verebilir (aldol kondensasyonu).","nl":"Een enoliseerbare carbonylverbinding treedt op als nucleofiel (als enolaat) en valt een andere carbonylverbinding aan, waarbij een β-hydroxycarbonyl wordt gevormd (aldoltoevoeging), dat kan dehydrateren tot een α,β-onverzadigd carbonyl (aldolcondensatie).","ru":"Енолизуемое карбонильное соединение выступает как нуклеофил (в форме енолята), атакуя другое карбонильное соединение, образуя β-гидроксикарбонильное соединение (альдольное присоединение), которое может дегидратироваться с образованием α,β-ненасыщенного карбонильного соединения (альдольная конденсация).","zh":"可烯醇化的羰基化合物作为亲核试剂（以烯醇盐形式）进攻另一个羰基化合物，形成β-羟基羰基化合物（羟醛加成），可脱水形成α,β-不饱和羰基化合物（羟醛缩合）。","pt_BR":"Um composto carbonílico enolizável atua como nucleófilo (como seu enolato) atacando outro composto carbonílico, formando um β-hidróxi carbonil (adição aldólica), que pode desidratar para formar um carbonil α,β-insaturado (condensação aldólica).","pt_PT":"Um composto carbonílico enolizável atua como nucleófilo (como o seu enolato) atacando outro composto carbonílico, formando um β-hidróxi carbonilo (adição aldólica), que pode desidratar para formar um carbonilo α,β-insaturado (condensação aldólica)."}},
  { id: 'dc-mcat-0062', deck_id: 'deck-mcat', sort_order: 62, front: "Nucleophilic Acyl Substitution", back: "Carboxylic acid derivatives (acyl chlorides > anhydrides > esters > amides, in decreasing reactivity) undergo substitution at the carbonyl carbon: nucleophile adds → tetrahedral intermediate → leaving group departs." , front_translations: {"es":"Substituición Acílica Nucleofílica","de":"Nukleophile Acylsubstitution","fr":"Substitution acyle nucléophile","tr":"Nükleofilik Açil Sübstitüsyonu","nl":"Nucleofiele acylsubstitutie","ru":"Нуклеофильное ацильное замещение","zh":"亲核酰基取代","pt_BR":"Substituição Acílica Nucleofílica","pt_PT":"Substituição Acílica Nucleofílica"}, back_translations: {"es":"Derivados de ácidos carboxílicos (cloretos de acila > anidridos > ésteres > amidas, en reatividad decrescente) sofrem substituición en el carbono carbonílico: nucleófilo se adiciona → intermediário tetraédrico → grupo de saída parte.","de":"Carbonsäurederivate (Acylchloride > Anhydride > Ester > Amide, in abnehmender Reaktivität) unterliegen Substitution am Carbonylkohlenstoff: Nukleophil addiert → tetraedrisches Intermediat → Abgangsgruppe verlässt.","fr":"Les dérivés d'acides carboxyliques (chlorures d'acyle > anhydrides > esters > amides, par réactivité décroissante) subissent une substitution au carbone carbonyle : le nucléophile s'additionne → intermédiaire tétraédrique → départ du groupe partant.","tr":"Karboksilik asit türevleri (açil klorürler > anhidritler > esterler > amitler, azalan reaktivite sırasıyla) karbonil karbonunda sübstitüsyona uğrar: nükleofil eklenir → tetraedral ara ürün → ayrılan grup ayrılır.","nl":"Carbonzuurderivaten (acylchloriden > anhydriden > esters > amiden, in afnemende reactiviteit) ondergaan substitutie aan het carbonylkoolstof: nucleofiel voegt toe → tetraëdrisch intermediair → vertrekkende groep vertrekt.","ru":"Производные карбоновых кислот (ацилхлориды > ангидриды > сложные эфиры > амиды, в порядке убывания реакционной способности) подвергаются замещению у карбонильного углерода: нуклеофил присоединяется → тетраэдрический интермедиат → уходящая группа уходит.","zh":"羧酸衍生物（酰氯 > 酸酐 > 酯 > 酰胺，反应活性递减）在羰基碳上发生取代反应：亲核试剂加成→四面体中间体→离去基团离去。","pt_BR":"Derivados de ácidos carboxílicos (cloretos de acila > anidridos > ésteres > amidas, em reatividade decrescente) sofrem substituição no carbono carbonílico: nucleófilo se adiciona → intermediário tetraédrico → grupo de saída parte.","pt_PT":"Derivados de ácidos carboxílicos (cloretos de acilo > anidridos > ésteres > amidas, em reatividade decrescente) sofrem substituição no carbono carbonílico: nucleófilo adiciona-se → intermediário tetraédrico → grupo de saída parte."}},
  { id: 'dc-mcat-0063', deck_id: 'deck-mcat', sort_order: 63, front: "Aromatic Electrophilic Substitution (EAS)", back: "Benzene rings react with electrophiles (E⁺), not in addition (which would destroy aromaticity), but in substitution. Activating groups (OH, NH₂, alkyl) direct ortho/para; deactivating groups (NO₂, CN, COOH) direct meta." , front_translations: {"es":"Substituición Eletrofílica Aromática (EAS)","de":"Aromatische elektrophile Substitution (EAS)","fr":"Substitution électrophile aromatique (EAS)","tr":"Aromatik Elektrofilik Sübstitüsyon (EAS)","nl":"Aromatische elektrofiele substitutie (EAS)","ru":"Электрофильное ароматическое замещение (EAS)","zh":"芳香族亲电取代反应（EAS）","pt_BR":"Substituição Eletrofílica Aromática (EAS)","pt_PT":"Substituição Eletrofílica Aromática (EAS)"}, back_translations: {"es":"Anéis de benzeno reaje con eletrófilos (Y⁺), no en adición (que destruiria a aromaticidad), pero en substituición. Grupos ativadores (OH, NH₂, alquil) direcionam orto/para; grupos desativadores (NO₂, CN, COOH) direcionam meta.","de":"Benzolringe reagieren mit Elektrophilen (E⁺), nicht in Addition (die die Aromatizität zerstören würde), sondern in Substitution. Aktivierende Gruppen (OH, NH₂, Alkyl) dirigieren ortho/para; desaktivierende Gruppen (NO₂, CN, COOH) dirigieren meta.","fr":"Les cycles benzéniques réagissent avec les électrophiles (E⁺), non par addition (qui détruirait l'aromaticité), mais par substitution. Les groupes activants (OH, NH₂, alkyle) orientent en ortho/para ; les groupes désactivants (NO₂, CN, COOH) orientent en méta.","tr":"Benzen halkaları elektrofillerle (E⁺) reaksiyona girer; katılma yoluyla değil (aromatikliği bozar), sübstitüsyon yoluyla. Aktive edici gruplar (OH, NH₂, alkil) orto/para yönlendirir; deaktive edici gruplar (NO₂, CN, COOH) meta yönlendirir.","nl":"Benzeenringen reageren met elektrofielen (E⁺), niet via additie (wat de aromaticiteit zou vernietigen), maar via substitutie. Activerende groepen (OH, NH₂, alkyl) richten ortho/para; deactiverende groepen (NO₂, CN, COOH) richten meta.","ru":"Бензольные кольца реагируют с электрофилами (E⁺) не присоединением (что разрушило бы ароматичность), а замещением. Активирующие группы (OH, NH₂, алкил) направляют в орто/пара-положения; дезактивирующие группы (NO₂, CN, COOH) направляют в мета-положение.","zh":"苯环与亲电试剂（E⁺）反应，不是加成（会破坏芳香性），而是取代。活化基团（OH、NH₂、烷基）定位于邻/对位；钝化基团（NO₂、CN、COOH）定位于间位。","pt_BR":"Anéis de benzeno reagem com eletrófilos (E⁺), não em adição (que destruiria a aromaticidade), mas em substituição. Grupos ativadores (OH, NH₂, alquil) direcionam orto/para; grupos desativadores (NO₂, CN, COOH) direcionam meta.","pt_PT":"Anéis de benzeno reagem com eletrófilos (E⁺), não em adição (que destruiria a aromaticidade), mas em substituição. Grupos ativadores (OH, NH₂, alquilo) direcionam orto/para; grupos desativadores (NO₂, CN, COOH) direcionam meta."}},
  { id: 'dc-mcat-0064', deck_id: 'deck-mcat', sort_order: 64, front: "Oxidation and Reduction of Organic Compounds", back: "Oxidation: addition of O or loss of H (increases carbon oxidation state). Reduction: loss of O or addition of H. Alcohol → aldehyde/ketone → carboxylic acid (progressive oxidation). Common oxidizers: KMnO₄, CrO₃, PCC (mild, stops at aldehyde)." , front_translations: {"es":"Oxidación y Redución de Compostos Organicos","de":"Oxidation und Reduktion organischer Verbindungen","fr":"Oxydation et réduction des composés organiques","tr":"Organik Bileşiklerin Oksidasyonu ve Redüksiyonu","nl":"Oxidatie en reductie van organische verbindingen","ru":"Окисление и восстановление органических соединений","zh":"有机化合物的氧化与还原","pt_BR":"Oxidação e Redução de Compostos Orgânicos","pt_PT":"Oxidação e Redução de Compostos Orgânicos"}, back_translations: {"es":"Oxidación: adición de El o perda de H (aumenta el estado de oxidación del carbono). Redución: perda de El o adición de H. Álcool → aldeído/cetona → ácido carboxílico (oxidación progressiva). Oxidantes comuns: KMnO₄, CrO₃, PCC (suave, para en el aldeído).","de":"Oxidation: Zugabe von O oder Verlust von H (erhöht die Kohlenstoff-Oxidationsstufe). Reduktion: Verlust von O oder Zugabe von H. Alkohol → Aldehyd/Keton → Carbonsäure (fortschreitende Oxidation). Häufige Oxidationsmittel: KMnO₄, CrO₃, PCC (mild, stoppt beim Aldehyd).","fr":"Oxydation : ajout de O ou perte de H (augmente le degré d'oxydation du carbone). Réduction : perte de O ou ajout de H. Alcool → aldéhyde/cétone → acide carboxylique (oxydation progressive). Oxydants courants : KMnO₄, CrO₃, PCC (doux, s'arrête à l'aldéhyde).","tr":"Oksidasyon: O eklenmesi veya H kaybı (karbon oksidasyon durumunu artırır). Redüksiyon: O kaybı veya H eklenmesi. Alkol → aldehit/keton → karboksilik asit (aşamalı oksidasyon). Yaygın oksitleyiciler: KMnO₄, CrO₃, PCC (hafif, aldehitte durur).","nl":"Oxidatie: toevoeging van O of verlies van H (verhoogt de oxidatietoestand van koolstof). Reductie: verlies van O of toevoeging van H. Alcohol → aldehyde/keton → carbonzuur (progressieve oxidatie). Veelgebruikte oxidatiemiddelen: KMnO₄, CrO₃, PCC (mild, stopt bij aldehyde).","ru":"Окисление: добавление O или потеря H (повышает степень окисления углерода). Восстановление: потеря O или добавление H. Спирт → альдегид/кетон → карбоновая кислота (последовательное окисление). Распространённые окислители: KMnO₄, CrO₃, PCC (мягкий, останавливается на альдегиде).","zh":"氧化：加O或失H（碳氧化态升高）。还原：失O或加H。醇→醛/酮→羧酸（逐步氧化）。常见氧化剂：KMnO₄、CrO₃、PCC（温和，停留在醛阶段）。","pt_BR":"Oxidação: adição de O ou perda de H (aumenta o estado de oxidação do carbono). Redução: perda de O ou adição de H. Álcool → aldeído/cetona → ácido carboxílico (oxidação progressiva). Oxidantes comuns: KMnO₄, CrO₃, PCC (suave, para no aldeído).","pt_PT":"Oxidação: adição de O ou perda de H (aumenta o estado de oxidação do carbono). Redução: perda de O ou adição de H. Álcool → aldeído/cetona → ácido carboxílico (oxidação progressiva). Oxidantes comuns: KMnO₄, CrO₃, PCC (suave, para no aldeído)."}},
  { id: 'dc-mcat-0065', deck_id: 'deck-mcat', sort_order: 65, front: "IR Spectroscopy Key Absorptions", back: "O–H stretch: broad 2500–3300 cm⁻¹ (carboxylic acid) or 3200–3550 cm⁻¹ (alcohol). N–H stretch: 3300–3500 cm⁻¹. C=O stretch (carbonyl): 1630–1850 cm⁻¹. C=C stretch: 1620–1680 cm⁻¹. C–H stretch: ~3000 cm⁻¹." , front_translations: {"es":"Espectroscopia IV: Absorciones Principais","de":"IR-Spektroskopie: Wichtige Absorptionen","fr":"Spectroscopie IR : Absorptions clés","tr":"IR Spektroskopisi: Temel Absorpsiyonlar","nl":"IR-spectroscopie: Belangrijke absorpties","ru":"ИК-спектроскопия: Ключевые полосы поглощения","zh":"红外光谱：关键吸收峰","pt_BR":"Espectroscopia IV: Absorções Principais","pt_PT":"Espectroscopia IV: Absorções Principais"}, back_translations: {"es":"Estiramento El–H: ancho 2500–3300 cm⁻¹ (ácido carboxílico) o 3200–3550 cm⁻¹ (álcool). Estiramento N–H: 3300–3500 cm⁻¹. Estiramento C=El (carbonila): 1630–1850 cm⁻¹. Estiramento C=C: 1620–1680 cm⁻¹. Estiramento C–H: ~3000 cm⁻¹.","de":"O–H-Streckschwingung: breit 2500–3300 cm⁻¹ (Carbonsäure) oder 3200–3550 cm⁻¹ (Alkohol). N–H-Streckschwingung: 3300–3500 cm⁻¹. C=O-Streckschwingung (Carbonyl): 1630–1850 cm⁻¹. C=C-Streckschwingung: 1620–1680 cm⁻¹. C–H-Streckschwingung: ~3000 cm⁻¹.","fr":"Élongation O–H : large 2500–3300 cm⁻¹ (acide carboxylique) ou 3200–3550 cm⁻¹ (alcool). Élongation N–H : 3300–3500 cm⁻¹. Élongation C=O (carbonyle) : 1630–1850 cm⁻¹. Élongation C=C : 1620–1680 cm⁻¹. Élongation C–H : ~3000 cm⁻¹.","tr":"O–H gerilme: geniş 2500–3300 cm⁻¹ (karboksilik asit) veya 3200–3550 cm⁻¹ (alkol). N–H gerilme: 3300–3500 cm⁻¹. C=O gerilme (karbonil): 1630–1850 cm⁻¹. C=C gerilme: 1620–1680 cm⁻¹. C–H gerilme: ~3000 cm⁻¹.","nl":"O–H-strekvibratie: breed 2500–3300 cm⁻¹ (carbonzuur) of 3200–3550 cm⁻¹ (alcohol). N–H-strekvibratie: 3300–3500 cm⁻¹. C=O-strekvibratie (carbonyl): 1630–1850 cm⁻¹. C=C-strekvibratie: 1620–1680 cm⁻¹. C–H-strekvibratie: ~3000 cm⁻¹.","ru":"Валентные колебания O–H: широкая полоса 2500–3300 см⁻¹ (карбоновая кислота) или 3200–3550 см⁻¹ (спирт). Валентные колебания N–H: 3300–3500 см⁻¹. Валентные колебания C=O (карбонил): 1630–1850 см⁻¹. Валентные колебания C=C: 1620–1680 см⁻¹. Валентные колебания C–H: ~3000 см⁻¹.","zh":"O–H伸缩振动：宽峰2500–3300 cm⁻¹（羧酸）或3200–3550 cm⁻¹（醇）。N–H伸缩振动：3300–3500 cm⁻¹。C=O伸缩振动（羰基）：1630–1850 cm⁻¹。C=C伸缩振动：1620–1680 cm⁻¹。C–H伸缩振动：~3000 cm⁻¹。","pt_BR":"Estiramento O–H: largo 2500–3300 cm⁻¹ (ácido carboxílico) ou 3200–3550 cm⁻¹ (álcool). Estiramento N–H: 3300–3500 cm⁻¹. Estiramento C=O (carbonila): 1630–1850 cm⁻¹. Estiramento C=C: 1620–1680 cm⁻¹. Estiramento C–H: ~3000 cm⁻¹.","pt_PT":"Estiramento O–H: largo 2500–3300 cm⁻¹ (ácido carboxílico) ou 3200–3550 cm⁻¹ (álcool). Estiramento N–H: 3300–3500 cm⁻¹. Estiramento C=O (carbonilo): 1630–1850 cm⁻¹. Estiramento C=C: 1620–1680 cm⁻¹. Estiramento C–H: ~3000 cm⁻¹."}},
  // --- Physics ---
  { id: 'dc-mcat-0066', deck_id: 'deck-mcat', sort_order: 66, front: "Ohm's Law and Circuits (MCAT)", back: "V = IR. Series: same current, voltages add (R_total = ΣR). Parallel: same voltage, currents add (1/R_total = Σ1/R). Power: P = IV = I²R = V²/R. Capacitors: opposite of resistors in series/parallel." , front_translations: {"es":"Ley de Ohm y Circuitos (MCAT)","de":"Ohmsches Gesetz und Schaltkreise (MCAT)","fr":"Loi d'Ohm et circuits (MCAT)","tr":"Ohm Yasası ve Devreler (MCAT)","nl":"Wet van Ohm en schakelingen (MCAT)","ru":"Закон Ома и электрические цепи (MCAT)","zh":"欧姆定律与电路（MCAT）","pt_BR":"Lei de Ohm e Circuitos (MCAT)","pt_PT":"Lei de Ohm e Circuitos (MCAT)"}, back_translations: {"es":"V = IR. Série: misma corrente, tensões somam (R_total = ΣR). Paralelo: misma tensão, correntes somam (1/R_total = Σ1/R). Potencia: P = IV = I²R = V²/R. Capacitores: oposto de los resistores en série/paralelo.","de":"V = IR. Reihenschaltung: gleicher Strom, Spannungen addieren sich (R_total = ΣR). Parallelschaltung: gleiche Spannung, Ströme addieren sich (1/R_total = Σ1/R). Leistung: P = IV = I²R = V²/R. Kondensatoren: entgegengesetzt zu Widerständen in Reihen-/Parallelschaltung.","fr":"V = IR. Série : même courant, les tensions s'additionnent (R_total = ΣR). Parallèle : même tension, les courants s'additionnent (1/R_total = Σ1/R). Puissance : P = IV = I²R = V²/R. Condensateurs : opposé des résistances en série/parallèle.","tr":"V = IR. Seri: aynı akım, gerilimler toplanır (R_total = ΣR). Paralel: aynı gerilim, akımlar toplanır (1/R_total = Σ1/R). Güç: P = IV = I²R = V²/R. Kapasitörler: seri/paralelde dirençlerin tersi.","nl":"V = IR. Serie: dezelfde stroom, spanningen tellen op (R_totaal = ΣR). Parallel: dezelfde spanning, stromen tellen op (1/R_totaal = Σ1/R). Vermogen: P = IV = I²R = V²/R. Condensatoren: tegengesteld aan weerstanden in serie/parallel.","ru":"V = IR. Последовательно: одинаковый ток, напряжения складываются (R_total = ΣR). Параллельно: одинаковое напряжение, токи складываются (1/R_total = Σ1/R). Мощность: P = IV = I²R = V²/R. Конденсаторы: противоположны резисторам при последовательном/параллельном соединении.","zh":"V = IR。串联：电流相同，电压相加（R_total = ΣR）。并联：电压相同，电流相加（1/R_total = Σ1/R）。功率：P = IV = I²R = V²/R。电容器：在串联/并联中与电阻相反。","pt_BR":"V = IR. Série: mesma corrente, tensões somam (R_total = ΣR). Paralelo: mesma tensão, correntes somam (1/R_total = Σ1/R). Potência: P = IV = I²R = V²/R. Capacitores: oposto dos resistores em série/paralelo.","pt_PT":"V = IR. Série: mesma corrente, tensões somam (R_total = ΣR). Paralelo: mesma tensão, correntes somam (1/R_total = Σ1/R). Potência: P = IV = I²R = V²/R. Condensadores: oposto dos resistores em série/paralelo."}},
  { id: 'dc-mcat-0067', deck_id: 'deck-mcat', sort_order: 67, front: "Fluids: Pressure and Buoyancy", back: "P = ρgh (hydrostatic pressure). Buoyant force F_b = ρ_fluid·V_submerged·g (Archimedes). An object floats if ρ_object < ρ_fluid. Clinical relevance: lung buoyancy, IV fluid pressure, cerebrospinal fluid." , front_translations: {"es":"Fluidos: Presión y Empuxo","de":"Fluide: Druck und Auftrieb","fr":"Fluides : Pression et poussée d'Archimède","tr":"Akışkanlar: Basınç ve Kaldırma Kuvveti","nl":"Vloeistoffen: Druk en opwaartse kracht","ru":"Жидкости: Давление и выталкивающая сила","zh":"流体：压强与浮力","pt_BR":"Fluidos: Pressão e Empuxo","pt_PT":"Fluidos: Pressão e Impulsão"}, back_translations: {"es":"P = ρgh (presión hidrostática). Força de empuxo F_b = ρ_fluido·V_submerso·g (Arquimedes). Un objeto flutua se ρ_objeto < ρ_fluido. Relevancia clínica: flutuabilidad pulmonar, presión de fluidos IV, líquido cefalorraquidiano.","de":"P = ρgh (hydrostatischer Druck). Auftriebskraft F_b = ρ_Fluid·V_eingetaucht·g (Archimedes). Ein Objekt schwimmt, wenn ρ_Objekt < ρ_Fluid. Klinische Relevanz: Lungenauftrieb, IV-Flüssigkeitsdruck, Liquor cerebrospinalis.","fr":"P = ρgh (pression hydrostatique). Force de flottabilité F_b = ρ_fluide·V_immergé·g (Archimède). Un objet flotte si ρ_objet < ρ_fluide. Pertinence clinique : flottabilité pulmonaire, pression des fluides IV, liquide céphalorachidien.","tr":"P = ρgh (hidrostatik basınç). Kaldırma kuvveti F_b = ρ_akışkan·V_batık·g (Arşimet). Bir cisim ρ_cisim < ρ_akışkan ise yüzer. Klinik ilgi: akciğer kaldırma kuvveti, IV sıvı basıncı, beyin omurilik sıvısı.","nl":"P = ρgh (hydrostatische druk). Opwaartse kracht F_b = ρ_vloeistof·V_ondergedompeld·g (Archimedes). Een object drijft als ρ_object < ρ_vloeistof. Klinische relevantie: longdrijfvermogen, IV-vloeistofdruk, cerebrospinale vloeistof.","ru":"P = ρgh (гидростатическое давление). Выталкивающая сила F_b = ρ_жидкости·V_погружённого·g (Архимед). Объект плавает, если ρ_объекта < ρ_жидкости. Клиническое значение: плавучесть лёгких, давление внутривенных жидкостей, спинномозговая жидкость.","zh":"P = ρgh（静水压强）。浮力 F_b = ρ_流体·V_浸没·g（阿基米德）。物体密度 ρ_物体 < ρ_流体 时漂浮。临床相关性：肺浮力、静脉输液压力、脑脊液。","pt_BR":"P = ρgh (pressão hidrostática). Força de empuxo F_b = ρ_fluido·V_submerso·g (Arquimedes). Um objeto flutua se ρ_objeto < ρ_fluido. Relevância clínica: flutuabilidade pulmonar, pressão de fluidos IV, líquido cefalorraquidiano.","pt_PT":"P = ρgh (pressão hidrostática). Força de impulsão F_b = ρ_fluido·V_submerso·g (Arquimedes). Um objeto flutua se ρ_objeto < ρ_fluido. Relevância clínica: flutuabilidade pulmonar, pressão de fluidos IV, líquido cefalorraquidiano."}},
  { id: 'dc-mcat-0068', deck_id: 'deck-mcat', sort_order: 68, front: "Bernoulli's Principle and Poiseuille's Law", back: "Bernoulli: P + ½ρv² + ρgh = constant (flow speed and pressure inversely related). Poiseuille: Q = πr⁴ΔP/(8ηL). Flow is proportional to r⁴ — doubling radius increases flow 16-fold. Relevant to vascular resistance." , front_translations: {"es":"Princípio de Bernoulli y Ley de Poiseuille","de":"Bernoulli-Prinzip und Poiseuille-Gesetz","fr":"Principe de Bernoulli et loi de Poiseuille","tr":"Bernoulli Prensibi ve Poiseuille Yasası","nl":"Principe van Bernoulli en wet van Poiseuille","ru":"Принцип Бернулли и закон Пуазейля","zh":"伯努利原理与泊肃叶定律","pt_BR":"Princípio de Bernoulli e Lei de Poiseuille","pt_PT":"Princípio de Bernoulli e Lei de Poiseuille"}, back_translations: {"es":"Bernoulli: P + ½ρv² + ρgh = constante (velocidad de flujo y presión inversamente relacionadas). Poiseuille: Q = πr⁴ΔP/(8ηL). El flujo es proporcional a r⁴ — dobrar el raio aumenta el flujo 16 veces. Relevante para a resistencia vascular.","de":"Bernoulli: P + ½ρv² + ρgh = Konstante (Strömungsgeschwindigkeit und Druck umgekehrt proportional). Poiseuille: Q = πr⁴ΔP/(8ηL). Durchfluss ist proportional zu r⁴ — Verdopplung des Radius erhöht den Durchfluss um das 16-fache. Relevant für den Gefäßwiderstand.","fr":"Bernoulli : P + ½ρv² + ρgh = constante (vitesse d'écoulement et pression inversement liées). Poiseuille : Q = πr⁴ΔP/(8ηL). Le débit est proportionnel à r⁴ — doubler le rayon augmente le débit de 16 fois. Pertinent pour la résistance vasculaire.","tr":"Bernoulli: P + ½ρv² + ρgh = sabit (akış hızı ve basınç ters orantılı). Poiseuille: Q = πr⁴ΔP/(8ηL). Akış r⁴ ile orantılıdır — yarıçapı ikiye katlamak akışı 16 kat artırır. Vasküler direnç ile ilgili.","nl":"Bernoulli: P + ½ρv² + ρgh = constante (stroomsnelheid en druk omgekeerd evenredig). Poiseuille: Q = πr⁴ΔP/(8ηL). Debiet is evenredig met r⁴ — verdubbeling van de straal verhoogt het debiet 16-voudig. Relevant voor vasculaire weerstand.","ru":"Бернулли: P + ½ρv² + ρgh = const (скорость потока и давление обратно пропорциональны). Пуазейль: Q = πr⁴ΔP/(8ηL). Расход пропорционален r⁴ — удвоение радиуса увеличивает расход в 16 раз. Релевантно для сосудистого сопротивления.","zh":"伯努利：P + ½ρv² + ρgh = 常数（流速与压强成反比）。泊肃叶：Q = πr⁴ΔP/(8ηL)。流量与r⁴成正比——半径加倍，流量增加16倍。与血管阻力相关。","pt_BR":"Bernoulli: P + ½ρv² + ρgh = constante (velocidade de fluxo e pressão inversamente relacionadas). Poiseuille: Q = πr⁴ΔP/(8ηL). O fluxo é proporcional a r⁴ — dobrar o raio aumenta o fluxo 16 vezes. Relevante para a resistência vascular.","pt_PT":"Bernoulli: P + ½ρv² + ρgh = constante (velocidade de fluxo e pressão inversamente relacionadas). Poiseuille: Q = πr⁴ΔP/(8ηL). O fluxo é proporcional a r⁴ — duplicar o raio aumenta o fluxo 16 vezes. Relevante para a resistência vascular."}},
  { id: 'dc-mcat-0069', deck_id: 'deck-mcat', sort_order: 69, front: "Optics: Lenses and Mirrors", back: "Thin lens equation: 1/f = 1/do + 1/di. Convex lens (converging): f > 0. Concave lens (diverging): f < 0. Magnification: m = -di/do. Real images: di > 0 (opposite side of lens); virtual images: di < 0 (same side as object)." , front_translations: {"es":"Óptica: Lentes y Espelhos","de":"Optik: Linsen und Spiegel","fr":"Optique : Lentilles et miroirs","tr":"Optik: Mercekler ve Aynalar","nl":"Optica: Lenzen en spiegels","ru":"Оптика: Линзы и зеркала","zh":"光学：透镜与反射镜","pt_BR":"Óptica: Lentes e Espelhos","pt_PT":"Óptica: Lentes e Espelhos"}, back_translations: {"es":"Equación de la lente delgada: 1/f = 1/del + 1/di. Lente convexa (convergente): f > 0. Lente concava (divergente): f < 0. Ampliación: m = -di/del. Imajes reais: di > 0 (lado oposto de la lente); imajes virtuais: di < 0 (mismo lado del objeto).","de":"Dünne-Linsen-Gleichung: 1/f = 1/do + 1/di. Konvexlinse (sammelnd): f > 0. Konkavlinse (zerstreuend): f < 0. Vergrößerung: m = -di/do. Reelle Bilder: di > 0 (gegenüberliegende Seite der Linse); virtuelle Bilder: di < 0 (gleiche Seite wie Objekt).","fr":"Équation des lentilles minces : 1/f = 1/do + 1/di. Lentille convexe (convergente) : f > 0. Lentille concave (divergente) : f < 0. Grossissement : m = -di/do. Images réelles : di > 0 (côté opposé de la lentille) ; images virtuelles : di < 0 (même côté que l'objet).","tr":"İnce mercek denklemi: 1/f = 1/do + 1/di. Dışbükey mercek (yakınsak): f > 0. İçbükey mercek (ıraksak): f < 0. Büyütme: m = -di/do. Gerçek görüntüler: di > 0 (merceğin karşı tarafı); sanal görüntüler: di < 0 (cisimle aynı taraf).","nl":"Dunne-lensvergelijking: 1/f = 1/do + 1/di. Bolle lens (convergerend): f > 0. Holle lens (divergerend): f < 0. Vergroting: m = -di/do. Reële beelden: di > 0 (tegenovergestelde kant van lens); virtuele beelden: di < 0 (dezelfde kant als object).","ru":"Формула тонкой линзы: 1/f = 1/do + 1/di. Выпуклая линза (собирающая): f > 0. Вогнутая линза (рассеивающая): f < 0. Увеличение: m = -di/do. Действительные изображения: di > 0 (противоположная сторона линзы); мнимые изображения: di < 0 (та же сторона, что и объект).","zh":"薄透镜方程：1/f = 1/do + 1/di。凸透镜（汇聚）：f > 0。凹透镜（发散）：f < 0。放大率：m = -di/do。实像：di > 0（透镜另一侧）；虚像：di < 0（与物体同侧）。","pt_BR":"Equação da lente fina: 1/f = 1/do + 1/di. Lente convexa (convergente): f > 0. Lente côncava (divergente): f < 0. Ampliação: m = -di/do. Imagens reais: di > 0 (lado oposto da lente); imagens virtuais: di < 0 (mesmo lado do objeto).","pt_PT":"Equação da lente fina: 1/f = 1/do + 1/di. Lente convexa (convergente): f > 0. Lente côncava (divergente): f < 0. Ampliação: m = -di/do. Imagens reais: di > 0 (lado oposto da lente); imagens virtuais: di < 0 (mesmo lado do objeto)."}},
  { id: 'dc-mcat-0070', deck_id: 'deck-mcat', sort_order: 70, front: "Sound: Intensity and Decibels", back: "β = 10 log(I/I₀), I₀ = 10⁻¹² W/m². Every 10 dB increase = 10× intensity. Frequency of sound perceived as pitch. Speed of sound ≈ 343 m/s in air; much faster in liquids and solids. Ultrasound uses frequencies >20,000 Hz." , front_translations: {"es":"Som: Intensidad y Decibéis","de":"Schall: Intensität und Dezibel","fr":"Son : Intensité et décibels","tr":"Ses: Şiddet ve Desibel","nl":"Geluid: Intensiteit en decibel","ru":"Звук: Интенсивность и децибелы","zh":"声音：强度与分贝","pt_BR":"Som: Intensidade e Decibéis","pt_PT":"Som: Intensidade e Decibéis"}, back_translations: {"es":"β = 10 log(I/I₀), I₀ = 10⁻¹² W/m². Cada aumento de 10 dB = 10× a intensidad. La frecuencia del sonido es percebida como altura tonal. Velocidad del sonido ≈ 343 m/s en el aire; muy más rápida en líquidos y sólidos. El ultrassom usa frequencias >20.000 Hz.","de":"β = 10 log(I/I₀), I₀ = 10⁻¹² W/m². Jede 10-dB-Erhöhung = 10× Intensität. Schallfrequenz wird als Tonhöhe wahrgenommen. Schallgeschwindigkeit ≈ 343 m/s in Luft; viel schneller in Flüssigkeiten und Festkörpern. Ultraschall verwendet Frequenzen >20.000 Hz.","fr":"β = 10 log(I/I₀), I₀ = 10⁻¹² W/m². Chaque augmentation de 10 dB = 10× l'intensité. La fréquence du son est perçue comme la hauteur tonale. Vitesse du son ≈ 343 m/s dans l'air ; beaucoup plus rapide dans les liquides et solides. L'échographie utilise des fréquences >20 000 Hz.","tr":"β = 10 log(I/I₀), I₀ = 10⁻¹² W/m². Her 10 dB artış = 10× şiddet. Ses frekansı perde olarak algılanır. Ses hızı ≈ 343 m/s (havada); sıvı ve katılarda çok daha hızlı. Ultrason >20.000 Hz frekansları kullanır.","nl":"β = 10 log(I/I₀), I₀ = 10⁻¹² W/m². Elke 10 dB toename = 10× intensiteit. Frequentie van geluid wordt waargenomen als toonhoogte. Geluidssnelheid ≈ 343 m/s in lucht; veel sneller in vloeistoffen en vaste stoffen. Echografie gebruikt frequenties >20.000 Hz.","ru":"β = 10 log(I/I₀), I₀ = 10⁻¹² Вт/м². Каждое увеличение на 10 дБ = 10× интенсивность. Частота звука воспринимается как высота тона. Скорость звука ≈ 343 м/с в воздухе; намного быстрее в жидкостях и твёрдых телах. Ультразвук использует частоты >20 000 Гц.","zh":"β = 10 log(I/I₀)，I₀ = 10⁻¹² W/m²。每增加10 dB = 强度×10。声音频率被感知为音调。声速 ≈ 343 m/s（空气中）；在液体和固体中快得多。超声波使用频率 >20,000 Hz。","pt_BR":"β = 10 log(I/I₀), I₀ = 10⁻¹² W/m². Cada aumento de 10 dB = 10× a intensidade. A frequência do som é percebida como altura tonal. Velocidade do som ≈ 343 m/s no ar; muito mais rápida em líquidos e sólidos. O ultrassom usa frequências >20.000 Hz.","pt_PT":"β = 10 log(I/I₀), I₀ = 10⁻¹² W/m². Cada aumento de 10 dB = 10× a intensidade. A frequência do som é percecionada como altura tonal. Velocidade do som ≈ 343 m/s no ar; muito mais rápida em líquidos e sólidos. O ultrassom usa frequências >20 000 Hz."}},
  { id: 'dc-mcat-0071', deck_id: 'deck-mcat', sort_order: 71, front: "Electromagnetic Spectrum (MCAT)", back: "Radio → microwave → infrared → visible (ROYGBIV) → ultraviolet → X-ray → gamma. Higher frequency = higher energy = shorter wavelength. Gamma rays have highest energy (nuclear decay); UV causes DNA damage (thymine dimers)." , front_translations: {"es":"Espectro eletromagnético (MCAT)","de":"Elektromagnetisches Spektrum (MCAT)","fr":"Spectre électromagnétique (MCAT)","tr":"Elektromanyetik Spektrum (MCAT)","nl":"Elektromagnetisch spectrum (MCAT)","ru":"Электромагнитный спектр (MCAT)","zh":"电磁波谱 (MCAT)","pt_BR":"Espectro eletromagnético (MCAT)","pt_PT":"Espectro eletromagnético (MCAT)"}, back_translations: {"es":"Rádio → micro-ondas → infravermelho → visible (ROYGBIV) → ultravioleta → raios X → gama. Maior frecuencia = mayor energía = menor comprimento de onda. Raios gama tienen a mayor energía (decaimento nuclear); UV causa danos al DNA (dímeros de timina).","de":"Radio → Mikrowelle → Infrarot → sichtbar (ROYGBIV) → Ultraviolett → Röntgen → Gamma. Höhere Frequenz = höhere Energie = kürzere Wellenlänge. Gammastrahlen haben die höchste Energie (Kernzerfall); UV verursacht DNA-Schäden (Thymin-Dimere).","fr":"Radio → micro-ondes → infrarouge → visible (ROYGBIV) → ultraviolet → rayons X → gamma. Fréquence plus élevée = énergie plus élevée = longueur d'onde plus courte. Les rayons gamma ont l'énergie la plus élevée (désintégration nucléaire) ; les UV causent des dommages à l'ADN (dimères de thymine).","tr":"Radyo → mikrodalga → kızılötesi → görünür (ROYGBIV) → morötesi → X-ışını → gama. Daha yüksek frekans = daha yüksek enerji = daha kısa dalga boyu. Gama ışınları en yüksek enerjiye sahiptir (nükleer bozunma); UV, DNA hasarına neden olur (timin dimerleri).","nl":"Radio → magnetron → infrarood → zichtbaar (ROYGBIV) → ultraviolet → röntgen → gamma. Hogere frequentie = hogere energie = kortere golflengte. Gammastralen hebben de hoogste energie (kernverval); UV veroorzaakt DNA-schade (thyminedimeren).","ru":"Радио → микроволны → инфракрасное → видимое (ROYGBIV) → ультрафиолетовое → рентгеновское → гамма. Более высокая частота = более высокая энергия = более короткая длина волны. Гамма-лучи имеют наибольшую энергию (ядерный распад); УФ вызывает повреждение ДНК (тиминовые димеры).","zh":"无线电 → 微波 → 红外线 → 可见光 (ROYGBIV) → 紫外线 → X射线 → 伽马射线。频率越高 = 能量越高 = 波长越短。伽马射线能量最高（核衰变）；紫外线导致DNA损伤（胸腺嘧啶二聚体）。","pt_BR":"Rádio → micro-ondas → infravermelho → visível (ROYGBIV) → ultravioleta → raios X → gama. Maior frequência = maior energia = menor comprimento de onda. Raios gama têm a maior energia (decaimento nuclear); UV causa danos ao DNA (dímeros de timina).","pt_PT":"Rádio → micro-ondas → infravermelho → visível (ROYGBIV) → ultravioleta → raios X → gama. Maior frequência = maior energia = menor comprimento de onda. Raios gama têm a maior energia (decaimento nuclear); UV causa danos no DNA (dímeros de timina)."}},
  { id: 'dc-mcat-0072', deck_id: 'deck-mcat', sort_order: 72, front: "Photoelectric Effect (MCAT)", back: "Electrons ejected from a metal when light of sufficient frequency (not intensity) strikes it. E_k = hf - φ. If hf < φ (work function), no electrons are ejected regardless of intensity. Demonstrates photon nature of light." , front_translations: {"es":"Efeito fotoelétrico (MCAT)","de":"Photoelektrischer Effekt (MCAT)","fr":"Effet photoélectrique (MCAT)","tr":"Fotoelektrik Etki (MCAT)","nl":"Foto-elektrisch effect (MCAT)","ru":"Фотоэлектрический эффект (MCAT)","zh":"光电效应 (MCAT)","pt_BR":"Efeito fotoelétrico (MCAT)","pt_PT":"Efeito fotoelétrico (MCAT)"}, back_translations: {"es":"Elétrons son ejetados de un metal cuando luz de frecuencia suficiente (no intensidad) el alcanza. Y_k = hf - φ. Se hf < φ (función trabajo), ningún electrón es ejetado independentemente de la intensidad. Demonstra a natureza fotonica de la luz.","de":"Elektronen werden aus einem Metall herausgeschlagen, wenn Licht mit ausreichender Frequenz (nicht Intensität) darauf trifft. E_k = hf - φ. Wenn hf < φ (Austrittsarbeit), werden unabhängig von der Intensität keine Elektronen herausgelöst. Demonstriert die Photonennatur des Lichts.","fr":"Des électrons sont éjectés d'un métal lorsqu'une lumière de fréquence suffisante (pas d'intensité) le frappe. E_k = hf - φ. Si hf < φ (travail de sortie), aucun électron n'est éjecté quelle que soit l'intensité. Démontre la nature photonique de la lumière.","tr":"Yeterli frekansta (yoğunlukta değil) ışık bir metale çarptığında elektronlar yüzeyden fırlatılır. E_k = hf - φ. Eğer hf < φ (iş fonksiyonu) ise, yoğunluktan bağımsız olarak hiçbir elektron fırlatılmaz. Işığın foton doğasını gösterir.","nl":"Elektronen worden uit een metaal geslagen wanneer licht met voldoende frequentie (niet intensiteit) erop valt. E_k = hf - φ. Als hf < φ (werkfunctie), worden er geen elektronen uitgestoten, ongeacht de intensiteit. Toont de fotonaard van licht aan.","ru":"Электроны выбиваются из металла, когда свет достаточной частоты (не интенсивности) падает на него. E_k = hf - φ. Если hf < φ (работа выхода), электроны не выбиваются независимо от интенсивности. Демонстрирует фотонную природу света.","zh":"当足够频率（而非强度）的光照射金属时，电子从金属中被弹出。E_k = hf - φ。如果 hf < φ（功函数），无论强度如何都不会弹出电子。证明了光的光子本质。","pt_BR":"Elétrons são ejetados de um metal quando luz de frequência suficiente (não intensidade) o atinge. E_k = hf - φ. Se hf < φ (função trabalho), nenhum elétron é ejetado independentemente da intensidade. Demonstra a natureza fotônica da luz.","pt_PT":"Eletrões são ejetados de um metal quando luz de frequência suficiente (não intensidade) o atinge. E_k = hf - φ. Se hf < φ (função trabalho), nenhum eletrão é ejetado independentemente da intensidade. Demonstra a natureza fotónica da luz."}},
  { id: 'dc-mcat-0073', deck_id: 'deck-mcat', sort_order: 73, front: "Nuclear Reactions: Alpha, Beta, Gamma", back: "Alpha (α) decay: Z decreases by 2, A decreases by 4. Beta-minus (β⁻) decay: n → p, Z increases by 1, A unchanged; emits electron + antineutrino. Gamma (γ) decay: no change in Z or A; emits high-energy photon from excited nucleus." , front_translations: {"es":"Reaciones nucleares: Alfa, Beta, Gama","de":"Kernreaktionen: Alpha, Beta, Gamma","fr":"Réactions nucléaires : Alpha, Bêta, Gamma","tr":"Nükleer Reaksiyonlar: Alfa, Beta, Gama","nl":"Kernreacties: Alfa, Bèta, Gamma","ru":"Ядерные реакции: Альфа, Бета, Гамма","zh":"核反应：Alpha、Beta、Gamma","pt_BR":"Reações nucleares: Alfa, Beta, Gama","pt_PT":"Reações nucleares: Alfa, Beta, Gama"}, back_translations: {"es":"Decaimento alfa (α): Z disminuye en 2, La disminuye en 4. Decaimento beta-menos (β⁻): n → p, Z aumenta en 1, La inalterado; emite electrón + antineutrino. Decaimento gama (γ): sin alteración en Z o A; emite fóton de alta energía del núcleo excitado.","de":"Alpha (α)-Zerfall: Z nimmt um 2 ab, A nimmt um 4 ab. Beta-minus (β⁻)-Zerfall: n → p, Z nimmt um 1 zu, A unverändert; emittiert Elektron + Antineutrino. Gamma (γ)-Zerfall: keine Änderung von Z oder A; emittiert hochenergetisches Photon aus angeregtem Kern.","fr":"Désintégration alpha (α) : Z diminue de 2, A diminue de 4. Désintégration bêta-moins (β⁻) : n → p, Z augmente de 1, A inchangé ; émet un électron + antineutrino. Désintégration gamma (γ) : pas de changement de Z ou A ; émet un photon de haute énergie du noyau excité.","tr":"Alfa (α) bozunumu: Z 2 azalır, A 4 azalır. Beta-eksi (β⁻) bozunumu: n → p, Z 1 artar, A değişmez; elektron + antinötrino yayar. Gama (γ) bozunumu: Z veya A'da değişiklik yok; uyarılmış çekirdekten yüksek enerjili foton yayar.","nl":"Alfaverval (α): Z neemt af met 2, A neemt af met 4. Bèta-minusverval (β⁻): n → p, Z neemt toe met 1, A onveranderd; zendt elektron + antineutrino uit. Gammaverval (γ): geen verandering in Z of A; zendt hoogenergetisch foton uit vanuit aangeslagen kern.","ru":"Альфа (α)-распад: Z уменьшается на 2, A уменьшается на 4. Бета-минус (β⁻)-распад: n → p, Z увеличивается на 1, A не меняется; испускает электрон + антинейтрино. Гамма (γ)-распад: Z и A не меняются; испускает высокоэнергетический фотон из возбуждённого ядра.","zh":"Alpha (α) 衰变：Z减少2，A减少4。Beta-负 (β⁻) 衰变：n → p，Z增加1，A不变；释放电子 + 反中微子。Gamma (γ) 衰变：Z和A不变；从激发态原子核释放高能光子。","pt_BR":"Decaimento alfa (α): Z diminui em 2, A diminui em 4. Decaimento beta-menos (β⁻): n → p, Z aumenta em 1, A inalterado; emite elétron + antineutrino. Decaimento gama (γ): sem alteração em Z ou A; emite fóton de alta energia do núcleo excitado.","pt_PT":"Decaimento alfa (α): Z diminui em 2, A diminui em 4. Decaimento beta-menos (β⁻): n → p, Z aumenta em 1, A inalterado; emite eletrão + antineutrino. Decaimento gama (γ): sem alteração em Z ou A; emite fotão de alta energia do núcleo excitado."}},
  { id: 'dc-mcat-0074', deck_id: 'deck-mcat', sort_order: 74, front: "E = mc² and Mass Defect", back: "Nuclear binding energy = Δm × c². Mass defect is the difference between the mass of a nucleus and the sum of masses of its constituent nucleons. This lost mass is converted to binding energy. Iron-56 has the greatest binding energy per nucleon." , front_translations: {"es":"Y = mc² y defeito de masa","de":"E = mc² und Massendefekt","fr":"E = mc² et défaut de masse","tr":"E = mc² ve Kütle Açığı","nl":"E = mc² en massadefect","ru":"E = mc² и дефект массы","zh":"E = mc² 与质量亏损","pt_BR":"E = mc² e defeito de massa","pt_PT":"E = mc² e defeito de massa"}, back_translations: {"es":"Energia de enlace nuclear = Δm × c². El defeito de masa es a diferencia entre a masa de un núcleo y a suma de las massas de sus núcleons constituintes. Essa masa perdida es convertida en energía de enlace. El ferro-56 tiene a mayor energía de enlace por núcleon.","de":"Kernbindungsenergie = Δm × c². Der Massendefekt ist die Differenz zwischen der Masse eines Kerns und der Summe der Massen seiner Nukleonen. Diese verlorene Masse wird in Bindungsenergie umgewandelt. Eisen-56 hat die größte Bindungsenergie pro Nukleon.","fr":"Énergie de liaison nucléaire = Δm × c². Le défaut de masse est la différence entre la masse d'un noyau et la somme des masses de ses nucléons constitutifs. Cette masse perdue est convertie en énergie de liaison. Le fer-56 a la plus grande énergie de liaison par nucléon.","tr":"Nükleer bağlanma enerjisi = Δm × c². Kütle açığı, bir çekirdeğin kütlesi ile onu oluşturan nükleonların kütleleri toplamı arasındaki farktır. Bu kayıp kütle bağlanma enerjisine dönüştürülür. Demir-56 nükleon başına en büyük bağlanma enerjisine sahiptir.","nl":"Kernbindingsenergie = Δm × c². Het massadefect is het verschil tussen de massa van een kern en de som van de massa's van de samenstellende nucleonen. Deze verloren massa wordt omgezet in bindingsenergie. IJzer-56 heeft de grootste bindingsenergie per nucleon.","ru":"Энергия связи ядра = Δm × c². Дефект массы — это разница между массой ядра и суммой масс составляющих его нуклонов. Эта потерянная масса преобразуется в энергию связи. Железо-56 имеет наибольшую энергию связи на нуклон.","zh":"核结合能 = Δm × c²。质量亏损是原子核质量与其组成核子质量之和的差值。这部分失去的质量转化为结合能。铁-56具有最大的每核子结合能。","pt_BR":"Energia de ligação nuclear = Δm × c². O defeito de massa é a diferença entre a massa de um núcleo e a soma das massas de seus núcleons constituintes. Essa massa perdida é convertida em energia de ligação. O ferro-56 tem a maior energia de ligação por núcleon.","pt_PT":"Energia de ligação nuclear = Δm × c². O defeito de massa é a diferença entre a massa de um núcleo e a soma das massas dos seus nucleões constituintes. Essa massa perdida é convertida em energia de ligação. O ferro-56 tem a maior energia de ligação por nucleão."}},
  { id: 'dc-mcat-0075', deck_id: 'deck-mcat', sort_order: 75, front: "Work, Energy, and Power (MCAT)", back: "W = Fd·cosθ. KE = ½mv². PE = mgh. Conservation of energy: KE + PE = constant (no friction). Power P = W/t = Fv. The work-energy theorem: net work = ΔKE. On the MCAT, check for conservative vs. non-conservative forces." , front_translations: {"es":"Trabalho, energía y potencia (MCAT)","de":"Arbeit, Energie und Leistung (MCAT)","fr":"Travail, énergie et puissance (MCAT)","tr":"İş, Enerji ve Güç (MCAT)","nl":"Arbeid, energie en vermogen (MCAT)","ru":"Работа, энергия и мощность (MCAT)","zh":"功、能量和功率 (MCAT)","pt_BR":"Trabalho, energia e potência (MCAT)","pt_PT":"Trabalho, energia e potência (MCAT)"}, back_translations: {"es":"W = Fd·cosθ. KE = ½mv². PE = mgh. Conservación de energía: KE + PE = constante (sin atrito). Potencia P = W/t = Fv. Teorema trabajo-energía: trabajo líquido = ΔKE. No MCAT, verifique fuerzas conservativas vs. no conservativas.","de":"W = Fd·cosθ. KE = ½mv². PE = mgh. Energieerhaltung: KE + PE = konstant (ohne Reibung). Leistung P = W/t = Fv. Arbeit-Energie-Theorem: Nettoarbeit = ΔKE. Im MCAT auf konservative vs. nicht-konservative Kräfte achten.","fr":"W = Fd·cosθ. KE = ½mv². PE = mgh. Conservation de l'énergie : KE + PE = constante (sans frottement). Puissance P = W/t = Fv. Théorème travail-énergie : travail net = ΔKE. Au MCAT, vérifier les forces conservatives vs. non conservatives.","tr":"W = Fd·cosθ. KE = ½mv². PE = mgh. Enerjinin korunumu: KE + PE = sabit (sürtünme yoksa). Güç P = W/t = Fv. İş-enerji teoremi: net iş = ΔKE. MCAT'te korunumlu ve korunumsuz kuvvetleri kontrol edin.","nl":"W = Fd·cosθ. KE = ½mv². PE = mgh. Behoud van energie: KE + PE = constant (zonder wrijving). Vermogen P = W/t = Fv. Arbeid-energietheorema: netto arbeid = ΔKE. Op het MCAT, let op conservatieve vs. niet-conservatieve krachten.","ru":"W = Fd·cosθ. KE = ½mv². PE = mgh. Закон сохранения энергии: KE + PE = const (без трения). Мощность P = W/t = Fv. Теорема работы-энергии: суммарная работа = ΔKE. На MCAT проверяйте консервативные и неконсервативные силы.","zh":"W = Fd·cosθ。KE = ½mv²。PE = mgh。能量守恒：KE + PE = 常数（无摩擦）。功率 P = W/t = Fv。动能定理：净功 = ΔKE。在MCAT中注意保守力与非保守力。","pt_BR":"W = Fd·cosθ. KE = ½mv². PE = mgh. Conservação de energia: KE + PE = constante (sem atrito). Potência P = W/t = Fv. Teorema trabalho-energia: trabalho líquido = ΔKE. No MCAT, verifique forças conservativas vs. não conservativas.","pt_PT":"W = Fd·cosθ. KE = ½mv². PE = mgh. Conservação de energia: KE + PE = constante (sem atrito). Potência P = W/t = Fv. Teorema trabalho-energia: trabalho líquido = ΔKE. No MCAT, verifique forças conservativas vs. não conservativas."}},
  { id: 'dc-mcat-0076', deck_id: 'deck-mcat', sort_order: 76, front: "Projectile Motion (MCAT)", back: "Horizontal: constant velocity (v_x = v₀cosθ, x = v_xt). Vertical: constant acceleration g downward (y = v₀sinθ·t - ½gt²). Range is maximized at 45°. The two components are completely independent." , front_translations: {"es":"Movimento de projétil (MCAT)","de":"Projektilbewegung (MCAT)","fr":"Mouvement de projectile (MCAT)","tr":"Mermi Hareketi (MCAT)","nl":"Projectielbeweging (MCAT)","ru":"Движение снаряда (MCAT)","zh":"抛体运动 (MCAT)","pt_BR":"Movimento de projétil (MCAT)","pt_PT":"Movimento de projétil (MCAT)"}, back_translations: {"es":"Horizontal: velocidad constante (v_x = v₀cosθ, x = v_xt). Vertical: aceleración constante g para bajo (y = v₀sinθ·t - ½gt²). El alcance es máximo a 45°. Los de los componentes son completamente independentes.","de":"Horizontal: konstante Geschwindigkeit (v_x = v₀cosθ, x = v_xt). Vertikal: konstante Beschleunigung g nach unten (y = v₀sinθ·t - ½gt²). Reichweite ist bei 45° maximal. Die beiden Komponenten sind völlig unabhängig.","fr":"Horizontal : vitesse constante (v_x = v₀cosθ, x = v_xt). Vertical : accélération constante g vers le bas (y = v₀sinθ·t - ½gt²). La portée est maximale à 45°. Les deux composantes sont totalement indépendantes.","tr":"Yatay: sabit hız (v_x = v₀cosθ, x = v_xt). Dikey: sabit ivme g aşağı yönde (y = v₀sinθ·t - ½gt²). Menzil 45°'de maksimuma ulaşır. İki bileşen tamamen bağımsızdır.","nl":"Horizontaal: constante snelheid (v_x = v₀cosθ, x = v_xt). Verticaal: constante versnelling g naar beneden (y = v₀sinθ·t - ½gt²). Bereik is maximaal bij 45°. De twee componenten zijn volledig onafhankelijk.","ru":"Горизонтальная: постоянная скорость (v_x = v₀cosθ, x = v_xt). Вертикальная: постоянное ускорение g вниз (y = v₀sinθ·t - ½gt²). Дальность максимальна при 45°. Две компоненты полностью независимы.","zh":"水平方向：匀速运动（v_x = v₀cosθ，x = v_xt）。垂直方向：匀加速运动，g向下（y = v₀sinθ·t - ½gt²）。射程在45°时最大。两个分量完全独立。","pt_BR":"Horizontal: velocidade constante (v_x = v₀cosθ, x = v_xt). Vertical: aceleração constante g para baixo (y = v₀sinθ·t - ½gt²). O alcance é máximo a 45°. Os dois componentes são completamente independentes.","pt_PT":"Horizontal: velocidade constante (v_x = v₀cosθ, x = v_xt). Vertical: aceleração constante g para baixo (y = v₀sinθ·t - ½gt²). O alcance é máximo a 45°. As duas componentes são completamente independentes."}},
  { id: 'dc-mcat-0077', deck_id: 'deck-mcat', sort_order: 77, front: "Springs and Simple Harmonic Motion", back: "F = -kx (Hooke's Law). T = 2π√(m/k) for spring; T = 2π√(L/g) for pendulum. Maximum KE at equilibrium (x=0); maximum PE at maximum displacement. Total mechanical energy is conserved: E = ½kA²." , front_translations: {"es":"Molas y movimiento harmonico simples","de":"Federn und einfache harmonische Bewegung","fr":"Ressorts et mouvement harmonique simple","tr":"Yaylar ve Basit Harmonik Hareket","nl":"Veren en eenvoudige harmonische beweging","ru":"Пружины и простое гармоническое движение","zh":"弹簧与简谐运动","pt_BR":"Molas e movimento harmônico simples","pt_PT":"Molas e movimento harmónico simples"}, back_translations: {"es":"F = -kx (Ley de Hooke). T = 2π√(m/k) para mola; T = 2π√(L/g) para pendulo. KE máxima en el equilíbrio (x=0); PE máxima en el deslocamento máximo. La energía mecánica total es conservada: Y = ½kA².","de":"F = -kx (Hookesches Gesetz). T = 2π√(m/k) für Feder; T = 2π√(L/g) für Pendel. Maximale KE im Gleichgewicht (x=0); maximale PE bei maximaler Auslenkung. Gesamte mechanische Energie ist erhalten: E = ½kA².","fr":"F = -kx (loi de Hooke). T = 2π√(m/k) pour un ressort ; T = 2π√(L/g) pour un pendule. KE maximale à l'équilibre (x=0) ; PE maximale au déplacement maximal. L'énergie mécanique totale est conservée : E = ½kA².","tr":"F = -kx (Hooke Yasası). T = 2π√(m/k) yay için; T = 2π√(L/g) sarkaç için. Denge noktasında (x=0) maksimum KE; maksimum yer değiştirmede maksimum PE. Toplam mekanik enerji korunur: E = ½kA².","nl":"F = -kx (wet van Hooke). T = 2π√(m/k) voor veer; T = 2π√(L/g) voor slinger. Maximale KE bij evenwicht (x=0); maximale PE bij maximale uitwijking. Totale mechanische energie blijft behouden: E = ½kA².","ru":"F = -kx (закон Гука). T = 2π√(m/k) для пружины; T = 2π√(L/g) для маятника. Максимальная KE в положении равновесия (x=0); максимальная PE при максимальном смещении. Полная механическая энергия сохраняется: E = ½kA².","zh":"F = -kx（胡克定律）。弹簧：T = 2π√(m/k)；摆：T = 2π√(L/g)。平衡位置（x=0）时动能最大；最大位移时势能最大。总机械能守恒：E = ½kA²。","pt_BR":"F = -kx (Lei de Hooke). T = 2π√(m/k) para mola; T = 2π√(L/g) para pêndulo. KE máxima no equilíbrio (x=0); PE máxima no deslocamento máximo. A energia mecânica total é conservada: E = ½kA².","pt_PT":"F = -kx (Lei de Hooke). T = 2π√(m/k) para mola; T = 2π√(L/g) para pêndulo. KE máxima no equilíbrio (x=0); PE máxima no deslocamento máximo. A energia mecânica total é conservada: E = ½kA²."}},
  { id: 'dc-mcat-0078', deck_id: 'deck-mcat', sort_order: 78, front: "Torque and Rotational Equilibrium", back: "τ = rFsinθ. For rotational equilibrium, Στ = 0 and ΣF = 0. Lever problems are common on the MCAT; especially relevant to musculoskeletal biomechanics (forearm as a class 3 lever)." , front_translations: {"es":"Torque y equilíbrio rotacional","de":"Drehmoment und Rotationsgleichgewicht","fr":"Couple et équilibre rotationnel","tr":"Tork ve Dönme Dengesi","nl":"Koppel en rotatiebalans","ru":"Момент силы и вращательное равновесие","zh":"力矩与转动平衡","pt_BR":"Torque e equilíbrio rotacional","pt_PT":"Torque e equilíbrio rotacional"}, back_translations: {"es":"τ = rFsinθ. Para equilíbrio rotacional, Στ = 0 y ΣF = 0. Problemas de alavanca son comuns en el MCAT; especialmente relevantes para a biomecanica musculoesquelética (antebraço como alavanca de clase 3).","de":"τ = rFsinθ. Für Rotationsgleichgewicht: Στ = 0 und ΣF = 0. Hebelprobleme sind im MCAT häufig; besonders relevant für die Biomechanik des Bewegungsapparats (Unterarm als Hebel der 3. Klasse).","fr":"τ = rFsinθ. Pour l'équilibre rotationnel, Στ = 0 et ΣF = 0. Les problèmes de levier sont courants au MCAT ; particulièrement pertinents pour la biomécanique musculosquelettique (l'avant-bras comme levier de classe 3).","tr":"τ = rFsinθ. Dönme dengesi için Στ = 0 ve ΣF = 0. Kaldıraç problemleri MCAT'te yaygındır; özellikle kas-iskelet biyomekaniği ile ilgilidir (önkol 3. sınıf kaldıraç olarak).","nl":"τ = rFsinθ. Voor rotatiebalans: Στ = 0 en ΣF = 0. Hefboomproblemen komen veel voor op het MCAT; vooral relevant voor musculoskeletale biomechanica (onderarm als klasse 3-hefboom).","ru":"τ = rFsinθ. Для вращательного равновесия: Στ = 0 и ΣF = 0. Задачи на рычаг часто встречаются на MCAT; особенно актуальны для биомеханики опорно-двигательной системы (предплечье как рычаг 3-го рода).","zh":"τ = rFsinθ。转动平衡条件：Στ = 0 且 ΣF = 0。杠杆问题在MCAT中很常见；尤其与肌肉骨骼生物力学相关（前臂作为第三类杠杆）。","pt_BR":"τ = rFsinθ. Para equilíbrio rotacional, Στ = 0 e ΣF = 0. Problemas de alavanca são comuns no MCAT; especialmente relevantes para a biomecânica musculoesquelética (antebraço como alavanca de classe 3).","pt_PT":"τ = rFsinθ. Para equilíbrio rotacional, Στ = 0 e ΣF = 0. Problemas de alavanca são comuns no MCAT; especialmente relevantes para a biomecânica musculoesquelética (antebraço como alavanca de classe 3)."}},
  // --- Psychology & Sociology ---
  { id: 'dc-mcat-0079', deck_id: 'deck-mcat', sort_order: 79, front: "Piaget's Stages of Cognitive Development", back: "Sensorimotor (0–2 yrs): object permanence. Preoperational (2–7 yrs): symbolic thought, egocentrism, lack of conservation. Concrete operational (7–11 yrs): logical operations on concrete objects. Formal operational (12+ yrs): abstract reasoning." , front_translations: {"es":"Estágios del desarrollo cognitivo de Piaget","de":"Piagets Stufen der kognitiven Entwicklung","fr":"Les stades du développement cognitif de Piaget","tr":"Piaget'nin Bilişsel Gelişim Evreleri","nl":"Piagets stadia van cognitieve ontwikkeling","ru":"Стадии когнитивного развития Пиаже","zh":"皮亚杰的认知发展阶段","pt_BR":"Estágios do desenvolvimento cognitivo de Piaget","pt_PT":"Estágios do desenvolvimento cognitivo de Piaget"}, back_translations: {"es":"Sensório-motor (0–2 anos): permanencia del objeto. Pré-operatório (2–7 anos): pensamiento simbólico, egocentrismo, falta de conservación. Operatório concreto (7–11 anos): operaciones lógicas sobre objetos concretos. Operatório formal (12+ anos): raciocínio abstrato.","de":"Sensomotorisch (0–2 Jahre): Objektpermanenz. Präoperational (2–7 Jahre): symbolisches Denken, Egozentrismus, fehlende Erhaltung. Konkret-operational (7–11 Jahre): logische Operationen an konkreten Objekten. Formal-operational (12+ Jahre): abstraktes Denken.","fr":"Sensorimoteur (0–2 ans) : permanence de l'objet. Préopératoire (2–7 ans) : pensée symbolique, égocentrisme, absence de conservation. Opératoire concret (7–11 ans) : opérations logiques sur des objets concrets. Opératoire formel (12+ ans) : raisonnement abstrait.","tr":"Duyusal-motor (0–2 yaş): nesne sürekliliği. İşlem öncesi (2–7 yaş): sembolik düşünce, benmerkezcilik, korunum eksikliği. Somut işlemler (7–11 yaş): somut nesneler üzerinde mantıksal işlemler. Soyut işlemler (12+ yaş): soyut akıl yürütme.","nl":"Sensomotorisch (0–2 jaar): objectpermanentie. Preoperationeel (2–7 jaar): symbolisch denken, egocentrisme, gebrek aan conservatie. Concreet-operationeel (7–11 jaar): logische bewerkingen op concrete objecten. Formeel-operationeel (12+ jaar): abstract redeneren.","ru":"Сенсомоторная (0–2 года): постоянство объекта. Дооперациональная (2–7 лет): символическое мышление, эгоцентризм, отсутствие сохранения. Конкретно-операциональная (7–11 лет): логические операции с конкретными объектами. Формально-операциональная (12+ лет): абстрактное мышление.","zh":"感知运动期（0-2岁）：客体永久性。前运算期（2-7岁）：象征性思维、自我中心、缺乏守恒。具体运算期（7-11岁）：对具体事物进行逻辑运算。形式运算期（12岁以上）：抽象推理。","pt_BR":"Sensório-motor (0–2 anos): permanência do objeto. Pré-operatório (2–7 anos): pensamento simbólico, egocentrismo, falta de conservação. Operatório concreto (7–11 anos): operações lógicas sobre objetos concretos. Operatório formal (12+ anos): raciocínio abstrato.","pt_PT":"Sensório-motor (0–2 anos): permanência do objeto. Pré-operatório (2–7 anos): pensamento simbólico, egocentrismo, falta de conservação. Operatório concreto (7–11 anos): operações lógicas sobre objetos concretos. Operatório formal (12+ anos): raciocínio abstrato."}},
  { id: 'dc-mcat-0080', deck_id: 'deck-mcat', sort_order: 80, front: "Vygotsky's Zone of Proximal Development", back: "The range of tasks a learner can accomplish with guidance but not alone. The 'scaffolding' provided by a more knowledgeable person helps a child move through the ZPD. Emphasizes social and cultural context in learning." , front_translations: {"es":"Zona de desarrollo proximal de Vygotsky","de":"Vygotskys Zone der proximalen Entwicklung","fr":"La zone proximale de développement de Vygotsky","tr":"Vygotsky'nin Yakınsal Gelişim Alanı","nl":"Vygotsky's zone van naaste ontwikkeling","ru":"Зона ближайшего развития Выготского","zh":"维果茨基的最近发展区","pt_BR":"Zona de desenvolvimento proximal de Vygotsky","pt_PT":"Zona de desenvolvimento proximal de Vygotsky"}, back_translations: {"es":"La gama de tarefas que un aprendiz puede realizar con orientación, pero no sozinho. El 'andaimento' fornecido por una persona más experiente ayuda a niño a avançar por la ZPD. Enfatiza el contexto social y cultural en la aprendizaje.","de":"Der Bereich von Aufgaben, die ein Lernender mit Anleitung, aber nicht allein bewältigen kann. Das von einer kompetenteren Person bereitgestellte 'Scaffolding' hilft einem Kind, sich durch die ZPD zu bewegen. Betont den sozialen und kulturellen Kontext beim Lernen.","fr":"L'éventail de tâches qu'un apprenant peut accomplir avec de l'aide mais pas seul. L'« étayage » fourni par une personne plus compétente aide l'enfant à progresser dans la ZPD. Met l'accent sur le contexte social et culturel dans l'apprentissage.","tr":"Öğrenenin rehberlikle başarabildiği ancak tek başına başaramadığı görev aralığı. Daha bilgili bir kişinin sağladığı 'iskele' çocuğun ZPD boyunca ilerlemesine yardımcı olur. Öğrenmede sosyal ve kültürel bağlamı vurgular.","nl":"Het scala aan taken dat een leerling met begeleiding kan uitvoeren maar niet alleen. De 'scaffolding' door een meer ervaren persoon helpt het kind door de ZPD te bewegen. Benadrukt de sociale en culturele context bij het leren.","ru":"Диапазон задач, которые учащийся может выполнить с помощью, но не самостоятельно. «Строительные леса» (scaffolding), предоставляемые более компетентным человеком, помогают ребёнку продвигаться через ZPD. Подчёркивает социальный и культурный контекст в обучении.","zh":"学习者在指导下能完成但独自无法完成的任务范围。由更有知识的人提供的\"脚手架\"帮助儿童通过最近发展区。强调学习中的社会和文化背景。","pt_BR":"A gama de tarefas que um aprendiz pode realizar com orientação, mas não sozinho. O 'andaimento' fornecido por uma pessoa mais experiente ajuda a criança a avançar pela ZPD. Enfatiza o contexto social e cultural na aprendizagem.","pt_PT":"A gama de tarefas que um aprendiz pode realizar com orientação, mas não sozinho. O 'andaimento' fornecido por uma pessoa mais experiente ajuda a criança a avançar pela ZPD. Enfatiza o contexto social e cultural na aprendizagem."}},
  { id: 'dc-mcat-0081', deck_id: 'deck-mcat', sort_order: 81, front: "Freud's Psychosexual Stages", back: "Oral (0–1), Anal (1–3), Phallic (3–6; Oedipus/Electra complex), Latency (6–puberty), Genital (puberty+). Fixation at a stage (due to frustration or overindulgence) leads to adult personality characteristics associated with that stage." , front_translations: {"es":"Estágios psicossexuais de Freud","de":"Freuds psychosexuelle Phasen","fr":"Les stades psychosexuels de Freud","tr":"Freud'un Psikoseksüel Evreleri","nl":"Freuds psychoseksuele stadia","ru":"Психосексуальные стадии Фрейда","zh":"弗洛伊德的心理性欲发展阶段","pt_BR":"Estágios psicossexuais de Freud","pt_PT":"Estágios psicossexuais de Freud"}, back_translations: {"es":"Oral (0–1), Anal (1–3), Fálico (3–6; complexo de Édipo/Electra), Latencia (6–puberdad), Genital (puberdad+). La fixación en un etapa (por frustración o gratificación excessiva) leva a características de personalidad adulta associadas a esse etapa.","de":"Oral (0–1), Anal (1–3), Phallisch (3–6; Ödipus-/Elektra-Komplex), Latenz (6–Pubertät), Genital (Pubertät+). Fixierung auf einer Stufe (durch Frustration oder Überbefriedigung) führt zu Persönlichkeitsmerkmalen im Erwachsenenalter, die mit dieser Stufe verbunden sind.","fr":"Oral (0–1), Anal (1–3), Phallique (3–6 ; complexe d'Œdipe/d'Électre), Latence (6–puberté), Génital (puberté+). La fixation à un stade (par frustration ou excès de gratification) entraîne des caractéristiques de personnalité adulte associées à ce stade.","tr":"Oral (0–1), Anal (1–3), Fallik (3–6; Ödipus/Elektra kompleksi), Latans (6–ergenlik), Genital (ergenlik+). Bir evrede saplanma (hayal kırıklığı veya aşırı tatmin nedeniyle) o evreyle ilişkili yetişkin kişilik özelliklerine yol açar.","nl":"Oraal (0–1), Anaal (1–3), Fallisch (3–6; Oedipus-/Elektracomplex), Latentie (6–puberteit), Genitaal (puberteit+). Fixatie op een stadium (door frustratie of overbevrediging) leidt tot volwassen persoonlijkheidskenmerken die verband houden met dat stadium.","ru":"Оральная (0–1), Анальная (1–3), Фаллическая (3–6; Эдипов/Электра комплекс), Латентная (6–пубертат), Генитальная (пубертат+). Фиксация на стадии (из-за фрустрации или чрезмерного удовлетворения) приводит к характеристикам взрослой личности, связанным с этой стадией.","zh":"口唇期（0-1岁），肛门期（1-3岁），性器期（3-6岁；俄狄浦斯/厄勒克特拉情结），潜伏期（6岁-青春期），生殖期（青春期+）。在某阶段的固着（由于挫折或过度满足）导致与该阶段相关的成人人格特征。","pt_BR":"Oral (0–1), Anal (1–3), Fálico (3–6; complexo de Édipo/Electra), Latência (6–puberdade), Genital (puberdade+). A fixação em um estágio (por frustração ou gratificação excessiva) leva a características de personalidade adulta associadas a esse estágio.","pt_PT":"Oral (0–1), Anal (1–3), Fálico (3–6; complexo de Édipo/Electra), Latência (6–puberdade), Genital (puberdade+). A fixação num estágio (por frustração ou gratificação excessiva) leva a características de personalidade adulta associadas a esse estágio."}},
  { id: 'dc-mcat-0082', deck_id: 'deck-mcat', sort_order: 82, front: "Freud's Structural Model", back: "Id: unconscious, pleasure principle, instinctual drives. Ego: reality principle, mediates between id and superego. Superego: internalized moral standards ('conscience'). Defense mechanisms protect the ego from anxiety." , front_translations: {"es":"Modelo estrutural de Freud","de":"Freuds Strukturmodell","fr":"Le modèle structural de Freud","tr":"Freud'un Yapısal Modeli","nl":"Freuds structureel model","ru":"Структурная модель Фрейда","zh":"弗洛伊德的结构模型","pt_BR":"Modelo estrutural de Freud","pt_PT":"Modelo estrutural de Freud"}, back_translations: {"es":"Id: inconsciente, principio del prazer, impulsos instintivos. Ego: principio de la realidad, media entre el id y el superego. Superego: padrões morais internalizados ('conciencia'). Mecanismos de defesa protegen el ego de la ansiedad.","de":"Es: unbewusst, Lustprinzip, Triebe. Ich: Realitätsprinzip, vermittelt zwischen Es und Über-Ich. Über-Ich: internalisierte moralische Standards ('Gewissen'). Abwehrmechanismen schützen das Ich vor Angst.","fr":"Ça : inconscient, principe de plaisir, pulsions instinctives. Moi : principe de réalité, médiateur entre le ça et le surmoi. Surmoi : normes morales intériorisées (« conscience »). Les mécanismes de défense protègent le moi de l'anxiété.","tr":"İd: bilinçdışı, haz ilkesi, içgüdüsel dürtüler. Ego: gerçeklik ilkesi, id ve süperego arasında arabuluculuk yapar. Süperego: içselleştirilmiş ahlaki standartlar ('vicdan'). Savunma mekanizmaları egoyu kaygıdan korur.","nl":"Id: onbewust, lustprincipe, instinctieve driften. Ego: realiteitsprincipe, bemiddelt tussen id en superego. Superego: geïnternaliseerde morele normen ('geweten'). Afweermechanismen beschermen het ego tegen angst.","ru":"Оно: бессознательное, принцип удовольствия, инстинктивные влечения. Эго: принцип реальности, посредник между Оно и Сверх-Я. Сверх-Я: интернализированные моральные стандарты («совесть»). Защитные механизмы защищают Эго от тревоги.","zh":"本我：无意识，快乐原则，本能驱力。自我：现实原则，在本我和超我之间调节。超我：内化的道德标准（\"良心\"）。防御机制保护自我免受焦虑。","pt_BR":"Id: inconsciente, princípio do prazer, impulsos instintivos. Ego: princípio da realidade, media entre o id e o superego. Superego: padrões morais internalizados ('consciência'). Mecanismos de defesa protegem o ego da ansiedade.","pt_PT":"Id: inconsciente, princípio do prazer, impulsos instintivos. Ego: princípio da realidade, medeia entre o id e o superego. Superego: padrões morais internalizados ('consciência'). Mecanismos de defesa protegem o ego da ansiedade."}},
  { id: 'dc-mcat-0083', deck_id: 'deck-mcat', sort_order: 83, front: "Defense Mechanisms", back: "Repression (blocking thoughts from consciousness), denial, projection (attributing own feelings to others), rationalization, displacement (redirecting emotions to a safer target), sublimation (channeling drives constructively), regression." , front_translations: {"es":"Mecanismos de defesa","de":"Abwehrmechanismen","fr":"Mécanismes de défense","tr":"Savunma Mekanizmaları","nl":"Afweermechanismen","ru":"Защитные механизмы","zh":"防御机制","pt_BR":"Mecanismos de defesa","pt_PT":"Mecanismos de defesa"}, back_translations: {"es":"Represión (bloquear pensamientos de la conciencia), negación, projeción (atribuir los propios sentimientos a los outros), racionalización, deslocamento (redirecionar emociones para un alvo más seguro), sublimación (canalizar impulsos construtivamente), regresión.","de":"Verdrängung (Blockieren von Gedanken aus dem Bewusstsein), Verleugnung, Projektion (eigene Gefühle anderen zuschreiben), Rationalisierung, Verschiebung (Emotionen auf ein sichereres Ziel umlenken), Sublimierung (Triebe konstruktiv kanalisieren), Regression.","fr":"Refoulement (bloquer les pensées de la conscience), déni, projection (attribuer ses propres sentiments aux autres), rationalisation, déplacement (rediriger les émotions vers une cible plus sûre), sublimation (canaliser les pulsions de manière constructive), régression.","tr":"Bastırma (düşünceleri bilinçten engelleme), inkâr, yansıtma (kendi duygularını başkalarına atfetme), rasyonelleştirme, yer değiştirme (duyguları daha güvenli bir hedefe yönlendirme), yüceltme (dürtüleri yapıcı şekilde kanalize etme), gerileme.","nl":"Verdringing (gedachten uit het bewustzijn blokkeren), ontkenning, projectie (eigen gevoelens aan anderen toeschrijven), rationalisatie, verplaatsing (emoties naar een veiliger doel richten), sublimatie (driften constructief kanaliseren), regressie.","ru":"Вытеснение (блокирование мыслей из сознания), отрицание, проекция (приписывание своих чувств другим), рационализация, смещение (перенаправление эмоций на более безопасную цель), сублимация (конструктивное направление влечений), регрессия.","zh":"压抑（将思想阻挡在意识之外）、否认、投射（将自己的感受归因于他人）、合理化、置换（将情绪转向更安全的目标）、升华（建设性地引导驱力）、退行。","pt_BR":"Repressão (bloquear pensamentos da consciência), negação, projeção (atribuir os próprios sentimentos aos outros), racionalização, deslocamento (redirecionar emoções para um alvo mais seguro), sublimação (canalizar impulsos construtivamente), regressão.","pt_PT":"Repressão (bloquear pensamentos da consciência), negação, projeção (atribuir os próprios sentimentos aos outros), racionalização, deslocamento (redirecionar emoções para um alvo mais seguro), sublimação (canalizar impulsos construtivamente), regressão."}},
  { id: 'dc-mcat-0084', deck_id: 'deck-mcat', sort_order: 84, front: "Classical Conditioning (Pavlov)", back: "Neutral stimulus (NS) repeatedly paired with unconditioned stimulus (UCS) → NS becomes conditioned stimulus (CS) that elicits conditioned response (CR). Principles: acquisition, extinction, spontaneous recovery, generalization, discrimination." , front_translations: {"es":"Condicionamento clássico (Pavlov)","de":"Klassische Konditionierung (Pavlov)","fr":"Conditionnement classique (Pavlov)","tr":"Klasik Koşullanma (Pavlov)","nl":"Klassieke conditionering (Pavlov)","ru":"Классическое обусловливание (Павлов)","zh":"经典条件反射（巴甫洛夫）","pt_BR":"Condicionamento clássico (Pavlov)","pt_PT":"Condicionamento clássico (Pavlov)"}, back_translations: {"es":"Estímulo neutro (NS) repetidamente pareado con estímulo incondicionado (UCS) → NS se torna estímulo condicionado (CS) que elicia respuesta condicionada (CR). Princípios: adquisición, extinción, recuperación espontanea, generalización, discriminación.","de":"Neutraler Stimulus (NS) wird wiederholt mit unkonditioniertem Stimulus (UCS) gepaart → NS wird zum konditionierten Stimulus (CS), der eine konditionierte Reaktion (CR) auslöst. Prinzipien: Akquisition, Extinktion, spontane Erholung, Generalisierung, Diskrimination.","fr":"Un stimulus neutre (NS) est associé de manière répétée à un stimulus inconditionnel (UCS) → le NS devient un stimulus conditionnel (CS) qui provoque une réponse conditionnelle (CR). Principes : acquisition, extinction, récupération spontanée, généralisation, discrimination.","tr":"Nötr uyaran (NS) tekrar tekrar koşulsuz uyaranla (UCS) eşleştirilir → NS, koşullu tepki (CR) ortaya çıkaran koşullu uyaran (CS) haline gelir. İlkeler: edinim, sönme, kendiliğinden geri gelme, genelleme, ayırt etme.","nl":"Neutrale stimulus (NS) herhaaldelijk gekoppeld aan onconditionele stimulus (UCS) → NS wordt conditionele stimulus (CS) die conditionele respons (CR) oproept. Principes: acquisitie, extinctie, spontaan herstel, generalisatie, discriminatie.","ru":"Нейтральный стимул (NS) многократно сочетается с безусловным стимулом (UCS) → NS становится условным стимулом (CS), вызывающим условную реакцию (CR). Принципы: приобретение, угасание, спонтанное восстановление, генерализация, дифференцировка.","zh":"中性刺激（NS）反复与无条件刺激（UCS）配对 → NS变为条件刺激（CS），引发条件反应（CR）。原则：习得、消退、自发恢复、泛化、辨别。","pt_BR":"Estímulo neutro (NS) repetidamente pareado com estímulo incondicionado (UCS) → NS se torna estímulo condicionado (CS) que elicia resposta condicionada (CR). Princípios: aquisição, extinção, recuperação espontânea, generalização, discriminação.","pt_PT":"Estímulo neutro (NS) repetidamente emparelhado com estímulo incondicionado (UCS) → NS torna-se estímulo condicionado (CS) que provoca resposta condicionada (CR). Princípios: aquisição, extinção, recuperação espontânea, generalização, discriminação."}},
  { id: 'dc-mcat-0085', deck_id: 'deck-mcat', sort_order: 85, front: "Operant Conditioning (Skinner)", back: "Behavior is shaped by its consequences. Positive reinforcement: add pleasant stimulus → increase behavior. Negative reinforcement: remove unpleasant stimulus → increase behavior. Punishment (positive or negative) → decrease behavior." , front_translations: {"es":"Condicionamento operante (Skinner)","de":"Operante Konditionierung (Skinner)","fr":"Conditionnement opérant (Skinner)","tr":"Edimsel Koşullanma (Skinner)","nl":"Operante conditionering (Skinner)","ru":"Оперантное обусловливание (Скиннер)","zh":"操作性条件反射（斯金纳）","pt_BR":"Condicionamento operante (Skinner)","pt_PT":"Condicionamento operante (Skinner)"}, back_translations: {"es":"El comportamiento es moldado por sus consecuencias. Reforço positivo: adicionar estímulo agradable → aumentar comportamiento. Reforço negativo: remover estímulo desagradable → aumentar comportamiento. Punición (positiva o negativa) → diminuir comportamiento.","de":"Verhalten wird durch seine Konsequenzen geformt. Positive Verstärkung: angenehmen Stimulus hinzufügen → Verhalten steigern. Negative Verstärkung: unangenehmen Stimulus entfernen → Verhalten steigern. Bestrafung (positiv oder negativ) → Verhalten verringern.","fr":"Le comportement est façonné par ses conséquences. Renforcement positif : ajouter un stimulus agréable → augmenter le comportement. Renforcement négatif : retirer un stimulus désagréable → augmenter le comportement. Punition (positive ou négative) → diminuer le comportement.","tr":"Davranış sonuçlarıyla şekillenir. Pozitif pekiştirme: hoş uyaran ekleme → davranışı artırma. Negatif pekiştirme: hoş olmayan uyaranı kaldırma → davranışı artırma. Ceza (pozitif veya negatif) → davranışı azaltma.","nl":"Gedrag wordt gevormd door de gevolgen ervan. Positieve bekrachtiging: aangename stimulus toevoegen → gedrag versterken. Negatieve bekrachtiging: onaangename stimulus verwijderen → gedrag versterken. Straf (positief of negatief) → gedrag verminderen.","ru":"Поведение формируется его последствиями. Положительное подкрепление: добавить приятный стимул → увеличить поведение. Отрицательное подкрепление: убрать неприятный стимул → увеличить поведение. Наказание (положительное или отрицательное) → уменьшить поведение.","zh":"行为由其后果塑造。正强化：添加愉快刺激 → 增加行为。负强化：移除不愉快刺激 → 增加行为。惩罚（正惩罚或负惩罚）→ 减少行为。","pt_BR":"O comportamento é moldado por suas consequências. Reforço positivo: adicionar estímulo agradável → aumentar comportamento. Reforço negativo: remover estímulo desagradável → aumentar comportamento. Punição (positiva ou negativa) → diminuir comportamento.","pt_PT":"O comportamento é moldado pelas suas consequências. Reforço positivo: adicionar estímulo agradável → aumentar comportamento. Reforço negativo: remover estímulo desagradável → aumentar comportamento. Punição (positiva ou negativa) → diminuir comportamento."}},
  { id: 'dc-mcat-0086', deck_id: 'deck-mcat', sort_order: 86, front: "Schedules of Reinforcement", back: "Fixed ratio (FR): reinforce after set number of responses (high rate, post-reinforcement pause). Variable ratio (VR): most resistant to extinction (e.g., gambling). Fixed interval (FI): scalloped pattern. Variable interval (VI): steady rate." , front_translations: {"es":"Esquemas de refuerzo","de":"Verstärkungspläne","fr":"Programmes de renforcement","tr":"Pekiştirme Programları","nl":"Bekrachtigingsschema's","ru":"Режимы подкрепления","zh":"强化程序表","pt_BR":"Esquemas de reforço","pt_PT":"Esquemas de reforço"}, back_translations: {"es":"Razão fixa (FR): refuerzo após número definido de respuestas (alta taxa, pausa pós-refuerzo). Razão variable (VR): más resistente a la extinción (ex.: jogos de azar). Intervalo fixo (FI): padrão escalonado. Intervalo variable (VI): taxa constante.","de":"Feste Quote (FR): Verstärkung nach festgelegter Anzahl von Reaktionen (hohe Rate, Pause nach Verstärkung). Variable Quote (VR): am resistentesten gegen Extinktion (z.B. Glücksspiel). Festes Intervall (FI): wellenförmiges Muster. Variables Intervall (VI): gleichmäßige Rate.","fr":"Ratio fixe (FR) : renforcement après un nombre défini de réponses (taux élevé, pause post-renforcement). Ratio variable (VR) : le plus résistant à l'extinction (ex. jeux de hasard). Intervalle fixe (FI) : patron en escalier. Intervalle variable (VI) : taux régulier.","tr":"Sabit oran (FR): belirli sayıda tepkiden sonra pekiştirme (yüksek oran, pekiştirme sonrası duraklama). Değişken oran (VR): sönmeye en dirençli (örn. kumar). Sabit aralık (FI): tarak deseni. Değişken aralık (VI): sabit oran.","nl":"Vaste ratio (FR): bekrachtiging na vast aantal responsen (hoge snelheid, pauze na bekrachtiging). Variabele ratio (VR): meest resistent tegen extinctie (bijv. gokken). Vast interval (FI): geschulpt patroon. Variabel interval (VI): gelijkmatig tempo.","ru":"Фиксированное соотношение (FR): подкрепление после определённого числа реакций (высокая частота, пауза после подкрепления). Переменное соотношение (VR): наиболее устойчиво к угасанию (напр., азартные игры). Фиксированный интервал (FI): волнообразный паттерн. Переменный интервал (VI): равномерная частота.","zh":"固定比率（FR）：在固定反应次数后强化（高频率，强化后停顿）。可变比率（VR）：最抗消退（如赌博）。固定间隔（FI）：扇形模式。可变间隔（VI）：稳定速率。","pt_BR":"Razão fixa (FR): reforço após número definido de respostas (alta taxa, pausa pós-reforço). Razão variável (VR): mais resistente à extinção (ex.: jogos de azar). Intervalo fixo (FI): padrão escalonado. Intervalo variável (VI): taxa constante.","pt_PT":"Razão fixa (FR): reforço após número definido de respostas (alta taxa, pausa pós-reforço). Razão variável (VR): mais resistente à extinção (ex.: jogos de azar). Intervalo fixo (FI): padrão escalonado. Intervalo variável (VI): taxa constante."}},
  { id: 'dc-mcat-0087', deck_id: 'deck-mcat', sort_order: 87, front: "Observational Learning (Bandura)", back: "Learning by observing others (models). Requires: attention, retention, reproduction, and motivation. The Bobo doll experiment demonstrated that children imitate aggressive behavior observed in adults. Basis of social learning theory." , front_translations: {"es":"Aprendizaje observacional (Bandura)","de":"Beobachtungslernen (Bandura)","fr":"Apprentissage par observation (Bandura)","tr":"Gözlemsel Öğrenme (Bandura)","nl":"Observationeel leren (Bandura)","ru":"Обучение через наблюдение (Бандура)","zh":"观察学习（班杜拉）","pt_BR":"Aprendizagem observacional (Bandura)","pt_PT":"Aprendizagem observacional (Bandura)"}, back_translations: {"es":"Aprendizaje por la observación de outros (modelos). Requer: atención, retención, reprodución y motivación. El experimento del boneco Bobo demonstrou que niños imitam comportamiento agressivo observado en adultos. Base de la teoría de la aprendizaje social.","de":"Lernen durch Beobachtung anderer (Modelle). Erfordert: Aufmerksamkeit, Behalten, Reproduktion und Motivation. Das Bobo-Puppen-Experiment zeigte, dass Kinder aggressives Verhalten von Erwachsenen imitieren. Grundlage der sozialen Lerntheorie.","fr":"Apprentissage par observation d'autrui (modèles). Nécessite : attention, rétention, reproduction et motivation. L'expérience de la poupée Bobo a démontré que les enfants imitent les comportements agressifs observés chez les adultes. Base de la théorie de l'apprentissage social.","tr":"Başkalarını (modelleri) gözlemleyerek öğrenme. Gereklilikler: dikkat, hatırlama, yeniden üretme ve motivasyon. Bobo bebek deneyi, çocukların yetişkinlerde gözlemlenen saldırgan davranışları taklit ettiğini göstermiştir. Sosyal öğrenme teorisinin temeli.","nl":"Leren door anderen (modellen) te observeren. Vereist: aandacht, retentie, reproductie en motivatie. Het Bobo-popexperiment toonde aan dat kinderen agressief gedrag van volwassenen imiteren. Basis van de sociale leertheorie.","ru":"Обучение путём наблюдения за другими (моделями). Требует: внимание, запоминание, воспроизведение и мотивацию. Эксперимент с куклой Бобо продемонстрировал, что дети подражают агрессивному поведению взрослых. Основа теории социального научения.","zh":"通过观察他人（模型）来学习。需要：注意、保持、再现和动机。波波玩偶实验证明儿童会模仿成人的攻击性行为。社会学习理论的基础。","pt_BR":"Aprendizagem pela observação de outros (modelos). Requer: atenção, retenção, reprodução e motivação. O experimento do boneco Bobo demonstrou que crianças imitam comportamento agressivo observado em adultos. Base da teoria da aprendizagem social.","pt_PT":"Aprendizagem pela observação de outros (modelos). Requer: atenção, retenção, reprodução e motivação. A experiência do boneco Bobo demonstrou que as crianças imitam comportamento agressivo observado em adultos. Base da teoria da aprendizagem social."}},
  { id: 'dc-mcat-0088', deck_id: 'deck-mcat', sort_order: 88, front: "Maslow's Hierarchy of Needs", back: "A motivational pyramid: Physiological (food, water, sleep) → Safety → Love/Belonging → Esteem → Self-Actualization. Lower needs must generally be satisfied before higher ones become motivating. Criticized for cultural bias." , front_translations: {"es":"Hierarquia de necesidades de Maslow","de":"Maslows Bedürfnishierarchie","fr":"La pyramide des besoins de Maslow","tr":"Maslow'un İhtiyaçlar Hiyerarşisi","nl":"Maslows behoeftehiërarchie","ru":"Пирамида потребностей Маслоу","zh":"马斯洛的需求层次理论","pt_BR":"Hierarquia de necessidades de Maslow","pt_PT":"Hierarquia de necessidades de Maslow"}, back_translations: {"es":"Una piramide motivacional: Fisiológico (comida, agua, sono) → Segurança → Amor/Pertencimento → Estima → Autorrealización. Necessidades inferiores generalmente devem ser satisfeitas antes que las superiores se tornem motivadoras. Criticada por viés cultural.","de":"Eine Motivationspyramide: Physiologisch (Nahrung, Wasser, Schlaf) → Sicherheit → Liebe/Zugehörigkeit → Wertschätzung → Selbstverwirklichung. Niedrigere Bedürfnisse müssen im Allgemeinen befriedigt sein, bevor höhere motivierend wirken. Kritisiert wegen kultureller Voreingenommenheit.","fr":"Une pyramide motivationnelle : Physiologique (nourriture, eau, sommeil) → Sécurité → Amour/Appartenance → Estime → Réalisation de soi. Les besoins inférieurs doivent généralement être satisfaits avant que les supérieurs ne deviennent motivants. Critiquée pour son biais culturel.","tr":"Motivasyonel bir piramit: Fizyolojik (yiyecek, su, uyku) → Güvenlik → Sevgi/Ait Olma → Saygınlık → Kendini Gerçekleştirme. Alt ihtiyaçlar genellikle üst ihtiyaçlar motive edici olmadan önce karşılanmalıdır. Kültürel önyargı nedeniyle eleştirilir.","nl":"Een motivatiepiramide: Fysiologisch (voedsel, water, slaap) → Veiligheid → Liefde/Verbondenheid → Waardering → Zelfactualisatie. Lagere behoeften moeten over het algemeen bevredigd zijn voordat hogere behoeften motiverend worden. Bekritiseerd vanwege culturele vooringenomenheid.","ru":"Мотивационная пирамида: Физиологические (еда, вода, сон) → Безопасность → Любовь/Принадлежность → Уважение → Самоактуализация. Низшие потребности должны быть удовлетворены, прежде чем высшие станут мотивирующими. Критикуется за культурную предвзятость.","zh":"动机金字塔：生理需求（食物、水、睡眠）→ 安全需求 → 爱与归属 → 尊重需求 → 自我实现。低层需求通常必须先满足，高层需求才会产生激励作用。因文化偏见受到批评。","pt_BR":"Uma pirâmide motivacional: Fisiológico (comida, água, sono) → Segurança → Amor/Pertencimento → Estima → Autorrealização. Necessidades inferiores geralmente devem ser satisfeitas antes que as superiores se tornem motivadoras. Criticada por viés cultural.","pt_PT":"Uma pirâmide motivacional: Fisiológico (comida, água, sono) → Segurança → Amor/Pertença → Estima → Autorrealização. Necessidades inferiores geralmente devem ser satisfeitas antes que as superiores se tornem motivadoras. Criticada por viés cultural."}},
  { id: 'dc-mcat-0089', deck_id: 'deck-mcat', sort_order: 89, front: "Erikson's Stages of Psychosocial Development", back: "Eight stages, each with a conflict: Trust vs. Mistrust (infancy), Autonomy vs. Shame (toddler), Initiative vs. Guilt (preschool), Industry vs. Inferiority (school age), Identity vs. Role Confusion (adolescence), Intimacy vs. Isolation (young adult), Generativity vs. Stagnation (middle adult), Integrity vs. Despair (old age)." , front_translations: {"es":"Estágios del desarrollo psicossocial de Erikson","de":"Eriksons Stufen der psychosozialen Entwicklung","fr":"Les stades du développement psychosocial d'Erikson","tr":"Erikson'un Psikososyal Gelişim Evreleri","nl":"Eriksons stadia van psychosociale ontwikkeling","ru":"Стадии психосоциального развития Эриксона","zh":"埃里克森的心理社会发展阶段","pt_BR":"Estágios do desenvolvimento psicossocial de Erikson","pt_PT":"Estágios do desenvolvimento psicossocial de Erikson"}, back_translations: {"es":"Oito etapas, cada un con un conflito: Confiança vs. Desconfiança (infancia), Autonomia vs. Vergonha (niño pequeña), Iniciativa vs. Culpa (pré-escolar), Diligencia vs. Inferioridad (edad escolar), Identidad vs. Confusão de papéis (adolescencia), Intimidad vs. Isolamento (jovem adulto), Generatividad vs. Estagnación (adulto médio), Integridad vs. Desespero (velhice).","de":"Acht Stufen, jede mit einem Konflikt: Vertrauen vs. Misstrauen (Säuglingsalter), Autonomie vs. Scham (Kleinkind), Initiative vs. Schuld (Vorschulalter), Fleiß vs. Minderwertigkeitsgefühl (Schulalter), Identität vs. Rollenkonfusion (Adoleszenz), Intimität vs. Isolation (junges Erwachsenenalter), Generativität vs. Stagnation (mittleres Erwachsenenalter), Integrität vs. Verzweiflung (hohes Alter).","fr":"Huit stades, chacun avec un conflit : Confiance vs. Méfiance (nourrisson), Autonomie vs. Honte (tout-petit), Initiative vs. Culpabilité (préscolaire), Industrie vs. Infériorité (âge scolaire), Identité vs. Confusion des rôles (adolescence), Intimité vs. Isolement (jeune adulte), Générativité vs. Stagnation (adulte moyen), Intégrité vs. Désespoir (vieillesse).","tr":"Her biri bir çatışma içeren sekiz evre: Güven vs. Güvensizlik (bebeklik), Özerklik vs. Utanç (yürüme çağı), Girişkenlik vs. Suçluluk (okul öncesi), Çalışkanlık vs. Aşağılık duygusu (okul çağı), Kimlik vs. Rol Karmaşası (ergenlik), Yakınlık vs. Yalıtılmışlık (genç yetişkinlik), Üretkenlik vs. Durgunluk (orta yetişkinlik), Bütünlük vs. Umutsuzluk (yaşlılık).","nl":"Acht stadia, elk met een conflict: Vertrouwen vs. Wantrouwen (zuigelingentijd), Autonomie vs. Schaamte (peuter), Initiatief vs. Schuld (kleuter), Vlijt vs. Minderwaardigheid (schoolleeftijd), Identiteit vs. Rolverwarring (adolescentie), Intimiteit vs. Isolatie (jong volwassene), Generativiteit vs. Stagnatie (midden volwassene), Integriteit vs. Wanhoop (ouderdom).","ru":"Восемь стадий, каждая с конфликтом: Доверие vs. Недоверие (младенчество), Автономия vs. Стыд (раннее детство), Инициатива vs. Вина (дошкольный возраст), Трудолюбие vs. Неполноценность (школьный возраст), Идентичность vs. Спутанность ролей (подростковый), Близость vs. Изоляция (молодой взрослый), Генеративность vs. Стагнация (средний взрослый), Целостность vs. Отчаяние (старость).","zh":"八个阶段，每个都有冲突：信任 vs. 不信任（婴儿期），自主 vs. 羞耻（幼儿期），主动 vs. 内疚（学前期），勤勉 vs. 自卑（学龄期），同一性 vs. 角色混乱（青春期），亲密 vs. 孤立（青年期），繁殖 vs. 停滞（中年期），完整 vs. 绝望（老年期）。","pt_BR":"Oito estágios, cada um com um conflito: Confiança vs. Desconfiança (infância), Autonomia vs. Vergonha (criança pequena), Iniciativa vs. Culpa (pré-escolar), Diligência vs. Inferioridade (idade escolar), Identidade vs. Confusão de papéis (adolescência), Intimidade vs. Isolamento (jovem adulto), Generatividade vs. Estagnação (adulto médio), Integridade vs. Desespero (velhice).","pt_PT":"Oito estágios, cada um com um conflito: Confiança vs. Desconfiança (infância), Autonomia vs. Vergonha (criança pequena), Iniciativa vs. Culpa (pré-escolar), Diligência vs. Inferioridade (idade escolar), Identidade vs. Confusão de papéis (adolescência), Intimidade vs. Isolamento (jovem adulto), Generatividade vs. Estagnação (adulto médio), Integridade vs. Desespero (velhice)."}},
  { id: 'dc-mcat-0090', deck_id: 'deck-mcat', sort_order: 90, front: "Attribution Theory", back: "Explains how people attribute causes to events. Internal (dispositional) attribution: behavior is due to the person's character. External (situational) attribution: behavior is due to circumstances. Fundamental attribution error: overemphasizing dispositional causes for others' behavior." , front_translations: {"es":"Teoria de la atribuición","de":"Attributionstheorie","fr":"Théorie de l'attribution","tr":"Atıf Teorisi","nl":"Attributietheorie","ru":"Теория атрибуции","zh":"归因理论","pt_BR":"Teoria da atribuição","pt_PT":"Teoria da atribuição"}, back_translations: {"es":"Explica como las personas atribuem causas a los eventos. Atribuición interna (disposicional): el comportamiento es debido al caráter de la persona. Atribuición externa (situacional): el comportamiento es devido a las circunstancias. Erro fundamental de atribuición: supervalorizar causas disposicionais para el comportamiento de los outros.","de":"Erklärt, wie Menschen Ursachen für Ereignisse zuschreiben. Interne (dispositionale) Attribution: Verhalten ist auf den Charakter der Person zurückzuführen. Externe (situationale) Attribution: Verhalten ist auf Umstände zurückzuführen. Fundamentaler Attributionsfehler: Überbewertung dispositionaler Ursachen für das Verhalten anderer.","fr":"Explique comment les gens attribuent des causes aux événements. Attribution interne (dispositionnelle) : le comportement est dû au caractère de la personne. Attribution externe (situationnelle) : le comportement est dû aux circonstances. Erreur fondamentale d'attribution : surestimation des causes dispositionnelles pour le comportement d'autrui.","tr":"İnsanların olaylara nasıl nedenler atfettiğini açıklar. İçsel (kişisel) atıf: davranış kişinin karakterinden kaynaklanır. Dışsal (durumsal) atıf: davranış koşullardan kaynaklanır. Temel atıf hatası: başkalarının davranışları için kişisel nedenleri abartma.","nl":"Verklaart hoe mensen oorzaken toekennen aan gebeurtenissen. Interne (dispositionele) attributie: gedrag is te wijten aan het karakter van de persoon. Externe (situationele) attributie: gedrag is te wijten aan omstandigheden. Fundamentele attributiefout: overschatting van dispositionele oorzaken voor andermans gedrag.","ru":"Объясняет, как люди приписывают причины событиям. Внутренняя (диспозиционная) атрибуция: поведение обусловлено характером человека. Внешняя (ситуационная) атрибуция: поведение обусловлено обстоятельствами. Фундаментальная ошибка атрибуции: переоценка диспозиционных причин поведения других.","zh":"解释人们如何为事件归因。内部（性格）归因：行为归因于个人性格。外部（情境）归因：行为归因于环境。基本归因错误：过度强调他人行为的性格因素。","pt_BR":"Explica como as pessoas atribuem causas aos eventos. Atribuição interna (disposicional): o comportamento é devido ao caráter da pessoa. Atribuição externa (situacional): o comportamento é devido às circunstâncias. Erro fundamental de atribuição: supervalorizar causas disposicionais para o comportamento dos outros.","pt_PT":"Explica como as pessoas atribuem causas aos eventos. Atribuição interna (disposicional): o comportamento deve-se ao carácter da pessoa. Atribuição externa (situacional): o comportamento deve-se às circunstâncias. Erro fundamental de atribuição: sobrevalorizar causas disposicionais para o comportamento dos outros."}},
  { id: 'dc-mcat-0091', deck_id: 'deck-mcat', sort_order: 91, front: "Social Stratification", back: "The hierarchical arrangement of individuals in society based on socioeconomic status, power, and prestige. Systems: caste (ascribed, rigid), class (achieved, fluid), meritocracy (based on merit). Socioeconomic status (SES) impacts health outcomes." , front_translations: {"es":"Estratificación social","de":"Soziale Schichtung","fr":"Stratification sociale","tr":"Sosyal Tabakalaşma","nl":"Sociale stratificatie","ru":"Социальная стратификация","zh":"社会分层","pt_BR":"Estratificação social","pt_PT":"Estratificação social"}, back_translations: {"es":"La organización hierárquica de los indivíduos en la sociedad con base en el status socioeconomico, poder y prestígio. Sistemas: casta (atribuído, rígido), clase (adquirido, fluido), meritocracia (basada en el mérito). El status socioeconomico (SES) impacta los resultados de salud.","de":"Die hierarchische Anordnung von Individuen in der Gesellschaft basierend auf sozioökonomischem Status, Macht und Prestige. Systeme: Kaste (zugeschrieben, starr), Klasse (erworben, flexibel), Meritokratie (leistungsbasiert). Sozioökonomischer Status (SES) beeinflusst Gesundheitsergebnisse.","fr":"L'arrangement hiérarchique des individus dans la société basé sur le statut socio-économique, le pouvoir et le prestige. Systèmes : caste (attribué, rigide), classe (acquis, fluide), méritocratie (basée sur le mérite). Le statut socio-économique (SES) impacte les résultats de santé.","tr":"Bireylerin toplumda sosyoekonomik statü, güç ve prestije göre hiyerarşik düzenlenmesi. Sistemler: kast (atfedilen, katı), sınıf (kazanılan, esnek), meritokrasi (liyakate dayalı). Sosyoekonomik statü (SES) sağlık sonuçlarını etkiler.","nl":"De hiërarchische rangschikking van individuen in de samenleving op basis van sociaaleconomische status, macht en prestige. Systemen: kaste (toegeschreven, rigide), klasse (verworven, flexibel), meritocratie (op verdienste gebaseerd). Sociaaleconomische status (SES) beïnvloedt gezondheidsuitkomsten.","ru":"Иерархическое расположение индивидов в обществе на основе социально-экономического статуса, власти и престижа. Системы: каста (приписанная, жёсткая), класс (достигнутый, гибкий), меритократия (основанная на заслугах). Социально-экономический статус (SES) влияет на показатели здоровья.","zh":"基于社会经济地位、权力和声望对社会中个体的等级排列。体系：种姓制度（先赋的，刚性的）、阶级（后致的，流动的）、精英制度（基于才能）。社会经济地位（SES）影响健康结果。","pt_BR":"A organização hierárquica dos indivíduos na sociedade com base no status socioeconômico, poder e prestígio. Sistemas: casta (atribuído, rígido), classe (adquirido, fluido), meritocracia (baseada no mérito). O status socioeconômico (SES) impacta os resultados de saúde.","pt_PT":"A organização hierárquica dos indivíduos na sociedade com base no estatuto socioeconómico, poder e prestígio. Sistemas: casta (atribuído, rígido), classe (adquirido, fluido), meritocracia (baseada no mérito). O estatuto socioeconómico (SES) impacta os resultados de saúde."}},
  { id: 'dc-mcat-0092', deck_id: 'deck-mcat', sort_order: 92, front: "Health Disparities", back: "Differences in health outcomes across racial, ethnic, socioeconomic, or geographic groups, often due to systemic inequalities. Social determinants of health (income, education, housing, access to care) are the primary drivers." , front_translations: {"es":"Disparidades en salud","de":"Gesundheitliche Ungleichheiten","fr":"Disparités en santé","tr":"Sağlık Eşitsizlikleri","nl":"Gezondheidsverschillen","ru":"Неравенство в здоровье","zh":"健康差异","pt_BR":"Disparidades em saúde","pt_PT":"Disparidades em saúde"}, back_translations: {"es":"Diferenças en los resultados de salud entre grupos raciais, étnicos, socioeconomicos o geográficos, frecuentemente debido a desigualdades sistemicas. Los determinantes sociais de la salud (renda, educación, moradia, acceso a cuidados) son los principales impulsionadores.","de":"Unterschiede in Gesundheitsergebnissen zwischen rassischen, ethnischen, sozioökonomischen oder geografischen Gruppen, oft aufgrund systemischer Ungleichheiten. Soziale Determinanten der Gesundheit (Einkommen, Bildung, Wohnen, Zugang zur Versorgung) sind die Haupttreiber.","fr":"Différences dans les résultats de santé entre groupes raciaux, ethniques, socio-économiques ou géographiques, souvent dues à des inégalités systémiques. Les déterminants sociaux de la santé (revenus, éducation, logement, accès aux soins) sont les principaux moteurs.","tr":"Irk, etnik köken, sosyoekonomik veya coğrafi gruplara göre sağlık sonuçlarındaki farklılıklar, genellikle sistemik eşitsizliklerden kaynaklanır. Sağlığın sosyal belirleyicileri (gelir, eğitim, konut, bakıma erişim) temel etkenlerdir.","nl":"Verschillen in gezondheidsuitkomsten tussen raciale, etnische, sociaaleconomische of geografische groepen, vaak als gevolg van systemische ongelijkheden. Sociale determinanten van gezondheid (inkomen, onderwijs, huisvesting, toegang tot zorg) zijn de belangrijkste drijfveren.","ru":"Различия в показателях здоровья между расовыми, этническими, социально-экономическими или географическими группами, часто обусловленные системным неравенством. Социальные детерминанты здоровья (доход, образование, жильё, доступ к медицинской помощи) являются основными факторами.","zh":"不同种族、民族、社会经济或地理群体之间的健康结果差异，通常由系统性不平等造成。健康的社会决定因素（收入、教育、住房、医疗可及性）是主要驱动因素。","pt_BR":"Diferenças nos resultados de saúde entre grupos raciais, étnicos, socioeconômicos ou geográficos, frequentemente devido a desigualdades sistêmicas. Os determinantes sociais da saúde (renda, educação, moradia, acesso a cuidados) são os principais impulsionadores.","pt_PT":"Diferenças nos resultados de saúde entre grupos raciais, étnicos, socioeconómicos ou geográficos, frequentemente devido a desigualdades sistémicas. Os determinantes sociais da saúde (rendimento, educação, habitação, acesso a cuidados) são os principais impulsionadores."}},
  { id: 'dc-mcat-0093', deck_id: 'deck-mcat', sort_order: 93, front: "Implicit vs. Explicit Bias", back: "Explicit bias: conscious, deliberate attitudes or stereotypes. Implicit bias: unconscious associations that affect behavior without awareness. Both can impact healthcare delivery and contribute to health disparities. Measured by the Implicit Association Test (IAT)." , front_translations: {"es":"Viés implícito vs. explícito","de":"Implizite vs. explizite Voreingenommenheit","fr":"Biais implicite vs. explicite","tr":"Örtük ve Açık Önyargı","nl":"Impliciete vs. expliciete bias","ru":"Имплицитная и эксплицитная предвзятость","zh":"内隐偏见与外显偏见","pt_BR":"Viés implícito vs. explícito","pt_PT":"Viés implícito vs. explícito"}, back_translations: {"es":"Viés explícito: atitudes o estereótipos conscientes y deliberados. Viés implícito: associaciones inconscientes que afectan el comportamiento sin conciencia. Ambos pueden impactar a prestación de cuidados de salud y contribuir para disparidades en salud. Medido por el Implicit Association Test (IAT).","de":"Explizite Voreingenommenheit: bewusste, absichtliche Einstellungen oder Stereotypen. Implizite Voreingenommenheit: unbewusste Assoziationen, die das Verhalten ohne Bewusstsein beeinflussen. Beide können die Gesundheitsversorgung beeinflussen und zu gesundheitlichen Ungleichheiten beitragen. Gemessen durch den Implicit Association Test (IAT).","fr":"Biais explicite : attitudes ou stéréotypes conscients et délibérés. Biais implicite : associations inconscientes qui affectent le comportement sans en avoir conscience. Les deux peuvent impacter la prestation de soins et contribuer aux disparités en santé. Mesuré par l'Implicit Association Test (IAT).","tr":"Açık önyargı: bilinçli, kasıtlı tutumlar veya stereotipler. Örtük önyargı: farkındalık olmadan davranışı etkileyen bilinçdışı çağrışımlar. Her ikisi de sağlık hizmeti sunumunu etkileyebilir ve sağlık eşitsizliklerine katkıda bulunabilir. Implicit Association Test (IAT) ile ölçülür.","nl":"Expliciete bias: bewuste, opzettelijke attitudes of stereotypen. Impliciete bias: onbewuste associaties die gedrag beïnvloeden zonder bewustzijn. Beide kunnen de gezondheidszorg beïnvloeden en bijdragen aan gezondheidsverschillen. Gemeten door de Implicit Association Test (IAT).","ru":"Эксплицитная предвзятость: сознательные, намеренные установки или стереотипы. Имплицитная предвзятость: бессознательные ассоциации, влияющие на поведение без осознания. Обе могут влиять на оказание медицинской помощи и способствовать неравенству в здоровье. Измеряется с помощью Implicit Association Test (IAT).","zh":"外显偏见：有意识的、故意的态度或刻板印象。内隐偏见：无意识的联想，在不知不觉中影响行为。两者都可能影响医疗服务并加剧健康差异。通过内隐联想测试（IAT）测量。","pt_BR":"Viés explícito: atitudes ou estereótipos conscientes e deliberados. Viés implícito: associações inconscientes que afetam o comportamento sem consciência. Ambos podem impactar a prestação de cuidados de saúde e contribuir para disparidades em saúde. Medido pelo Implicit Association Test (IAT).","pt_PT":"Viés explícito: atitudes ou estereótipos conscientes e deliberados. Viés implícito: associações inconscientes que afetam o comportamento sem consciência. Ambos podem impactar a prestação de cuidados de saúde e contribuir para disparidades em saúde. Medido pelo Implicit Association Test (IAT)."}},
  { id: 'dc-mcat-0094', deck_id: 'deck-mcat', sort_order: 94, front: "Socialization", back: "The lifelong process by which individuals learn and internalize the norms, values, and behaviors of their culture. Primary socialization: family and early childhood. Secondary socialization: schools, peers, media." , front_translations: {"es":"Socialización","de":"Sozialisation","fr":"Socialisation","tr":"Sosyalleşme","nl":"Socialisatie","ru":"Социализация","zh":"社会化","pt_BR":"Socialização","pt_PT":"Socialização"}, back_translations: {"es":"El proceso a lo ancho de la vida por el qual los indivíduos aprendem y internalizam las normas, valores y comportamientos de su cultura. Socialización primária: família y primera infancia. Socialización secundária: escolas, pares, mídia.","de":"Der lebenslange Prozess, durch den Individuen die Normen, Werte und Verhaltensweisen ihrer Kultur lernen und verinnerlichen. Primäre Sozialisation: Familie und frühe Kindheit. Sekundäre Sozialisation: Schulen, Gleichaltrige, Medien.","fr":"Le processus de toute une vie par lequel les individus apprennent et intériorisent les normes, valeurs et comportements de leur culture. Socialisation primaire : famille et petite enfance. Socialisation secondaire : écoles, pairs, médias.","tr":"Bireylerin kültürlerinin normlarını, değerlerini ve davranışlarını öğrenip içselleştirdiği yaşam boyu süreç. Birincil sosyalleşme: aile ve erken çocukluk. İkincil sosyalleşme: okullar, akranlar, medya.","nl":"Het levenslange proces waardoor individuen de normen, waarden en gedragingen van hun cultuur leren en internaliseren. Primaire socialisatie: gezin en vroege kindertijd. Secundaire socialisatie: scholen, leeftijdsgenoten, media.","ru":"Пожизненный процесс, в ходе которого индивиды усваивают и интернализируют нормы, ценности и модели поведения своей культуры. Первичная социализация: семья и раннее детство. Вторичная социализация: школы, сверстники, СМИ.","zh":"个体学习并内化其文化的规范、价值观和行为的终身过程。初级社会化：家庭和幼儿时期。次级社会化：学校、同伴、媒体。","pt_BR":"O processo ao longo da vida pelo qual os indivíduos aprendem e internalizam as normas, valores e comportamentos de sua cultura. Socialização primária: família e primeira infância. Socialização secundária: escolas, pares, mídia.","pt_PT":"O processo ao longo da vida pelo qual os indivíduos aprendem e internalizam as normas, valores e comportamentos da sua cultura. Socialização primária: família e primeira infância. Socialização secundária: escolas, pares, média."}},
  { id: 'dc-mcat-0095', deck_id: 'deck-mcat', sort_order: 95, front: "Social Influence: Conformity, Compliance, Obedience", back: "Conformity: changing behavior to match group norms (Asch's line study). Compliance: agreeing to a direct request. Obedience: following authority figures' directives (Milgram's shock experiment). Social loafing: reduced effort in a group." , front_translations: {"es":"Influencia Social: Conformidad, Complacencia, Obediencia","de":"Sozialer Einfluss: Konformität, Compliance, Gehorsam","fr":"Influence sociale : conformité, compliance, obéissance","tr":"Sosyal Etki: Uyma, İtaat Etme, Boyun Eğme","nl":"Sociale invloed: conformiteit, compliance, gehoorzaamheid","ru":"Социальное влияние: конформизм, уступчивость, подчинение","zh":"社会影响：从众、顺从、服从","pt_BR":"Influência Social: Conformidade, Complacência, Obediência","pt_PT":"Influência Social: Conformidade, Complacência, Obediência"}, back_translations: {"es":"Conformidad: mudar comportamiento para se adequar a las normas del grupo (estudio de las líneas de Asch). Complacencia: concordar con un pedido direto. Obediencia: seguir las orientaciones de figuras de autoridad (experimento de choque de Milgram). Preguiça social: esforço reduzido en grupo.","de":"Konformität: Verhaltensänderung, um Gruppennormen zu entsprechen (Aschs Linienexperiment). Compliance: Zustimmung zu einer direkten Bitte. Gehorsam: Befolgen von Anweisungen einer Autoritätsperson (Milgrams Schockexperiment). Soziales Faulenzen: verringerte Anstrengung in einer Gruppe.","fr":"Conformité : changer de comportement pour correspondre aux normes du groupe (étude des lignes d'Asch). Compliance : accepter une demande directe. Obéissance : suivre les directives de figures d'autorité (expérience de choc de Milgram). Paresse sociale : effort réduit dans un groupe.","tr":"Uyma: grup normlarına uymak için davranış değiştirme (Asch'ın çizgi deneyi). İtaat etme: doğrudan bir talebe razı olma. Boyun eğme: otorite figürlerinin yönergelerini takip etme (Milgram'ın şok deneyi). Sosyal kaytarma: grupta azalmış çaba.","nl":"Conformiteit: gedrag aanpassen aan groepsnormen (Asch's lijnonderzoek). Compliance: instemmen met een direct verzoek. Gehoorzaamheid: opvolgen van instructies van autoriteitsfiguren (Milgrams schokexperiment). Sociaal lijntrekken: verminderde inspanning in een groep.","ru":"Конформизм: изменение поведения в соответствии с групповыми нормами (эксперимент Аша с линиями). Уступчивость: согласие на прямую просьбу. Подчинение: выполнение указаний авторитетных лиц (эксперимент Милгрэма с электрошоком). Социальная леность: снижение усилий в группе.","zh":"从众：改变行为以符合群体规范（Asch的线段实验）。顺从：同意直接的请求。服从：遵循权威人物的指令（Milgram的电击实验）。社会懈怠：在群体中减少努力。","pt_BR":"Conformidade: mudar comportamento para se adequar às normas do grupo (estudo das linhas de Asch). Complacência: concordar com um pedido direto. Obediência: seguir as orientações de figuras de autoridade (experimento de choque de Milgram). Preguiça social: esforço reduzido em grupo.","pt_PT":"Conformidade: mudar comportamento para se adequar às normas do grupo (estudo das linhas de Asch). Complacência: concordar com um pedido direto. Obediência: seguir as orientações de figuras de autoridade (experiência de choque de Milgram). Preguiça social: esforço reduzido em grupo."}},
  { id: 'dc-mcat-0096', deck_id: 'deck-mcat', sort_order: 96, front: "Prejudice, Stereotyping, and Discrimination", back: "Stereotype: a fixed, generalized belief about a group. Prejudice: a negative attitude toward a group (affective component). Discrimination: unfair treatment based on group membership (behavioral component). Self-fulfilling prophecy and stereotype threat are related phenomena." , front_translations: {"es":"Preconceito, Estereotipaje y Discriminación","de":"Vorurteile, Stereotypisierung und Diskriminierung","fr":"Préjugés, stéréotypes et discrimination","tr":"Önyargı, Stereotipleme ve Ayrımcılık","nl":"Vooroordelen, stereotypering en discriminatie","ru":"Предрассудки, стереотипизация и дискриминация","zh":"偏见、刻板印象与歧视","pt_BR":"Preconceito, Estereotipagem e Discriminação","pt_PT":"Preconceito, Estereotipagem e Discriminação"}, back_translations: {"es":"Estereótipo: creencia fixa y generalizada sobre un grupo. Preconceito: atitude negativa en relación con un grupo (componente afectivo). Discriminación: tratamiento injusto basado en la pertença a un grupo (componente comportamental). Profecia autorrealizable y ameaça del estereótipo son fenómenos relacionados.","de":"Stereotyp: eine feste, verallgemeinerte Überzeugung über eine Gruppe. Vorurteil: eine negative Einstellung gegenüber einer Gruppe (affektive Komponente). Diskriminierung: unfaire Behandlung aufgrund der Gruppenzugehörigkeit (Verhaltenskomponente). Selbsterfüllende Prophezeiung und Stereotype-Threat sind verwandte Phänomene.","fr":"Stéréotype : croyance fixe et généralisée sur un groupe. Préjugé : attitude négative envers un groupe (composante affective). Discrimination : traitement injuste basé sur l'appartenance à un groupe (composante comportementale). La prophétie autoréalisatrice et la menace du stéréotype sont des phénomènes apparentés.","tr":"Stereotip: bir grup hakkında sabit, genelleştirilmiş bir inanç. Önyargı: bir gruba karşı olumsuz tutum (duygusal bileşen). Ayrımcılık: grup üyeliğine dayalı haksız muamele (davranışsal bileşen). Kendini gerçekleştiren kehanet ve stereotip tehdidi ilişkili olgulardır.","nl":"Stereotyp: een vast, gegeneraliseerd geloof over een groep. Vooroordeel: een negatieve houding tegenover een groep (affectieve component). Discriminatie: oneerlijke behandeling op basis van groepslidmaatschap (gedragscomponent). Zelfvervullende voorspelling en stereotypedreiging zijn verwante fenomenen.","ru":"Стереотип: устойчивое, обобщённое убеждение о группе. Предрассудок: негативная установка по отношению к группе (аффективный компонент). Дискриминация: несправедливое обращение на основании принадлежности к группе (поведенческий компонент). Самоисполняющееся пророчество и угроза стереотипа — родственные явления.","zh":"刻板印象：对某一群体固定的、概括性的信念。偏见：对某一群体的消极态度（情感成分）。歧视：基于群体成员身份的不公平对待（行为成分）。自我实现预言和刻板印象威胁是相关现象。","pt_BR":"Estereótipo: crença fixa e generalizada sobre um grupo. Preconceito: atitude negativa em relação a um grupo (componente afetivo). Discriminação: tratamento injusto baseado na pertença a um grupo (componente comportamental). Profecia autorrealizável e ameaça do estereótipo são fenômenos relacionados.","pt_PT":"Estereótipo: crença fixa e generalizada sobre um grupo. Preconceito: atitude negativa em relação a um grupo (componente afetivo). Discriminação: tratamento injusto baseado na pertença a um grupo (componente comportamental). Profecia autorrealizável e ameaça do estereótipo são fenómenos relacionados."}},
  { id: 'dc-mcat-0097', deck_id: 'deck-mcat', sort_order: 97, front: "Memory: Encoding, Storage, Retrieval", back: "Encoding: converting information into a neural code. Storage: maintaining information over time (sensory → short-term/working → long-term). Retrieval: accessing stored information. Failure can occur at any stage." , front_translations: {"es":"Memória: Codificación, Armazenamento, Recuperación","de":"Gedächtnis: Enkodierung, Speicherung, Abruf","fr":"Mémoire : encodage, stockage, récupération","tr":"Bellek: Kodlama, Depolama, Geri Çağırma","nl":"Geheugen: codering, opslag, ophalen","ru":"Память: кодирование, хранение, извлечение","zh":"记忆：编码、存储、提取","pt_BR":"Memória: Codificação, Armazenamento, Recuperação","pt_PT":"Memória: Codificação, Armazenamento, Recuperação"}, back_translations: {"es":"Codificación: conversão de informaciones en código neural. Armazenamento: manutención de informaciones a lo ancho del tiempo (sensorial → corto prazo/memoria de trabajo → ancho prazo). Recuperación: acceso a informaciones armazenadas. La falha puede ocorrer en cualquier etapa.","de":"Enkodierung: Umwandlung von Informationen in einen neuronalen Code. Speicherung: Aufrechterhaltung von Informationen über die Zeit (sensorisch → Kurzzeit-/Arbeitsgedächtnis → Langzeitgedächtnis). Abruf: Zugriff auf gespeicherte Informationen. Versagen kann in jedem Stadium auftreten.","fr":"Encodage : conversion de l'information en code neuronal. Stockage : maintien de l'information dans le temps (sensoriel → court terme/mémoire de travail → long terme). Récupération : accès aux informations stockées. L'échec peut survenir à n'importe quelle étape.","tr":"Kodlama: bilgiyi sinirsel bir koda dönüştürme. Depolama: bilgiyi zaman içinde sürdürme (duyusal → kısa süreli/çalışma belleği → uzun süreli). Geri çağırma: depolanmış bilgiye erişme. Başarısızlık herhangi bir aşamada meydana gelebilir.","nl":"Codering: omzetten van informatie in een neurale code. Opslag: behouden van informatie over de tijd (sensorisch → korte termijn/werkgeheugen → lange termijn). Ophalen: toegang tot opgeslagen informatie. Falen kan in elk stadium optreden.","ru":"Кодирование: преобразование информации в нейронный код. Хранение: поддержание информации во времени (сенсорная → кратковременная/рабочая → долговременная память). Извлечение: доступ к сохранённой информации. Сбой может произойти на любом этапе.","zh":"编码：将信息转换为神经代码。存储：在时间上维持信息（感觉记忆→短期/工作记忆→长期记忆）。提取：访问已存储的信息。任何阶段都可能发生失败。","pt_BR":"Codificação: conversão de informações em código neural. Armazenamento: manutenção de informações ao longo do tempo (sensorial → curto prazo/memória de trabalho → longo prazo). Recuperação: acesso a informações armazenadas. A falha pode ocorrer em qualquer estágio.","pt_PT":"Codificação: conversão de informações em código neural. Armazenamento: manutenção de informações ao longo do tempo (sensorial → curto prazo/memória de trabalho → longo prazo). Recuperação: acesso a informações armazenadas. A falha pode ocorrer em qualquer fase."}},
  { id: 'dc-mcat-0098', deck_id: 'deck-mcat', sort_order: 98, front: "Long-Term Memory Types", back: "Explicit (declarative) memory: episodic (personal events; hippocampus) and semantic (facts; hippocampus). Implicit (non-declarative) memory: procedural (skills; basal ganglia, cerebellum), priming, conditioned responses (amygdala for fear)." , front_translations: {"es":"Tipos de Memória de Longo Prazo","de":"Langzeitgedächtnistypen","fr":"Types de mémoire à long terme","tr":"Uzun Süreli Bellek Türleri","nl":"Typen langetermijngeheugen","ru":"Типы долговременной памяти","zh":"长期记忆类型","pt_BR":"Tipos de Memória de Longo Prazo","pt_PT":"Tipos de Memória de Longo Prazo"}, back_translations: {"es":"Memória explícita (declarativa): episódica (eventos pessoais; hipocampo) y semantica (hechos; hipocampo). Memória implícita (no declarativa): procedural (habilidades; ganglios de la base, cerebelo), priming, respuestas condicionadas (amígdala para medo).","de":"Explizites (deklaratives) Gedächtnis: episodisch (persönliche Ereignisse; Hippocampus) und semantisch (Fakten; Hippocampus). Implizites (nicht-deklaratives) Gedächtnis: prozedural (Fähigkeiten; Basalganglien, Kleinhirn), Priming, konditionierte Reaktionen (Amygdala bei Angst).","fr":"Mémoire explicite (déclarative) : épisodique (événements personnels ; hippocampe) et sémantique (faits ; hippocampe). Mémoire implicite (non déclarative) : procédurale (compétences ; ganglions de la base, cervelet), amorçage, réponses conditionnées (amygdale pour la peur).","tr":"Açık (bildirimsel) bellek: epizodik (kişisel olaylar; hipokampüs) ve semantik (olgular; hipokampüs). Örtük (bildirimsel olmayan) bellek: prosedürel (beceriler; bazal ganglionlar, serebellum), hazırlama, koşullanmış tepkiler (korku için amigdala).","nl":"Expliciet (declaratief) geheugen: episodisch (persoonlijke gebeurtenissen; hippocampus) en semantisch (feiten; hippocampus). Impliciet (niet-declaratief) geheugen: procedureel (vaardigheden; basale ganglia, cerebellum), priming, geconditioneerde reacties (amygdala voor angst).","ru":"Эксплицитная (декларативная) память: эпизодическая (личные события; гиппокамп) и семантическая (факты; гиппокамп). Имплицитная (недекларативная) память: процедурная (навыки; базальные ганглии, мозжечок), прайминг, условные реакции (миндалевидное тело для страха).","zh":"外显（陈述性）记忆：情景记忆（个人事件；海马体）和语义记忆（事实；海马体）。内隐（非陈述性）记忆：程序性记忆（技能；基底神经节、小脑）、启动效应、条件反射（杏仁核与恐惧相关）。","pt_BR":"Memória explícita (declarativa): episódica (eventos pessoais; hipocampo) e semântica (fatos; hipocampo). Memória implícita (não declarativa): procedural (habilidades; gânglios da base, cerebelo), priming, respostas condicionadas (amígdala para medo).","pt_PT":"Memória explícita (declarativa): episódica (eventos pessoais; hipocampo) e semântica (factos; hipocampo). Memória implícita (não declarativa): procedimental (competências; gânglios da base, cerebelo), priming, respostas condicionadas (amígdala para medo)."}},
  { id: 'dc-mcat-0099', deck_id: 'deck-mcat', sort_order: 99, front: "Stress and the HPA Axis", back: "Perceived stress → hypothalamus releases CRH → anterior pituitary releases ACTH → adrenal cortex releases cortisol. Cortisol mobilizes energy (raises blood glucose), suppresses immune system, and inhibits reproduction. Chronic stress = elevated cortisol → harmful effects." , front_translations: {"es":"Estresse y el Eixo HPA","de":"Stress und die HPA-Achse","fr":"Stress et l'axe HPA","tr":"Stres ve HPA Aksı","nl":"Stress en de HPA-as","ru":"Стресс и ось HPA","zh":"应激与HPA轴","pt_BR":"Estresse e o Eixo HPA","pt_PT":"Stress e o Eixo HPA"}, back_translations: {"es":"Estresse percebido → hipotálamo libera CRH → hipófise anterior libera ACTH → córtex adrenal libera cortisol. El cortisol mobiliza energía (aumenta a glicose sanguínea), suprime el sistema inmunológico y inibe a reprodución. Estresse crónico = cortisol elevado → efectos prejudiciais.","de":"Wahrgenommener Stress → Hypothalamus setzt CRH frei → Hypophysenvorderlappen setzt ACTH frei → Nebennierenrinde setzt Cortisol frei. Cortisol mobilisiert Energie (erhöht Blutzucker), unterdrückt das Immunsystem und hemmt die Reproduktion. Chronischer Stress = erhöhtes Cortisol → schädliche Auswirkungen.","fr":"Stress perçu → l'hypothalamus libère la CRH → l'hypophyse antérieure libère l'ACTH → le cortex surrénalien libère le cortisol. Le cortisol mobilise l'énergie (augmente la glycémie), supprime le système immunitaire et inhibe la reproduction. Stress chronique = cortisol élevé → effets nocifs.","tr":"Algılanan stres → hipotalamus CRH salgılar → ön hipofiz ACTH salgılar → adrenal korteks kortizol salgılar. Kortizol enerji mobilize eder (kan şekerini yükseltir), bağışıklık sistemini baskılar ve üremeyi inhibe eder. Kronik stres = yüksek kortizol → zararlı etkiler.","nl":"Waargenomen stress → hypothalamus geeft CRH af → adenohypofyse geeft ACTH af → bijnierschors geeft cortisol af. Cortisol mobiliseert energie (verhoogt bloedglucose), onderdrukt het immuunsysteem en remt de voortplanting. Chronische stress = verhoogd cortisol → schadelijke effecten.","ru":"Воспринимаемый стресс → гипоталамус выделяет CRH → передняя доля гипофиза выделяет ACTH → кора надпочечников выделяет кортизол. Кортизол мобилизует энергию (повышает уровень глюкозы в крови), подавляет иммунную систему и угнетает репродуктивную функцию. Хронический стресс = повышенный кортизол → вредные последствия.","zh":"感知到的压力→下丘脑释放CRH→垂体前叶释放ACTH→肾上腺皮质释放皮质醇。皮质醇动员能量（升高血糖）、抑制免疫系统并抑制生殖功能。慢性应激=皮质醇升高→有害影响。","pt_BR":"Estresse percebido → hipotálamo libera CRH → hipófise anterior libera ACTH → córtex adrenal libera cortisol. O cortisol mobiliza energia (aumenta a glicose sanguínea), suprime o sistema imunológico e inibe a reprodução. Estresse crônico = cortisol elevado → efeitos prejudiciais.","pt_PT":"Stress percebido → hipotálamo liberta CRH → hipófise anterior liberta ACTH → córtex suprarrenal liberta cortisol. O cortisol mobiliza energia (aumenta a glicose sanguínea), suprime o sistema imunitário e inibe a reprodução. Stress crónico = cortisol elevado → efeitos prejudiciais."}},
  { id: 'dc-mcat-0100', deck_id: 'deck-mcat', sort_order: 100, front: "Biological Basis of Behavior: Neurotransmitters", back: "Dopamine: reward, motivation, motor control (Parkinson's). Serotonin: mood, sleep, appetite (↓ in depression). GABA: inhibitory (benzodiazepines enhance GABA). Glutamate: main excitatory NT. Acetylcholine: muscle contraction, memory, REM sleep." , front_translations: {"es":"Base Biológica del Comportamento: Neurotransmissores","de":"Biologische Grundlagen des Verhaltens: Neurotransmitter","fr":"Bases biologiques du comportement : neurotransmetteurs","tr":"Davranışın Biyolojik Temeli: Nörotransmitterler","nl":"Biologische basis van gedrag: neurotransmitters","ru":"Биологические основы поведения: нейромедиаторы","zh":"行为的生物学基础：神经递质","pt_BR":"Base Biológica do Comportamento: Neurotransmissores","pt_PT":"Base Biológica do Comportamento: Neurotransmissores"}, back_translations: {"es":"Dopamina: recompensa, motivación, controle motor (Parkinson). Serotonina: humor, sono, apetite (↓ en la depresión). GABA: inibitório (benzodiazepínicos potencializam el GABA). Glutamato: principal NT excitatório. Acetilcolina: contración muscular, memoria, sono REM.","de":"Dopamin: Belohnung, Motivation, Motorsteuerung (Parkinson). Serotonin: Stimmung, Schlaf, Appetit (↓ bei Depression). GABA: inhibitorisch (Benzodiazepine verstärken GABA). Glutamat: wichtigster exzitatorischer NT. Acetylcholin: Muskelkontraktion, Gedächtnis, REM-Schlaf.","fr":"Dopamine : récompense, motivation, contrôle moteur (Parkinson). Sérotonine : humeur, sommeil, appétit (↓ dans la dépression). GABA : inhibiteur (les benzodiazépines renforcent le GABA). Glutamate : principal NT excitateur. Acétylcholine : contraction musculaire, mémoire, sommeil paradoxal.","tr":"Dopamin: ödül, motivasyon, motor kontrol (Parkinson). Serotonin: duygudurum, uyku, iştah (depresyonda ↓). GABA: inhibitör (benzodiazepinler GABA'yı güçlendirir). Glutamat: başlıca eksitatör NT. Asetilkolin: kas kasılması, bellek, REM uykusu.","nl":"Dopamine: beloning, motivatie, motorische controle (Parkinson). Serotonine: stemming, slaap, eetlust (↓ bij depressie). GABA: inhibitorisch (benzodiazepinen versterken GABA). Glutamaat: belangrijkste excitatorische NT. Acetylcholine: spiercontractie, geheugen, REM-slaap.","ru":"Дофамин: вознаграждение, мотивация, моторный контроль (болезнь Паркинсона). Серотонин: настроение, сон, аппетит (↓ при депрессии). GABA: тормозной (бензодиазепины усиливают GABA). Глутамат: основной возбуждающий нейромедиатор. Ацетилхолин: сокращение мышц, память, REM-сон.","zh":"多巴胺：奖赏、动机、运动控制（帕金森病）。血清素：情绪、睡眠、食欲（抑郁症中↓）。GABA：抑制性（苯二氮卓类增强GABA）。谷氨酸：主要兴奋性神经递质。乙酰胆碱：肌肉收缩、记忆、REM睡眠。","pt_BR":"Dopamina: recompensa, motivação, controle motor (Parkinson). Serotonina: humor, sono, apetite (↓ na depressão). GABA: inibitório (benzodiazepínicos potencializam o GABA). Glutamato: principal NT excitatório. Acetilcolina: contração muscular, memória, sono REM.","pt_PT":"Dopamina: recompensa, motivação, controlo motor (Parkinson). Serotonina: humor, sono, apetite (↓ na depressão). GABA: inibitório (benzodiazepinas potenciam o GABA). Glutamato: principal NT excitatório. Acetilcolina: contração muscular, memória, sono REM."}},
  { id: 'dc-mcat-0101', deck_id: 'deck-mcat', sort_order: 101, front: "Sleep Stages and Brain Waves", back: "NREM 1: theta waves (light sleep). NREM 2: sleep spindles, K-complexes. NREM 3: delta waves (slow-wave, deep, restorative sleep). REM: theta/beta waves; dreaming; muscle atonia; memory consolidation. REM sleep disorder: lack of muscle atonia." , front_translations: {"es":"Estágios del Sono y Ondas Cerebrais","de":"Schlafstadien und Gehirnwellen","fr":"Stades du sommeil et ondes cérébrales","tr":"Uyku Evreleri ve Beyin Dalgaları","nl":"Slaapstadia en hersengolven","ru":"Стадии сна и мозговые волны","zh":"睡眠阶段与脑电波","pt_BR":"Estágios do Sono e Ondas Cerebrais","pt_PT":"Fases do Sono e Ondas Cerebrais"}, back_translations: {"es":"NREM 1: ondas teta (sono ligero). NREM 2: fusos del sono, complexos K. NREM 3: ondas delta (sono profundo, restaurador). REM: ondas teta/beta; sonhos; atonia muscular; consolidación de la memoria. Distúrbio del sono REM: falta de atonia muscular.","de":"NREM 1: Theta-Wellen (leichter Schlaf). NREM 2: Schlafspindeln, K-Komplexe. NREM 3: Delta-Wellen (Tiefschlaf, erholsamer Schlaf). REM: Theta-/Beta-Wellen; Träumen; Muskelatonie; Gedächtniskonsolidierung. REM-Schlaf-Verhaltensstörung: fehlende Muskelatonie.","fr":"NREM 1 : ondes thêta (sommeil léger). NREM 2 : fuseaux de sommeil, complexes K. NREM 3 : ondes delta (sommeil profond, réparateur). REM : ondes thêta/bêta ; rêves ; atonie musculaire ; consolidation de la mémoire. Trouble du sommeil paradoxal : absence d'atonie musculaire.","tr":"NREM 1: teta dalgaları (hafif uyku). NREM 2: uyku iğleri, K-kompleksleri. NREM 3: delta dalgaları (yavaş dalga, derin, onarıcı uyku). REM: teta/beta dalgaları; rüya görme; kas atonisi; bellek konsolidasyonu. REM uyku bozukluğu: kas atonisi eksikliği.","nl":"NREM 1: thetagolven (lichte slaap). NREM 2: slaapspoelen, K-complexen. NREM 3: deltagolven (diepe, herstellende slaap). REM: theta-/bètagolven; dromen; spieratonie; geheugenconsolidatie. REM-slaapstoornis: gebrek aan spieratonie.","ru":"NREM 1: тета-волны (лёгкий сон). NREM 2: сонные веретёна, K-комплексы. NREM 3: дельта-волны (медленноволновой, глубокий, восстановительный сон). REM: тета-/бета-волны; сновидения; мышечная атония; консолидация памяти. Расстройство REM-сна: отсутствие мышечной атонии.","zh":"NREM 1：θ波（浅睡眠）。NREM 2：睡眠纺锤波、K复合波。NREM 3：δ波（慢波深睡眠，恢复性睡眠）。REM：θ/β波；做梦；肌肉张力丧失；记忆巩固。REM睡眠障碍：缺乏肌肉张力丧失。","pt_BR":"NREM 1: ondas teta (sono leve). NREM 2: fusos do sono, complexos K. NREM 3: ondas delta (sono profundo, restaurador). REM: ondas teta/beta; sonhos; atonia muscular; consolidação da memória. Distúrbio do sono REM: falta de atonia muscular.","pt_PT":"NREM 1: ondas teta (sono leve). NREM 2: fusos do sono, complexos K. NREM 3: ondas delta (sono profundo, restaurador). REM: ondas teta/beta; sonhos; atonia muscular; consolidação da memória. Perturbação do sono REM: falta de atonia muscular."}},
  { id: 'dc-mcat-0102', deck_id: 'deck-mcat', sort_order: 102, front: "Sensory Perception: Signal Detection Theory", back: "Hits (correctly detect signal), misses (fail to detect), false alarms (detect absent signal), correct rejections. Sensitivity (d') reflects ability to discriminate signal from noise; criterion (β) reflects decision bias. Important in medical testing." , front_translations: {"es":"Percepción Sensorial: Teoria de Detección de Sinal","de":"Sensorische Wahrnehmung: Signalentdeckungstheorie","fr":"Perception sensorielle : théorie de la détection du signal","tr":"Duyusal Algı: Sinyal Tespit Teorisi","nl":"Zintuiglijke waarneming: signaaldetectietheorie","ru":"Сенсорное восприятие: теория обнаружения сигнала","zh":"感知觉：信号检测理论","pt_BR":"Percepção Sensorial: Teoria de Detecção de Sinal","pt_PT":"Perceção Sensorial: Teoria de Deteção de Sinal"}, back_translations: {"es":"Acertos (detección correta del señal), falhas (no detección), alarmes falsos (detección de señal ausente), rejeiciones corretas. Sensibilidad (d') reflete a capacidad de discriminar señal del ruído; critério (β) reflete viés de decisão. Importante en pruebas médicos.","de":"Treffer (Signal korrekt erkannt), Auslasser (Signal nicht erkannt), falscher Alarm (abwesendes Signal erkannt), korrekte Zurückweisungen. Sensitivität (d') spiegelt die Fähigkeit wider, Signal von Rauschen zu unterscheiden; Kriterium (β) spiegelt Entscheidungsverzerrung wider. Wichtig in der medizinischen Diagnostik.","fr":"Détections correctes (signal correctement détecté), omissions (signal non détecté), fausses alarmes (signal absent détecté), rejets corrects. La sensibilité (d') reflète la capacité à discriminer le signal du bruit ; le critère (β) reflète le biais décisionnel. Important dans les tests médicaux.","tr":"İsabet (sinyali doğru tespit etme), kaçırma (tespit edememe), yanlış alarm (olmayan sinyali tespit etme), doğru ret. Duyarlılık (d') sinyali gürültüden ayırt etme yeteneğini yansıtır; kriter (β) karar yanlılığını yansıtır. Tıbbi testlerde önemlidir.","nl":"Hits (signaal correct gedetecteerd), missers (signaal niet gedetecteerd), vals alarm (afwezig signaal gedetecteerd), correcte afwijzingen. Gevoeligheid (d') weerspiegelt het vermogen om signaal van ruis te onderscheiden; criterium (β) weerspiegelt beslissingsvertekening. Belangrijk bij medische testen.","ru":"Попадания (правильное обнаружение сигнала), пропуски (необнаружение сигнала), ложные тревоги (обнаружение отсутствующего сигнала), правильные отклонения. Чувствительность (d') отражает способность отличать сигнал от шума; критерий (β) отражает склонность к принятию решения. Важно в медицинской диагностике.","zh":"击中（正确检测到信号）、漏报（未能检测到信号）、虚报（检测到不存在的信号）、正确拒斥。灵敏度（d'）反映区分信号与噪声的能力；判断标准（β）反映决策偏向。在医学检测中很重要。","pt_BR":"Acertos (detecção correta do sinal), falhas (não detecção), alarmes falsos (detecção de sinal ausente), rejeições corretas. Sensibilidade (d') reflete a capacidade de discriminar sinal do ruído; critério (β) reflete viés de decisão. Importante em testes médicos.","pt_PT":"Acertos (deteção correta do sinal), falhas (não deteção), alarmes falsos (deteção de sinal ausente), rejeições corretas. Sensibilidade (d') reflete a capacidade de discriminar sinal do ruído; critério (β) reflete viés de decisão. Importante em testes médicos."}},
  { id: 'dc-mcat-0103', deck_id: 'deck-mcat', sort_order: 103, front: "Gestalt Principles of Perception", back: "Proximity, similarity, continuity, closure, figure-ground, common fate. The brain organizes sensory input into meaningful wholes (Gestalt = 'whole form'). These principles explain how we perceive organized patterns in everyday vision." , front_translations: {"es":"Princípios de la Gestalt de Percepción","de":"Gestaltprinzipien der Wahrnehmung","fr":"Principes de la Gestalt en perception","tr":"Gestalt Algı İlkeleri","nl":"Gestaltprincipes van waarneming","ru":"Гештальт-принципы восприятия","zh":"格式塔知觉原理","pt_BR":"Princípios da Gestalt de Percepção","pt_PT":"Princípios da Gestalt de Perceção"}, back_translations: {"es":"Proximidad, similaridad, continuidad, fechamento, figura-fundo, destino comum. El cerebro organiza a entrada sensorial en conjuntos significativos (Gestalt = 'forma intera'). Esses principios explicam como percebemos padrões organizados en la visão cotidiana.","de":"Nähe, Ähnlichkeit, Kontinuität, Geschlossenheit, Figur-Grund, gemeinsames Schicksal. Das Gehirn organisiert sensorische Eingaben zu bedeutungsvollen Ganzen (Gestalt = 'ganze Form'). Diese Prinzipien erklären, wie wir im Alltag organisierte Muster wahrnehmen.","fr":"Proximité, similarité, continuité, clôture, figure-fond, destin commun. Le cerveau organise les entrées sensorielles en ensembles significatifs (Gestalt = « forme entière »). Ces principes expliquent comment nous percevons des motifs organisés dans la vision quotidienne.","tr":"Yakınlık, benzerlik, süreklilik, tamamlama, figür-zemin, ortak kader. Beyin duyusal girdileri anlamlı bütünler halinde düzenler (Gestalt = 'bütün biçim'). Bu ilkeler günlük görüşte düzenli kalıpları nasıl algıladığımızı açıklar.","nl":"Nabijheid, gelijkenis, continuïteit, geslotenheid, figuur-grond, gemeenschappelijk lot. Het brein organiseert zintuiglijke input tot betekenisvolle gehelen (Gestalt = 'gehele vorm'). Deze principes verklaren hoe we georganiseerde patronen waarnemen in het dagelijkse zien.","ru":"Близость, сходство, непрерывность, замкнутость, фигура-фон, общая судьба. Мозг организует сенсорные данные в осмысленные целостности (Gestalt = «целостная форма»). Эти принципы объясняют, как мы воспринимаем организованные паттерны в повседневном зрении.","zh":"邻近性、相似性、连续性、封闭性、图形-背景、共同命运。大脑将感觉输入组织成有意义的整体（Gestalt=\\\"完整形式\\\"）。这些原理解释了我们如何在日常视觉中感知有组织的模式。","pt_BR":"Proximidade, similaridade, continuidade, fechamento, figura-fundo, destino comum. O cérebro organiza a entrada sensorial em conjuntos significativos (Gestalt = 'forma inteira'). Esses princípios explicam como percebemos padrões organizados na visão cotidiana.","pt_PT":"Proximidade, similaridade, continuidade, fechamento, figura-fundo, destino comum. O cérebro organiza a entrada sensorial em conjuntos significativos (Gestalt = 'forma inteira'). Estes princípios explicam como percecionamos padrões organizados na visão quotidiana."}},
  { id: 'dc-mcat-0104', deck_id: 'deck-mcat', sort_order: 104, front: "Emotion Theories", back: "James-Lange: physiological response first → emotion follows. Cannon-Bard: physiological response and emotion occur simultaneously. Schachter-Singer (Two-Factor): arousal + cognitive label → emotion. Lazarus: cognitive appraisal is necessary for emotion." , front_translations: {"es":"Teorias de la Emoción","de":"Emotionstheorien","fr":"Théories des émotions","tr":"Duygu Teorileri","nl":"Emotietheorieën","ru":"Теории эмоций","zh":"情绪理论","pt_BR":"Teorias da Emoção","pt_PT":"Teorias da Emoção"}, back_translations: {"es":"James-Lange: respuesta fisiológica primero → emoción sigue. Cannon-Bard: respuesta fisiológica y emoción ocurren simultáneamente. Schachter-Singer (Dois Fatores): ativación + rótulo cognitivo → emoción. Lazarus: avaliación cognitiva es necesaria para a emoción.","de":"James-Lange: physiologische Reaktion zuerst → Emotion folgt. Cannon-Bard: physiologische Reaktion und Emotion treten gleichzeitig auf. Schachter-Singer (Zwei-Faktoren-Theorie): Erregung + kognitive Bezeichnung → Emotion. Lazarus: kognitive Bewertung ist für Emotion notwendig.","fr":"James-Lange : réponse physiologique d'abord → l'émotion suit. Cannon-Bard : réponse physiologique et émotion surviennent simultanément. Schachter-Singer (deux facteurs) : activation + étiquette cognitive → émotion. Lazarus : l'évaluation cognitive est nécessaire pour l'émotion.","tr":"James-Lange: önce fizyolojik tepki → ardından duygu. Cannon-Bard: fizyolojik tepki ve duygu eş zamanlı gerçekleşir. Schachter-Singer (İki Faktör): uyarılma + bilişsel etiketleme → duygu. Lazarus: bilişsel değerlendirme duygu için gereklidir.","nl":"James-Lange: fysiologische reactie eerst → emotie volgt. Cannon-Bard: fysiologische reactie en emotie treden gelijktijdig op. Schachter-Singer (tweefactorentheorie): arousal + cognitief label → emotie. Lazarus: cognitieve beoordeling is noodzakelijk voor emotie.","ru":"Джеймса-Ланге: сначала физиологическая реакция → затем эмоция. Кэннона-Барда: физиологическая реакция и эмоция возникают одновременно. Шехтера-Сингера (двухфакторная): возбуждение + когнитивная оценка → эмоция. Лазарус: когнитивная оценка необходима для эмоции.","zh":"James-Lange：先有生理反应→后产生情绪。Cannon-Bard：生理反应和情绪同时发生。Schachter-Singer（双因素理论）：唤醒+认知标记→情绪。Lazarus：认知评价是情绪的必要条件。","pt_BR":"James-Lange: resposta fisiológica primeiro → emoção segue. Cannon-Bard: resposta fisiológica e emoção ocorrem simultaneamente. Schachter-Singer (Dois Fatores): ativação + rótulo cognitivo → emoção. Lazarus: avaliação cognitiva é necessária para a emoção.","pt_PT":"James-Lange: resposta fisiológica primeiro → emoção segue. Cannon-Bard: resposta fisiológica e emoção ocorrem simultaneamente. Schachter-Singer (Dois Fatores): ativação + rótulo cognitivo → emoção. Lazarus: avaliação cognitiva é necessária para a emoção."}},
  { id: 'dc-mcat-0105', deck_id: 'deck-mcat', sort_order: 105, front: "Identity and Self-Concept", back: "Self-concept: beliefs and knowledge about oneself. Self-esteem: evaluative component (how good/bad one feels about oneself). Social identity theory (Tajfel): people derive identity from group membership; ingroup favoritism, outgroup derogation." , front_translations: {"es":"Identidad y Autoconceito","de":"Identität und Selbstkonzept","fr":"Identité et concept de soi","tr":"Kimlik ve Benlik Kavramı","nl":"Identiteit en zelfconcept","ru":"Идентичность и Я-концепция","zh":"身份认同与自我概念","pt_BR":"Identidade e Autoconceito","pt_PT":"Identidade e Autoconceito"}, back_translations: {"es":"Autoconceito: creencias y conocimiento sobre si mismo. Autoestima: componente avaliativo (quão bem/mal a persona se sente sobre si misma). Teoria de la identidad social (Tajfel): personas derivam identidad de la pertença al grupo; favoritismo endogrupal, desfavorecimento exogrupal.","de":"Selbstkonzept: Überzeugungen und Wissen über sich selbst. Selbstwertgefühl: bewertende Komponente (wie gut/schlecht man sich selbst empfindet). Soziale Identitätstheorie (Tajfel): Menschen leiten ihre Identität aus der Gruppenzugehörigkeit ab; Eigengruppenbevorzugung, Fremdgruppenabwertung.","fr":"Concept de soi : croyances et connaissances sur soi-même. Estime de soi : composante évaluative (comment on se sent à propos de soi-même). Théorie de l'identité sociale (Tajfel) : les gens tirent leur identité de leur appartenance à un groupe ; favoritisme endogroupe, dévalorisation exogroupe.","tr":"Benlik kavramı: kişinin kendisi hakkındaki inançları ve bilgisi. Özsaygı: değerlendirici bileşen (kişinin kendini ne kadar iyi/kötü hissettiği). Sosyal kimlik teorisi (Tajfel): insanlar kimliklerini grup üyeliğinden elde eder; iç-grup kayırmacılığı, dış-grup aşağılaması.","nl":"Zelfconcept: overtuigingen en kennis over zichzelf. Zelfwaardering: evaluatieve component (hoe goed/slecht men zich over zichzelf voelt). Sociale identiteitstheorie (Tajfel): mensen ontlenen identiteit aan groepslidmaatschap; ingroepfavoritisme, uitgroepdevaluatie.","ru":"Я-концепция: убеждения и знания о себе. Самооценка: оценочный компонент (насколько хорошо/плохо человек относится к себе). Теория социальной идентичности (Тэджфел): люди черпают идентичность из принадлежности к группе; фаворитизм к своей группе, дискриминация чужой группы.","zh":"自我概念：关于自身的信念和知识。自尊：评价性成分（对自己感觉好/坏的程度）。社会认同理论（Tajfel）：人们从群体成员身份中获取认同；内群体偏好，外群体贬低。","pt_BR":"Autoconceito: crenças e conhecimento sobre si mesmo. Autoestima: componente avaliativo (quão bem/mal a pessoa se sente sobre si mesma). Teoria da identidade social (Tajfel): pessoas derivam identidade da pertença ao grupo; favoritismo endogrupal, desfavorecimento exogrupal.","pt_PT":"Autoconceito: crenças e conhecimento sobre si próprio. Autoestima: componente avaliativo (quão bem/mal a pessoa se sente sobre si mesma). Teoria da identidade social (Tajfel): as pessoas derivam identidade da pertença ao grupo; favoritismo endogrupal, desfavorecimento exogrupal."}},
  // --- Additional MCAT High-Yield Topics ---
  { id: 'dc-mcat-0106', deck_id: 'deck-mcat', sort_order: 106, front: "Endocrine System: Pituitary Hormones", back: "Anterior pituitary (adenohypophysis): GH, TSH, ACTH, FSH, LH, prolactin (regulated by hypothalamic releasing/inhibiting hormones). Posterior pituitary (neurohypophysis): stores and releases ADH (vasopressin) and oxytocin (made in hypothalamus)." , front_translations: {"es":"Sistema Endócrino: Hormonios de la Hipófise","de":"Endokrines System: Hypophysenhormone","fr":"Système endocrinien : hormones hypophysaires","tr":"Endokrin Sistem: Hipofiz Hormonları","nl":"Endocrien systeem: hypofysehormonen","ru":"Эндокринная система: гормоны гипофиза","zh":"内分泌系统：垂体激素","pt_BR":"Sistema Endócrino: Hormônios da Hipófise","pt_PT":"Sistema Endócrino: Hormonas da Hipófise"}, back_translations: {"es":"Hipófise anterior (adeno-hipófise): GH, TSH, ACTH, FSH, LH, prolactina (regulados por hormonas hipotalamicos de liberación/inibición). Hipófise posterior (neuro-hipófise): almacena y libera ADH (vasopressina) y ocitocina (producidos en el hipotálamo).","de":"Hypophysenvorderlappen (Adenohypophyse): GH, TSH, ACTH, FSH, LH, Prolaktin (reguliert durch hypothalamische Releasing-/Inhibiting-Hormone). Hypophysenhinterlappen (Neurohypophyse): speichert und setzt ADH (Vasopressin) und Oxytocin frei (im Hypothalamus gebildet).","fr":"Hypophyse antérieure (adénohypophyse) : GH, TSH, ACTH, FSH, LH, prolactine (régulées par les hormones hypothalamiques de libération/inhibition). Hypophyse postérieure (neurohypophyse) : stocke et libère ADH (vasopressine) et ocytocine (produites dans l'hypothalamus).","tr":"Ön hipofiz (adenohipofiz): GH, TSH, ACTH, FSH, LH, prolaktin (hipotalamik salgılatıcı/baskılayıcı hormonlar tarafından düzenlenir). Arka hipofiz (nörohipofiz): ADH (vazopressin) ve oksitosin depolar ve salgılar (hipotalamusta üretilir).","nl":"Adenohypofyse (voorste kwab): GH, TSH, ACTH, FSH, LH, prolactine (gereguleerd door hypothalamische releasing-/inhibiting-hormonen). Neurohypofyse (achterste kwab): slaat ADH (vasopressine) en oxytocine op en geeft ze af (gemaakt in hypothalamus).","ru":"Передняя доля гипофиза (аденогипофиз): GH, TSH, ACTH, FSH, LH, пролактин (регулируются рилизинг-/ингибирующими гормонами гипоталамуса). Задняя доля гипофиза (нейрогипофиз): хранит и выделяет ADH (вазопрессин) и окситоцин (синтезируются в гипоталамусе).","zh":"垂体前叶（腺垂体）：GH、TSH、ACTH、FSH、LH、催乳素（受下丘脑释放/抑制激素调节）。垂体后叶（神经垂体）：储存并释放ADH（加压素）和催产素（在下丘脑合成）。","pt_BR":"Hipófise anterior (adeno-hipófise): GH, TSH, ACTH, FSH, LH, prolactina (regulados por hormônios hipotalâmicos de liberação/inibição). Hipófise posterior (neuro-hipófise): armazena e libera ADH (vasopressina) e ocitocina (produzidos no hipotálamo).","pt_PT":"Hipófise anterior (adeno-hipófise): GH, TSH, ACTH, FSH, LH, prolactina (regulados por hormonas hipotalâmicas de libertação/inibição). Hipófise posterior (neuro-hipófise): armazena e liberta ADH (vasopressina) e ocitocina (produzidos no hipotálamo)."}},
  { id: 'dc-mcat-0107', deck_id: 'deck-mcat', sort_order: 107, front: "Renal Tubule: Reabsorption and Secretion", back: "Proximal convoluted tubule: reabsorbs ~67% Na⁺, glucose, amino acids, HCO₃⁻. Loop of Henle: concentrating gradient. DCT: aldosterone regulates Na⁺/K⁺. Collecting duct: ADH regulates water reabsorption. 'Loops' create hyperosmotic medullary gradient." , front_translations: {"es":"Túbulo Renal: Reabsorción y Secreción","de":"Nierentubulus: Reabsorption und Sekretion","fr":"Tubule rénal : réabsorption et sécrétion","tr":"Renal Tübül: Geri Emilim ve Sekresyon","nl":"Niertubulus: reabsorptie en secretie","ru":"Почечный каналец: реабсорбция и секреция","zh":"肾小管：重吸收与分泌","pt_BR":"Túbulo Renal: Reabsorção e Secreção","pt_PT":"Túbulo Renal: Reabsorção e Secreção"}, back_translations: {"es":"Túbulo contorcido proximal: reabsorve ~67% de Na⁺, glicose, aminoácidos, HCO₃⁻. Alça de Henle: gradiente de concentración. DCT: aldosterona regula Na⁺/K⁺. Ducto coletor: ADH regula a reabsorción de agua. As alças crean el gradiente medular hiperosmótico.","de":"Proximaler gewundener Tubulus: resorbiert ~67% Na⁺, Glukose, Aminosäuren, HCO₃⁻. Henle-Schleife: Konzentrierungsgradient. DCT: Aldosteron reguliert Na⁺/K⁺. Sammelrohr: ADH reguliert Wasserreabsorption. Die Schleifen erzeugen den hyperosmotischen medullären Gradienten.","fr":"Tubule contourné proximal : réabsorbe ~67% du Na⁺, glucose, acides aminés, HCO₃⁻. Anse de Henle : gradient de concentration. DCT : l'aldostérone régule Na⁺/K⁺. Canal collecteur : l'ADH régule la réabsorption d'eau. Les anses créent le gradient médullaire hyperosmotique.","tr":"Proksimal kıvrımlı tübül: ~%67 Na⁺, glukoz, amino asitler, HCO₃⁻ geri emilir. Henle kulpu: konsantrasyon gradyanı. DCT: aldosteron Na⁺/K⁺'ı düzenler. Toplayıcı kanal: ADH su geri emilimini düzenler. Kulplar hiperosmotik medüller gradyanı oluşturur.","nl":"Proximale gekronkelde tubulus: reabsorbeert ~67% Na⁺, glucose, aminozuren, HCO₃⁻. Lis van Henle: concentratiegradient. DCT: aldosteron reguleert Na⁺/K⁺. Verzamelbuis: ADH reguleert waterreabsorptie. De lissen creëren de hyperosmotische medullaire gradiënt.","ru":"Проксимальный извитой каналец: реабсорбирует ~67% Na⁺, глюкозу, аминокислоты, HCO₃⁻. Петля Генле: концентрирующий градиент. DCT: альдостерон регулирует Na⁺/K⁺. Собирательный проток: ADH регулирует реабсорбцию воды. Петли создают гиперосмотический мозговой градиент.","zh":"近端小管：重吸收约67%的Na⁺、葡萄糖、氨基酸、HCO₃⁻。亨利环：浓缩梯度。DCT：醛固酮调节Na⁺/K⁺。集合管：ADH调节水的重吸收。环形结构创造高渗髓质梯度。","pt_BR":"Túbulo contorcido proximal: reabsorve ~67% de Na⁺, glicose, aminoácidos, HCO₃⁻. Alça de Henle: gradiente de concentração. DCT: aldosterona regula Na⁺/K⁺. Ducto coletor: ADH regula a reabsorção de água. As alças criam o gradiente medular hiperosmótico.","pt_PT":"Túbulo contornado proximal: reabsorve ~67% de Na⁺, glicose, aminoácidos, HCO₃⁻. Ansa de Henle: gradiente de concentração. DCT: aldosterona regula Na⁺/K⁺. Ducto coletor: ADH regula a reabsorção de água. As ansas criam o gradiente medular hiperosmótico."}},
  { id: 'dc-mcat-0108', deck_id: 'deck-mcat', sort_order: 108, front: "Renin-Angiotensin-Aldosterone System (RAAS)", back: "Low BP/blood volume → kidney releases renin → cleaves angiotensinogen to angiotensin I → ACE converts to angiotensin II → causes vasoconstriction + aldosterone release (Na⁺/water retention) + ADH release → raises BP." , front_translations: {"es":"Sistema Renina-Angiotensina-Aldosterona (RAAS)","de":"Renin-Angiotensin-Aldosteron-System (RAAS)","fr":"Système rénine-angiotensine-aldostérone (RAAS)","tr":"Renin-Anjiyotensin-Aldosteron Sistemi (RAAS)","nl":"Renine-angiotensine-aldosteronsysteem (RAAS)","ru":"Ренин-ангиотензин-альдостероновая система (RAAS)","zh":"肾素-血管紧张素-醛固酮系统 (RAAS)","pt_BR":"Sistema Renina-Angiotensina-Aldosterona (RAAS)","pt_PT":"Sistema Renina-Angiotensina-Aldosterona (RAAS)"}, back_translations: {"es":"PA baja/volumen sanguíneo bajo → riñón libera renina → cliva angiotensinogenio en angiotensina I → ACE convierte en angiotensina II → causa vasoconstrición + liberación de aldosterona (retención de Na⁺/agua) + liberación de ADH → eleva a PA.","de":"Niedriger Blutdruck/Blutvolumen → Niere setzt Renin frei → spaltet Angiotensinogen zu Angiotensin I → ACE wandelt zu Angiotensin II um → verursacht Vasokonstriktion + Aldosteron-Freisetzung (Na⁺/Wasserretention) + ADH-Freisetzung → erhöht den Blutdruck.","fr":"PA basse/volume sanguin bas → le rein libère la rénine → clive l'angiotensinogène en angiotensine I → l'ACE convertit en angiotensine II → provoque vasoconstriction + libération d'aldostérone (rétention Na⁺/eau) + libération d'ADH → augmente la PA.","tr":"Düşük KB/kan hacmi → böbrek renin salgılar → anjiyotensinojeni anjiyotensin I'e parçalar → ACE anjiyotensin II'ye dönüştürür → vazokonstriksiyona + aldosteron salınımına (Na⁺/su tutulumu) + ADH salınımına neden olur → KB'yi yükseltir.","nl":"Lage bloeddruk/bloedvolume → nier geeft renine af → klieft angiotensinogeen tot angiotensine I → ACE converteert naar angiotensine II → veroorzaakt vasoconstrictie + aldosteronafgifte (Na⁺/waterretentie) + ADH-afgifte → verhoogt bloeddruk.","ru":"Низкое АД/объём крови → почка выделяет ренин → расщепляет ангиотензиноген до ангиотензина I → ACE превращает в ангиотензин II → вызывает вазоконстрикцию + выброс альдостерона (задержка Na⁺/воды) + выброс ADH → повышает АД.","zh":"低血压/血容量→肾脏释放肾素→将血管紧张素原裂解为血管紧张素I→ACE转化为血管紧张素II→引起血管收缩+醛固酮释放（Na⁺/水潴留）+ADH释放→升高血压。","pt_BR":"PA baixa/volume sanguíneo baixo → rim libera renina → cliva angiotensinogênio em angiotensina I → ACE converte em angiotensina II → causa vasoconstrição + liberação de aldosterona (retenção de Na⁺/água) + liberação de ADH → eleva a PA.","pt_PT":"PA baixa/volume sanguíneo baixo → rim liberta renina → cliva angiotensinogénio em angiotensina I → ACE converte em angiotensina II → causa vasoconstrição + libertação de aldosterona (retenção de Na⁺/água) + libertação de ADH → eleva a PA."}},
  { id: 'dc-mcat-0109', deck_id: 'deck-mcat', sort_order: 109, front: "Cardiac Output", back: "CO = Heart Rate × Stroke Volume. Normal CO ≈ 5 L/min. Stroke volume is influenced by preload (Frank-Starling: more stretch → more force), afterload (resistance against which heart pumps), and contractility." , front_translations: {"es":"Débito Cardíaco","de":"Herzzeitvolumen","fr":"Débit cardiaque","tr":"Kardiyak Debi","nl":"Hartminuutvolume","ru":"Сердечный выброс","zh":"心输出量","pt_BR":"Débito Cardíaco","pt_PT":"Débito Cardíaco"}, back_translations: {"es":"DC = Frequencia Cardíaca × Volume Sistólico. DC normal ≈ 5 L/min. El volumen sistólico es influenciado por la pré-carga (Frank-Starling: más estiramento → más fuerza), pós-carga (resistencia contra a qual el corazón bombeia) y contratilidad.","de":"HZV = Herzfrequenz × Schlagvolumen. Normales HZV ≈ 5 L/min. Das Schlagvolumen wird beeinflusst durch Vorlast (Frank-Starling: mehr Dehnung → mehr Kraft), Nachlast (Widerstand, gegen den das Herz pumpt) und Kontraktilität.","fr":"DC = Fréquence cardiaque × Volume d'éjection systolique. DC normal ≈ 5 L/min. Le volume d'éjection est influencé par la précharge (Frank-Starling : plus d'étirement → plus de force), la postcharge (résistance contre laquelle le cœur pompe) et la contractilité.","tr":"KD = Kalp Hızı × Atım Hacmi. Normal KD ≈ 5 L/dk. Atım hacmi ön yük (Frank-Starling: daha fazla gerilme → daha fazla kuvvet), ard yük (kalbin pompaladığı direnç) ve kontraktilite tarafından etkilenir.","nl":"HMV = Hartfrequentie × Slagvolume. Normaal HMV ≈ 5 L/min. Slagvolume wordt beïnvloed door preload (Frank-Starling: meer rek → meer kracht), afterload (weerstand waartegen het hart pompt) en contractiliteit.","ru":"СВ = ЧСС × Ударный объём. Нормальный СВ ≈ 5 л/мин. Ударный объём зависит от преднагрузки (Франка-Старлинга: больше растяжение → больше сила), постнагрузки (сопротивление, против которого качает сердце) и сократимости.","zh":"CO = 心率 × 每搏输出量。正常CO约5 L/min。每搏输出量受前负荷（Frank-Starling定律：更多拉伸→更大力量）、后负荷（心脏泵血所对抗的阻力）和收缩力的影响。","pt_BR":"DC = Frequência Cardíaca × Volume Sistólico. DC normal ≈ 5 L/min. O volume sistólico é influenciado pela pré-carga (Frank-Starling: mais estiramento → mais força), pós-carga (resistência contra a qual o coração bombeia) e contratilidade.","pt_PT":"DC = Frequência Cardíaca × Volume Sistólico. DC normal ≈ 5 L/min. O volume sistólico é influenciado pela pré-carga (Frank-Starling: mais estiramento → mais força), pós-carga (resistência contra a qual o coração bombeia) e contratilidade."}},
  { id: 'dc-mcat-0110', deck_id: 'deck-mcat', sort_order: 110, front: "Hemoglobin Oxygen Dissociation Curve", back: "Sigmoidal curve due to cooperative binding. Shifts right (reduced O₂ affinity) with ↑T, ↑CO₂, ↑[H⁺] (acidosis), ↑2,3-BPG (Bohr effect) — facilitates O₂ unloading in active tissues. Shifts left in lungs (high O₂, low CO₂)." , front_translations: {"es":"Curva de Dissociación Oxígeno-Hemoglobina","de":"Hämoglobin-Sauerstoff-Dissoziationskurve","fr":"Courbe de dissociation de l'oxyhémoglobine","tr":"Hemoglobin Oksijen Disosiasyon Eğrisi","nl":"Hemoglobine-zuurstofdissociatiecurve","ru":"Кривая диссоциации оксигемоглобина","zh":"血红蛋白-氧解离曲线","pt_BR":"Curva de Dissociação Oxigênio-Hemoglobina","pt_PT":"Curva de Dissociação Oxigénio-Hemoglobina"}, back_translations: {"es":"Curva sigmoide debido a la enlace cooperativa. Desvio para a direita (afinidad por El₂ reduzida) con ↑T, ↑CO₂, ↑[H⁺] (acidose), ↑2,3-BPG (efecto Bohr) — facilita a liberación de El₂ en los tejidos ativos. Desvio para a esquerda en los pulmones (El₂ alto, CO₂ bajo).","de":"Sigmoidale Kurve aufgrund kooperativer Bindung. Rechtsverschiebung (verringerte O₂-Affinität) bei ↑T, ↑CO₂, ↑[H⁺] (Azidose), ↑2,3-BPG (Bohr-Effekt) — erleichtert O₂-Abgabe in aktiven Geweben. Linksverschiebung in der Lunge (hoher O₂, niedriger CO₂).","fr":"Courbe sigmoïde due à la liaison coopérative. Déplacement vers la droite (affinité O₂ réduite) avec ↑T, ↑CO₂, ↑[H⁺] (acidose), ↑2,3-BPG (effet Bohr) — facilite le relargage d'O₂ dans les tissus actifs. Déplacement vers la gauche dans les poumons (O₂ élevé, CO₂ bas).","tr":"Kooperatif bağlanma nedeniyle sigmoid eğri. Sağa kayma (azalmış O₂ afinitesi): ↑T, ↑CO₂, ↑[H⁺] (asidoz), ↑2,3-BPG (Bohr etkisi) — aktif dokularda O₂ bırakılmasını kolaylaştırır. Akciğerlerde sola kayma (yüksek O₂, düşük CO₂).","nl":"Sigmoïdale curve door coöperatieve binding. Verschuift naar rechts (verlaagde O₂-affiniteit) bij ↑T, ↑CO₂, ↑[H⁺] (acidose), ↑2,3-BPG (Bohr-effect) — vergemakkelijkt O₂-afgifte in actieve weefsels. Verschuift naar links in de longen (hoog O₂, laag CO₂).","ru":"Сигмоидная кривая из-за кооперативного связывания. Сдвиг вправо (снижение сродства к O₂) при ↑T, ↑CO₂, ↑[H⁺] (ацидоз), ↑2,3-БФГ (эффект Бора) — способствует отдаче O₂ в активных тканях. Сдвиг влево в лёгких (высокий O₂, низкий CO₂).","zh":"由于协同结合呈S形曲线。右移（O₂亲和力降低）：↑T、↑CO₂、↑[H⁺]（酸中毒）、↑2,3-BPG（Bohr效应）——促进活跃组织中O₂的释放。在肺部左移（高O₂、低CO₂）。","pt_BR":"Curva sigmoide devido à ligação cooperativa. Desvio para a direita (afinidade por O₂ reduzida) com ↑T, ↑CO₂, ↑[H⁺] (acidose), ↑2,3-BPG (efeito Bohr) — facilita a liberação de O₂ nos tecidos ativos. Desvio para a esquerda nos pulmões (O₂ alto, CO₂ baixo).","pt_PT":"Curva sigmoide devido à ligação cooperativa. Desvio para a direita (afinidade por O₂ reduzida) com ↑T, ↑CO₂, ↑[H⁺] (acidose), ↑2,3-BPG (efeito Bohr) — facilita a libertação de O₂ nos tecidos ativos. Desvio para a esquerda nos pulmões (O₂ alto, CO₂ baixo)."}},
  { id: 'dc-mcat-0111', deck_id: 'deck-mcat', sort_order: 111, front: "Blood Pressure Regulation Summary", back: "Short-term: baroreceptors (carotid sinus/aortic arch) → ANS adjustments (HR, vasomotor tone). Long-term: RAAS (sodium/water balance), ADH (water reabsorption). ANS: sympathetic increases BP; parasympathetic decreases HR." , front_translations: {"es":"Resumo de la Regulación de la Presión Arterial","de":"Zusammenfassung der Blutdruckregulation","fr":"Résumé de la régulation de la pression artérielle","tr":"Kan Basıncı Regülasyonu Özeti","nl":"Samenvatting bloeddrukregulatie","ru":"Обзор регуляции артериального давления","zh":"血压调节总结","pt_BR":"Resumo da Regulação da Pressão Arterial","pt_PT":"Resumo da Regulação da Pressão Arterial"}, back_translations: {"es":"Curto prazo: barorreceptores (seio carotídeo/arco aórtico) → ajustes del SNA (FC, tonus vasomotor). Longo prazo: RAAS (equilíbrio sódio/agua), ADH (reabsorción de agua). SNA: simpático aumenta a PA; parassimpático disminuye a FC.","de":"Kurzfristig: Barorezeptoren (Karotissinus/Aortenbogen) → ANS-Anpassungen (HF, Vasomotorik). Langfristig: RAAS (Natrium-/Wasserhaushalt), ADH (Wasserreabsorption). ANS: Sympathikus erhöht den Blutdruck; Parasympathikus senkt die Herzfrequenz.","fr":"Court terme : barorécepteurs (sinus carotidien/arc aortique) → ajustements du SNA (FC, tonus vasomoteur). Long terme : RAAS (équilibre sodium/eau), ADH (réabsorption d'eau). SNA : le sympathique augmente la PA ; le parasympathique diminue la FC.","tr":"Kısa vadeli: baroreseptörler (karotis sinüsü/aort arkı) → OSS ayarlamaları (KH, vazomotor tonus). Uzun vadeli: RAAS (sodyum/su dengesi), ADH (su geri emilimi). OSS: sempatik KB'yi artırır; parasempatik KH'yi azaltır.","nl":"Korte termijn: baroreceptoren (sinus caroticus/aortaboog) → ANS-aanpassingen (HF, vasomotorische tonus). Lange termijn: RAAS (natrium-/waterbalans), ADH (waterreabsorptie). ANS: sympathisch verhoogt bloeddruk; parasympathisch verlaagt hartfrequentie.","ru":"Краткосрочно: барорецепторы (каротидный синус/дуга аорты) → регуляция ВНС (ЧСС, сосудистый тонус). Долгосрочно: RAAS (баланс натрия/воды), ADH (реабсорбция воды). ВНС: симпатическая повышает АД; парасимпатическая снижает ЧСС.","zh":"短期：压力感受器（颈动脉窦/主动脉弓）→自主神经系统调节（心率、血管运动张力）。长期：RAAS（钠/水平衡）、ADH（水重吸收）。自主神经系统：交感神经升高血压；副交感神经降低心率。","pt_BR":"Curto prazo: barorreceptores (seio carotídeo/arco aórtico) → ajustes do SNA (FC, tônus vasomotor). Longo prazo: RAAS (equilíbrio sódio/água), ADH (reabsorção de água). SNA: simpático aumenta a PA; parassimpático diminui a FC.","pt_PT":"Curto prazo: barorreceptores (seio carotídeo/arco aórtico) → ajustes do SNA (FC, tónus vasomotor). Longo prazo: RAAS (equilíbrio sódio/água), ADH (reabsorção de água). SNA: simpático aumenta a PA; parassimpático diminui a FC."}},
  { id: 'dc-mcat-0112', deck_id: 'deck-mcat', sort_order: 112, front: "Coagulation Cascade Overview", back: "Extrinsic pathway: tissue factor (III) + VII → activated. Intrinsic pathway: XII, XI, IX, VIII. Both converge at factor X → Xa + Va → prothrombin (II) → thrombin → fibrinogen → fibrin clot. Warfarin blocks vitamin K-dependent factors (II, VII, IX, X)." , front_translations: {"es":"Visão Geral de la Cascata de Coagulación","de":"Überblick über die Gerinnungskaskade","fr":"Aperçu de la cascade de coagulation","tr":"Pıhtılaşma Kaskadına Genel Bakış","nl":"Overzicht stollingscascade","ru":"Обзор каскада свёртывания крови","zh":"凝血级联反应概述","pt_BR":"Visão Geral da Cascata de Coagulação","pt_PT":"Visão Geral da Cascata de Coagulação"}, back_translations: {"es":"Via extrínseca: fator tecidual (III) + VII → ativados. Via intrínseca: XII, XI, IX, VIII. Ambas convergem en el fator X → Xa + Va → protrombina (II) → trombina → fibrinogenio → coágulo de fibrina. Varfarina bloqueia fatores dependentes de vitamina K (II, VII, IX, X).","de":"Extrinsischer Weg: Gewebefaktor (III) + VII → aktiviert. Intrinsischer Weg: XII, XI, IX, VIII. Beide konvergieren bei Faktor X → Xa + Va → Prothrombin (II) → Thrombin → Fibrinogen → Fibringerinnsel. Warfarin blockiert Vitamin-K-abhängige Faktoren (II, VII, IX, X).","fr":"Voie extrinsèque : facteur tissulaire (III) + VII → activés. Voie intrinsèque : XII, XI, IX, VIII. Les deux convergent au facteur X → Xa + Va → prothrombine (II) → thrombine → fibrinogène → caillot de fibrine. La warfarine bloque les facteurs dépendants de la vitamine K (II, VII, IX, X).","tr":"Ekstrinsik yol: doku faktörü (III) + VII → aktive edilir. İntrinsik yol: XII, XI, IX, VIII. Her ikisi faktör X'te birleşir → Xa + Va → protrombin (II) → trombin → fibrinojen → fibrin pıhtısı. Warfarin vitamin K bağımlı faktörleri bloke eder (II, VII, IX, X).","nl":"Extrinsieke weg: weefselfactor (III) + VII → geactiveerd. Intrinsieke weg: XII, XI, IX, VIII. Beide convergeren bij factor X → Xa + Va → protrombine (II) → trombine → fibrinogeen → fibrinestolsel. Warfarine blokkeert vitamine K-afhankelijke factoren (II, VII, IX, X).","ru":"Внешний путь: тканевый фактор (III) + VII → активация. Внутренний путь: XII, XI, IX, VIII. Оба сходятся на факторе X → Xa + Va → протромбин (II) → тромбин → фибриноген → фибриновый сгусток. Варфарин блокирует витамин К-зависимые факторы (II, VII, IX, X).","zh":"外源性途径：组织因子（III）+ VII→激活。内源性途径：XII、XI、IX、VIII。两者汇聚于因子X→Xa + Va→凝血酶原（II）→凝血酶→纤维蛋白原→纤维蛋白凝块。华法林阻断维生素K依赖因子（II、VII、IX、X）。","pt_BR":"Via extrínseca: fator tecidual (III) + VII → ativados. Via intrínseca: XII, XI, IX, VIII. Ambas convergem no fator X → Xa + Va → protrombina (II) → trombina → fibrinogênio → coágulo de fibrina. Varfarina bloqueia fatores dependentes de vitamina K (II, VII, IX, X).","pt_PT":"Via extrínseca: fator tecidual (III) + VII → ativados. Via intrínseca: XII, XI, IX, VIII. Ambas convergem no fator X → Xa + Va → protrombina (II) → trombina → fibrinogénio → coágulo de fibrina. Varfarina bloqueia fatores dependentes de vitamina K (II, VII, IX, X)."}},
  { id: 'dc-mcat-0113', deck_id: 'deck-mcat', sort_order: 113, front: "Respiratory Control", back: "Chemoreceptors detect changes in blood CO₂, O₂, and pH. Central chemoreceptors (medulla): most sensitive to PCO₂ (via CSF pH). Peripheral chemoreceptors (carotid and aortic bodies): respond to PO₂, PCO₂, and pH. Hypercapnia is the primary respiratory drive." , front_translations: {"es":"Controle Respiratório","de":"Atemregulation","fr":"Contrôle respiratoire","tr":"Solunum Kontrolü","nl":"Ademhalingsregulatie","ru":"Регуляция дыхания","zh":"呼吸调控","pt_BR":"Controle Respiratório","pt_PT":"Controlo Respiratório"}, back_translations: {"es":"Quimiorreceptores detectam cambios en el CO₂, El₂ y pH sanguíneos. Quimiorreceptores centrais (bulbo): más sensibles a la PCO₂ (via pH del LCR). Quimiorreceptores periféricos (cuerpos carotídeos y aórticos): respondem a PO₂, PCO₂ y pH. Hipercapnia es el principal estímulo respiratório.","de":"Chemorezeptoren erkennen Veränderungen von CO₂, O₂ und pH im Blut. Zentrale Chemorezeptoren (Medulla): am empfindlichsten für PCO₂ (über Liquor-pH). Periphere Chemorezeptoren (Karotis- und Aortenkörperchen): reagieren auf PO₂, PCO₂ und pH. Hyperkapnie ist der primäre Atemantrieb.","fr":"Les chémorécepteurs détectent les variations de CO₂, O₂ et pH sanguins. Chémorécepteurs centraux (bulbe rachidien) : les plus sensibles à la PCO₂ (via le pH du LCR). Chémorécepteurs périphériques (corpuscules carotidiens et aortiques) : répondent à la PO₂, PCO₂ et au pH. L'hypercapnie est le stimulus respiratoire principal.","tr":"Kemoreseptörler kan CO₂, O₂ ve pH değişikliklerini algılar. Merkezi kemoreseptörler (medulla): PCO₂'ye en duyarlı (BOS pH'ı aracılığıyla). Periferik kemoreseptörler (karotis ve aort cisimleri): PO₂, PCO₂ ve pH'ya yanıt verir. Hiperkapni birincil solunum uyaranıdır.","nl":"Chemoreceptoren detecteren veranderingen in bloed-CO₂, O₂ en pH. Centrale chemoreceptoren (medulla): meest gevoelig voor PCO₂ (via CSV-pH). Perifere chemoreceptoren (glomus caroticum en aorticum): reageren op PO₂, PCO₂ en pH. Hypercapnie is de primaire ademhalingsprikkel.","ru":"Хеморецепторы регистрируют изменения CO₂, O₂ и pH крови. Центральные хеморецепторы (продолговатый мозг): наиболее чувствительны к PCO₂ (через pH спинномозговой жидкости). Периферические хеморецепторы (каротидные и аортальные тельца): реагируют на PO₂, PCO₂ и pH. Гиперкапния — основной стимул дыхания.","zh":"化学感受器检测血液CO₂、O₂和pH的变化。中枢化学感受器（延髓）：对PCO₂最敏感（通过脑脊液pH）。外周化学感受器（颈动脉体和主动脉体）：对PO₂、PCO₂和pH作出反应。高碳酸血症是主要的呼吸驱动力。","pt_BR":"Quimiorreceptores detectam mudanças no CO₂, O₂ e pH sanguíneos. Quimiorreceptores centrais (bulbo): mais sensíveis à PCO₂ (via pH do LCR). Quimiorreceptores periféricos (corpos carotídeos e aórticos): respondem a PO₂, PCO₂ e pH. Hipercapnia é o principal estímulo respiratório.","pt_PT":"Quimiorreceptores detetam alterações no CO₂, O₂ e pH sanguíneos. Quimiorreceptores centrais (bulbo): mais sensíveis à PCO₂ (via pH do LCR). Quimiorreceptores periféricos (corpos carotídeos e aórticos): respondem a PO₂, PCO₂ e pH. Hipercapnia é o principal estímulo respiratório."}},
  { id: 'dc-mcat-0114', deck_id: 'deck-mcat', sort_order: 114, front: "Muscle Contraction: Cardiac vs. Skeletal", back: "Skeletal: voluntary, multinucleated, no gap junctions, needs all-or-nothing AP per fiber. Cardiac: involuntary, uninucleated, gap junctions (electrical syncytium), longer AP (plateau phase due to Ca²⁺ L-channels), no tetanus." , front_translations: {"es":"Contración Muscular: Cardíaca vs. Esquelética","de":"Muskelkontraktion: Herz- vs. Skelettmuskel","fr":"Contraction musculaire : cardiaque vs. squelettique","tr":"Kas Kasılması: Kardiyak vs. İskelet","nl":"Spiercontractie: hart- vs. skeletspier","ru":"Сокращение мышц: сердечная vs. скелетная","zh":"肌肉收缩：心肌与骨骼肌","pt_BR":"Contração Muscular: Cardíaca vs. Esquelética","pt_PT":"Contração Muscular: Cardíaca vs. Esquelética"}, back_translations: {"es":"Esquelético: voluntário, multinucleado, sin junciones comunicantes, necessita de PA tudo-o-nada por fibra. Cardíaco: involuntário, uninucleado, junciones comunicantes (sincício eléctrico), PA más ancho (fase de plato por canais de Ca²⁺ tipo L), sin tétano.","de":"Skelettmuskel: willkürlich, mehrkernig, keine Gap Junctions, benötigt Alles-oder-Nichts-AP pro Faser. Herzmuskel: unwillkürlich, einkernig, Gap Junctions (elektrisches Synzytium), längeres AP (Plateauphase durch Ca²⁺-L-Kanäle), kein Tetanus.","fr":"Squelettique : volontaire, multinucléé, pas de jonctions communicantes, nécessite un PA tout-ou-rien par fibre. Cardiaque : involontaire, uninucléé, jonctions communicantes (syncytium électrique), PA plus long (phase plateau due aux canaux Ca²⁺ de type L), pas de tétanos.","tr":"İskelet: istemli, çok çekirdekli, gap junction yok, fiber başına ya hep ya hiç AP gerektirir. Kardiyak: istemsiz, tek çekirdekli, gap junction'lar (elektriksel sinsityum), daha uzun AP (Ca²⁺ L-kanallarına bağlı plato fazı), tetanus yok.","nl":"Skeletspier: willekeurig, meercellig, geen gap junctions, vereist alles-of-niets AP per vezel. Hartspier: onwillekeurig, éénkernig, gap junctions (elektrisch syncytium), langer AP (plateaufase door Ca²⁺ L-kanalen), geen tetanus.","ru":"Скелетная: произвольная, многоядерная, без щелевых контактов, требует потенциал действия по принципу «всё или ничего» для каждого волокна. Сердечная: непроизвольная, одноядерная, щелевые контакты (электрический синцитий), более длительный ПД (фаза плато из-за Ca²⁺ L-каналов), тетанус невозможен.","zh":"骨骼肌：随意肌，多核，无缝隙连接，每条纤维需要全或无动作电位。心肌：不随意肌，单核，缝隙连接（电合胞体），更长的动作电位（由Ca²⁺ L型通道引起的平台期），不会发生强直收缩。","pt_BR":"Esquelético: voluntário, multinucleado, sem junções comunicantes, necessita de PA tudo-ou-nada por fibra. Cardíaco: involuntário, uninucleado, junções comunicantes (sincício elétrico), PA mais longo (fase de platô por canais de Ca²⁺ tipo L), sem tétano.","pt_PT":"Esquelético: voluntário, multinucleado, sem junções comunicantes, necessita de PA tudo-ou-nada por fibra. Cardíaco: involuntário, uninucleado, junções comunicantes (sincício elétrico), PA mais longo (fase de plateau por canais de Ca²⁺ tipo L), sem tétano."}},
  { id: 'dc-mcat-0115', deck_id: 'deck-mcat', sort_order: 115, front: "Immune Response: B vs. T Cells", back: "B cells: mature in bone marrow, produce antibodies (humoral immunity), activated by Th2 cells. T cells: mature in thymus, cell-mediated immunity. CD4+ (helper): activate B cells and cytotoxic T cells. CD8+ (cytotoxic): kill infected/tumor cells." , front_translations: {"es":"Resposta Imune: Células B vs. T","de":"Immunantwort: B- vs. T-Zellen","fr":"Réponse immunitaire : cellules B vs. T","tr":"İmmün Yanıt: B vs. T Hücreleri","nl":"Immuunrespons: B- vs. T-cellen","ru":"Иммунный ответ: B- vs. T-клетки","zh":"免疫应答：B细胞与T细胞","pt_BR":"Resposta Imune: Células B vs. T","pt_PT":"Resposta Imune: Células B vs. T"}, back_translations: {"es":"Células B: amadurecem en la médula ósea, producen anticorpos (imunidad humoral), ativadas por células Th2. Células T: amadurecem en el timo, imunidad celular. CD4+ (auxiliares): ativam células B y T citotóxicas. CD8+ (citotóxicas): matam células infectadas/tumorais.","de":"B-Zellen: reifen im Knochenmark, produzieren Antikörper (humorale Immunität), aktiviert durch Th2-Zellen. T-Zellen: reifen im Thymus, zellvermittelte Immunität. CD4+ (Helfer): aktivieren B-Zellen und zytotoxische T-Zellen. CD8+ (zytotoxisch): töten infizierte/Tumorzellen.","fr":"Cellules B : maturation dans la moelle osseuse, production d'anticorps (immunité humorale), activées par les cellules Th2. Cellules T : maturation dans le thymus, immunité cellulaire. CD4+ (auxiliaires) : activent les cellules B et les T cytotoxiques. CD8+ (cytotoxiques) : tuent les cellules infectées/tumorales.","tr":"B hücreleri: kemik iliğinde olgunlaşır, antikor üretir (hümoral bağışıklık), Th2 hücreleri tarafından aktive edilir. T hücreleri: timusta olgunlaşır, hücresel bağışıklık. CD4+ (yardımcı): B hücrelerini ve sitotoksik T hücrelerini aktive eder. CD8+ (sitotoksik): enfekte/tümör hücrelerini öldürür.","nl":"B-cellen: rijpen in beenmerg, produceren antilichamen (humorale immuniteit), geactiveerd door Th2-cellen. T-cellen: rijpen in thymus, celgemedieerde immuniteit. CD4+ (helper): activeren B-cellen en cytotoxische T-cellen. CD8+ (cytotoxisch): doden geïnfecteerde/tumorcellen.","ru":"B-клетки: созревают в костном мозге, вырабатывают антитела (гуморальный иммунитет), активируются Th2-клетками. T-клетки: созревают в тимусе, клеточный иммунитет. CD4+ (хелперы): активируют B-клетки и цитотоксические T-клетки. CD8+ (цитотоксические): убивают инфицированные/опухолевые клетки.","zh":"B细胞：在骨髓中成熟，产生抗体（体液免疫），由Th2细胞激活。T细胞：在胸腺中成熟，细胞免疫。CD4+（辅助性）：激活B细胞和细胞毒性T细胞。CD8+（细胞毒性）：杀死感染细胞/肿瘤细胞。","pt_BR":"Células B: amadurecem na medula óssea, produzem anticorpos (imunidade humoral), ativadas por células Th2. Células T: amadurecem no timo, imunidade celular. CD4+ (auxiliares): ativam células B e T citotóxicas. CD8+ (citotóxicas): matam células infectadas/tumorais.","pt_PT":"Células B: amadurecem na medula óssea, produzem anticorpos (imunidade humoral), ativadas por células Th2. Células T: amadurecem no timo, imunidade celular. CD4+ (auxiliares): ativam células B e T citotóxicas. CD8+ (citotóxicas): matam células infetadas/tumorais."}},
  { id: 'dc-mcat-0116', deck_id: 'deck-mcat', sort_order: 116, front: "MHC Class I vs. Class II", back: "MHC I: on all nucleated cells; presents endogenous peptides (intracellular pathogens, cancer) to CD8+ cytotoxic T cells. MHC II: on antigen-presenting cells (macrophages, B cells, dendritic cells); presents exogenous peptides to CD4+ helper T cells." , front_translations: {"es":"MHC Classe I vs. Classe II","de":"MHC Klasse I vs. Klasse II","fr":"CMH classe I vs. classe II","tr":"MHC Sınıf I vs. Sınıf II","nl":"MHC klasse I vs. klasse II","ru":"MHC класса I vs. класса II","zh":"MHC I类与II类","pt_BR":"MHC Classe I vs. Classe II","pt_PT":"MHC Classe I vs. Classe II"}, back_translations: {"es":"MHC I: en todas las células nucleadas; apresenta peptídeos endógenos (patógenos intracelulares, cancer) para células T citotóxicas CD8+. MHC II: en células apresentadoras de antígeno (macrófagos, células B, células dendríticas); apresenta peptídeos exógenos para células T auxiliares CD4+.","de":"MHC I: auf allen kernhaltigen Zellen; präsentiert endogene Peptide (intrazelluläre Pathogene, Krebs) an CD8+ zytotoxische T-Zellen. MHC II: auf antigenpräsentierenden Zellen (Makrophagen, B-Zellen, dendritische Zellen); präsentiert exogene Peptide an CD4+ T-Helferzellen.","fr":"CMH I : sur toutes les cellules nucléées ; présente les peptides endogènes (pathogènes intracellulaires, cancer) aux lymphocytes T cytotoxiques CD8+. CMH II : sur les cellules présentatrices d'antigènes (macrophages, cellules B, cellules dendritiques) ; présente les peptides exogènes aux lymphocytes T auxiliaires CD4+.","tr":"MHC I: tüm çekirdekli hücrelerde; endojen peptidleri (hücre içi patojenler, kanser) CD8+ sitotoksik T hücrelerine sunar. MHC II: antijen sunan hücrelerde (makrofajlar, B hücreleri, dendritik hücreler); ekzojen peptidleri CD4+ yardımcı T hücrelerine sunar.","nl":"MHC I: op alle kernhoudende cellen; presenteert endogene peptiden (intracellulaire pathogenen, kanker) aan CD8+ cytotoxische T-cellen. MHC II: op antigeenpresenterende cellen (macrofagen, B-cellen, dendritische cellen); presenteert exogene peptiden aan CD4+ helper-T-cellen.","ru":"MHC I: на всех ядросодержащих клетках; представляет эндогенные пептиды (внутриклеточные патогены, рак) CD8+ цитотоксическим T-клеткам. MHC II: на антигенпрезентирующих клетках (макрофаги, B-клетки, дендритные клетки); представляет экзогенные пептиды CD4+ T-хелперам.","zh":"MHC I：存在于所有有核细胞上；将内源性肽（细胞内病原体、癌症）呈递给CD8+细胞毒性T细胞。MHC II：存在于抗原呈递细胞（巨噬细胞、B细胞、树突状细胞）上；将外源性肽呈递给CD4+辅助性T细胞。","pt_BR":"MHC I: em todas as células nucleadas; apresenta peptídeos endógenos (patógenos intracelulares, câncer) para células T citotóxicas CD8+. MHC II: em células apresentadoras de antígeno (macrófagos, células B, células dendríticas); apresenta peptídeos exógenos para células T auxiliares CD4+.","pt_PT":"MHC I: em todas as células nucleadas; apresenta péptidos endógenos (patógenos intracelulares, cancro) a células T citotóxicas CD8+. MHC II: em células apresentadoras de antigénio (macrófagos, células B, células dendríticas); apresenta péptidos exógenos a células T auxiliares CD4+."}},
  { id: 'dc-mcat-0117', deck_id: 'deck-mcat', sort_order: 117, front: "Complement System", back: "A cascade of plasma proteins that enhances immune response. Three pathways (classical, lectin, alternative) converge at C3 → C3b (opsonization), MAC (lysis), C3a/C5a (anaphylatoxins causing inflammation and chemotaxis)." , front_translations: {"es":"Sistema Complemento","de":"Komplementsystem","fr":"Système du complément","tr":"Kompleman Sistemi","nl":"Complementsysteem","ru":"Система комплемента","zh":"补体系统","pt_BR":"Sistema Complemento","pt_PT":"Sistema do Complemento"}, back_translations: {"es":"Una cascata de proteínas plasmáticas que potencializa a respuesta imune. Tres vias (clássica, lectina, alternativa) convergem en C3 → C3b (opsonización), MAC (lise), C3a/C5a (anafilatoxinas causando inflamación y quimiotaxia).","de":"Eine Kaskade von Plasmaproteinen, die die Immunantwort verstärkt. Drei Wege (klassisch, Lektin, alternativ) konvergieren bei C3 → C3b (Opsonisierung), MAC (Lyse), C3a/C5a (Anaphylatoxine, die Entzündung und Chemotaxis verursachen).","fr":"Une cascade de protéines plasmatiques qui renforce la réponse immunitaire. Trois voies (classique, lectine, alternative) convergent au niveau de C3 → C3b (opsonisation), MAC (lyse), C3a/C5a (anaphylatoxines provoquant inflammation et chimiotaxie).","tr":"Bağışıklık yanıtını güçlendiren plazma proteinleri kaskadı. Üç yol (klasik, lektin, alternatif) C3'te birleşir → C3b (opsonizasyon), MAC (lizis), C3a/C5a (enflamasyon ve kemotaksise neden olan anafilatoksinler).","nl":"Een cascade van plasmaproteïnen die de immuunrespons versterkt. Drie routes (klassiek, lectine, alternatief) convergeren bij C3 → C3b (opsonisatie), MAC (lysis), C3a/C5a (anafylatoxinen die ontsteking en chemotaxis veroorzaken).","ru":"Каскад белков плазмы, усиливающий иммунный ответ. Три пути (классический, лектиновый, альтернативный) сходятся на C3 → C3b (опсонизация), MAC (лизис), C3a/C5a (анафилатоксины, вызывающие воспаление и хемотаксис).","zh":"一组增强免疫反应的血浆蛋白级联反应。三条途径（经典途径、凝集素途径、替代途径）汇聚于C3→C3b（调理作用）、MAC（溶解）、C3a/C5a（引起炎症和趋化作用的过敏毒素）。","pt_BR":"Uma cascata de proteínas plasmáticas que potencializa a resposta imune. Três vias (clássica, lectina, alternativa) convergem em C3 → C3b (opsonização), MAC (lise), C3a/C5a (anafilatoxinas causando inflamação e quimiotaxia).","pt_PT":"Uma cascata de proteínas plasmáticas que potencia a resposta imune. Três vias (clássica, lectina, alternativa) convergem em C3 → C3b (opsonização), MAC (lise), C3a/C5a (anafilatoxinas causando inflamação e quimiotaxia)."}},
  { id: 'dc-mcat-0118', deck_id: 'deck-mcat', sort_order: 118, front: "Hardy-Weinberg Equilibrium (MCAT)", back: "p² + 2pq + q² = 1; p + q = 1. In a non-evolving population, allele and genotype frequencies remain constant. HWE violations indicate evolutionary forces: selection, mutation, migration, non-random mating, genetic drift." , front_translations: {"es":"Equilíbrio de Hardy-Weinberg (MCAT)","de":"Hardy-Weinberg-Gleichgewicht (MCAT)","fr":"Équilibre de Hardy-Weinberg (MCAT)","tr":"Hardy-Weinberg Dengesi (MCAT)","nl":"Hardy-Weinberg-evenwicht (MCAT)","ru":"Равновесие Харди-Вайнберга (MCAT)","zh":"Hardy-Weinberg平衡 (MCAT)","pt_BR":"Equilíbrio de Hardy-Weinberg (MCAT)","pt_PT":"Equilíbrio de Hardy-Weinberg (MCAT)"}, back_translations: {"es":"p² + 2pq + q² = 1; p + q = 1. En una población que no está evoluindo, las frequencias alélicas y genotípicas permanecen constantes. Violaciones del HWE indican fuerzas evolutivas: seleción, mutación, migración, acasalamento no aleatório, deriva genética.","de":"p² + 2pq + q² = 1; p + q = 1. In einer nicht-evolvierenden Population bleiben Allel- und Genotypfrequenzen konstant. HWE-Verletzungen deuten auf evolutionäre Kräfte hin: Selektion, Mutation, Migration, nicht-zufällige Paarung, genetische Drift.","fr":"p² + 2pq + q² = 1 ; p + q = 1. Dans une population non évolutive, les fréquences alléliques et génotypiques restent constantes. Les violations de l'HWE indiquent des forces évolutives : sélection, mutation, migration, appariement non aléatoire, dérive génétique.","tr":"p² + 2pq + q² = 1; p + q = 1. Evrimleşmeyen bir popülasyonda allel ve genotip frekansları sabit kalır. HWE ihlalleri evrimsel güçleri gösterir: seçilim, mutasyon, göç, rastgele olmayan çiftleşme, genetik sürüklenme.","nl":"p² + 2pq + q² = 1; p + q = 1. In een niet-evoluerende populatie blijven allel- en genotypefrequenties constant. HWE-schendingen wijzen op evolutionaire krachten: selectie, mutatie, migratie, niet-willekeurige paring, genetische drift.","ru":"p² + 2pq + q² = 1; p + q = 1. В неэволюционирующей популяции частоты аллелей и генотипов остаются постоянными. Нарушения HWE указывают на эволюционные силы: отбор, мутация, миграция, неслучайное скрещивание, генетический дрейф.","zh":"p² + 2pq + q² = 1；p + q = 1。在非进化的种群中，等位基因和基因型频率保持不变。HWE偏离表明存在进化力量：选择、突变、迁移、非随机交配、遗传漂变。","pt_BR":"p² + 2pq + q² = 1; p + q = 1. Em uma população que não está evoluindo, as frequências alélicas e genotípicas permanecem constantes. Violações do HWE indicam forças evolutivas: seleção, mutação, migração, acasalamento não aleatório, deriva genética.","pt_PT":"p² + 2pq + q² = 1; p + q = 1. Numa população que não está a evoluir, as frequências alélicas e genotípicas permanecem constantes. Violações do HWE indicam forças evolutivas: seleção, mutação, migração, acasalamento não aleatório, deriva genética."}},
  { id: 'dc-mcat-0119', deck_id: 'deck-mcat', sort_order: 119, front: "MCAT: Common Lab Techniques", back: "PCR (amplify DNA), gel electrophoresis (separate by size), Southern blot (detect DNA), Northern blot (detect RNA), Western blot (detect protein), ELISA (quantify protein), flow cytometry (cell sorting), CRISPR (gene editing)." , front_translations: {"es":"MCAT: Técnicas Laboratoriais Comuns","de":"MCAT: Gängige Labortechniken","fr":"MCAT : techniques de laboratoire courantes","tr":"MCAT: Yaygın Laboratuvar Teknikleri","nl":"MCAT: veelvoorkomende laboratoriumtechnieken","ru":"MCAT: распространённые лабораторные методы","zh":"MCAT：常见实验室技术","pt_BR":"MCAT: Técnicas Laboratoriais Comuns","pt_PT":"MCAT: Técnicas Laboratoriais Comuns"}, back_translations: {"es":"PCR (amplificación de DNA), eletroforese en gel (separación por tamaño), Southern blot (detección de DNA), Northern blot (detección de RNA), Western blot (detección de proteína), ELISA (quantificación de proteína), citometria de flujo (classificación celular), CRISPR (edición genica).","de":"PCR (DNA-Amplifikation), Gelelektrophorese (Trennung nach Größe), Southern Blot (DNA-Nachweis), Northern Blot (RNA-Nachweis), Western Blot (Protein-Nachweis), ELISA (Protein-Quantifizierung), Durchflusszytometrie (Zellsortierung), CRISPR (Genbearbeitung).","fr":"PCR (amplification de l'ADN), électrophorèse sur gel (séparation par taille), Southern blot (détection d'ADN), Northern blot (détection d'ARN), Western blot (détection de protéines), ELISA (quantification de protéines), cytométrie en flux (tri cellulaire), CRISPR (édition génique).","tr":"PCR (DNA amplifikasyonu), jel elektroforezi (boyuta göre ayırma), Southern blot (DNA tespiti), Northern blot (RNA tespiti), Western blot (protein tespiti), ELISA (protein kantifikasyonu), akış sitometrisi (hücre sıralama), CRISPR (gen düzenleme).","nl":"PCR (DNA-amplificatie), gelelektroforese (scheiding op grootte), Southern blot (DNA-detectie), Northern blot (RNA-detectie), Western blot (eiwitdetectie), ELISA (eiwitkwantificering), flowcytometrie (celsortering), CRISPR (genbewerking).","ru":"PCR (амплификация ДНК), гель-электрофорез (разделение по размеру), Саузерн-блот (обнаружение ДНК), Нозерн-блот (обнаружение РНК), Вестерн-блот (обнаружение белка), ELISA (количественное определение белка), проточная цитометрия (сортировка клеток), CRISPR (редактирование генов).","zh":"PCR（扩增DNA）、凝胶电泳（按大小分离）、Southern blot（检测DNA）、Northern blot（检测RNA）、Western blot（检测蛋白质）、ELISA（定量蛋白质）、流式细胞术（细胞分选）、CRISPR（基因编辑）。","pt_BR":"PCR (amplificação de DNA), eletroforese em gel (separação por tamanho), Southern blot (detecção de DNA), Northern blot (detecção de RNA), Western blot (detecção de proteína), ELISA (quantificação de proteína), citometria de fluxo (classificação celular), CRISPR (edição gênica).","pt_PT":"PCR (amplificação de DNA), eletroforese em gel (separação por tamanho), Southern blot (deteção de DNA), Northern blot (deteção de RNA), Western blot (deteção de proteína), ELISA (quantificação de proteína), citometria de fluxo (classificação celular), CRISPR (edição génica)."}},
  { id: 'dc-mcat-0120', deck_id: 'deck-mcat', sort_order: 120, front: "Statistics: Mean, Median, Mode", back: "Mean: arithmetic average; sensitive to outliers. Median: middle value; robust to outliers; used for skewed distributions (e.g., income). Mode: most frequent value. In a normal distribution, mean = median = mode." , front_translations: {"es":"Estatística: Média, Mediana, Moda","de":"Statistik: Mittelwert, Median, Modus","fr":"Statistiques : Moyenne, Médiane, Mode","tr":"İstatistik: Ortalama, Medyan, Mod","nl":"Statistiek: Gemiddelde, Mediaan, Modus","ru":"Статистика: Среднее, Медиана, Мода","zh":"统计学：均值、中位数、众数","pt_BR":"Estatística: Média, Mediana, Moda","pt_PT":"Estatística: Média, Mediana, Moda"}, back_translations: {"es":"Média: média aritmética; sensible a valores discrepantes. Mediana: valor central; robusta a valores discrepantes; usada para distribuiciones assimétricas (ex.: renda). Moda: valor más frequente. En una distribución normal: média = mediana = moda.","de":"Mittelwert: arithmetischer Durchschnitt; empfindlich gegenüber Ausreißern. Median: mittlerer Wert; robust gegenüber Ausreißern; verwendet bei schiefen Verteilungen (z. B. Einkommen). Modus: häufigster Wert. In einer Normalverteilung gilt: Mittelwert = Median = Modus.","fr":"Moyenne : moyenne arithmétique ; sensible aux valeurs aberrantes. Médiane : valeur centrale ; robuste face aux valeurs aberrantes ; utilisée pour les distributions asymétriques (ex. : revenus). Mode : valeur la plus fréquente. Dans une distribution normale : moyenne = médiane = mode.","tr":"Ortalama: aritmetik ortalama; aykırı değerlere duyarlıdır. Medyan: ortadaki değer; aykırı değerlere dayanıklıdır; çarpık dağılımlarda kullanılır (ör. gelir). Mod: en sık görülen değer. Normal dağılımda ortalama = medyan = mod.","nl":"Gemiddelde: rekenkundig gemiddelde; gevoelig voor uitschieters. Mediaan: middelste waarde; robuust tegen uitschieters; gebruikt bij scheve verdelingen (bv. inkomen). Modus: meest voorkomende waarde. In een normale verdeling geldt: gemiddelde = mediaan = modus.","ru":"Среднее: арифметическое среднее; чувствительно к выбросам. Медиана: срединное значение; устойчива к выбросам; используется для асимметричных распределений (напр., доход). Мода: наиболее часто встречающееся значение. В нормальном распределении: среднее = медиана = мода.","zh":"均值：算术平均值；对异常值敏感。中位数：中间值；对异常值具有鲁棒性；用于偏态分布（如收入）。众数：出现频率最高的值。在正态分布中：均值 = 中位数 = 众数。","pt_BR":"Média: média aritmética; sensível a valores discrepantes. Mediana: valor central; robusta a valores discrepantes; usada para distribuições assimétricas (ex.: renda). Moda: valor mais frequente. Em uma distribuição normal: média = mediana = moda.","pt_PT":"Média: média aritmética; sensível a valores discrepantes. Mediana: valor central; robusta a valores discrepantes; utilizada para distribuições assimétricas (ex.: rendimento). Moda: valor mais frequente. Numa distribuição normal: média = mediana = moda."}},
  { id: 'dc-mcat-0121', deck_id: 'deck-mcat', sort_order: 121, front: "Standard Deviation and Normal Distribution", back: "SD measures spread of data around the mean. In a normal distribution: ±1 SD contains 68%, ±2 SD contains 95%, ±3 SD contains 99.7% of data. Standard error (SE) = SD/√n; measures precision of the mean estimate." , front_translations: {"es":"Desvio Padrão y Distribuición Normal","de":"Standardabweichung und Normalverteilung","fr":"Écart-type et distribution normale","tr":"Standart Sapma ve Normal Dağılım","nl":"Standaardafwijking en normale verdeling","ru":"Стандартное отклонение и нормальное распределение","zh":"标准差与正态分布","pt_BR":"Desvio Padrão e Distribuição Normal","pt_PT":"Desvio Padrão e Distribuição Normal"}, back_translations: {"es":"SD mide a dispersão de los datos en torno de la média. En una distribución normal: ±1 SD contiene 68%, ±2 SD contiene 95%, ±3 SD contiene 99,7% de los datos. Erro padrão (SE) = SD/√n; mide a precisão de la estimativa de la média.","de":"SD misst die Streuung der Daten um den Mittelwert. In einer Normalverteilung: ±1 SD enthält 68 %, ±2 SD enthält 95 %, ±3 SD enthält 99,7 % der Daten. Standardfehler (SE) = SD/√n; misst die Präzision der Mittelwertschätzung.","fr":"SD mesure la dispersion des données autour de la moyenne. Dans une distribution normale : ±1 SD contient 68 %, ±2 SD contient 95 %, ±3 SD contient 99,7 % des données. Erreur standard (SE) = SD/√n ; mesure la précision de l'estimation de la moyenne.","tr":"SD, verilerin ortalama etrafındaki yayılımını ölçer. Normal dağılımda: ±1 SD %68, ±2 SD %95, ±3 SD %99,7 veriyi içerir. Standart hata (SE) = SD/√n; ortalama tahmininin hassasiyetini ölçer.","nl":"SD meet de spreiding van gegevens rond het gemiddelde. In een normale verdeling: ±1 SD bevat 68%, ±2 SD bevat 95%, ±3 SD bevat 99,7% van de gegevens. Standaardfout (SE) = SD/√n; meet de precisie van de gemiddeldeschatting.","ru":"SD измеряет разброс данных вокруг среднего. В нормальном распределении: ±1 SD содержит 68%, ±2 SD — 95%, ±3 SD — 99,7% данных. Стандартная ошибка (SE) = SD/√n; измеряет точность оценки среднего.","zh":"SD 衡量数据围绕均值的离散程度。在正态分布中：±1 SD 包含 68%，±2 SD 包含 95%，±3 SD 包含 99.7% 的数据。标准误差 (SE) = SD/√n；衡量均值估计的精确度。","pt_BR":"SD mede a dispersão dos dados em torno da média. Em uma distribuição normal: ±1 SD contém 68%, ±2 SD contém 95%, ±3 SD contém 99,7% dos dados. Erro padrão (SE) = SD/√n; mede a precisão da estimativa da média.","pt_PT":"SD mede a dispersão dos dados em torno da média. Numa distribuição normal: ±1 SD contém 68%, ±2 SD contém 95%, ±3 SD contém 99,7% dos dados. Erro padrão (SE) = SD/√n; mede a precisão da estimativa da média."}},
  { id: 'dc-mcat-0122', deck_id: 'deck-mcat', sort_order: 122, front: "Study Design: Observational vs. Experimental", back: "Observational: cohort (follow exposed/unexposed forward), case-control (compare cases/controls backward), cross-sectional (snapshot in time). Experimental: randomized controlled trial (RCT; gold standard for causality). Blinding reduces bias." , front_translations: {"es":"Desenho de Estudo: Observacional vs. Experimental","de":"Studiendesign: Beobachtend vs. Experimentell","fr":"Plan d'étude : Observationnel vs. Expérimental","tr":"Çalışma Tasarımı: Gözlemsel ve Deneysel","nl":"Studieontwerp: Observationeel vs. Experimenteel","ru":"Дизайн исследования: наблюдательное и экспериментальное","zh":"研究设计：观察性研究与实验性研究","pt_BR":"Desenho de Estudo: Observacional vs. Experimental","pt_PT":"Desenho de Estudo: Observacional vs. Experimental"}, back_translations: {"es":"Observacional: coorte (acompanhar expostos/no expostos prospectivamente), caso-controle (comparar casos/controles retrospectivamente), transversal (instantaneo en el tiempo). Experimental: ensaio clínico randomizado (RCT; padrão-ouro para causalidad). El cegamento reduce viés.","de":"Beobachtend: Kohortenstudie (Exponierte/Nicht-Exponierte vorwärts verfolgen), Fall-Kontroll-Studie (Fälle/Kontrollen rückwärts vergleichen), Querschnittsstudie (Momentaufnahme). Experimentell: randomisierte kontrollierte Studie (RCT; Goldstandard für Kausalität). Verblindung reduziert Verzerrung.","fr":"Observationnel : cohorte (suivi prospectif exposés/non-exposés), cas-témoins (comparaison rétrospective cas/témoins), transversal (instantané). Expérimental : essai contrôlé randomisé (RCT ; référence pour la causalité). La mise en aveugle réduit les biais.","tr":"Gözlemsel: kohort (maruz kalan/kalmayanları ileriye doğru izleme), vaka-kontrol (vakaları/kontrolleri geriye doğru karşılaştırma), kesitsel (anlık görüntü). Deneysel: randomize kontrollü çalışma (RCT; nedensellik için altın standart). Körleme yanlılığı azaltır.","nl":"Observationeel: cohort (blootgestelden/niet-blootgestelden voorwaarts volgen), case-control (cases/controles achterwaarts vergelijken), cross-sectioneel (momentopname). Experimenteel: gerandomiseerde gecontroleerde trial (RCT; gouden standaard voor causaliteit). Blindering vermindert bias.","ru":"Наблюдательное: когортное (проспективное наблюдение за подвергшимися/не подвергшимися воздействию), «случай-контроль» (ретроспективное сравнение случаев/контролей), поперечное (моментальный срез). Экспериментальное: рандомизированное контролируемое исследование (RCT; золотой стандарт причинности). Ослепление снижает систематические ошибки.","zh":"观察性：队列研究（前瞻性追踪暴露/未暴露者）、病例对照研究（回顾性比较病例/对照）、横断面研究（时间截面）。实验性：随机对照试验（RCT；因果关系的金标准）。盲法减少偏倚。","pt_BR":"Observacional: coorte (acompanhar expostos/não expostos prospectivamente), caso-controle (comparar casos/controles retrospectivamente), transversal (instantâneo no tempo). Experimental: ensaio clínico randomizado (RCT; padrão-ouro para causalidade). O cegamento reduz viés.","pt_PT":"Observacional: coorte (acompanhar expostos/não expostos prospetivamente), caso-controlo (comparar casos/controlos retrospetivamente), transversal (instantâneo no tempo). Experimental: ensaio clínico aleatorizado (RCT; padrão de referência para causalidade). A ocultação reduz viés."}},
  { id: 'dc-mcat-0123', deck_id: 'deck-mcat', sort_order: 123, front: "Relative Risk vs. Odds Ratio", back: "Relative risk (RR): used in cohort studies; incidence in exposed / incidence in unexposed. Odds ratio (OR): used in case-control studies; odds of exposure in cases / odds of exposure in controls. OR ≈ RR when disease is rare." , front_translations: {"es":"Risco Relativo vs. Razão de Chances","de":"Relatives Risiko vs. Odds Ratio","fr":"Risque relatif vs. Odds Ratio","tr":"Relatif Risk ve Odds Oranı","nl":"Relatief risico vs. Odds Ratio","ru":"Относительный риск и отношение шансов","zh":"相对风险与比值比","pt_BR":"Risco Relativo vs. Razão de Chances","pt_PT":"Risco Relativo vs. Odds Ratio"}, back_translations: {"es":"Risco relativo (RR): usado en estudios de coorte; incidencia en los expostos / incidencia en los no expostos. Razão de chances (OR): usada en estudios caso-controle; chances de exposición en los casos / chances de exposición en los controles. OR ≈ RR cuando a enfermedad es rara.","de":"Relatives Risiko (RR): in Kohortenstudien verwendet; Inzidenz bei Exponierten / Inzidenz bei Nicht-Exponierten. Odds Ratio (OR): in Fall-Kontroll-Studien verwendet; Expositionschancen bei Fällen / Expositionschancen bei Kontrollen. OR ≈ RR wenn die Erkrankung selten ist.","fr":"Risque relatif (RR) : utilisé dans les études de cohorte ; incidence chez les exposés / incidence chez les non-exposés. Odds ratio (OR) : utilisé dans les études cas-témoins ; cote d'exposition chez les cas / cote d'exposition chez les témoins. OR ≈ RR lorsque la maladie est rare.","tr":"Relatif risk (RR): kohort çalışmalarında kullanılır; maruz kalanlardaki insidans / maruz kalmayanlardaki insidans. Odds oranı (OR): vaka-kontrol çalışmalarında kullanılır; vakalarda maruziyet odds'u / kontrollerde maruziyet odds'u. Hastalık nadir olduğunda OR ≈ RR.","nl":"Relatief risico (RR): gebruikt in cohortstudies; incidentie bij blootgestelden / incidentie bij niet-blootgestelden. Odds ratio (OR): gebruikt in case-controlstudies; odds van blootstelling bij cases / odds van blootstelling bij controles. OR ≈ RR wanneer de ziekte zeldzaam is.","ru":"Относительный риск (RR): используется в когортных исследованиях; заболеваемость среди подвергшихся / заболеваемость среди не подвергшихся воздействию. Отношение шансов (OR): используется в исследованиях «случай-контроль»; шансы экспозиции у случаев / шансы экспозиции у контролей. OR ≈ RR при редком заболевании.","zh":"相对风险 (RR)：用于队列研究；暴露组发病率 / 非暴露组发病率。比值比 (OR)：用于病例对照研究；病例组暴露比值 / 对照组暴露比值。当疾病罕见时 OR ≈ RR。","pt_BR":"Risco relativo (RR): usado em estudos de coorte; incidência nos expostos / incidência nos não expostos. Razão de chances (OR): usada em estudos caso-controle; chances de exposição nos casos / chances de exposição nos controles. OR ≈ RR quando a doença é rara.","pt_PT":"Risco relativo (RR): utilizado em estudos de coorte; incidência nos expostos / incidência nos não expostos. Odds ratio (OR): utilizado em estudos caso-controlo; odds de exposição nos casos / odds de exposição nos controlos. OR ≈ RR quando a doença é rara."}},
  { id: 'dc-mcat-0124', deck_id: 'deck-mcat', sort_order: 124, front: "Bias and Confounding", back: "Selection bias: non-representative sampling. Recall bias: differential recall between groups (common in case-control). Confounding: a third variable associated with both exposure and outcome. Controlled by randomization (RCTs) or statistical adjustment." , front_translations: {"es":"Viés y Confundimento","de":"Verzerrung und Confounding","fr":"Biais et facteurs de confusion","tr":"Yanlılık ve Karıştırıcı Faktörler","nl":"Bias en confounding","ru":"Систематические ошибки и конфаундинг","zh":"偏倚与混杂因素","pt_BR":"Viés e Confundimento","pt_PT":"Viés e Confundimento"}, back_translations: {"es":"Viés de seleción: amostraje no representativa. Viés de memoria: recordación diferencial entre grupos (comum en estudios caso-controle). Confundimento: una tercera variable associada tanto a la exposición quanto al desfecho. Controlado por randomización (RCTs) o ajuste estatístico.","de":"Selektionsbias: nicht repräsentative Stichprobe. Recall-Bias: unterschiedliche Erinnerung zwischen Gruppen (häufig bei Fall-Kontroll-Studien). Confounding: eine dritte Variable, die sowohl mit der Exposition als auch mit dem Ergebnis assoziiert ist. Kontrolliert durch Randomisierung (RCTs) oder statistische Adjustierung.","fr":"Biais de sélection : échantillonnage non représentatif. Biais de rappel : rappel différentiel entre les groupes (courant dans les études cas-témoins). Confusion : une troisième variable associée à la fois à l'exposition et au résultat. Contrôlé par randomisation (RCTs) ou ajustement statistique.","tr":"Seçim yanlılığı: temsili olmayan örnekleme. Hatırlama yanlılığı: gruplar arasında farklı hatırlama (vaka-kontrol çalışmalarında yaygın). Karıştırıcı faktör: hem maruziyet hem de sonuçla ilişkili üçüncü bir değişken. Randomizasyon (RCT'ler) veya istatistiksel düzeltme ile kontrol edilir.","nl":"Selectiebias: niet-representatieve steekproef. Herinneringsbias: verschil in herinnering tussen groepen (vaak bij case-controlstudies). Confounding: een derde variabele die geassocieerd is met zowel blootstelling als uitkomst. Gecontroleerd door randomisatie (RCTs) of statistische correctie.","ru":"Систематическая ошибка отбора: нерепрезентативная выборка. Ошибка воспоминания: различное воспоминание между группами (типично для исследований «случай-контроль»). Конфаундинг: третья переменная, связанная и с воздействием, и с исходом. Контролируется рандомизацией (RCT) или статистической коррекцией.","zh":"选择偏倚：非代表性抽样。回忆偏倚：各组之间的差异性回忆（病例对照研究中常见）。混杂：与暴露和结局均相关的第三变量。通过随机化（RCT）或统计调整来控制。","pt_BR":"Viés de seleção: amostragem não representativa. Viés de memória: recordação diferencial entre grupos (comum em estudos caso-controle). Confundimento: uma terceira variável associada tanto à exposição quanto ao desfecho. Controlado por randomização (RCTs) ou ajuste estatístico.","pt_PT":"Viés de seleção: amostragem não representativa. Viés de memória: recordação diferencial entre grupos (comum em estudos caso-controlo). Confundimento: uma terceira variável associada tanto à exposição como ao resultado. Controlado por aleatorização (RCTs) ou ajuste estatístico."}},
  { id: 'dc-mcat-0125', deck_id: 'deck-mcat', sort_order: 125, front: "Urea Cycle", back: "Converts toxic ammonia to urea in the liver (some steps in mitochondria, some in cytoplasm). Net reaction: 2 NH₃ + CO₂ → urea + H₂O. Consumes 3 ATP per cycle. Urea is excreted by the kidneys." , front_translations: {"es":"Ciclo de la Ureia","de":"Harnstoffzyklus","fr":"Cycle de l'urée","tr":"Üre Döngüsü","nl":"Ureumcyclus","ru":"Цикл мочевины","zh":"尿素循环","pt_BR":"Ciclo da Ureia","pt_PT":"Ciclo da Ureia"}, back_translations: {"es":"Converte amonia tóxica en ureia en el hígado (algunas etapas en las mitocondrias, outras en el citoplasma). Reación líquida: 2 NH₃ + CO₂ → ureia + H₂El. Consome 3 ATP por ciclo. La ureia es excretada por los riñones.","de":"Wandelt toxisches Ammoniak in Harnstoff in der Leber um (einige Schritte in den Mitochondrien, einige im Zytoplasma). Nettoreaktion: 2 NH₃ + CO₂ → Harnstoff + H₂O. Verbraucht 3 ATP pro Zyklus. Harnstoff wird über die Nieren ausgeschieden.","fr":"Convertit l'ammoniac toxique en urée dans le foie (certaines étapes dans les mitochondries, d'autres dans le cytoplasme). Réaction nette : 2 NH₃ + CO₂ → urée + H₂O. Consomme 3 ATP par cycle. L'urée est excrétée par les reins.","tr":"Karaciğerde toksik amonyağı üreye dönüştürür (bazı adımlar mitokondride, bazıları sitoplazmada). Net reaksiyon: 2 NH₃ + CO₂ → üre + H₂O. Döngü başına 3 ATP tüketir. Üre böbrekler tarafından atılır.","nl":"Zet giftig ammoniak om in ureum in de lever (sommige stappen in mitochondriën, sommige in cytoplasma). Nettoreactie: 2 NH₃ + CO₂ → ureum + H₂O. Verbruikt 3 ATP per cyclus. Ureum wordt uitgescheiden door de nieren.","ru":"Превращает токсичный аммиак в мочевину в печени (часть реакций в митохондриях, часть в цитоплазме). Суммарная реакция: 2 NH₃ + CO₂ → мочевина + H₂O. Потребляет 3 АТФ за цикл. Мочевина выводится почками.","zh":"在肝脏中将有毒的氨转化为尿素（部分步骤在线粒体中，部分在细胞质中）。净反应：2 NH₃ + CO₂ → 尿素 + H₂O。每个循环消耗 3 ATP。尿素由肾脏排泄。","pt_BR":"Converte amônia tóxica em ureia no fígado (algumas etapas nas mitocôndrias, outras no citoplasma). Reação líquida: 2 NH₃ + CO₂ → ureia + H₂O. Consome 3 ATP por ciclo. A ureia é excretada pelos rins.","pt_PT":"Converte amoníaco tóxico em ureia no fígado (algumas etapas nas mitocôndrias, outras no citoplasma). Reação líquida: 2 NH₃ + CO₂ → ureia + H₂O. Consome 3 ATP por ciclo. A ureia é excretada pelos rins."}},
  { id: 'dc-mcat-0126', deck_id: 'deck-mcat', sort_order: 126, front: "Cholesterol Metabolism", back: "Synthesized in the liver from acetyl-CoA via HMG-CoA reductase (rate-limiting step; inhibited by statins). Transported in LDL (delivers to tissues), HDL (reverse transport to liver). Precursor to steroid hormones, bile acids, vitamin D." , front_translations: {"es":"Metabolismo del Colesterol","de":"Cholesterinstoffwechsel","fr":"Métabolisme du cholestérol","tr":"Kolesterol Metabolizması","nl":"Cholesterolmetabolisme","ru":"Метаболизм холестерина","zh":"胆固醇代谢","pt_BR":"Metabolismo do Colesterol","pt_PT":"Metabolismo do Colesterol"}, back_translations: {"es":"Sintetizado en el hígado a partir de acetil-CoA via HMG-CoA redutase (etapa limitante; inibida por estatinas). Transportado en LDL (entrega a los tejidos), HDL (transporte reverso al hígado). Precursor de hormonas esteroides, ácidos biliares, vitamina D.","de":"In der Leber aus Acetyl-CoA über HMG-CoA-Reduktase synthetisiert (geschwindigkeitsbestimmender Schritt; durch Statine gehemmt). Transport in LDL (Lieferung an Gewebe), HDL (Rücktransport zur Leber). Vorstufe von Steroidhormonen, Gallensäuren, Vitamin D.","fr":"Synthétisé dans le foie à partir d'acétyl-CoA via HMG-CoA réductase (étape limitante ; inhibée par les statines). Transporté par LDL (livraison aux tissus), HDL (transport inverse vers le foie). Précurseur des hormones stéroïdiennes, des acides biliaires, de la vitamine D.","tr":"Karaciğerde asetil-CoA'dan HMG-CoA redüktaz ile sentezlenir (hız sınırlayıcı basamak; statinlerle inhibe edilir). LDL (dokulara taşıma), HDL (karaciğere geri taşıma) ile taşınır. Steroid hormonların, safra asitlerinin, D vitamininin öncüsüdür.","nl":"Gesynthetiseerd in de lever uit acetyl-CoA via HMG-CoA-reductase (snelheidsbepalende stap; geremd door statines). Getransporteerd in LDL (levering aan weefsels), HDL (omgekeerd transport naar lever). Precursor van steroïdhormonen, galzuren, vitamine D.","ru":"Синтезируется в печени из ацетил-КоА через ГМГ-КоА-редуктазу (лимитирующая стадия; ингибируется статинами). Транспортируется в ЛПНП (доставка к тканям), ЛПВП (обратный транспорт в печень). Предшественник стероидных гормонов, жёлчных кислот, витамина D.","zh":"在肝脏中由乙酰辅酶A通过HMG-CoA还原酶合成（限速步骤；被他汀类药物抑制）。由LDL运输（递送至组织），HDL（逆向运输至肝脏）。是类固醇激素、胆汁酸、维生素D的前体。","pt_BR":"Sintetizado no fígado a partir de acetil-CoA via HMG-CoA redutase (etapa limitante; inibida por estatinas). Transportado em LDL (entrega aos tecidos), HDL (transporte reverso ao fígado). Precursor de hormônios esteroides, ácidos biliares, vitamina D.","pt_PT":"Sintetizado no fígado a partir de acetil-CoA via HMG-CoA redutase (etapa limitante; inibida por estatinas). Transportado em LDL (entrega aos tecidos), HDL (transporte reverso ao fígado). Precursor de hormonas esteroides, ácidos biliares, vitamina D."}},
  { id: 'dc-mcat-0127', deck_id: 'deck-mcat', sort_order: 127, front: "Vitamins: Fat-Soluble (ADEK)", back: "A (retinol): vision, immune function. D (calciferol): Ca²⁺ absorption. E (tocopherol): antioxidant. K (phylloquinone): clotting factors (II, VII, IX, X). Stored in fat; excess is toxic. Deficiency: A→night blindness; D→rickets; K→bleeding." , front_translations: {"es":"Vitaminas: Lipossolúveis (ADEK)","de":"Vitamine: Fettlöslich (ADEK)","fr":"Vitamines : Liposolubles (ADEK)","tr":"Vitaminler: Yağda Çözünen (ADEK)","nl":"Vitamines: Vetoplosbaar (ADEK)","ru":"Витамины: Жирорастворимые (ADEK)","zh":"维生素：脂溶性维生素（ADEK）","pt_BR":"Vitaminas: Lipossolúveis (ADEK)","pt_PT":"Vitaminas: Lipossolúveis (ADEK)"}, back_translations: {"es":"La (retinol): visão, función imunológica. D (calciferol): absorción de Ca²⁺. Y (tocoferol): antioxidante. K (filoquinona): fatores de coagulación (II, VII, IX, X). Armazenadas en la gordura; exceso es tóxico. Deficiencia: La→ceguera noturna; D→raquitismo; K→sangramento.","de":"A (Retinol): Sehen, Immunfunktion. D (Calciferol): Ca²⁺-Aufnahme. E (Tocopherol): Antioxidans. K (Phyllochinon): Gerinnungsfaktoren (II, VII, IX, X). Im Fett gespeichert; Überschuss ist toxisch. Mangel: A→Nachtblindheit; D→Rachitis; K→Blutungen.","fr":"A (rétinol) : vision, fonction immunitaire. D (calciférol) : absorption du Ca²⁺. E (tocophérol) : antioxydant. K (phylloquinone) : facteurs de coagulation (II, VII, IX, X). Stockées dans les graisses ; l'excès est toxique. Carence : A→cécité nocturne ; D→rachitisme ; K→hémorragies.","tr":"A (retinol): görme, bağışıklık fonksiyonu. D (kalsiferol): Ca²⁺ emilimi. E (tokoferol): antioksidan. K (fillokinon): pıhtılaşma faktörleri (II, VII, IX, X). Yağda depolanır; fazlası toksiktir. Eksiklik: A→gece körlüğü; D→raşitizm; K→kanama.","nl":"A (retinol): zicht, immuunfunctie. D (calciferol): Ca²⁺-opname. E (tocoferol): antioxidant. K (fylloquinon): stollingsfactoren (II, VII, IX, X). Opgeslagen in vet; overmaat is toxisch. Deficiëntie: A→nachtblindheid; D→rachitis; K→bloedingen.","ru":"A (ретинол): зрение, иммунитет. D (кальциферол): всасывание Ca²⁺. E (токоферол): антиоксидант. K (филлохинон): факторы свёртывания (II, VII, IX, X). Накапливаются в жировой ткани; избыток токсичен. Дефицит: A→ночная слепота; D→рахит; K→кровотечения.","zh":"A（视黄醇）：视觉、免疫功能。D（钙化醇）：Ca²⁺ 吸收。E（生育酚）：抗氧化剂。K（叶绿醌）：凝血因子（II、VII、IX、X）。储存在脂肪中；过量有毒。缺乏：A→夜盲症；D→佝偻病；K→出血。","pt_BR":"A (retinol): visão, função imunológica. D (calciferol): absorção de Ca²⁺. E (tocoferol): antioxidante. K (filoquinona): fatores de coagulação (II, VII, IX, X). Armazenadas na gordura; excesso é tóxico. Deficiência: A→cegueira noturna; D→raquitismo; K→sangramento.","pt_PT":"A (retinol): visão, função imunitária. D (calciferol): absorção de Ca²⁺. E (tocoferol): antioxidante. K (filoquinona): fatores de coagulação (II, VII, IX, X). Armazenadas na gordura; excesso é tóxico. Deficiência: A→cegueira noturna; D→raquitismo; K→hemorragia."}},
  { id: 'dc-mcat-0128', deck_id: 'deck-mcat', sort_order: 128, front: "Vitamins: Water-Soluble", back: "B vitamins (thiamine B1, riboflavin B2, niacin B3, B6, folate B9, B12) and Vitamin C. Not stored (excreted in urine). B12 deficiency: megaloblastic anemia + neurological symptoms; requires intrinsic factor for absorption. Folate deficiency: megaloblastic anemia, neural tube defects." , front_translations: {"es":"Vitaminas: Hidrossolúveis","de":"Vitamine: Wasserlöslich","fr":"Vitamines : Hydrosolubles","tr":"Vitaminler: Suda Çözünen","nl":"Vitamines: Wateroplosbaar","ru":"Витамины: Водорастворимые","zh":"维生素：水溶性维生素","pt_BR":"Vitaminas: Hidrossolúveis","pt_PT":"Vitaminas: Hidrossolúveis"}, back_translations: {"es":"Vitaminas B (tiamina B1, riboflavina B2, niacina B3, B6, folato B9, B12) y vitamina C. No son armazenadas (excretadas en la urina). Deficiencia de B12: anemia megaloblástica + síntomas neurológicos; requiere fator intrínseco para absorción. Deficiencia de folato: anemia megaloblástica, defeitos del tubo neural.","de":"B-Vitamine (Thiamin B1, Riboflavin B2, Niacin B3, B6, Folat B9, B12) und Vitamin C. Werden nicht gespeichert (im Urin ausgeschieden). B12-Mangel: megaloblastäre Anämie + neurologische Symptome; erfordert Intrinsic Factor zur Absorption. Folatmangel: megaloblastäre Anämie, Neuralrohrdefekte.","fr":"Vitamines B (thiamine B1, riboflavine B2, niacine B3, B6, folate B9, B12) et vitamine C. Non stockées (excrétées dans l'urine). Carence en B12 : anémie mégaloblastique + symptômes neurologiques ; nécessite le facteur intrinsèque pour l'absorption. Carence en folate : anémie mégaloblastique, anomalies du tube neural.","tr":"B vitaminleri (tiamin B1, riboflavin B2, niasin B3, B6, folat B9, B12) ve C vitamini. Depolanmaz (idrarla atılır). B12 eksikliği: megaloblastik anemi + nörolojik semptomlar; emilim için intrinsik faktör gerektirir. Folat eksikliği: megaloblastik anemi, nöral tüp defektleri.","nl":"B-vitamines (thiamine B1, riboflavine B2, niacine B3, B6, folaat B9, B12) en vitamine C. Worden niet opgeslagen (uitgescheiden in urine). B12-deficiëntie: megaloblastaire anemie + neurologische symptomen; vereist intrinsieke factor voor absorptie. Folaatdeficiëntie: megaloblastaire anemie, neurale buisdefecten.","ru":"Витамины группы B (тиамин B1, рибофлавин B2, ниацин B3, B6, фолат B9, B12) и витамин C. Не накапливаются (выводятся с мочой). Дефицит B12: мегалобластная анемия + неврологические симптомы; для всасывания необходим внутренний фактор. Дефицит фолата: мегалобластная анемия, дефекты нервной трубки.","zh":"B 族维生素（硫胺素 B1、核黄素 B2、烟酸 B3、B6、叶酸 B9、B12）和维生素 C。不储存（经尿排出）。B12 缺乏：巨幼细胞性贫血 + 神经症状；吸收需要内因子。叶酸缺乏：巨幼细胞性贫血、神经管缺陷。","pt_BR":"Vitaminas B (tiamina B1, riboflavina B2, niacina B3, B6, folato B9, B12) e vitamina C. Não são armazenadas (excretadas na urina). Deficiência de B12: anemia megaloblástica + sintomas neurológicos; requer fator intrínseco para absorção. Deficiência de folato: anemia megaloblástica, defeitos do tubo neural.","pt_PT":"Vitaminas B (tiamina B1, riboflavina B2, niacina B3, B6, folato B9, B12) e vitamina C. Não são armazenadas (excretadas na urina). Deficiência de B12: anemia megaloblástica + sintomas neurológicos; requer fator intrínseco para absorção. Deficiência de folato: anemia megaloblástica, defeitos do tubo neural."}},
  { id: 'dc-mcat-0129', deck_id: 'deck-mcat', sort_order: 129, front: "Cytochrome P450 (CYP) System", back: "A family of liver enzymes responsible for Phase I drug metabolism (oxidation, reduction, hydrolysis). Can be induced (↑ enzyme activity, ↓ drug effect) or inhibited (↓ enzyme activity, ↑ drug levels and toxicity). Example: rifampin induces, grapefruit inhibits." , front_translations: {"es":"Sistema Citocromo P450 (CYP)","de":"Cytochrom P450 (CYP)-System","fr":"Système du cytochrome P450 (CYP)","tr":"Sitokrom P450 (CYP) Sistemi","nl":"Cytochroom P450 (CYP)-systeem","ru":"Система цитохрома P450 (CYP)","zh":"细胞色素P450（CYP）系统","pt_BR":"Sistema Citocromo P450 (CYP)","pt_PT":"Sistema Citocromo P450 (CYP)"}, back_translations: {"es":"Una família de enzimas hepáticas responsables por el metabolismo de fase I de los fármacos (oxidación, reducción, hidrólise). Pode ser induzido (↑ atividad enzimática, ↓ efecto del fármaco) o inibido (↓ atividad enzimática, ↑ niveles del fármaco y toxicidad). Exemplo: rifampicina induz, toranja inibe.","de":"Eine Familie von Leberenzymen, die für den Phase-I-Arzneimittelstoffwechsel verantwortlich sind (Oxidation, Reduktion, Hydrolyse). Kann induziert (↑ Enzymaktivität, ↓ Arzneimittelwirkung) oder gehemmt werden (↓ Enzymaktivität, ↑ Arzneimittelspiegel und Toxizität). Beispiel: Rifampicin induziert, Grapefruit hemmt.","fr":"Une famille d'enzymes hépatiques responsables du métabolisme de phase I des médicaments (oxydation, réduction, hydrolyse). Peut être induit (↑ activité enzymatique, ↓ effet du médicament) ou inhibé (↓ activité enzymatique, ↑ taux et toxicité du médicament). Exemple : rifampicine induit, pamplemousse inhibe.","tr":"Faz I ilaç metabolizmasından (oksidasyon, redüksiyon, hidroliz) sorumlu bir karaciğer enzim ailesi. İndüklenebilir (↑ enzim aktivitesi, ↓ ilaç etkisi) veya inhibe edilebilir (↓ enzim aktivitesi, ↑ ilaç düzeyleri ve toksisite). Örnek: rifampisin indükler, greyfurt inhibe eder.","nl":"Een familie van leverenzymen verantwoordelijk voor fase I-geneesmiddelmetabolisme (oxidatie, reductie, hydrolyse). Kan geïnduceerd (↑ enzymactiviteit, ↓ geneesmiddeleffect) of geïnhibeerd worden (↓ enzymactiviteit, ↑ geneesmiddelspiegels en toxiciteit). Voorbeeld: rifampicine induceert, grapefruit remt.","ru":"Семейство ферментов печени, ответственных за метаболизм лекарств I фазы (окисление, восстановление, гидролиз). Могут быть индуцированы (↑ активность фермента, ↓ эффект препарата) или ингибированы (↓ активность фермента, ↑ уровень препарата и токсичность). Пример: рифампицин индуцирует, грейпфрут ингибирует.","zh":"一类肝脏酶家族，负责I期药物代谢（氧化、还原、水解）。可被诱导（↑酶活性，↓药物效果）或抑制（↓酶活性，↑药物水平和毒性）。例如：利福平诱导，葡萄柚抑制。","pt_BR":"Uma família de enzimas hepáticas responsáveis pelo metabolismo de fase I dos fármacos (oxidação, redução, hidrólise). Pode ser induzido (↑ atividade enzimática, ↓ efeito do fármaco) ou inibido (↓ atividade enzimática, ↑ níveis do fármaco e toxicidade). Exemplo: rifampicina induz, toranja inibe.","pt_PT":"Uma família de enzimas hepáticas responsáveis pelo metabolismo de fase I dos fármacos (oxidação, redução, hidrólise). Pode ser induzido (↑ atividade enzimática, ↓ efeito do fármaco) ou inibido (↓ atividade enzimática, ↑ níveis do fármaco e toxicidade). Exemplo: rifampicina induz, toranja inibe."}},
  { id: 'dc-mcat-0130', deck_id: 'deck-mcat', sort_order: 130, front: "Receptor Pharmacology: Agonists and Antagonists", back: "Full agonist: activates receptor to maximum response (Emax). Partial agonist: can act as agonist or antagonist depending on context; submaximal Emax. Competitive antagonist: reversible, overcomed by ↑ agonist. Irreversible antagonist: permanently blocks receptor." , front_translations: {"es":"Farmacologia de Receptores: Agonistas y Antagonistas","de":"Rezeptorpharmakologie: Agonisten und Antagonisten","fr":"Pharmacologie des récepteurs : Agonistes et antagonistes","tr":"Reseptör Farmakolojisi: Agonistler ve Antagonistler","nl":"Receptorfarmacologie: Agonisten en antagonisten","ru":"Фармакология рецепторов: Агонисты и антагонисты","zh":"受体药理学：激动剂与拮抗剂","pt_BR":"Farmacologia de Receptores: Agonistas e Antagonistas","pt_PT":"Farmacologia de Recetores: Agonistas e Antagonistas"}, back_translations: {"es":"Agonista total: ativa el receptor hasta a respuesta máxima (Emax). Agonista parcial: puede agir como agonista o antagonista dependendo del contexto; Emax submáximo. Antagonista competitivo: reversible, superado por ↑ agonista. Antagonista irreversible: bloqueia el receptor permanentemente.","de":"Voller Agonist: aktiviert den Rezeptor bis zur maximalen Antwort (Emax). Partieller Agonist: kann je nach Kontext als Agonist oder Antagonist wirken; submaximales Emax. Kompetitiver Antagonist: reversibel, durch ↑ Agonist überwindbar. Irreversibler Antagonist: blockiert den Rezeptor dauerhaft.","fr":"Agoniste complet : active le récepteur jusqu'à la réponse maximale (Emax). Agoniste partiel : peut agir comme agoniste ou antagoniste selon le contexte ; Emax sous-maximal. Antagoniste compétitif : réversible, surmonté par ↑ agoniste. Antagoniste irréversible : bloque le récepteur de façon permanente.","tr":"Tam agonist: reseptörü maksimum yanıta kadar aktive eder (Emax). Kısmi agonist: bağlama göre agonist veya antagonist olarak davranabilir; submaksimal Emax. Kompetitif antagonist: geri dönüşümlü, ↑ agonist ile aşılır. İrreversibel antagonist: reseptörü kalıcı olarak bloke eder.","nl":"Volledige agonist: activeert de receptor tot maximale respons (Emax). Partiële agonist: kan als agonist of antagonist werken afhankelijk van de context; submaximale Emax. Competitieve antagonist: reversibel, overwonnen door ↑ agonist. Irreversibele antagonist: blokkeert de receptor permanent.","ru":"Полный агонист: активирует рецептор до максимального ответа (Emax). Частичный агонист: может действовать как агонист или антагонист в зависимости от контекста; субмаксимальный Emax. Конкурентный антагонист: обратимый, преодолевается ↑ агониста. Необратимый антагонист: блокирует рецептор навсегда.","zh":"完全激动剂：将受体激活至最大反应（Emax）。部分激动剂：根据情况可作为激动剂或拮抗剂；亚最大 Emax。竞争性拮抗剂：可逆，可被↑激动剂克服。不可逆拮抗剂：永久性阻断受体。","pt_BR":"Agonista total: ativa o receptor até a resposta máxima (Emax). Agonista parcial: pode agir como agonista ou antagonista dependendo do contexto; Emax submáximo. Antagonista competitivo: reversível, superado por ↑ agonista. Antagonista irreversível: bloqueia o receptor permanentemente.","pt_PT":"Agonista total: ativa o recetor até à resposta máxima (Emax). Agonista parcial: pode agir como agonista ou antagonista dependendo do contexto; Emax submáximo. Antagonista competitivo: reversível, superado por ↑ agonista. Antagonista irreversível: bloqueia o recetor permanentemente."}},
  { id: 'dc-mcat-0131', deck_id: 'deck-mcat', sort_order: 131, front: "Photosynthesis: Light Reactions", back: "In thylakoid membrane: light absorbed by chlorophyll → excites electrons → water is split (O₂ released) → electrons pass through ETC (PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺ reductase → NADPH). ATP produced by photophosphorylation." , front_translations: {"es":"Fotossíntese: Reaciones Luminosas","de":"Photosynthese: Lichtreaktionen","fr":"Photosynthèse : Réactions lumineuses","tr":"Fotosentez: Işık Reaksiyonları","nl":"Fotosynthese: Lichtreacties","ru":"Фотосинтез: Световые реакции","zh":"光合作用：光反应","pt_BR":"Fotossíntese: Reações Luminosas","pt_PT":"Fotossíntese: Reações Luminosas"}, back_translations: {"es":"Na membrana tilacoide: luz absorbida por la clorofila → excita electrones → agua es clivada (El₂ liberado) → electrones passam por la CTE (PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺ redutase → NADPH). ATP producido por fotofosforilación.","de":"In der Thylakoidmembran: Licht wird von Chlorophyll absorbiert → regt Elektronen an → Wasser wird gespalten (O₂ freigesetzt) → Elektronen durchlaufen ETC (PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺-Reduktase → NADPH). ATP wird durch Photophosphorylierung erzeugt.","fr":"Dans la membrane thylakoïde : la lumière absorbée par la chlorophylle → excite les électrons → l'eau est scindée (O₂ libéré) → les électrons passent par la chaîne de transport (PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺ réductase → NADPH). L'ATP est produit par photophosphorylation.","tr":"Tilakoit zarında: klorofil tarafından emilen ışık → elektronları uyarır → su parçalanır (O₂ salınır) → elektronlar ETC'den geçer (PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺ redüktaz → NADPH). ATP fotofosforilasyonla üretilir.","nl":"In het thylakoïdmembraan: licht geabsorbeerd door chlorofyl → wekt elektronen op → water wordt gesplitst (O₂ vrijgekomen) → elektronen passeren ETC (PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺-reductase → NADPH). ATP geproduceerd door fotofosforylering.","ru":"В тилакоидной мембране: свет поглощается хлорофиллом → возбуждает электроны → вода расщепляется (выделяется O₂) → электроны проходят по ЭТЦ (PSII → PQ → Cyt b6f → PC → PSI → Fd → НАДФ⁺-редуктаза → НАДФН). АТФ образуется путём фотофосфорилирования.","zh":"在类囊体膜中：叶绿素吸收光→激发电子→水被分解（释放O₂）→电子通过电子传递链（PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺还原酶 → NADPH）。ATP通过光合磷酸化产生。","pt_BR":"Na membrana tilacoide: luz absorvida pela clorofila → excita elétrons → água é clivada (O₂ liberado) → elétrons passam pela CTE (PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺ redutase → NADPH). ATP produzido por fotofosforilação.","pt_PT":"Na membrana tilacoide: luz absorvida pela clorofila → excita eletrões → água é clivada (O₂ libertado) → eletrões passam pela CTE (PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺ redutase → NADPH). ATP produzido por fotofosforilação."}},
  { id: 'dc-mcat-0132', deck_id: 'deck-mcat', sort_order: 132, front: "Calvin Cycle (MCAT)", back: "3 turns fix 3 CO₂ using 9 ATP and 6 NADPH to produce 1 G3P (net). Three phases: carbon fixation (CO₂ + RuBP → 3-PGA, by RuBisCo), reduction (3-PGA → G3P), regeneration of RuBP. Occurs in stroma." , front_translations: {"es":"Ciclo de Calvin (MCAT)","de":"Calvin-Zyklus (MCAT)","fr":"Cycle de Calvin (MCAT)","tr":"Calvin Döngüsü (MCAT)","nl":"Calvincyclus (MCAT)","ru":"Цикл Кальвина (MCAT)","zh":"卡尔文循环（MCAT）","pt_BR":"Ciclo de Calvin (MCAT)","pt_PT":"Ciclo de Calvin (MCAT)"}, back_translations: {"es":"3 voltas fixam 3 CO₂ usando 9 ATP y 6 NADPH para produzir 1 G3P (líquido). Tres fases: fixación de carbono (CO₂ + RuBP → 3-PGA, por la RuBisCo), reducción (3-PGA → G3P), regeneración del RuBP. Ocorre en el estroma.","de":"3 Durchläufe fixieren 3 CO₂ unter Verwendung von 9 ATP und 6 NADPH zur Produktion von 1 G3P (netto). Drei Phasen: Kohlenstofffixierung (CO₂ + RuBP → 3-PGA, durch RuBisCo), Reduktion (3-PGA → G3P), Regeneration von RuBP. Findet im Stroma statt.","fr":"3 tours fixent 3 CO₂ en utilisant 9 ATP et 6 NADPH pour produire 1 G3P (net). Trois phases : fixation du carbone (CO₂ + RuBP → 3-PGA, par RuBisCo), réduction (3-PGA → G3P), régénération du RuBP. Se déroule dans le stroma.","tr":"3 döngü, 9 ATP ve 6 NADPH kullanarak 3 CO₂ fikse eder ve 1 G3P (net) üretir. Üç faz: karbon fiksasyonu (CO₂ + RuBP → 3-PGA, RuBisCo ile), indirgeme (3-PGA → G3P), RuBP rejenerasyonu. Stromada gerçekleşir.","nl":"3 rondes fixeren 3 CO₂ met 9 ATP en 6 NADPH om 1 G3P (netto) te produceren. Drie fasen: koolstoffixatie (CO₂ + RuBP → 3-PGA, door RuBisCo), reductie (3-PGA → G3P), regeneratie van RuBP. Vindt plaats in het stroma.","ru":"3 оборота фиксируют 3 CO₂, используя 9 АТФ и 6 НАДФН, производя 1 Г3Ф (нетто). Три фазы: фиксация углерода (CO₂ + РуБФ → 3-ФГК, ферментом RuBisCo), восстановление (3-ФГК → Г3Ф), регенерация РуБФ. Происходит в строме.","zh":"3轮循环固定3个CO₂，使用9个ATP和6个NADPH产生1个G3P（净值）。三个阶段：碳固定（CO₂ + RuBP → 3-PGA，由RuBisCo催化）、还原（3-PGA → G3P）、RuBP再生。发生在基质中。","pt_BR":"3 voltas fixam 3 CO₂ usando 9 ATP e 6 NADPH para produzir 1 G3P (líquido). Três fases: fixação de carbono (CO₂ + RuBP → 3-PGA, pela RuBisCo), redução (3-PGA → G3P), regeneração do RuBP. Ocorre no estroma.","pt_PT":"3 voltas fixam 3 CO₂ usando 9 ATP e 6 NADPH para produzir 1 G3P (líquido). Três fases: fixação de carbono (CO₂ + RuBP → 3-PGA, pela RuBisCo), redução (3-PGA → G3P), regeneração do RuBP. Ocorre no estroma."}},
  { id: 'dc-mcat-0133', deck_id: 'deck-mcat', sort_order: 133, front: "Lactate Dehydrogenase (LDH)", back: "Enzyme that interconverts pyruvate and lactate using NAD⁺/NADH. During anaerobic glycolysis, LDH regenerates NAD⁺ (converting pyruvate → lactate) allowing glycolysis to continue. Serum LDH is a marker of tissue damage." , front_translations: {"es":"Lactato Desidrogenase (LDH)","de":"Lactatdehydrogenase (LDH)","fr":"Lactate déshydrogénase (LDH)","tr":"Laktat Dehidrojenaz (LDH)","nl":"Lactaatdehydrogenase (LDH)","ru":"Лактатдегидрогеназа (LDH)","zh":"乳酸脱氢酶（LDH）","pt_BR":"Lactato Desidrogenase (LDH)","pt_PT":"Lactato Desidrogenase (LDH)"}, back_translations: {"es":"Enzima que interconverte piruvato y lactato usando NAD⁺/NADH. Durante a glicólise anaeróbia, a LDH regenera NAD⁺ (convirtiendo piruvato → lactato), permitiendo que a glicólise continue. La LDH sérica es un marcador de dano tecidual.","de":"Enzym, das Pyruvat und Laktat unter Verwendung von NAD⁺/NADH ineinander umwandelt. Bei anaerober Glykolyse regeneriert LDH NAD⁺ (Umwandlung von Pyruvat → Laktat), sodass die Glykolyse fortgesetzt werden kann. Serum-LDH ist ein Marker für Gewebeschäden.","fr":"Enzyme qui interconvertit le pyruvate et le lactate en utilisant NAD⁺/NADH. Lors de la glycolyse anaérobie, la LDH régénère le NAD⁺ (convertissant le pyruvate → lactate) permettant à la glycolyse de continuer. La LDH sérique est un marqueur de lésion tissulaire.","tr":"NAD⁺/NADH kullanarak piruvat ve laktatı birbirine dönüştüren enzim. Anaerobik glikolizde LDH, NAD⁺'yi rejenerere eder (piruvat → laktat dönüşümü) ve glikolizin devam etmesini sağlar. Serum LDH doku hasarının bir göstergesidir.","nl":"Enzym dat pyruvaat en lactaat interconverteert met NAD⁺/NADH. Tijdens anaerobe glycolyse regenereert LDH NAD⁺ (omzetting pyruvaat → lactaat) zodat glycolyse kan doorgaan. Serum-LDH is een marker voor weefselschade.","ru":"Фермент, взаимопревращающий пируват и лактат с использованием НАД⁺/НАДН. При анаэробном гликолизе ЛДГ регенерирует НАД⁺ (превращая пируват → лактат), позволяя гликолизу продолжаться. Сывороточная ЛДГ — маркер повреждения тканей.","zh":"利用NAD⁺/NADH催化丙酮酸和乳酸相互转化的酶。在无氧糖酵解中，LDH再生NAD⁺（将丙酮酸→乳酸），使糖酵解得以继续。血清LDH是组织损伤的标志物。","pt_BR":"Enzima que interconverte piruvato e lactato usando NAD⁺/NADH. Durante a glicólise anaeróbia, a LDH regenera NAD⁺ (convertendo piruvato → lactato), permitindo que a glicólise continue. A LDH sérica é um marcador de dano tecidual.","pt_PT":"Enzima que interconverte piruvato e lactato usando NAD⁺/NADH. Durante a glicólise anaeróbia, a LDH regenera NAD⁺ (convertendo piruvato → lactato), permitindo que a glicólise continue. A LDH sérica é um marcador de lesão tecidular."}},
  { id: 'dc-mcat-0134', deck_id: 'deck-mcat', sort_order: 134, front: "Anaplerotic Reactions", back: "Reactions that replenish TCA cycle intermediates that have been used for biosynthesis. The most important: pyruvate + CO₂ → oxaloacetate (by pyruvate carboxylase, activated by acetyl-CoA). Ensures TCA cycle can continue operating." , front_translations: {"es":"Reaciones Anapleróticas","de":"Anaplerotische Reaktionen","fr":"Réactions anaplérotiques","tr":"Anaplerotik Reaksiyonlar","nl":"Anaplerotische reacties","ru":"Анаплеротические реакции","zh":"回补反应","pt_BR":"Reações Anapleróticas","pt_PT":"Reações Anapleróticas"}, back_translations: {"es":"Reaciones que reabastecem los intermediários del ciclo TCA que fueron usados para biossíntese. La más importante: piruvato + CO₂ → oxaloacetato (por la piruvato carboxilase, ativada por acetil-CoA). Garante que el ciclo TCA possa continuar operando.","de":"Reaktionen, die TCA-Zyklus-Intermediate auffüllen, die für die Biosynthese verwendet wurden. Die wichtigste: Pyruvat + CO₂ → Oxalacetat (durch Pyruvatcarboxylase, aktiviert durch Acetyl-CoA). Stellt sicher, dass der TCA-Zyklus weiter funktionieren kann.","fr":"Réactions qui reconstituent les intermédiaires du cycle de l'acide citrique utilisés pour la biosynthèse. La plus importante : pyruvate + CO₂ → oxaloacétate (par la pyruvate carboxylase, activée par l'acétyl-CoA). Assure que le cycle de l'acide citrique peut continuer à fonctionner.","tr":"Biyosentez için kullanılmış TCA döngüsü ara ürünlerini yenileyen reaksiyonlar. En önemlisi: piruvat + CO₂ → oksaloasetat (piruvat karboksilaz ile, asetil-CoA tarafından aktive edilir). TCA döngüsünün çalışmaya devam etmesini sağlar.","nl":"Reacties die TCA-cyclus-intermediairen aanvullen die voor biosynthese zijn gebruikt. De belangrijkste: pyruvaat + CO₂ → oxaalacetaat (door pyruvaatcarboxylase, geactiveerd door acetyl-CoA). Zorgt ervoor dat de TCA-cyclus kan blijven functioneren.","ru":"Реакции, восполняющие промежуточные продукты цикла ТКК, использованные для биосинтеза. Наиболее важная: пируват + CO₂ → оксалоацетат (пируваткарбоксилазой, активируемой ацетил-КоА). Обеспечивает продолжение работы цикла ТКК.","zh":"补充已被用于生物合成的TCA循环中间产物的反应。最重要的反应：丙酮酸 + CO₂ → 草酰乙酸（由丙酮酸羧化酶催化，被乙酰辅酶A激活）。确保TCA循环能够继续运行。","pt_BR":"Reações que reabastecem os intermediários do ciclo TCA que foram usados para biossíntese. A mais importante: piruvato + CO₂ → oxaloacetato (pela piruvato carboxilase, ativada por acetil-CoA). Garante que o ciclo TCA possa continuar operando.","pt_PT":"Reações que reabastecem os intermediários do ciclo TCA que foram utilizados para biossíntese. A mais importante: piruvato + CO₂ → oxaloacetato (pela piruvato carboxilase, ativada por acetil-CoA). Garante que o ciclo TCA possa continuar a operar."}},
  { id: 'dc-mcat-0135', deck_id: 'deck-mcat', sort_order: 135, front: "Purine vs. Pyrimidine Synthesis", back: "Purines (A, G): synthesized de novo on a ribose-5-phosphate scaffold using amino acids, folate, CO₂. Pyrimidines (C, T/U): ring synthesized first, then attached to ribose. Inhibited by methotrexate (folate analog) — used in cancer and autoimmune disease." , front_translations: {"es":"Síntese de Purinas vs. Pirimidinas","de":"Purin- vs. Pyrimidinsynthese","fr":"Synthèse des purines vs. pyrimidines","tr":"Pürin ve Pirimidin Sentezi","nl":"Purine- vs. pyrimidinesynthese","ru":"Синтез пуринов и пиримидинов","zh":"嘌呤与嘧啶合成","pt_BR":"Síntese de Purinas vs. Pirimidinas","pt_PT":"Síntese de Purinas vs. Pirimidinas"}, back_translations: {"es":"Purinas (A, G): sintetizadas de nuevo en un esqueleto de ribose-5-fosfato usando aminoácidos, folato, CO₂. Pirimidinas (C, T/U): el anel es sintetizado primero, después ligado a la ribose. Inibida por el metotrexato (análogo del folato) — usado en el cancer y en enfermedades autoimunes.","de":"Purine (A, G): de novo auf einem Ribose-5-Phosphat-Gerüst unter Verwendung von Aminosäuren, Folat, CO₂ synthetisiert. Pyrimidine (C, T/U): Ring wird zuerst synthetisiert, dann an Ribose gebunden. Gehemmt durch Methotrexat (Folatanalogon) — verwendet bei Krebs und Autoimmunerkrankungen.","fr":"Purines (A, G) : synthétisées de novo sur un squelette de ribose-5-phosphate à partir d'acides aminés, de folate, de CO₂. Pyrimidines (C, T/U) : le cycle est synthétisé d'abord, puis attaché au ribose. Inhibée par le méthotrexate (analogue du folate) — utilisé dans le cancer et les maladies auto-immunes.","tr":"Pürinler (A, G): amino asitler, folat, CO₂ kullanılarak riboz-5-fosfat iskelesi üzerinde de novo sentezlenir. Pirimidinler (C, T/U): halka önce sentezlenir, sonra riboza bağlanır. Metotreksat (folat analoğu) ile inhibe edilir — kanser ve otoimmün hastalıklarda kullanılır.","nl":"Purines (A, G): de novo gesynthetiseerd op een ribose-5-fosfaatskelet met aminozuren, folaat, CO₂. Pyrimidines (C, T/U): ring wordt eerst gesynthetiseerd, dan aan ribose gekoppeld. Geremd door methotrexaat (folaatanaloog) — gebruikt bij kanker en auto-immuunziekten.","ru":"Пурины (A, G): синтезируются de novo на рибозо-5-фосфатном каркасе с использованием аминокислот, фолата, CO₂. Пиримидины (C, T/U): кольцо синтезируется первым, затем присоединяется к рибозе. Ингибируется метотрексатом (аналог фолата) — применяется при раке и аутоиммунных заболеваниях.","zh":"嘌呤（A、G）：在核糖-5-磷酸骨架上利用氨基酸、叶酸、CO₂从头合成。嘧啶（C、T/U）：先合成环，再连接到核糖上。被甲氨蝶呤（叶酸类似物）抑制——用于癌症和自身免疫性疾病。","pt_BR":"Purinas (A, G): sintetizadas de novo em um esqueleto de ribose-5-fosfato usando aminoácidos, folato, CO₂. Pirimidinas (C, T/U): o anel é sintetizado primeiro, depois ligado à ribose. Inibida pelo metotrexato (análogo do folato) — usado no câncer e em doenças autoimunes.","pt_PT":"Purinas (A, G): sintetizadas de novo num esqueleto de ribose-5-fosfato usando aminoácidos, folato, CO₂. Pirimidinas (C, T/U): o anel é sintetizado primeiro, depois ligado à ribose. Inibida pelo metotrexato (análogo do folato) — utilizado no cancro e em doenças autoimunes."}},
  { id: 'dc-mcat-0136', deck_id: 'deck-mcat', sort_order: 136, front: "Sickle Cell Disease", back: "Autosomal recessive; single point mutation (Glu → Val at position 6 of β-globin). Causes HbS to polymerize under low O₂, deforming RBCs into sickle shape. Heterozygotes (HbAS) have sickle cell trait and some malaria resistance." , front_translations: {"es":"Doença Falciforme","de":"Sichelzellkrankheit","fr":"Drépanocytose","tr":"Orak Hücre Hastalığı","nl":"Sikkelcelziekte","ru":"Серповидноклеточная анемия","zh":"镰状细胞病","pt_BR":"Doença Falciforme","pt_PT":"Doença Falciforme"}, back_translations: {"es":"Autossomica recessiva; mutación pontual única (Glu → Val en la posición 6 de la β-globina). Causa polimerización de la HbS sob bajo El₂, deformando las hemácias en forma de foice. Heterozigotos (HbAS) possuem el traço falciforme y alguna resistencia a la malária.","de":"Autosomal-rezessiv; Einzelpunktmutation (Glu → Val an Position 6 des β-Globins). Verursacht Polymerisation von HbS bei niedrigem O₂, was RBCs in Sichelform verformt. Heterozygote (HbAS) haben Sichelzelleigenschaft und gewisse Malariaresistenz.","fr":"Autosomique récessive ; mutation ponctuelle unique (Glu → Val en position 6 de la β-globine). Provoque la polymérisation de l'HbS en hypoxie, déformant les globules rouges en forme de faucille. Les hétérozygotes (HbAS) ont le trait drépanocytaire et une certaine résistance au paludisme.","tr":"Otozomal resesif; tek nokta mutasyonu (β-globinin 6. pozisyonunda Glu → Val). Düşük O₂'de HbS'nin polimerize olmasına neden olarak kırmızı kan hücrelerini orak şekline dönüştürür. Heterozigotlar (HbAS) orak hücre taşıyıcısıdır ve sıtmaya karşı bir miktar direnç gösterir.","nl":"Autosomaal recessief; puntmutatie (Glu → Val op positie 6 van β-globine). Veroorzaakt polymerisatie van HbS bij lage O₂, waardoor rode bloedcellen sikkelvormig worden. Heterozygoten (HbAS) hebben sikkelceltrek en enige malariaresistentie.","ru":"Аутосомно-рецессивное; точечная мутация (Glu → Val в позиции 6 β-глобина). Вызывает полимеризацию HbS при низком O₂, деформируя эритроциты в серповидную форму. Гетерозиготы (HbAS) имеют серповидноклеточный признак и частичную устойчивость к малярии.","zh":"常染色体隐性遗传；单点突变（β-珠蛋白第6位 Glu → Val）。导致 HbS 在低 O₂ 条件下聚合，使红细胞变成镰刀状。杂合子（HbAS）具有镰状细胞特征和一定的疟疾抗性。","pt_BR":"Autossômica recessiva; mutação pontual única (Glu → Val na posição 6 da β-globina). Causa polimerização da HbS sob baixo O₂, deformando as hemácias em forma de foice. Heterozigotos (HbAS) possuem o traço falciforme e alguma resistência à malária.","pt_PT":"Autossómica recessiva; mutação pontual única (Glu → Val na posição 6 da β-globina). Causa polimerização da HbS sob baixo O₂, deformando os eritrócitos em forma de foice. Heterozigotos (HbAS) possuem o traço falciforme e alguma resistência à malária."}},
  { id: 'dc-mcat-0137', deck_id: 'deck-mcat', sort_order: 137, front: "Autosomal Dominant vs. Recessive Inheritance", back: "Autosomal dominant: one mutant allele sufficient; affects each generation, M=F. Examples: Huntington's, Marfan syndrome, familial hypercholesterolemia. Autosomal recessive: two mutant alleles required; carriers unaffected; may skip generations. Examples: cystic fibrosis, PKU, sickle cell." , front_translations: {"es":"Herança Autossomica Dominante vs. Recessiva","de":"Autosomal-dominante vs. rezessive Vererbung","fr":"Hérédité autosomique dominante vs. récessive","tr":"Otozomal Dominant ve Resesif Kalıtım","nl":"Autosomaal dominante vs. recessieve overerving","ru":"Аутосомно-доминантное и рецессивное наследование","zh":"常染色体显性遗传与隐性遗传","pt_BR":"Herança Autossômica Dominante vs. Recessiva","pt_PT":"Herança Autossómica Dominante vs. Recessiva"}, back_translations: {"es":"Autossomica dominante: un alelo mutante es suficiente; afecta cada geración, M=F. Exemplos: Huntington, síndrome de Marfan, hipercolesterolemia familiar. Autossomica recessiva: de los alelos mutantes necesarios; portadores no afetados; puede pular geraciones. Exemplos: fibrose cística, PKU, enfermedad falciforme.","de":"Autosomal-dominant: ein mutiertes Allel genügt; betrifft jede Generation, M=F. Beispiele: Huntington, Marfan-Syndrom, familiäre Hypercholesterinämie. Autosomal-rezessiv: zwei mutierte Allele erforderlich; Träger nicht betroffen; kann Generationen überspringen. Beispiele: Mukoviszidose, PKU, Sichelzellanämie.","fr":"Autosomique dominant : un allèle muté suffit ; affecte chaque génération, H=F. Exemples : maladie de Huntington, syndrome de Marfan, hypercholestérolémie familiale. Autosomique récessif : deux allèles mutés nécessaires ; les porteurs ne sont pas atteints ; peut sauter des générations. Exemples : mucoviscidose, PCU, drépanocytose.","tr":"Otozomal dominant: bir mutant alel yeterlidir; her nesli etkiler, E=K. Örnekler: Huntington, Marfan sendromu, ailesel hiperkolesterolemi. Otozomal resesif: iki mutant alel gereklidir; taşıyıcılar etkilenmez; nesil atlayabilir. Örnekler: kistik fibrozis, PKU, orak hücre hastalığı.","nl":"Autosomaal dominant: één mutant allel volstaat; treft elke generatie, M=V. Voorbeelden: Huntington, Marfan-syndroom, familiaire hypercholesterolemie. Autosomaal recessief: twee mutante allelen vereist; dragers niet aangedaan; kan generaties overslaan. Voorbeelden: cystische fibrose, PKU, sikkelcelanemie.","ru":"Аутосомно-доминантное: достаточно одного мутантного аллеля; проявляется в каждом поколении, М=Ж. Примеры: болезнь Хантингтона, синдром Марфана, семейная гиперхолестеринемия. Аутосомно-рецессивное: необходимы два мутантных аллеля; носители здоровы; может пропускать поколения. Примеры: муковисцидоз, PKU, серповидноклеточная анемия.","zh":"常染色体显性：一个突变等位基因即可致病；每代均受累，男女比例相等。例：亨廷顿病、马凡综合征、家族性高胆固醇血症。常染色体隐性：需两个突变等位基因；携带者不受影响；可隔代遗传。例：囊性纤维化、PKU、镰状细胞病。","pt_BR":"Autossômica dominante: um alelo mutante é suficiente; afeta cada geração, M=F. Exemplos: Huntington, síndrome de Marfan, hipercolesterolemia familiar. Autossômica recessiva: dois alelos mutantes necessários; portadores não afetados; pode pular gerações. Exemplos: fibrose cística, PKU, doença falciforme.","pt_PT":"Autossómica dominante: um alelo mutante é suficiente; afeta cada geração, M=F. Exemplos: doença de Huntington, síndrome de Marfan, hipercolesterolemia familiar. Autossómica recessiva: dois alelos mutantes necessários; portadores não afetados; pode saltar gerações. Exemplos: fibrose quística, PKU, doença falciforme."}},
  { id: 'dc-mcat-0138', deck_id: 'deck-mcat', sort_order: 138, front: "Eukaryotic vs. Prokaryotic Ribosomes", back: "Prokaryotic: 70S (50S + 30S subunits). Eukaryotic: 80S (60S + 40S subunits). Mitochondria and chloroplasts have 70S ribosomes (endosymbiosis). Antibiotics exploit differences: aminoglycosides and tetracyclines target 30S; chloramphenicol and macrolides target 50S." , front_translations: {"es":"Ribossomos Eucarióticos vs. Procarióticos","de":"Eukaryotische vs. prokaryotische Ribosomen","fr":"Ribosomes eucaryotes vs. procaryotes","tr":"Ökaryotik ve Prokaryotik Ribozomlar","nl":"Eukaryotische vs. prokaryotische ribosomen","ru":"Рибосомы эукариот и прокариот","zh":"真核生物与原核生物核糖体","pt_BR":"Ribossomos Eucarióticos vs. Procarióticos","pt_PT":"Ribossomas Eucarióticos vs. Procarióticos"}, back_translations: {"es":"Procarióticos: 70S (subunidades 50S + 30S). Eucarióticos: 80S (subunidades 60S + 40S). Mitocondrias y cloroplastos possuem ribossomos 70S (endossimbiose). Antibióticos exploram las diferencias: aminoglicosídeos y tetraciclinas visam 30S; cloranfenicol y macrolídeos visam 50S.","de":"Prokaryotisch: 70S (50S + 30S Untereinheiten). Eukaryotisch: 80S (60S + 40S Untereinheiten). Mitochondrien und Chloroplasten haben 70S-Ribosomen (Endosymbiose). Antibiotika nutzen Unterschiede: Aminoglykoside und Tetracycline zielen auf 30S; Chloramphenicol und Makrolide auf 50S.","fr":"Procaryotes : 70S (sous-unités 50S + 30S). Eucaryotes : 80S (sous-unités 60S + 40S). Les mitochondries et chloroplastes possèdent des ribosomes 70S (endosymbiose). Les antibiotiques exploitent ces différences : aminoglycosides et tétracyclines ciblent 30S ; chloramphénicol et macrolides ciblent 50S.","tr":"Prokaryotik: 70S (50S + 30S alt birimleri). Ökaryotik: 80S (60S + 40S alt birimleri). Mitokondri ve kloroplastlar 70S ribozomlara sahiptir (endosimbiyoz). Antibiyotikler farklılıklardan yararlanır: aminoglikozidler ve tetrasiklinler 30S'i; kloramfenikol ve makrolidler 50S'i hedef alır.","nl":"Prokaryotisch: 70S (50S + 30S subeenheden). Eukaryotisch: 80S (60S + 40S subeenheden). Mitochondriën en chloroplasten hebben 70S-ribosomen (endosymbiose). Antibiotica benutten verschillen: aminoglycosiden en tetracyclines richten zich op 30S; chlooramfenicol en macroliden op 50S.","ru":"Прокариотические: 70S (субъединицы 50S + 30S). Эукариотические: 80S (субъединицы 60S + 40S). Митохондрии и хлоропласты имеют рибосомы 70S (эндосимбиоз). Антибиотики используют различия: аминогликозиды и тетрациклины нацелены на 30S; хлорамфеникол и макролиды — на 50S.","zh":"原核生物：70S（50S + 30S 亚基）。真核生物：80S（60S + 40S 亚基）。线粒体和叶绿体具有 70S 核糖体（内共生）。抗生素利用这些差异：氨基糖苷类和四环素类靶向 30S；氯霉素和大环内酯类靶向 50S。","pt_BR":"Procarióticos: 70S (subunidades 50S + 30S). Eucarióticos: 80S (subunidades 60S + 40S). Mitocôndrias e cloroplastos possuem ribossomos 70S (endossimbiose). Antibióticos exploram as diferenças: aminoglicosídeos e tetraciclinas visam 30S; cloranfenicol e macrolídeos visam 50S.","pt_PT":"Procarióticos: 70S (subunidades 50S + 30S). Eucarióticos: 80S (subunidades 60S + 40S). Mitocôndrias e cloroplastos possuem ribossomas 70S (endossimbiose). Antibióticos exploram as diferenças: aminoglicosídeos e tetraciclinas visam 30S; cloranfenicol e macrólidos visam 50S."}},
  { id: 'dc-mcat-0139', deck_id: 'deck-mcat', sort_order: 139, front: "Osmolality and Tonicity", back: "Osmolality: total concentration of all solutes (mOsm/kg). Tonicity: concentration of solutes that cannot cross the cell membrane (determines cell volume). Hypertonic solution → cell shrinks. Hypotonic → cell swells. Normal plasma osmolality ≈ 285–295 mOsm/kg." , front_translations: {"es":"Osmolalidad y Tonicidad","de":"Osmolalität und Tonizität","fr":"Osmolalité et tonicité","tr":"Osmolalite ve Tonisite","nl":"Osmolaliteit en toniciteit","ru":"Осмолярность и тоничность","zh":"渗透压与张力","pt_BR":"Osmolalidade e Tonicidade","pt_PT":"Osmolalidade e Tonicidade"}, back_translations: {"es":"Osmolalidad: concentración total de todos los solutos (mOsm/kg). Tonicidad: concentración de solutos que no pueden atravessar a membrana celular (determina el volumen celular). Solución hipertonica → célula encolhe. Hipotonica → célula incha. Osmolalidad plasmática normal ≈ 285–295 mOsm/kg.","de":"Osmolalität: Gesamtkonzentration aller gelösten Stoffe (mOsm/kg). Tonizität: Konzentration der Stoffe, die die Zellmembran nicht passieren können (bestimmt Zellvolumen). Hypertone Lösung → Zelle schrumpft. Hypotone → Zelle schwillt an. Normale Plasmaosmolalität ≈ 285–295 mOsm/kg.","fr":"Osmolalité : concentration totale de tous les solutés (mOsm/kg). Tonicité : concentration des solutés ne pouvant traverser la membrane cellulaire (détermine le volume cellulaire). Solution hypertonique → la cellule rétrécit. Hypotonique → la cellule gonfle. Osmolalité plasmatique normale ≈ 285–295 mOsm/kg.","tr":"Osmolalite: tüm çözünenlerin toplam konsantrasyonu (mOsm/kg). Tonisite: hücre zarını geçemeyen çözünenlerin konsantrasyonu (hücre hacmini belirler). Hipertonik çözelti → hücre büzülür. Hipotonik → hücre şişer. Normal plazma osmolalitesi ≈ 285–295 mOsm/kg.","nl":"Osmolaliteit: totale concentratie van alle opgeloste stoffen (mOsm/kg). Toniciteit: concentratie van stoffen die het celmembraan niet kunnen passeren (bepaalt celvolume). Hypertone oplossing → cel krimpt. Hypotoon → cel zwelt. Normale plasma-osmolaliteit ≈ 285–295 mOsm/kg.","ru":"Осмолярность: общая концентрация всех растворённых веществ (мОсм/кг). Тоничность: концентрация веществ, не проходящих через клеточную мембрану (определяет объём клетки). Гипертонический раствор → клетка сжимается. Гипотонический → клетка набухает. Нормальная осмолярность плазмы ≈ 285–295 мОсм/кг.","zh":"渗透压：所有溶质的总浓度（mOsm/kg）。张力：不能穿过细胞膜的溶质浓度（决定细胞体积）。高渗溶液 → 细胞皱缩。低渗 → 细胞膨胀。正常血浆渗透压 ≈ 285–295 mOsm/kg。","pt_BR":"Osmolalidade: concentração total de todos os solutos (mOsm/kg). Tonicidade: concentração de solutos que não podem atravessar a membrana celular (determina o volume celular). Solução hipertônica → célula encolhe. Hipotônica → célula incha. Osmolalidade plasmática normal ≈ 285–295 mOsm/kg.","pt_PT":"Osmolalidade: concentração total de todos os solutos (mOsm/kg). Tonicidade: concentração de solutos que não podem atravessar a membrana celular (determina o volume celular). Solução hipertónica → célula encolhe. Hipotónica → célula incha. Osmolalidade plasmática normal ≈ 285–295 mOsm/kg."}},
  { id: 'dc-mcat-0140', deck_id: 'deck-mcat', sort_order: 140, front: "Diabetes Insipidus vs. SIADH", back: "Diabetes insipidus: insufficient ADH (central DI) or unresponsive kidneys (nephrogenic DI) → dilute urine, hypernatremia, polydipsia. SIADH (syndrome of inappropriate ADH): excess ADH → concentrated urine, hyponatremia, water retention." , front_translations: {"es":"Diabetes Insípido vs. SIADH","de":"Diabetes insipidus vs. SIADH","fr":"Diabète insipide vs. SIADH","tr":"Diabetes İnsipidus ve SIADH","nl":"Diabetes insipidus vs. SIADH","ru":"Несахарный диабет и SIADH","zh":"尿崩症与SIADH","pt_BR":"Diabetes Insípido vs. SIADH","pt_PT":"Diabetes Insípido vs. SIADH"}, back_translations: {"es":"Diabetes insípido: ADH insuficiente (DI central) o riñones no responsivos (DI nefrogenico) → urina diluída, hipernatremia, polidipsia. SIADH (síndrome de la secreción inapropriada de ADH): exceso de ADH → urina concentrada, hiponatremia, retención de agua.","de":"Diabetes insipidus: unzureichendes ADH (zentraler DI) oder nicht ansprechende Nieren (nephrogener DI) → verdünnter Urin, Hypernatriämie, Polydipsie. SIADH (Syndrom der inadäquaten ADH-Sekretion): übermäßiges ADH → konzentrierter Urin, Hyponatriämie, Wasserretention.","fr":"Diabète insipide : ADH insuffisante (DI central) ou reins non répondeurs (DI néphrogénique) → urine diluée, hypernatrémie, polydipsie. SIADH (syndrome de sécrétion inappropriée d'ADH) : excès d'ADH → urine concentrée, hyponatrémie, rétention d'eau.","tr":"Diabetes insipidus: yetersiz ADH (santral Dİ) veya böbreklerin yanıtsızlığı (nefrojenik Dİ) → seyreltik idrar, hipernatremi, polidipsi. SIADH (uygunsuz ADH sendromu): aşırı ADH → konsantre idrar, hiponatremi, su retansiyonu.","nl":"Diabetes insipidus: onvoldoende ADH (centraal DI) of niet-reagerende nieren (nefrogeen DI) → verdunde urine, hypernatriëmie, polydipsie. SIADH (syndroom van inadequate ADH-secretie): overmatig ADH → geconcentreerde urine, hyponatriëmie, waterretentie.","ru":"Несахарный диабет: недостаток АДГ (центральный НД) или нечувствительные почки (нефрогенный НД) → разбавленная моча, гипернатриемия, полидипсия. SIADH (синдром неадекватной секреции АДГ): избыток АДГ → концентрированная моча, гипонатриемия, задержка воды.","zh":"尿崩症：ADH不足（中枢性DI）或肾脏无反应（肾源性DI）→ 稀释尿液、高钠血症、多饮。SIADH（抗利尿激素分泌不当综合征）：ADH过多 → 浓缩尿液、低钠血症、水潴留。","pt_BR":"Diabetes insípido: ADH insuficiente (DI central) ou rins não responsivos (DI nefrogênico) → urina diluída, hipernatremia, polidipsia. SIADH (síndrome da secreção inapropriada de ADH): excesso de ADH → urina concentrada, hiponatremia, retenção de água.","pt_PT":"Diabetes insípido: ADH insuficiente (DI central) ou rins não responsivos (DI nefrogénico) → urina diluída, hipernatremia, polidipsia. SIADH (síndrome de secreção inapropriada de ADH): excesso de ADH → urina concentrada, hiponatremia, retenção de água."}},
  { id: 'dc-mcat-0141', deck_id: 'deck-mcat', sort_order: 141, front: "Lung Volumes and Capacities", back: "Tidal volume (TV): normal breath ~500 mL. IRV: maximum inspiration above TV. ERV: maximum expiration below TV. Residual volume (RV): cannot be exhaled (~1.2 L). FRC = ERV + RV. TLC = TV + IRV + ERV + RV. FEV1/FVC distinguishes obstructive (<70%) from restrictive (normal ratio, reduced TLC)." , front_translations: {"es":"Volumes y Capacidades Pulmonares","de":"Lungenvolumina und -kapazitäten","fr":"Volumes et capacités pulmonaires","tr":"Akciğer Hacimleri ve Kapasiteleri","nl":"Longvolumes en -capaciteiten","ru":"Лёгочные объёмы и ёмкости","zh":"肺容量与肺活量","pt_BR":"Volumes e Capacidades Pulmonares","pt_PT":"Volumes e Capacidades Pulmonares"}, back_translations: {"es":"Volume corrente (TV): respiración normal ~500 mL. VRI: inspiración máxima encima del TV. VRE: expiración máxima debajo del TV. Volume residual (VR): no puede ser exalado (~1,2 L). CRF = VRE + VR. CPT = TV + VRI + VRE + VR. VEF1/CVF distingue obstrutivo (<70%) de restritivo (razão normal, CPT reduzida).","de":"Atemzugvolumen (TV): normaler Atemzug ~500 mL. IRV: maximale Inspiration über TV. ERV: maximale Exspiration unter TV. Residualvolumen (RV): kann nicht ausgeatmet werden (~1,2 L). FRC = ERV + RV. TLC = TV + IRV + ERV + RV. FEV1/FVC unterscheidet obstruktiv (<70 %) von restriktiv (normales Verhältnis, reduzierte TLC).","fr":"Volume courant (TV) : respiration normale ~500 mL. VRI : inspiration maximale au-dessus du TV. VRE : expiration maximale en dessous du TV. Volume résiduel (VR) : ne peut être expiré (~1,2 L). CRF = VRE + VR. CPT = TV + VRI + VRE + VR. VEMS/CVF distingue obstructif (<70 %) de restrictif (rapport normal, CPT réduite).","tr":"Tidal hacim (TV): normal nefes ~500 mL. IRV: TV üzerindeki maksimum inspirasyon. ERV: TV altındaki maksimum ekspirasyon. Rezidüel hacim (RV): dışarı verilemez (~1,2 L). FRC = ERV + RV. TLC = TV + IRV + ERV + RV. FEV1/FVC obstrüktif (<70%) ile restriktif (normal oran, azalmış TLC) ayrımını yapar.","nl":"Teugvolume (TV): normale ademhaling ~500 mL. IRV: maximale inspiratie boven TV. ERV: maximale expiratie onder TV. Residuvolume (RV): kan niet worden uitgeademd (~1,2 L). FRC = ERV + RV. TLC = TV + IRV + ERV + RV. FEV1/FVC onderscheidt obstructief (<70%) van restrictief (normale ratio, verlaagde TLC).","ru":"Дыхательный объём (ДО): обычный вдох ~500 мл. РОвд: максимальный вдох сверх ДО. РОвыд: максимальный выдох ниже ДО. Остаточный объём (ОО): не может быть выдохнут (~1,2 л). ФОЕ = РОвыд + ОО. ОЕЛ = ДО + РОвд + РОвыд + ОО. ОФВ1/ФЖЕЛ различает обструктивный (<70%) и рестриктивный тип (нормальное соотношение, сниженная ОЕЛ).","zh":"潮气量 (TV)：正常呼吸 ~500 mL。IRV：超过TV的最大吸气量。ERV：低于TV的最大呼气量。残气量 (RV)：无法呼出 (~1.2 L)。FRC = ERV + RV。TLC = TV + IRV + ERV + RV。FEV1/FVC 区分阻塞性（<70%）和限制性（比值正常，TLC降低）。","pt_BR":"Volume corrente (TV): respiração normal ~500 mL. VRI: inspiração máxima acima do TV. VRE: expiração máxima abaixo do TV. Volume residual (VR): não pode ser exalado (~1,2 L). CRF = VRE + VR. CPT = TV + VRI + VRE + VR. VEF1/CVF distingue obstrutivo (<70%) de restritivo (razão normal, CPT reduzida).","pt_PT":"Volume corrente (TV): respiração normal ~500 mL. VRI: inspiração máxima acima do TV. VRE: expiração máxima abaixo do TV. Volume residual (VR): não pode ser exalado (~1,2 L). CRF = VRE + VR. CPT = TV + VRI + VRE + VR. FEV1/CVF distingue obstrutivo (<70%) de restritivo (razão normal, CPT reduzida)."}},
  { id: 'dc-mcat-0142', deck_id: 'deck-mcat', sort_order: 142, front: "Neurotransmitter Metabolism: Monoamines", back: "MAO (monoamine oxidase) degrades dopamine, serotonin, and norepinephrine. MAO inhibitors (MAOIs) treat depression (dangerous tyramine interactions). COMT degrades catecholamines. Reuptake transporters (SERT, DAT, NET) are targets of SSRIs, SNRIs, TCAs, and cocaine." , front_translations: {"es":"Metabolismo de Neurotransmissores: Monoaminas","de":"Neurotransmitter-Stoffwechsel: Monoamine","fr":"Métabolisme des neurotransmetteurs : Monoamines","tr":"Nörotransmitter Metabolizması: Monoaminler","nl":"Neurotransmittermetabolisme: Monoaminen","ru":"Метаболизм нейромедиаторов: Моноамины","zh":"神经递质代谢：单胺类","pt_BR":"Metabolismo de Neurotransmissores: Monoaminas","pt_PT":"Metabolismo de Neurotransmissores: Monoaminas"}, back_translations: {"es":"MAO (monoamina oxidase) degrada dopamina, serotonina y norepinefrina. Inibidores de la MAO (IMAOs) tratam depresión (interacciones perigosas con tiramina). COMT degrada catecolaminas. Transportadores de recaptación (SERT, DAT, NET) son alvos de ISRSs, IRSNs, ADTs y cocaína.","de":"MAO (Monoaminoxidase) baut Dopamin, Serotonin und Noradrenalin ab. MAO-Hemmer (MAOIs) behandeln Depressionen (gefährliche Tyramin-Interaktionen). COMT baut Katecholamine ab. Wiederaufnahmetransporter (SERT, DAT, NET) sind Ziele von SSRIs, SNRIs, TCAs und Kokain.","fr":"La MAO (monoamine oxydase) dégrade la dopamine, la sérotonine et la noradrénaline. Les inhibiteurs de la MAO (IMAO) traitent la dépression (interactions dangereuses avec la tyramine). La COMT dégrade les catécholamines. Les transporteurs de recapture (SERT, DAT, NET) sont les cibles des ISRS, IRSN, ATC et de la cocaïne.","tr":"MAO (monoamin oksidaz) dopamin, serotonin ve norepinefrini yıkar. MAO inhibitörleri (MAOİ'ler) depresyonu tedavi eder (tehlikeli tiramin etkileşimleri). COMT katekolaminleri yıkar. Geri alım taşıyıcıları (SERT, DAT, NET) SSRİ'ler, SNRİ'ler, TCA'lar ve kokainin hedefleridir.","nl":"MAO (monoamineoxidase) breekt dopamine, serotonine en norepinefrine af. MAO-remmers (MAOIs) behandelen depressie (gevaarlijke tyramine-interacties). COMT breekt catecholaminen af. Heropnametransporters (SERT, DAT, NET) zijn doelwitten van SSRIs, SNRIs, TCAs en cocaïne.","ru":"МАО (моноаминоксидаза) расщепляет дофамин, серотонин и норадреналин. Ингибиторы МАО (ИМАО) лечат депрессию (опасные взаимодействия с тирамином). КОМТ расщепляет катехоламины. Транспортёры обратного захвата (SERT, DAT, NET) — мишени СИОЗС, СИОЗСН, ТЦА и кокаина.","zh":"MAO（单胺氧化酶）降解多巴胺、血清素和去甲肾上腺素。MAO抑制剂（MAOIs）治疗抑郁症（与酪胺有危险的相互作用）。COMT降解儿茶酚胺。再摄取转运体（SERT、DAT、NET）是SSRIs、SNRIs、TCAs和可卡因的靶点。","pt_BR":"MAO (monoamina oxidase) degrada dopamina, serotonina e norepinefrina. Inibidores da MAO (IMAOs) tratam depressão (interações perigosas com tiramina). COMT degrada catecolaminas. Transportadores de recaptação (SERT, DAT, NET) são alvos de ISRSs, IRSNs, ADTs e cocaína.","pt_PT":"MAO (monoamina oxidase) degrada dopamina, serotonina e norepinefrina. Inibidores da MAO (IMAOs) tratam a depressão (interações perigosas com tiramina). COMT degrada catecolaminas. Transportadores de recaptação (SERT, DAT, NET) são alvos de ISRSs, IRSNs, ADTs e cocaína."}},
  { id: 'dc-mcat-0143', deck_id: 'deck-mcat', sort_order: 143, front: "Pain Pathways", back: "Nociceptors in periphery → afferent fibers (Aδ: fast sharp pain; C fibers: slow burning pain) → dorsal horn → cross midline → spinothalamic tract → thalamus → cortex. Gate control theory: stimulating large Aβ fibers inhibits pain perception." , front_translations: {"es":"Vias de la Dor","de":"Schmerzwege","fr":"Voies de la douleur","tr":"Ağrı Yolakları","nl":"Pijnbanen","ru":"Болевые пути","zh":"痛觉通路","pt_BR":"Vias da Dor","pt_PT":"Vias da Dor"}, back_translations: {"es":"Nociceptores en la periferia → fibras aferentes (Aδ: dor rápida y aguda; fibras C: dor lenta y en queimación) → corno dorsal → cruzam a línea média → trato espinotalamico → tálamo → córtex. Teoria del portão: estimulación de fibras Aβ grandes inibe a percepción de la dor.","de":"Nozizeptoren in der Peripherie → afferente Fasern (Aδ: schneller, scharfer Schmerz; C-Fasern: langsamer, brennender Schmerz) → Hinterhorn → Kreuzung der Mittellinie → Tractus spinothalamicus → Thalamus → Kortex. Gate-Control-Theorie: Stimulation großer Aβ-Fasern hemmt die Schmerzwahrnehmung.","fr":"Nocicepteurs en périphérie → fibres afférentes (Aδ : douleur rapide et aiguë ; fibres C : douleur lente et brûlante) → corne dorsale → croisement de la ligne médiane → tractus spinothalamique → thalamus → cortex. Théorie du portillon : la stimulation des grosses fibres Aβ inhibe la perception de la douleur.","tr":"Periferdeki nosiseptörler → afferent lifler (Aδ: hızlı keskin ağrı; C lifleri: yavaş yanıcı ağrı) → arka boynuz → orta hattı geçiş → spinotalamik yolak → talamus → korteks. Kapı kontrol teorisi: büyük Aβ liflerinin uyarılması ağrı algısını inhibe eder.","nl":"Nociceptoren in periferie → afferente vezels (Aδ: snelle scherpe pijn; C-vezels: langzame brandende pijn) → achterhoorn → kruising middenlijn → tractus spinothalamicus → thalamus → cortex. Gate control-theorie: stimulatie van grote Aβ-vezels remt pijnperceptie.","ru":"Ноцицепторы на периферии → афферентные волокна (Aδ: быстрая острая боль; C-волокна: медленная жгучая боль) → задний рог → перекрёст по средней линии → спиноталамический тракт → таламус → кора. Теория воротного контроля: стимуляция крупных Aβ-волокон подавляет восприятие боли.","zh":"外周伤害感受器 → 传入纤维（Aδ：快速锐痛；C纤维：缓慢灼痛）→ 脊髓后角 → 越过中线 → 脊髓丘脑束 → 丘脑 → 大脑皮层。闸门控制理论：刺激大直径Aβ纤维抑制痛觉。","pt_BR":"Nociceptores na periferia → fibras aferentes (Aδ: dor rápida e aguda; fibras C: dor lenta e em queimação) → corno dorsal → cruzam a linha média → trato espinotalâmico → tálamo → córtex. Teoria do portão: estimulação de fibras Aβ grandes inibe a percepção da dor.","pt_PT":"Nociceptores na periferia → fibras aferentes (Aδ: dor rápida e aguda; fibras C: dor lenta e em queimadura) → corno dorsal → cruzam a linha média → trato espinotalâmico → tálamo → córtex. Teoria do portão: estimulação de fibras Aβ grandes inibe a perceção da dor."}},
  { id: 'dc-mcat-0144', deck_id: 'deck-mcat', sort_order: 144, front: "Hormones: Insulin and Glucagon Actions", back: "Insulin (fed state, β-cells): promotes glucose uptake (GLUT4 in muscle/fat), glycogenesis, lipogenesis, protein synthesis. Inhibits gluconeogenesis and lipolysis. Glucagon (fasted state, α-cells): promotes glycogenolysis, gluconeogenesis, lipolysis, ketogenesis." , front_translations: {"es":"Hormonios: Aciones de la Insulina y del Glucagon","de":"Hormone: Insulin- und Glucagonwirkungen","fr":"Hormones : Actions de l'insuline et du glucagon","tr":"Hormonlar: İnsülin ve Glukagon Etkileri","nl":"Hormonen: Insuline- en glucagonwerking","ru":"Гормоны: Действие инсулина и глюкагона","zh":"激素：胰岛素和胰高血糖素的作用","pt_BR":"Hormônios: Ações da Insulina e do Glucagon","pt_PT":"Hormonas: Ações da Insulina e do Glucagão"}, back_translations: {"es":"Insulina (estado alimentado, células β): promueve captación de glicose (GLUT4 en el músculo/gordura), glicogenese, lipogenese, síntese proteica. Inibe gliconeogenese y lipólise. Glucagon (estado de jejum, células α): promueve glicogenólise, gliconeogenese, lipólise, cetogenese.","de":"Insulin (Sättigungszustand, β-Zellen): fördert Glucoseaufnahme (GLUT4 in Muskel/Fett), Glykogensynthese, Lipogenese, Proteinsynthese. Hemmt Gluconeogenese und Lipolyse. Glucagon (Nüchternzustand, α-Zellen): fördert Glykogenolyse, Gluconeogenese, Lipolyse, Ketogenese.","fr":"Insuline (état nourri, cellules β) : favorise l'absorption du glucose (GLUT4 dans muscle/tissu adipeux), la glycogénèse, la lipogenèse, la synthèse protéique. Inhibe la néoglucogenèse et la lipolyse. Glucagon (état de jeûne, cellules α) : favorise la glycogénolyse, la néoglucogenèse, la lipolyse, la cétogenèse.","tr":"İnsülin (tok durum, β-hücreleri): glukoz alımını (kas/yağda GLUT4), glikojenezi, lipogenezi, protein sentezini destekler. Glukoneogenezi ve lipolizi inhibe eder. Glukagon (açlık durumu, α-hücreleri): glikojenolizi, glukoneogenezi, lipolizi, ketogenezi destekler.","nl":"Insuline (gevoede toestand, β-cellen): bevordert glucoseopname (GLUT4 in spier/vet), glycogenese, lipogenese, eiwitsynthese. Remt gluconeogenese en lipolyse. Glucagon (nuchtere toestand, α-cellen): bevordert glycogenolyse, gluconeogenese, lipolyse, ketogenese.","ru":"Инсулин (сытое состояние, β-клетки): способствует поглощению глюкозы (GLUT4 в мышцах/жировой ткани), гликогенезу, липогенезу, синтезу белка. Подавляет глюконеогенез и липолиз. Глюкагон (голодное состояние, α-клетки): способствует гликогенолизу, глюконеогенезу, липолизу, кетогенезу.","zh":"胰岛素（进食状态，β细胞）：促进葡萄糖摄取（肌肉/脂肪中的GLUT4）、糖原合成、脂肪合成、蛋白质合成。抑制糖异生和脂肪分解。胰高血糖素（禁食状态，α细胞）：促进糖原分解、糖异生、脂肪分解、酮体生成。","pt_BR":"Insulina (estado alimentado, células β): promove captação de glicose (GLUT4 no músculo/gordura), glicogênese, lipogênese, síntese proteica. Inibe gliconeogênese e lipólise. Glucagon (estado de jejum, células α): promove glicogenólise, gliconeogênese, lipólise, cetogênese.","pt_PT":"Insulina (estado alimentado, células β): promove captação de glicose (GLUT4 no músculo/gordura), glicogénese, lipogénese, síntese proteica. Inibe gluconeogénese e lipólise. Glucagão (estado de jejum, células α): promove glicogenólise, gluconeogénese, lipólise, cetogénese."}},
  { id: 'dc-mcat-0145', deck_id: 'deck-mcat', sort_order: 145, front: "Adrenal Cortex Hormones", back: "Zona glomerulosa → mineralocorticoids (aldosterone): Na⁺/K⁺ regulation. Zona fasciculata → glucocorticoids (cortisol): stress response, anti-inflammatory. Zona reticularis → androgens (DHEA). 'GFR' = zona order from outside in." , front_translations: {"es":"Hormonios del Córtex Adrenal","de":"Hormone der Nebennierenrinde","fr":"Hormones du cortex surrénalien","tr":"Adrenal Korteks Hormonları","nl":"Hormonen van de bijnierschors","ru":"Гормоны коры надпочечников","zh":"肾上腺皮质激素","pt_BR":"Hormônios do Córtex Adrenal","pt_PT":"Hormonas do Córtex Suprarrenal"}, back_translations: {"es":"Zona glomerulosa → mineralocorticoides (aldosterona): regulación de Na⁺/K⁺. Zona fasciculata → glicocorticoides (cortisol): respuesta al estresse, anti-inflamatório. Zona reticularis → andrógenos (DHEA). 'GFR' = ordem de las zonas de fuera para dentro.","de":"Zona glomerulosa → Mineralocorticoide (Aldosteron): Na⁺/K⁺-Regulation. Zona fasciculata → Glucocorticoide (Cortisol): Stressreaktion, entzündungshemmend. Zona reticularis → Androgene (DHEA). 'GFR' = Zonenreihenfolge von außen nach innen.","fr":"Zona glomerulosa → minéralocorticoïdes (aldostérone) : régulation Na⁺/K⁺. Zona fasciculata → glucocorticoïdes (cortisol) : réponse au stress, anti-inflammatoire. Zona reticularis → androgènes (DHEA). 'GFR' = ordre des zones de l'extérieur vers l'intérieur.","tr":"Zona glomerulosa → mineralokortikoidler (aldosteron): Na⁺/K⁺ düzenlemesi. Zona fasciculata → glukokortikoidler (kortizol): stres yanıtı, anti-enflamatuar. Zona reticularis → androjenler (DHEA). 'GFR' = dıştan içe zona sırası.","nl":"Zona glomerulosa → mineralocorticoïden (aldosteron): Na⁺/K⁺-regulatie. Zona fasciculata → glucocorticoïden (cortisol): stressrespons, anti-inflammatoir. Zona reticularis → androgenen (DHEA). 'GFR' = zonevolgorde van buiten naar binnen.","ru":"Zona glomerulosa → минералокортикоиды (альдостерон): регуляция Na⁺/K⁺. Zona fasciculata → глюкокортикоиды (кортизол): реакция на стресс, противовоспалительное действие. Zona reticularis → андрогены (DHEA). 'GFR' = порядок зон снаружи внутрь.","zh":"球状带 → 盐皮质激素（醛固酮）：Na⁺/K⁺调节。束状带 → 糖皮质激素（皮质醇）：应激反应、抗炎。网状带 → 雄激素（DHEA）。'GFR' = 从外到内的带层顺序。","pt_BR":"Zona glomerulosa → mineralocorticoides (aldosterona): regulação de Na⁺/K⁺. Zona fasciculata → glicocorticoides (cortisol): resposta ao estresse, anti-inflamatório. Zona reticularis → andrógenos (DHEA). 'GFR' = ordem das zonas de fora para dentro.","pt_PT":"Zona glomerulosa → mineralocorticoides (aldosterona): regulação de Na⁺/K⁺. Zona fasciculata → glucocorticoides (cortisol): resposta ao stress, anti-inflamatório. Zona reticularis → androgénios (DHEA). 'GFR' = ordem das zonas de fora para dentro."}},
  { id: 'dc-mcat-0146', deck_id: 'deck-mcat', sort_order: 146, front: "Thyroid Hormone Synthesis", back: "Iodide trapping → oxidation to I₂ → iodination of tyrosines on thyroglobulin (MIT, DIT) → coupling (T3, T4) → storage in follicle → proteolysis → secretion. T4 is converted to active T3 by deiodinases in periphery. TSH stimulates all steps." , front_translations: {"es":"Síntese del Hormonio Tireoidiano","de":"Schilddrüsenhormon-Synthese","fr":"Synthèse des hormones thyroïdiennes","tr":"Tiroid Hormonu Sentezi","nl":"Synthese van schildklierhormoon","ru":"Синтез тиреоидных гормонов","zh":"甲状腺激素合成","pt_BR":"Síntese do Hormônio Tireoidiano","pt_PT":"Síntese da Hormona Tiroideia"}, back_translations: {"es":"Captación de iodeto → oxidación a I₂ → iodinación de tirosinas en la tireoglobulina (MIT, DIT) → acoplamento (T3, T4) → almacenamiento en el folículo → proteólise → secreción. T4 es convertido en T3 ativo por desiodases en la periferia. TSH estimula todas las etapas.","de":"Iodid-Aufnahme → Oxidation zu I₂ → Iodierung von Tyrosinen auf Thyreoglobulin (MIT, DIT) → Kopplung (T3, T4) → Speicherung im Follikel → Proteolyse → Sekretion. T4 wird in der Peripherie durch Deiodinasen in aktives T3 umgewandelt. TSH stimuliert alle Schritte.","fr":"Captation d'iodure → oxydation en I₂ → iodation des tyrosines sur la thyroglobuline (MIT, DIT) → couplage (T3, T4) → stockage dans le follicule → protéolyse → sécrétion. T4 est convertie en T3 active par les désiodases en périphérie. TSH stimule toutes les étapes.","tr":"İyodür yakalama → I₂'ye oksidasyon → tiroglobulin üzerindeki tirozinlerin iyotlanması (MIT, DIT) → eşleşme (T3, T4) → follikülde depolama → proteoliz → sekresyon. T4, periferde deiyodinazlar tarafından aktif T3'e dönüştürülür. TSH tüm adımları uyarır.","nl":"Jodide-opname → oxidatie tot I₂ → jodering van tyrosines op thyreoglobuline (MIT, DIT) → koppeling (T3, T4) → opslag in follikel → proteolyse → secretie. T4 wordt in de periferie omgezet in actief T3 door deiodinasen. TSH stimuleert alle stappen.","ru":"Захват йодида → окисление до I₂ → йодирование тирозинов на тиреоглобулине (MIT, DIT) → конденсация (T3, T4) → хранение в фолликуле → протеолиз → секреция. T4 превращается в активный T3 дейодиназами на периферии. TSH стимулирует все этапы.","zh":"碘化物摄取 → 氧化为I₂ → 甲状腺球蛋白上酪氨酸碘化（MIT、DIT）→ 偶联（T3、T4）→ 滤泡中储存 → 蛋白水解 → 分泌。T4在外周由脱碘酶转化为活性T3。TSH刺激所有步骤。","pt_BR":"Captação de iodeto → oxidação a I₂ → iodinação de tirosinas na tireoglobulina (MIT, DIT) → acoplamento (T3, T4) → armazenamento no folículo → proteólise → secreção. T4 é convertido em T3 ativo por desiodases na periferia. TSH estimula todas as etapas.","pt_PT":"Captação de iodeto → oxidação a I₂ → iodinação de tirosinas na tiroglobulina (MIT, DIT) → acoplamento (T3, T4) → armazenamento no folículo → proteólise → secreção. T4 é convertida em T3 ativa por desiodinases na periferia. TSH estimula todas as etapas."}},
  { id: 'dc-mcat-0147', deck_id: 'deck-mcat', sort_order: 147, front: "Calcium Regulation", back: "PTH (parathyroid hormone): ↑ Ca²⁺ by ↑ bone resorption, ↑ renal reabsorption, ↑ calcitriol synthesis (→ intestinal absorption). Calcitonin (thyroid C cells): ↓ Ca²⁺ (minor role in humans). Vitamin D (calcitriol): ↑ intestinal Ca²⁺ and PO₄³⁻ absorption." , front_translations: {"es":"Regulación del Cálcio","de":"Kalziumregulation","fr":"Régulation du calcium","tr":"Kalsiyum Düzenlenmesi","nl":"Calciumregulatie","ru":"Регуляция кальция","zh":"钙调节","pt_BR":"Regulação do Cálcio","pt_PT":"Regulação do Cálcio"}, back_translations: {"es":"PTH (hormona paratireoidiano): ↑ Ca²⁺ por ↑ reabsorción ósea, ↑ reabsorción renal, ↑ síntese de calcitriol (→ absorción intestinal). Calcitonina (células C de la tireoide): ↓ Ca²⁺ (papel menor en humanos). Vitamina D (calcitriol): ↑ absorción intestinal de Ca²⁺ y PO₄³⁻.","de":"PTH (Parathormon): ↑ Ca²⁺ durch ↑ Knochenresorption, ↑ renale Rückresorption, ↑ Calcitriol-Synthese (→ intestinale Absorption). Calcitonin (Schilddrüsen-C-Zellen): ↓ Ca²⁺ (geringe Rolle beim Menschen). Vitamin D (Calcitriol): ↑ intestinale Ca²⁺- und PO₄³⁻-Absorption.","fr":"PTH (hormone parathyroïdienne) : ↑ Ca²⁺ par ↑ résorption osseuse, ↑ réabsorption rénale, ↑ synthèse de calcitriol (→ absorption intestinale). Calcitonine (cellules C thyroïdiennes) : ↓ Ca²⁺ (rôle mineur chez l'humain). Vitamine D (calcitriol) : ↑ absorption intestinale de Ca²⁺ et PO₄³⁻.","tr":"PTH (paratiroid hormon): ↑ Ca²⁺; ↑ kemik rezorpsiyonu, ↑ renal geri emilim, ↑ kalsitriol sentezi (→ bağırsak emilimi). Kalsitonin (tiroid C hücreleri): ↓ Ca²⁺ (insanlarda küçük rol). Vitamin D (kalsitriol): ↑ bağırsaktan Ca²⁺ ve PO₄³⁻ emilimi.","nl":"PTH (bijschildklierhormoon): ↑ Ca²⁺ door ↑ botresorptie, ↑ renale reabsorptie, ↑ calcitriolsynthese (→ intestinale absorptie). Calcitonine (schildklier C-cellen): ↓ Ca²⁺ (geringe rol bij de mens). Vitamine D (calcitriol): ↑ intestinale Ca²⁺- en PO₄³⁻-absorptie.","ru":"PTH (паратиреоидный гормон): ↑ Ca²⁺ за счёт ↑ резорбции кости, ↑ реабсорбции в почках, ↑ синтеза кальцитриола (→ всасывание в кишечнике). Кальцитонин (С-клетки щитовидной железы): ↓ Ca²⁺ (незначительная роль у человека). Витамин D (кальцитриол): ↑ всасывание Ca²⁺ и PO₄³⁻ в кишечнике.","zh":"PTH（甲状旁腺激素）：通过↑骨吸收、↑肾重吸收、↑骨化三醇合成（→肠道吸收）来↑Ca²⁺。降钙素（甲状腺C细胞）：↓Ca²⁺（在人体中作用较小）。维生素D（骨化三醇）：↑肠道Ca²⁺和PO₄³⁻吸收。","pt_BR":"PTH (hormônio paratireoidiano): ↑ Ca²⁺ por ↑ reabsorção óssea, ↑ reabsorção renal, ↑ síntese de calcitriol (→ absorção intestinal). Calcitonina (células C da tireoide): ↓ Ca²⁺ (papel menor em humanos). Vitamina D (calcitriol): ↑ absorção intestinal de Ca²⁺ e PO₄³⁻.","pt_PT":"PTH (hormona paratiroideia): ↑ Ca²⁺ por ↑ reabsorção óssea, ↑ reabsorção renal, ↑ síntese de calcitriol (→ absorção intestinal). Calcitonina (células C da tiroide): ↓ Ca²⁺ (papel menor em humanos). Vitamina D (calcitriol): ↑ absorção intestinal de Ca²⁺ e PO₄³⁻."}},
  { id: 'dc-mcat-0148', deck_id: 'deck-mcat', sort_order: 148, front: "Fertilization to Implantation", back: "Fertilization: sperm + secondary oocyte in fallopian tube → zygote. Cleavage → morula → blastocyst. Blastocyst implants into endometrium (~day 6). Trophoblast invades uterine wall; inner cell mass forms embryo. hCG maintains corpus luteum." , front_translations: {"es":"Da Fertilización a la Implantación","de":"Von der Befruchtung zur Implantation","fr":"De la fécondation à l'implantation","tr":"Döllenmeden İmplantasyona","nl":"Van bevruchting tot implantatie","ru":"От оплодотворения до имплантации","zh":"从受精到着床","pt_BR":"Da Fertilização à Implantação","pt_PT":"Da Fecundação à Implantação"}, back_translations: {"es":"Fertilización: espermatozoide + oócito secundário en la tuba uterina → zigoto. Clivaje → mórula → blastocisto. Blastocisto se implanta en el endométrio (~dia 6). Trofoblasto invade a pared uterina; masa celular interna forma el embrião. hCG mantiene el cuerpo lúteo.","de":"Befruchtung: Spermium + sekundäre Oozyte im Eileiter → Zygote. Furchung → Morula → Blastozyste. Blastozyste implantiert sich in das Endometrium (~Tag 6). Trophoblast dringt in die Uteruswand ein; innere Zellmasse bildet den Embryo. hCG erhält das Corpus luteum.","fr":"Fécondation : spermatozoïde + ovocyte secondaire dans la trompe → zygote. Clivage → morula → blastocyste. Le blastocyste s'implante dans l'endomètre (~jour 6). Le trophoblaste envahit la paroi utérine ; la masse cellulaire interne forme l'embryon. hCG maintient le corps jaune.","tr":"Döllenme: sperm + sekonder oosit fallop tüpünde → zigot. Bölünme → morula → blastosist. Blastosist endometriyuma implante olur (~6. gün). Trofoblast uterus duvarını invaze eder; iç hücre kütlesi embriyoyu oluşturur. hCG korpus luteumu korur.","nl":"Bevruchting: zaadcel + secundaire oöcyt in de eileider → zygote. Klieving → morula → blastocyste. Blastocyste implanteert in het endometrium (~dag 6). Trofoblast dringt de baarmoederwand binnen; binnenste celmassa vormt het embryo. hCG onderhoudt het corpus luteum.","ru":"Оплодотворение: сперматозоид + вторичный ооцит в маточной трубе → зигота. Дробление → морула → бластоциста. Бластоциста имплантируется в эндометрий (~день 6). Трофобласт внедряется в стенку матки; внутренняя клеточная масса формирует эмбрион. hCG поддерживает жёлтое тело.","zh":"受精：精子 + 次级卵母细胞在输卵管中 → 受精卵。卵裂 → 桑椹胚 → 囊胚。囊胚植入子宫内膜（约第6天）。滋养层侵入子宫壁；内细胞团形成胚胎。hCG维持黄体。","pt_BR":"Fertilização: espermatozoide + oócito secundário na tuba uterina → zigoto. Clivagem → mórula → blastocisto. Blastocisto se implanta no endométrio (~dia 6). Trofoblasto invade a parede uterina; massa celular interna forma o embrião. hCG mantém o corpo lúteo.","pt_PT":"Fecundação: espermatozoide + oócito secundário na trompa → zigoto. Clivagem → mórula → blastocisto. O blastocisto implanta-se no endométrio (~dia 6). O trofoblasto invade a parede uterina; a massa celular interna forma o embrião. hCG mantém o corpo lúteo."}},
  { id: 'dc-mcat-0149', deck_id: 'deck-mcat', sort_order: 149, front: "Germ Layers and Derivatives", back: "Ectoderm: skin epidermis, nervous system (neural tube → CNS; neural crest → PNS, adrenal medulla, melanocytes). Mesoderm: muscle, bone, connective tissue, cardiovascular, urogenital. Endoderm: epithelial linings of GI, respiratory, bladder." , front_translations: {"es":"Camadas Germinativas y Derivados","de":"Keimblätter und ihre Derivate","fr":"Feuillets embryonnaires et dérivés","tr":"Germ Tabakaları ve Türevleri","nl":"Kiembladen en hun derivaten","ru":"Зародышевые листки и их производные","zh":"胚层及其衍生物","pt_BR":"Camadas Germinativas e Derivados","pt_PT":"Folhetos Germinativos e Derivados"}, back_translations: {"es":"Ectoderma: epiderme, sistema nervioso (tubo neural → SNC; crista neural → SNP, medula adrenal, melanócitos). Mesoderma: músculos, huesos, tejido conjuntivo, cardiovascular, urogenital. Endoderma: revestimentos epiteliais del TGI, respiratório, bexiga.","de":"Ektoderm: Hautepidermis, Nervensystem (Neuralrohr → ZNS; Neuralleiste → PNS, Nebennierenmark, Melanozyten). Mesoderm: Muskeln, Knochen, Bindegewebe, Herz-Kreislauf, Urogenital. Endoderm: Epithelauskleidungen von GI-Trakt, Atemwegen, Blase.","fr":"Ectoderme : épiderme, système nerveux (tube neural → SNC ; crête neurale → SNP, médullosurrénale, mélanocytes). Mésoderme : muscles, os, tissu conjonctif, cardiovasculaire, urogénital. Endoderme : revêtements épithéliaux du tube digestif, respiratoire, vessie.","tr":"Ektoderm: deri epidermisi, sinir sistemi (nöral tüp → MSS; nöral krest → PSS, adrenal medulla, melanositler). Mezoderm: kas, kemik, bağ dokusu, kardiyovasküler, ürogenital. Endoderm: GI, solunum, mesane epitel astarları.","nl":"Ectoderm: huidepidermis, zenuwstelsel (neurale buis → CZS; neurale lijst → PZS, bijniermerg, melanocyten). Mesoderm: spieren, botten, bindweefsel, cardiovasculair, urogenitaal. Endoderm: epitheelbekleding van GI-tractus, luchtwegen, blaas.","ru":"Эктодерма: эпидермис кожи, нервная система (нервная трубка → ЦНС; нервный гребень → ПНС, мозговое вещество надпочечников, меланоциты). Мезодерма: мышцы, кости, соединительная ткань, сердечно-сосудистая, мочеполовая система. Энтодерма: эпителиальная выстилка ЖКТ, дыхательных путей, мочевого пузыря.","zh":"外胚层：皮肤表皮、神经系统（神经管→中枢神经系统；神经嵴→周围神经系统、肾上腺髓质、黑色素细胞）。中胚层：肌肉、骨骼、结缔组织、心血管、泌尿生殖系统。内胚层：消化道、呼吸道、膀胱的上皮内衬。","pt_BR":"Ectoderma: epiderme, sistema nervoso (tubo neural → SNC; crista neural → SNP, medula adrenal, melanócitos). Mesoderma: músculos, ossos, tecido conjuntivo, cardiovascular, urogenital. Endoderma: revestimentos epiteliais do TGI, respiratório, bexiga.","pt_PT":"Ectoderme: epiderme, sistema nervoso (tubo neural → SNC; crista neural → SNP, medula suprarrenal, melanócitos). Mesoderme: músculos, ossos, tecido conjuntivo, cardiovascular, urogenital. Endoderme: revestimentos epiteliais do TGI, respiratório, bexiga."}},
  { id: 'dc-mcat-0150', deck_id: 'deck-mcat', sort_order: 150, front: "Apoptosis vs. Necrosis", back: "Apoptosis: programmed, energy-dependent; orderly packaging of cell contents (apoptotic bodies phagocytosed; no inflammation). Caspase cascade. Necrosis: uncontrolled death from injury; cell swelling, membrane rupture, spillage of contents → inflammation." , front_translations: {"es":"Apoptose vs. Necrose","de":"Apoptose vs. Nekrose","fr":"Apoptose vs. Nécrose","tr":"Apoptoz vs. Nekroz","nl":"Apoptose vs. Necrose","ru":"Апоптоз vs. Некроз","zh":"细胞凋亡与坏死","pt_BR":"Apoptose vs. Necrose","pt_PT":"Apoptose vs. Necrose"}, back_translations: {"es":"Apoptose: programada, dependente de energía; empacotamento ordenado del conteúdo celular (cuerpos apoptóticos fagocitados; sin inflamación). Cascata de caspases. Necrose: muerte descontrolada por lesão; inchaço celular, ruptura de la membrana, vazamento del conteúdo → inflamación.","de":"Apoptose: programmiert, energieabhängig; geordnete Verpackung der Zellinhalte (apoptotische Körperchen werden phagozytiert; keine Entzündung). Caspase-Kaskade. Nekrose: unkontrollierter Tod durch Verletzung; Zellschwellung, Membranruptur, Austritt des Zellinhalts → Entzündung.","fr":"Apoptose : programmée, énergie-dépendante ; empaquetage ordonné du contenu cellulaire (corps apoptotiques phagocytés ; pas d'inflammation). Cascade de caspases. Nécrose : mort incontrôlée par lésion ; gonflement cellulaire, rupture membranaire, déversement du contenu → inflammation.","tr":"Apoptoz: programlı, enerji bağımlı; hücre içeriğinin düzenli paketlenmesi (apoptotik cisimcikler fagositoz edilir; inflamasyon yok). Kaspaz kaskadı. Nekroz: hasardan kaynaklanan kontrolsüz ölüm; hücre şişmesi, membran yırtılması, içerik dökülmesi → inflamasyon.","nl":"Apoptose: geprogrammeerd, energie-afhankelijk; ordelijke verpakking van celinhoud (apoptotische lichaampjes worden gefagocyteerd; geen ontsteking). Caspase-cascade. Necrose: ongecontroleerde dood door schade; celzwelling, membraanruptuur, inhoud lekt uit → ontsteking.","ru":"Апоптоз: запрограммированный, энергозависимый; упорядоченная упаковка содержимого клетки (апоптотические тельца фагоцитируются; без воспаления). Каспазный каскад. Некроз: неконтролируемая гибель от повреждения; набухание клетки, разрыв мембраны, выход содержимого → воспаление.","zh":"凋亡：程序性的、能量依赖的；细胞内容物有序包装（凋亡小体被吞噬；无炎症）。Caspase级联反应。坏死：损伤引起的不受控死亡；细胞肿胀、膜破裂、内容物溢出→炎症。","pt_BR":"Apoptose: programada, dependente de energia; empacotamento ordenado do conteúdo celular (corpos apoptóticos fagocitados; sem inflamação). Cascata de caspases. Necrose: morte descontrolada por lesão; inchaço celular, ruptura da membrana, vazamento do conteúdo → inflamação.","pt_PT":"Apoptose: programada, dependente de energia; empacotamento ordenado do conteúdo celular (corpos apoptóticos fagocitados; sem inflamação). Cascata de caspases. Necrose: morte descontrolada por lesão; tumefação celular, rutura da membrana, derrame do conteúdo → inflamação."}},
  { id: 'dc-mcat-0151', deck_id: 'deck-mcat', sort_order: 151, front: "p53 Tumor Suppressor", back: "The 'guardian of the genome.' Activated by DNA damage → triggers p21 (CDK inhibitor, halts cell cycle at G1/S) or apoptosis. Mutated in >50% of all human cancers. Both alleles must be lost (two-hit hypothesis)." , front_translations: {"es":"Supressor Tumoral p53","de":"p53-Tumorsuppressor","fr":"Suppresseur de tumeurs p53","tr":"p53 Tümör Baskılayıcı","nl":"p53-tumorsuppressor","ru":"Опухолевый супрессор p53","zh":"p53肿瘤抑制因子","pt_BR":"Supressor Tumoral p53","pt_PT":"Supressor Tumoral p53"}, back_translations: {"es":"El 'guardião del genoma'. Ativado por dano al DNA → aciona p21 (inibidor de CDK, para el ciclo celular en G1/S) o apoptose. Mutado en >50% de todos los canceres humanos. Ambos los alelos devem ser perdidos (hipótese de los de los golpes).","de":"Der 'Wächter des Genoms'. Aktiviert durch DNA-Schäden → löst p21 aus (CDK-Inhibitor, stoppt Zellzyklus an G1/S) oder Apoptose. In >50% aller menschlichen Krebsarten mutiert. Beide Allele müssen verloren gehen (Zwei-Treffer-Hypothese).","fr":"Le « gardien du génome ». Activé par les dommages à l'ADN → déclenche p21 (inhibiteur de CDK, arrêt du cycle cellulaire en G1/S) ou l'apoptose. Muté dans >50 % de tous les cancers humains. Les deux allèles doivent être perdus (hypothèse des deux coups).","tr":"'Genomun koruyucusu.' DNA hasarı ile aktive olur → p21'i tetikler (CDK inhibitörü, hücre döngüsünü G1/S'de durdurur) veya apoptozu başlatır. Tüm insan kanserlerinin >%50'sinde mutasyona uğramıştır. Her iki allel de kaybolmalıdır (iki vuruş hipotezi).","nl":"De 'bewaker van het genoom'. Geactiveerd door DNA-schade → activeert p21 (CDK-remmer, stopt celcyclus bij G1/S) of apoptose. Gemuteerd in >50% van alle menselijke kankers. Beide allelen moeten verloren gaan (twee-hit-hypothese).","ru":"«Страж генома». Активируется повреждением ДНК → запускает p21 (ингибитор CDK, останавливает клеточный цикл в G1/S) или апоптоз. Мутирован в >50% всех опухолей человека. Оба аллеля должны быть утрачены (гипотеза двух ударов).","zh":"“基因组的守护者”。被DNA损伤激活→触发p21（CDK抑制剂，在G1/S期阻止细胞周期）或凋亡。在超过50%的人类癌症中突变。两个等位基因都必须丢失（二次打击假说）。","pt_BR":"O 'guardião do genoma'. Ativado por dano ao DNA → aciona p21 (inibidor de CDK, para o ciclo celular em G1/S) ou apoptose. Mutado em >50% de todos os cânceres humanos. Ambos os alelos devem ser perdidos (hipótese dos dois golpes).","pt_PT":"O 'guardião do genoma'. Ativado por dano no DNA → aciona p21 (inibidor de CDK, para o ciclo celular em G1/S) ou apoptose. Mutado em >50% de todos os cancros humanos. Ambos os alelos devem ser perdidos (hipótese dos dois golpes)."}},
  { id: 'dc-mcat-0152', deck_id: 'deck-mcat', sort_order: 152, front: "Oncogene RAS", back: "A proto-oncogene encoding a GTPase in the MAPK signaling pathway. Mutant RAS is constitutively active (GTP-bound, cannot hydrolyze GTP → permanently signals cell growth). Mutated in ~30% of human cancers. A gain-of-function dominant mutation." , front_translations: {"es":"Oncogene RAS","de":"Onkogen RAS","fr":"Oncogène RAS","tr":"Onkojen RAS","nl":"Oncogen RAS","ru":"Онкоген RAS","zh":"癌基因RAS","pt_BR":"Oncogene RAS","pt_PT":"Oncogene RAS"}, back_translations: {"es":"Un proto-oncogene que codifica una GTPase en la via de sinalización MAPK. El RAS mutante es constitutivamente ativo (ligado al GTP, no consegue hidrolizar GTP → sinaliza permanentemente el crecimiento celular). Mutado en ~30% de los canceres humanos. Una mutación dominante de ganho de función.","de":"Ein Proto-Onkogen, das eine GTPase im MAPK-Signalweg kodiert. Mutantes RAS ist konstitutiv aktiv (GTP-gebunden, kann GTP nicht hydrolysieren → signalisiert dauerhaft Zellwachstum). In ~30% der menschlichen Krebsarten mutiert. Eine Gain-of-function dominante Mutation.","fr":"Un proto-oncogène codant une GTPase dans la voie de signalisation MAPK. Le RAS mutant est constitutivement actif (lié au GTP, ne peut hydrolyser le GTP → signale en permanence la croissance cellulaire). Muté dans ~30 % des cancers humains. Mutation dominante à gain de fonction.","tr":"MAPK sinyal yolunda bir GTPaz kodlayan bir proto-onkojen. Mutant RAS yapısal olarak aktiftir (GTP'ye bağlı, GTP'yi hidrolize edemez → kalıcı olarak hücre büyümesini sinyalleştirir). İnsan kanserlerinin ~%30'unda mutasyona uğramıştır. Fonksiyon kazanımı baskın mutasyonu.","nl":"Een proto-oncogen dat codeert voor een GTPase in de MAPK-signaalroute. Mutant RAS is constitutief actief (GTP-gebonden, kan GTP niet hydrolyseren → signaleert permanent celgroei). Gemuteerd in ~30% van menselijke kankers. Een gain-of-function dominante mutatie.","ru":"Протоонкоген, кодирующий ГТФазу в сигнальном пути MAPK. Мутантный RAS конститутивно активен (связан с ГТФ, не может гидролизовать ГТФ → постоянно передаёт сигнал роста). Мутирован в ~30% опухолей человека. Доминантная мутация с приобретением функции.","zh":"编码MAPK信号通路中GTPase的原癌基因。突变的RAS处于组成性活化状态（与GTP结合，无法水解GTP→持续发出细胞生长信号）。在约30%的人类癌症中突变。属于功能获得性显性突变。","pt_BR":"Um proto-oncogene que codifica uma GTPase na via de sinalização MAPK. O RAS mutante é constitutivamente ativo (ligado ao GTP, não consegue hidrolizar GTP → sinaliza permanentemente o crescimento celular). Mutado em ~30% dos cânceres humanos. Uma mutação dominante de ganho de função.","pt_PT":"Um proto-oncogene que codifica uma GTPase na via de sinalização MAPK. O RAS mutante é constitutivamente ativo (ligado ao GTP, não consegue hidrolizar GTP → sinaliza permanentemente o crescimento celular). Mutado em ~30% dos cancros humanos. Uma mutação dominante de ganho de função."}},
  { id: 'dc-mcat-0153', deck_id: 'deck-mcat', sort_order: 153, front: "Ion Channels and Patch Clamp", back: "Ion channels are membrane proteins that open/close in response to voltage, ligands, or mechanical stimuli. Patch-clamp technique: attaches a glass pipette to a tiny membrane patch to measure current through individual channels. Used to characterize channel behavior." , front_translations: {"es":"Canais Ionicos y Patch Clamp","de":"Ionenkanäle und Patch-Clamp-Technik","fr":"Canaux ioniques et technique du patch-clamp","tr":"İyon Kanalları ve Patch Clamp","nl":"Ionkanalen en patch-clamp","ru":"Ионные каналы и метод пэтч-кламп","zh":"离子通道与膜片钳技术","pt_BR":"Canais Iônicos e Patch Clamp","pt_PT":"Canais Iónicos e Patch Clamp"}, back_translations: {"es":"Canais ionicos son proteínas de membrana que abrem/fecham en respuesta a voltaje, ligantes o estímulos mecanicos. Técnica de patch-clamp: fixa una pipeta de vidro en un pequeño fragmento de membrana para medir a corrente a través de canais individuais. Usada para caracterizar el comportamiento de los canais.","de":"Ionenkanäle sind Membranproteine, die sich als Antwort auf Spannung, Liganden oder mechanische Reize öffnen/schließen. Patch-Clamp-Technik: befestigt eine Glaspipette an einem winzigen Membranstück, um den Strom durch einzelne Kanäle zu messen. Dient zur Charakterisierung des Kanalverhaltens.","fr":"Les canaux ioniques sont des protéines membranaires qui s'ouvrent/ferment en réponse à un voltage, des ligands ou des stimuli mécaniques. Technique du patch-clamp : fixe une pipette en verre sur un petit fragment de membrane pour mesurer le courant à travers un canal individuel. Utilisée pour caractériser le comportement des canaux.","tr":"İyon kanalları voltaj, ligand veya mekanik uyarılara yanıt olarak açılıp kapanan membran proteinleridir. Patch-clamp tekniği: tek kanallardan geçen akımı ölçmek için küçük bir membran parçasına cam pipet tutturur. Kanal davranışını karakterize etmek için kullanılır.","nl":"Ionkanalen zijn membraaneiwitten die openen/sluiten als reactie op spanning, liganden of mechanische prikkels. Patch-clamp-techniek: bevestigt een glazen pipet aan een klein membraanstukje om de stroom door individuele kanalen te meten. Wordt gebruikt om kanaalgedrag te karakteriseren.","ru":"Ионные каналы — мембранные белки, открывающиеся/закрывающиеся в ответ на напряжение, лиганды или механические стимулы. Метод пэтч-кламп: стеклянная пипетка присоединяется к участку мембраны для измерения тока через отдельные каналы. Используется для характеристики поведения каналов.","zh":"离子通道是响应电压、配体或机械刺激而开关的膜蛋白。膜片钳技术：将玻璃微管贴附在微小膜片上，测量单个通道的电流。用于表征通道行为。","pt_BR":"Canais iônicos são proteínas de membrana que abrem/fecham em resposta a voltagem, ligantes ou estímulos mecânicos. Técnica de patch-clamp: fixa uma pipeta de vidro em um pequeno fragmento de membrana para medir a corrente através de canais individuais. Usada para caracterizar o comportamento dos canais.","pt_PT":"Canais iónicos são proteínas de membrana que abrem/fecham em resposta a voltagem, ligandos ou estímulos mecânicos. Técnica de patch-clamp: fixa uma pipeta de vidro num pequeno fragmento de membrana para medir a corrente através de canais individuais. Usada para caracterizar o comportamento dos canais."}},
  { id: 'dc-mcat-0154', deck_id: 'deck-mcat', sort_order: 154, front: "Acetylcholine: Nicotinic vs. Muscarinic Receptors", back: "Nicotinic receptors: ligand-gated ion channels (Na⁺/K⁺); at NMJ and autonomic ganglia; blocked by curare (NMJ) or hexamethonium (ganglia). Muscarinic receptors: GPCRs; at target organs of parasympathetic nervous system; blocked by atropine." , front_translations: {"es":"Acetilcolina: Receptores Nicotínicos vs. Muscarínicos","de":"Acetylcholin: Nikotinische vs. Muskarinische Rezeptoren","fr":"Acétylcholine : récepteurs nicotiniques vs. muscariniques","tr":"Asetilkolin: Nikotinik vs. Muskarinik Reseptörler","nl":"Acetylcholine: nicotine- vs. muscarinereceptoren","ru":"Ацетилхолин: никотиновые vs. мускариновые рецепторы","zh":"乙酰胆碱：烟碱型与毒蕈碱型受体","pt_BR":"Acetilcolina: Receptores Nicotínicos vs. Muscarínicos","pt_PT":"Acetilcolina: Recetores Nicotínicos vs. Muscarínicos"}, back_translations: {"es":"Receptores nicotínicos: canais ionicos controlados por ligante (Na⁺/K⁺); en la JNM y ganglios autonomicos; bloqueados por curare (JNM) o hexametonio (ganglios). Receptores muscarínicos: GPCRs; en los órganos-alvo del sistema nervioso parassimpático; bloqueados por atropina.","de":"Nikotinische Rezeptoren: ligandengesteuerte Ionenkanäle (Na⁺/K⁺); an NMJ und autonomen Ganglien; blockiert durch Curare (NMJ) oder Hexamethonium (Ganglien). Muskarinische Rezeptoren: GPCRs; an Zielorganen des Parasympathikus; blockiert durch Atropin.","fr":"Récepteurs nicotiniques : canaux ioniques ligand-dépendants (Na⁺/K⁺) ; à la JNM et aux ganglions autonomes ; bloqués par le curare (JNM) ou l'hexaméthonium (ganglions). Récepteurs muscariniques : RCPG ; aux organes cibles du système parasympathique ; bloqués par l'atropine.","tr":"Nikotinik reseptörler: ligand kapılı iyon kanalları (Na⁺/K⁺); NMJ ve otonom ganglionlarda; kürar (NMJ) veya heksametonyum (ganglion) ile bloke edilir. Muskarinik reseptörler: GPCR'ler; parasempatik sinir sisteminin hedef organlarında; atropin ile bloke edilir.","nl":"Nicotinereceptoren: ligand-gestuurde ionkanalen (Na⁺/K⁺); bij NMJ en autonome ganglia; geblokkeerd door curare (NMJ) of hexamethonium (ganglia). Muscarinereceptoren: GPCR's; bij doelorganen van het parasympathisch zenuwstelsel; geblokkeerd door atropine.","ru":"Никотиновые рецепторы: лиганд-управляемые ионные каналы (Na⁺/K⁺); в НМС и вегетативных ганглиях; блокируются кураре (НМС) или гексаметонием (ганглии). Мускариновые рецепторы: GPCR; в органах-мишенях парасимпатической нервной системы; блокируются атропином.","zh":"烟碱型受体：配体门控离子通道（Na⁺/K⁺）；位于NMJ和自主神经节；被箭毒（NMJ）或六甲铵（神经节）阻断。毒蕈碱型受体：GPCR；位于副交感神经系统的靶器官；被阿托品阻断。","pt_BR":"Receptores nicotínicos: canais iônicos controlados por ligante (Na⁺/K⁺); na JNM e gânglios autonômicos; bloqueados por curare (JNM) ou hexametônio (gânglios). Receptores muscarínicos: GPCRs; nos órgãos-alvo do sistema nervoso parassimpático; bloqueados por atropina.","pt_PT":"Recetores nicotínicos: canais iónicos controlados por ligando (Na⁺/K⁺); na JNM e gânglios autonómicos; bloqueados por curare (JNM) ou hexametónio (gânglios). Recetores muscarínicos: GPCRs; nos órgãos-alvo do sistema nervoso parassimpático; bloqueados por atropina."}},
  { id: 'dc-mcat-0155', deck_id: 'deck-mcat', sort_order: 155, front: "Autonomic Nervous System", back: "Sympathetic ('fight or flight'): thoracolumbar origin; short pre-, long post-ganglionic; NE at target organs (except sweat glands/ACh). Parasympathetic ('rest and digest'): craniosacral; long pre-, short post-ganglionic; ACh at all junctions." , front_translations: {"es":"Sistema Nervoso Autonomo","de":"Autonomes Nervensystem","fr":"Système nerveux autonome","tr":"Otonom Sinir Sistemi","nl":"Autonoom zenuwstelsel","ru":"Вегетативная нервная система","zh":"自主神经系统","pt_BR":"Sistema Nervoso Autônomo","pt_PT":"Sistema Nervoso Autónomo"}, back_translations: {"es":"Simpático ('luta o fuga'): origem toracolombar; pré-ganglionar corto, pós-ganglionar ancho; NE en los órganos-alvo (excepto glándulas sudoríparas/ACh). Parassimpático ('descanso y digestión'): craniossacral; pré-ganglionar ancho, pós-ganglionar corto; ACh en todas las junciones.","de":"Sympathisch ('Kampf oder Flucht'): thorakolumbaler Ursprung; kurze prä-, lange postganglionäre Fasern; NE an Zielorganen (außer Schweißdrüsen/ACh). Parasympathisch ('Ruhe und Verdauung'): kraniosakral; lange prä-, kurze postganglionäre Fasern; ACh an allen Synapsen.","fr":"Sympathique (« lutte ou fuite ») : origine thoraco-lombaire ; pré-ganglionnaire court, post-ganglionnaire long ; NE aux organes cibles (sauf glandes sudoripares/ACh). Parasympathique (« repos et digestion ») : origine crânio-sacrée ; pré-ganglionnaire long, post-ganglionnaire court ; ACh à toutes les jonctions.","tr":"Sempatik ('savaş ya da kaç'): torakolomber kökenli; kısa pre-, uzun post-ganglionik; hedef organlarda NE (ter bezleri/ACh hariç). Parasempatik ('dinlen ve sindir'): kraniosakral; uzun pre-, kısa post-ganglionik; tüm kavşaklarda ACh.","nl":"Sympathisch ('vecht of vlucht'): thoracolumbale oorsprong; kort pre-, lang postganglionair; NE bij doelorganen (behalve zweetklieren/ACh). Parasympathisch ('rust en vertering'): craniosacraal; lang pre-, kort postganglionair; ACh bij alle verbindingen.","ru":"Симпатическая ('борьба или бегство'): торако-люмбальное происхождение; короткие пре-, длинные постганглионарные волокна; NE в органах-мишенях (кроме потовых желёз/ACh). Парасимпатическая ('отдых и пищеварение'): краниосакральная; длинные пре-, короткие постганглионарные; ACh во всех синапсах.","zh":"交感神经（“战斗或逃跑”）：胸腰段起源；短节前、长节后纤维；靶器官处释放NE（汗腺/ACh除外）。副交感神经（“休息与消化”）：颅骶段；长节前、短节后纤维；所有接头处释放ACh。","pt_BR":"Simpático ('luta ou fuga'): origem toracolombar; pré-ganglionar curto, pós-ganglionar longo; NE nos órgãos-alvo (exceto glândulas sudoríparas/ACh). Parassimpático ('descanso e digestão'): craniossacral; pré-ganglionar longo, pós-ganglionar curto; ACh em todas as junções.","pt_PT":"Simpático ('luta ou fuga'): origem toracolombar; pré-ganglionar curto, pós-ganglionar longo; NE nos órgãos-alvo (exceto glândulas sudoríparas/ACh). Parassimpático ('repouso e digestão'): craniossagrado; pré-ganglionar longo, pós-ganglionar curto; ACh em todas as junções."}},
  { id: 'dc-mcat-0156', deck_id: 'deck-mcat', sort_order: 156, front: "Blood Types and Rh Factor", back: "ABO system: A (A antigens, anti-B), B (B antigens, anti-A), AB (both antigens, no antibodies; universal recipient), O (no antigens, anti-A and anti-B; universal donor). Rh+ has D antigen; Rh- lacks it. Rh incompatibility can cause hemolytic disease of the newborn." , front_translations: {"es":"Tipos Sanguíneos y Fator Rh","de":"Blutgruppen und Rh-Faktor","fr":"Groupes sanguins et facteur Rh","tr":"Kan Grupları ve Rh Faktörü","nl":"Bloedgroepen en Rh-factor","ru":"Группы крови и резус-фактор","zh":"血型与Rh因子","pt_BR":"Tipos Sanguíneos e Fator Rh","pt_PT":"Grupos Sanguíneos e Fator Rh"}, back_translations: {"es":"Sistema ABO: La (antígenos A, anti-B), B (antígenos B, anti-A), AB (ambos antígenos, sin anticorpos; receptor universal), El (sin antígenos, anti-A y anti-B; doador universal). Rh+ tiene antígeno D; Rh- no tiene. Incompatibilidad Rh puede causar enfermedad hemolítica del recém-nascido.","de":"ABO-System: A (A-Antigene, Anti-B), B (B-Antigene, Anti-A), AB (beide Antigene, keine Antikörper; Universalempfänger), O (keine Antigene, Anti-A und Anti-B; Universalspender). Rh+ hat D-Antigen; Rh- fehlt es. Rh-Inkompatibilität kann hämolytische Erkrankung des Neugeborenen verursachen.","fr":"Système ABO : A (antigènes A, anti-B), B (antigènes B, anti-A), AB (les deux antigènes, pas d'anticorps ; receveur universel), O (pas d'antigènes, anti-A et anti-B ; donneur universel). Rh+ possède l'antigène D ; Rh- en est dépourvu. L'incompatibilité Rh peut causer la maladie hémolytique du nouveau-né.","tr":"ABO sistemi: A (A antijenleri, anti-B), B (B antijenleri, anti-A), AB (her iki antijen, antikor yok; evrensel alıcı), O (antijen yok, anti-A ve anti-B; evrensel verici). Rh+ D antijenine sahiptir; Rh- sahip değildir. Rh uyumsuzluğu yenidoğanın hemolitik hastalığına neden olabilir.","nl":"ABO-systeem: A (A-antigenen, anti-B), B (B-antigenen, anti-A), AB (beide antigenen, geen antilichamen; universele ontvanger), O (geen antigenen, anti-A en anti-B; universele donor). Rh+ heeft D-antigeen; Rh- mist het. Rh-incompatibiliteit kan hemolytische ziekte van de pasgeborene veroorzaken.","ru":"Система ABO: A (антигены A, анти-B), B (антигены B, анти-A), AB (оба антигена, нет антител; универсальный реципиент), O (нет антигенов, анти-A и анти-B; универсальный донор). Rh+ имеет D-антиген; Rh- не имеет. Rh-несовместимость может вызвать гемолитическую болезнь новорождённых.","zh":"ABO系统：A型（A抗原、抗B抗体），B型（B抗原、抗A抗体），AB型（两种抗原、无抗体；万能受血者），O型（无抗原、抗A和抗B抗体；万能供血者）。Rh+有D抗原；Rh-缺乏。Rh不相容可导致新生儿溶血病。","pt_BR":"Sistema ABO: A (antígenos A, anti-B), B (antígenos B, anti-A), AB (ambos antígenos, sem anticorpos; receptor universal), O (sem antígenos, anti-A e anti-B; doador universal). Rh+ tem antígeno D; Rh- não tem. Incompatibilidade Rh pode causar doença hemolítica do recém-nascido.","pt_PT":"Sistema ABO: A (antigénios A, anti-B), B (antigénios B, anti-A), AB (ambos os antigénios, sem anticorpos; recetor universal), O (sem antigénios, anti-A e anti-B; dador universal). Rh+ tem antigénio D; Rh- não tem. Incompatibilidade Rh pode causar doença hemolítica do recém-nascido."}},
  { id: 'dc-mcat-0157', deck_id: 'deck-mcat', sort_order: 157, front: "Protein Folding and Chaperones", back: "Protein folding is spontaneous, driven by hydrophobic collapse and entropy of water. Molecular chaperones (Hsp70, Hsp90, GroEL/GroES) prevent misfolding and aggregation, especially under stress. Misfolded proteins → proteasome degradation or aggregation diseases (prions, Alzheimer's)." , front_translations: {"es":"Enovelamento de Proteínas y Chaperonas","de":"Proteinfaltung und Chaperone","fr":"Repliement des protéines et chaperons","tr":"Protein Katlanması ve Şaperonlar","nl":"Eiwitvouwing en chaperonnes","ru":"Фолдинг белков и шапероны","zh":"蛋白质折叠与分子伴侣","pt_BR":"Enovelamento de Proteínas e Chaperonas","pt_PT":"Enrolamento de Proteínas e Chaperones"}, back_translations: {"es":"El enovelamento de proteínas es espontaneo, impulsionado por el colapso hidrofóbico y entropia de la agua. Chaperonas moleculares (Hsp70, Hsp90, GroEL/GroES) previenen enovelamento incorreto y agregación, especialmente sob estresse. Proteínas mal enoveladas → degradación por el proteassomo o enfermedades de agregación (príons, Alzheimer).","de":"Proteinfaltung ist spontan, angetrieben durch hydrophoben Kollaps und Entropie des Wassers. Molekulare Chaperone (Hsp70, Hsp90, GroEL/GroES) verhindern Fehlfaltung und Aggregation, besonders unter Stress. Fehlgefaltete Proteine → Proteasom-Abbau oder Aggregationskrankheiten (Prionen, Alzheimer).","fr":"Le repliement des protéines est spontané, entraîné par l'effondrement hydrophobe et l'entropie de l'eau. Les chaperons moléculaires (Hsp70, Hsp90, GroEL/GroES) préviennent le mauvais repliement et l'agrégation, surtout sous stress. Protéines mal repliées → dégradation par le protéasome ou maladies d'agrégation (prions, Alzheimer).","tr":"Protein katlanması spontandır, hidrofobik çöküş ve suyun entropisi tarafından yönlendirilir. Moleküler şaperonlar (Hsp70, Hsp90, GroEL/GroES) özellikle stres altında yanlış katlanmayı ve kümelenmeyi önler. Yanlış katlanan proteinler → proteazom degradasyonu veya kümelenme hastalıkları (prionlar, Alzheimer).","nl":"Eiwitvouwing is spontaan, aangedreven door hydrofobe collaps en entropie van water. Moleculaire chaperonnes (Hsp70, Hsp90, GroEL/GroES) voorkomen verkeerde vouwing en aggregatie, vooral onder stress. Verkeerd gevouwen eiwitten → proteasoomafbraak of aggregatieziekten (prionen, Alzheimer).","ru":"Фолдинг белков спонтанен, обусловлен гидрофобным коллапсом и энтропией воды. Молекулярные шапероны (Hsp70, Hsp90, GroEL/GroES) предотвращают неправильную укладку и агрегацию, особенно при стрессе. Неправильно свёрнутые белки → деградация в протеасоме или болезни агрегации (прионы, болезнь Альцгеймера).","zh":"蛋白质折叠是自发的，由疏水塌缩和水的熵驱动。分子伴侣（Hsp70、Hsp90、GroEL/GroES）防止错误折叠和聚集，尤其在应激条件下。错误折叠的蛋白质→蛋白酶体降解或聚集疾病（朊病毒、阿尔茨海默病）。","pt_BR":"O enovelamento de proteínas é espontâneo, impulsionado pelo colapso hidrofóbico e entropia da água. Chaperonas moleculares (Hsp70, Hsp90, GroEL/GroES) previnem enovelamento incorreto e agregação, especialmente sob estresse. Proteínas mal enoveladas → degradação pelo proteassomo ou doenças de agregação (príons, Alzheimer).","pt_PT":"O enrolamento de proteínas é espontâneo, impulsionado pelo colapso hidrofóbico e entropia da água. Chaperones moleculares (Hsp70, Hsp90, GroEL/GroES) previnem enrolamento incorreto e agregação, especialmente sob stress. Proteínas mal enroladas → degradação pelo proteassoma ou doenças de agregação (priões, Alzheimer)."}},
  { id: 'dc-mcat-0158', deck_id: 'deck-mcat', sort_order: 158, front: "Allosteric Regulation vs. Covalent Modification", back: "Allosteric: non-covalent binding of an effector at a site other than the active site changes enzyme conformation and activity (reversible). Covalent modification: phosphorylation/dephosphorylation by kinases/phosphatases alters enzyme activity (reversible but requires ATP)." , front_translations: {"es":"Regulación Alostérica vs. Modificación Covalente","de":"Allosterische Regulation vs. Kovalente Modifikation","fr":"Régulation allostérique vs. modification covalente","tr":"Allosterik Düzenleme vs. Kovalent Modifikasyon","nl":"Allosterische regulatie vs. covalente modificatie","ru":"Аллостерическая регуляция vs. ковалентная модификация","zh":"变构调节与共价修饰","pt_BR":"Regulação Alostérica vs. Modificação Covalente","pt_PT":"Regulação Alostérica vs. Modificação Covalente"}, back_translations: {"es":"Alostérica: enlace no covalente de un efetor en un sítio diferente del sítio ativo altera a conformación y atividad enzimática (reversible). Modificación covalente: fosforilación/desfosforilación por quinases/fosfatases altera a atividad enzimática (reversible, pero requiere ATP).","de":"Allosterisch: nicht-kovalente Bindung eines Effektors an einer anderen Stelle als dem aktiven Zentrum verändert Enzymkonformation und -aktivität (reversibel). Kovalente Modifikation: Phosphorylierung/Dephosphorylierung durch Kinasen/Phosphatasen verändert Enzymaktivität (reversibel, erfordert aber ATP).","fr":"Allostérique : liaison non covalente d'un effecteur à un site autre que le site actif, modifiant la conformation et l'activité de l'enzyme (réversible). Modification covalente : phosphorylation/déphosphorylation par kinases/phosphatases modifie l'activité enzymatique (réversible mais nécessite de l'ATP).","tr":"Allosterik: aktif bölge dışında bir bölgeye efektörün kovalent olmayan bağlanması enzim konformasyonunu ve aktivitesini değiştirir (tersinir). Kovalent modifikasyon: kinazlar/fosfatazlar tarafından fosforilasyon/defosforilasyon enzim aktivitesini değiştirir (tersinir ama ATP gerektirir).","nl":"Allosterisch: niet-covalente binding van een effector op een andere plaats dan het actieve centrum verandert enzymconformatie en -activiteit (reversibel). Covalente modificatie: fosforylering/defosforylering door kinasen/fosfatasen verandert enzymactiviteit (reversibel maar vereist ATP).","ru":"Аллостерическая: нековалентное связывание эффектора в участке, отличном от активного центра, изменяет конформацию и активность фермента (обратимо). Ковалентная модификация: фосфорилирование/дефосфорилирование киназами/фосфатазами изменяет активность фермента (обратимо, но требует АТФ).","zh":"变构调节：效应物在活性位点以外的位点进行非共价结合，改变酶的构象和活性（可逆）。共价修饰：激酶/磷酸酶的磷酸化/去磷酸化改变酶活性（可逆但需要ATP）。","pt_BR":"Alostérica: ligação não covalente de um efetor em um sítio diferente do sítio ativo altera a conformação e atividade enzimática (reversível). Modificação covalente: fosforilação/desfosforilação por quinases/fosfatases altera a atividade enzimática (reversível, mas requer ATP).","pt_PT":"Alostérica: ligação não covalente de um efetor num local diferente do centro ativo altera a conformação e atividade enzimática (reversível). Modificação covalente: fosforilação/desfosforilação por cinases/fosfatases altera a atividade enzimática (reversível, mas requer ATP)."}},
  { id: 'dc-mcat-0159', deck_id: 'deck-mcat', sort_order: 159, front: "Zymogen Activation", back: "Zymogens (enzyme precursors) are secreted in an inactive form and activated by proteolytic cleavage. Prevents damage to secretory organs. Examples: pepsinogen → pepsin (stomach acid); trypsinogen → trypsin (enterokinase in duodenum); prothrombin → thrombin." , front_translations: {"es":"Ativación de Zimogenios","de":"Zymogen-Aktivierung","fr":"Activation des zymogènes","tr":"Zimojen Aktivasyonu","nl":"Zymogeenactivering","ru":"Активация зимогенов","zh":"酶原激活","pt_BR":"Ativação de Zimogênios","pt_PT":"Ativação de Zimogénios"}, back_translations: {"es":"Zimogenios (precursores enzimáticos) son secretados en la forma inativa y ativados por clivaje proteolítica. Previne danos a los órganos secretores. Exemplos: pepsinogenio → pepsina (ácido gástrico); tripsinogenio → tripsina (enteroquinase en el duodeno); protrombina → trombina.","de":"Zymogene (Enzymvorstufen) werden in inaktiver Form sezerniert und durch proteolytische Spaltung aktiviert. Verhindert Schäden an sekretorischen Organen. Beispiele: Pepsinogen → Pepsin (Magensäure); Trypsinogen → Trypsin (Enterokinase im Duodenum); Prothrombin → Thrombin.","fr":"Les zymogènes (précurseurs enzymatiques) sont sécrétés sous forme inactive et activés par clivage protéolytique. Empêche les dommages aux organes sécréteurs. Exemples : pepsinogène → pepsine (acide gastrique) ; trypsinogène → trypsine (entérokinase dans le duodénum) ; prothrombine → thrombine.","tr":"Zimojenler (enzim öncüleri) inaktif formda salgılanır ve proteolitik bölünme ile aktive edilir. Salgı organlarına zarar verilmesini önler. Örnekler: pepsinojen → pepsin (mide asidi); tripsinojen → tripsin (duodenumda enterokinaz); protrombin → trombin.","nl":"Zymogenen (enzymprecursoren) worden in inactieve vorm uitgescheiden en geactiveerd door proteolytische splitsing. Voorkomt schade aan secretoire organen. Voorbeelden: pepsinogeen → pepsine (maagzuur); trypsinogeen → trypsine (enterokinase in duodenum); protrombine → trombine.","ru":"Зимогены (предшественники ферментов) секретируются в неактивной форме и активируются протеолитическим расщеплением. Предотвращает повреждение секреторных органов. Примеры: пепсиноген → пепсин (соляная кислота); трипсиноген → трипсин (энтерокиназа в двенадцатиперстной кишке); протромбин → тромбин.","zh":"酶原（酶前体）以非活性形式分泌，通过蛋白水解切割激活。防止对分泌器官的损伤。例：胃蛋白酶原→胃蛋白酶（胃酸）；胰蛋白酶原→胰蛋白酶（十二指肠肠激酶）；凝血酶原→凝血酶。","pt_BR":"Zimogênios (precursores enzimáticos) são secretados na forma inativa e ativados por clivagem proteolítica. Previne danos aos órgãos secretores. Exemplos: pepsinogênio → pepsina (ácido gástrico); tripsinogênio → tripsina (enteroquinase no duodeno); protrombina → trombina.","pt_PT":"Zimogénios (precursores enzimáticos) são secretados na forma inativa e ativados por clivagem proteolítica. Previne danos aos órgãos secretores. Exemplos: pepsinogénio → pepsina (ácido gástrico); tripsinogénio → tripsina (enteroquinase no duodeno); protrombina → trombina."}},
  { id: 'dc-mcat-0160', deck_id: 'deck-mcat', sort_order: 160, front: "Enzyme Cofactors and Coenzymes", back: "Cofactors: inorganic ions (Fe²⁺, Mg²⁺, Zn²⁺) required for enzyme activity. Coenzymes: organic molecules (often vitamins) that carry chemical groups: NAD⁺ (niacin, B3), FAD (riboflavin, B2), Coenzyme A (pantothenate, B5), TPP (thiamine, B1), PLP (B6)." , front_translations: {"es":"Cofatores y Coenzimas Enzimáticas","de":"Enzym-Kofaktoren und Coenzyme","fr":"Cofacteurs et coenzymes enzymatiques","tr":"Enzim Kofaktörleri ve Koenzimler","nl":"Enzymcofactoren en coenzymen","ru":"Кофакторы и коферменты ферментов","zh":"酶辅因子与辅酶","pt_BR":"Cofatores e Coenzimas Enzimáticas","pt_PT":"Cofatores e Coenzimas Enzimáticas"}, back_translations: {"es":"Cofatores: iones inorganicos (Fe²⁺, Mg²⁺, Zn²⁺) necesarios para a atividad enzimática. Coenzimas: moléculas organicas (frecuentemente vitaminas) que transportan grupos químicos: NAD⁺ (niacina, B3), FAD (riboflavina, B2), Coenzima A (pantotenato, B5), TPP (tiamina, B1), PLP (B6).","de":"Kofaktoren: anorganische Ionen (Fe²⁺, Mg²⁺, Zn²⁺), die für die Enzymaktivität erforderlich sind. Coenzyme: organische Moleküle (oft Vitamine), die chemische Gruppen transportieren: NAD⁺ (Niacin, B3), FAD (Riboflavin, B2), Coenzym A (Pantothensäure, B5), TPP (Thiamin, B1), PLP (B6).","fr":"Cofacteurs : ions inorganiques (Fe²⁺, Mg²⁺, Zn²⁺) nécessaires à l'activité enzymatique. Coenzymes : molécules organiques (souvent des vitamines) transportant des groupes chimiques : NAD⁺ (niacine, B3), FAD (riboflavine, B2), Coenzyme A (pantothénate, B5), TPP (thiamine, B1), PLP (B6).","tr":"Kofaktörler: enzim aktivitesi için gerekli inorganik iyonlar (Fe²⁺, Mg²⁺, Zn²⁺). Koenzimler: kimyasal gruplar taşıyan organik moleküller (genellikle vitaminler): NAD⁺ (niasin, B3), FAD (riboflavin, B2), Koenzim A (pantotenat, B5), TPP (tiamin, B1), PLP (B6).","nl":"Cofactoren: anorganische ionen (Fe²⁺, Mg²⁺, Zn²⁺) vereist voor enzymactiviteit. Coenzymen: organische moleculen (vaak vitaminen) die chemische groepen dragen: NAD⁺ (niacine, B3), FAD (riboflavine, B2), Coenzym A (pantothenaat, B5), TPP (thiamine, B1), PLP (B6).","ru":"Кофакторы: неорганические ионы (Fe²⁺, Mg²⁺, Zn²⁺), необходимые для активности фермента. Коферменты: органические молекулы (часто витамины), переносящие химические группы: NAD⁺ (ниацин, B3), FAD (рибофлавин, B2), Коэнзим A (пантотенат, B5), TPP (тиамин, B1), PLP (B6).","zh":"辅因子：酶活性所需的无机离子（Fe²⁺、Mg²⁺、Zn²⁺）。辅酶：携带化学基团的有机分子（通常是维生素）：NAD⁺（烟酸，B3）、FAD（核黄素，B2）、辅酶A（泛酸，B5）、TPP（硫胺素，B1）、PLP（B6）。","pt_BR":"Cofatores: íons inorgânicos (Fe²⁺, Mg²⁺, Zn²⁺) necessários para a atividade enzimática. Coenzimas: moléculas orgânicas (frequentemente vitaminas) que transportam grupos químicos: NAD⁺ (niacina, B3), FAD (riboflavina, B2), Coenzima A (pantotenato, B5), TPP (tiamina, B1), PLP (B6).","pt_PT":"Cofatores: iões inorgânicos (Fe²⁺, Mg²⁺, Zn²⁺) necessários para a atividade enzimática. Coenzimas: moléculas orgânicas (frequentemente vitaminas) que transportam grupos químicos: NAD⁺ (niacina, B3), FAD (riboflavina, B2), Coenzima A (pantotenato, B5), TPP (tiamina, B1), PLP (B6)."}},
  { id: 'dc-mcat-0161', deck_id: 'deck-mcat', sort_order: 161, front: "Fluid Mosaic Model", back: "Proposed by Singer and Nicolson (1972). The cell membrane is a fluid (dynamic, laterally mobile) bilayer of phospholipids with embedded proteins. Cholesterol increases membrane fluidity at low T and decreases it at high T (stabilizes membrane)." , front_translations: {"es":"Modelo del Mosaico Fluido","de":"Flüssig-Mosaik-Modell","fr":"Modèle de la mosaïque fluide","tr":"Akıcı Mozaik Modeli","nl":"Vloeibaar mozaïekmodel","ru":"Жидкостно-мозаичная модель","zh":"流动镶嵌模型","pt_BR":"Modelo do Mosaico Fluido","pt_PT":"Modelo do Mosaico Fluido"}, back_translations: {"es":"Proposto por Singer y Nicolson (1972). La membrana celular es una bicamada fluida (dinámica, con mobilidad lateral) de fosfolipídios con proteínas embutidas. El colesterol aumenta a fluidez de la membrana en baixas T y disminuye en altas T (estabiliza a membrana).","de":"Von Singer und Nicolson (1972) vorgeschlagen. Die Zellmembran ist eine fluide (dynamische, lateral bewegliche) Doppelschicht aus Phospholipiden mit eingebetteten Proteinen. Cholesterin erhöht die Membranfluidität bei niedrigen T und verringert sie bei hohen T (stabilisiert die Membran).","fr":"Proposé par Singer et Nicolson (1972). La membrane cellulaire est une bicouche fluide (dynamique, mobile latéralement) de phospholipides avec des protéines enchâssées. Le cholestérol augmente la fluidité membranaire à basse T et la diminue à haute T (stabilise la membrane).","tr":"Singer ve Nicolson (1972) tarafından önerildi. Hücre zarı, gömülü proteinlerle birlikte fosfolipidlerden oluşan akıcı (dinamik, yanal hareketli) bir çift tabakadır. Kolesterol düşük T'de membran akışkanlığını artırır, yüksek T'de azaltır (membranı stabilize eder).","nl":"Voorgesteld door Singer en Nicolson (1972). Het celmembraan is een fluïde (dynamische, lateraal beweeglijke) dubbellaag van fosfolipiden met ingebedde eiwitten. Cholesterol verhoogt de membraanvloeibaarheid bij lage T en verlaagt deze bij hoge T (stabiliseert het membraan).","ru":"Предложена Сингером и Николсоном (1972). Клеточная мембрана — жидкий (динамичный, латерально подвижный) бислой фосфолипидов с встроенными белками. Холестерин повышает текучесть мембраны при низкой T и понижает при высокой T (стабилизирует мембрану).","zh":"由Singer和Nicolson（1972）提出。细胞膜是由磷脂组成的流动（动态、侧向移动）双分子层，嵌有蛋白质。胆固醇在低温时增加膜流动性，在高温时降低膜流动性（稳定膜）。","pt_BR":"Proposto por Singer e Nicolson (1972). A membrana celular é uma bicamada fluida (dinâmica, com mobilidade lateral) de fosfolipídios com proteínas embutidas. O colesterol aumenta a fluidez da membrana em baixas T e diminui em altas T (estabiliza a membrana).","pt_PT":"Proposto por Singer e Nicolson (1972). A membrana celular é uma bicamada fluida (dinâmica, com mobilidade lateral) de fosfolípidos com proteínas incorporadas. O colesterol aumenta a fluidez da membrana a baixas T e diminui a altas T (estabiliza a membrana)."}},
  { id: 'dc-mcat-0162', deck_id: 'deck-mcat', sort_order: 162, front: "Second Messengers Summary", back: "cAMP (from adenylyl cyclase via Gs): activates PKA. cGMP (from guanylyl cyclase): activates PKG (e.g., NO → vasodilation). IP₃ (from PLC via Gq): releases Ca²⁺ from ER. DAG (from PLC): activates PKC. Ca²⁺: activates calmodulin, various kinases." , front_translations: {"es":"Resumo de los Segundos Mensageros","de":"Zusammenfassung der Second Messenger","fr":"Résumé des seconds messagers","tr":"İkincil Haberciler Özeti","nl":"Samenvatting van second messengers","ru":"Обзор вторичных мессенджеров","zh":"第二信使概要","pt_BR":"Resumo dos Segundos Mensageiros","pt_PT":"Resumo dos Segundos Mensageiros"}, back_translations: {"es":"cAMP (de la adenilil ciclase via Gs): ativa PKA. cGMP (de la guanilil ciclase): ativa PKG (ex.: NO → vasodilatación). IP₃ (de la PLC via Gq): libera Ca²⁺ del RE. DAG (de la PLC): ativa PKC. Ca²⁺: ativa calmodulina, várias quinases.","de":"cAMP (von Adenylylcyclase via Gs): aktiviert PKA. cGMP (von Guanylylcyclase): aktiviert PKG (z.B. NO → Vasodilatation). IP₃ (von PLC via Gq): setzt Ca²⁺ aus dem ER frei. DAG (von PLC): aktiviert PKC. Ca²⁺: aktiviert Calmodulin, verschiedene Kinasen.","fr":"cAMP (de l'adénylyl cyclase via Gs) : active PKA. cGMP (de la guanylyl cyclase) : active PKG (ex. NO → vasodilatation). IP₃ (de PLC via Gq) : libère Ca²⁺ du RE. DAG (de PLC) : active PKC. Ca²⁺ : active la calmoduline, diverses kinases.","tr":"cAMP (Gs üzerinden adenilil siklazdan): PKA'yı aktive eder. cGMP (guanilil siklazdan): PKG'yi aktive eder (örn. NO → vazodilatasyon). IP₃ (Gq üzerinden PLC'den): ER'den Ca²⁺ salar. DAG (PLC'den): PKC'yi aktive eder. Ca²⁺: kalmodülin ve çeşitli kinazları aktive eder.","nl":"cAMP (van adenylylcyclase via Gs): activeert PKA. cGMP (van guanylylcyclase): activeert PKG (bijv. NO → vasodilatatie). IP₃ (van PLC via Gq): geeft Ca²⁺ vrij uit het ER. DAG (van PLC): activeert PKC. Ca²⁺: activeert calmoduline, diverse kinasen.","ru":"cAMP (от аденилатциклазы через Gs): активирует PKA. cGMP (от гуанилатциклазы): активирует PKG (напр., NO → вазодилатация). IP₃ (от PLC через Gq): высвобождает Ca²⁺ из ЭПР. DAG (от PLC): активирует PKC. Ca²⁺: активирует кальмодулин, различные киназы.","zh":"cAMP（由腺苷酸环化酶经Gs产生）：激活PKA。cGMP（由鸟苷酸环化酶产生）：激活PKG（如NO→血管舒张）。IP₃（由PLC经Gq产生）：从内质网释放Ca²⁺。DAG（由PLC产生）：激活PKC。Ca²⁺：激活钙调蛋白及各种激酶。","pt_BR":"cAMP (da adenilil ciclase via Gs): ativa PKA. cGMP (da guanilil ciclase): ativa PKG (ex.: NO → vasodilatação). IP₃ (da PLC via Gq): libera Ca²⁺ do RE. DAG (da PLC): ativa PKC. Ca²⁺: ativa calmodulina, várias quinases.","pt_PT":"cAMP (da adenilil ciclase via Gs): ativa PKA. cGMP (da guanilil ciclase): ativa PKG (ex.: NO → vasodilatação). IP₃ (da PLC via Gq): liberta Ca²⁺ do RE. DAG (da PLC): ativa PKC. Ca²⁺: ativa calmodulina, várias cinases."}},
  { id: 'dc-mcat-0163', deck_id: 'deck-mcat', sort_order: 163, front: "Restriction Enzymes and Recombinant DNA", back: "Type II restriction enzymes cut dsDNA at specific palindromic sequences, producing sticky or blunt ends. DNA ligase joins fragments. Recombinant DNA technology uses these tools to clone genes into vectors for expression in host cells (E. coli, yeast)." , front_translations: {"es":"Enzimas de Restrición y DNA Recombinante","de":"Restriktionsenzyme und rekombinante DNA","fr":"Enzymes de restriction et ADN recombinant","tr":"Restriksiyon Enzimleri ve Rekombinant DNA","nl":"Restrictie-enzymen en recombinant DNA","ru":"Рестрикционные ферменты и рекомбинантная ДНК","zh":"限制酶与重组DNA","pt_BR":"Enzimas de Restrição e DNA Recombinante","pt_PT":"Enzimas de Restrição e DNA Recombinante"}, back_translations: {"es":"Enzimas de restrición tipo II cortam dsDNA en secuencias palindromicas específicas, produciendo extremidades coesivas o cegas. DNA ligase une los fragmentos. La tecnologia de DNA recombinante usa essas herramientas para clonar genes en vetores para expresión en células hospederas (Y. coli, levedura).","de":"Typ-II-Restriktionsenzyme schneiden dsDNA an spezifischen palindromischen Sequenzen und erzeugen klebrige oder glatte Enden. DNA-Ligase verbindet Fragmente. Rekombinante DNA-Technologie nutzt diese Werkzeuge, um Gene in Vektoren zur Expression in Wirtszellen (E. coli, Hefe) zu klonieren.","fr":"Les enzymes de restriction de type II coupent l'ADN double brin à des séquences palindromiques spécifiques, produisant des extrémités cohésives ou franches. La DNA ligase joint les fragments. La technologie de l'ADN recombinant utilise ces outils pour cloner des gènes dans des vecteurs pour expression dans des cellules hôtes (E. coli, levure).","tr":"Tip II restriksiyon enzimleri dsDNA'yı belirli palindromik dizilerde keser, yapışkan veya küt uçlar oluşturur. DNA ligaz fragmanları birleştirir. Rekombinant DNA teknolojisi bu araçları kullanarak genleri konak hücrelerde (E. coli, maya) ekspresyon için vektörlere klonlar.","nl":"Type II restrictie-enzymen knippen dsDNA bij specifieke palindromische sequenties en produceren plakkerige of stompe uiteinden. DNA-ligase verbindt fragmenten. Recombinant-DNA-technologie gebruikt deze hulpmiddelen om genen te kloneren in vectoren voor expressie in gastheercellen (E. coli, gist).","ru":"Рестрикционные ферменты типа II разрезают дцДНК по специфическим палиндромным последовательностям, образуя липкие или тупые концы. ДНК-лигаза соединяет фрагменты. Технология рекомбинантной ДНК использует эти инструменты для клонирования генов в векторы для экспрессии в клетках-хозяевах (E. coli, дрожжи).","zh":"II型限制酶在特定回文序列处切割双链DNA，产生黏性末端或平末端。DNA连接酶连接片段。重组DNA技术利用这些工具将基因克隆到载体中，在宿主细胞（大肠杆菌、酵母）中表达。","pt_BR":"Enzimas de restrição tipo II cortam dsDNA em sequências palindrômicas específicas, produzindo extremidades coesivas ou cegas. DNA ligase une os fragmentos. A tecnologia de DNA recombinante usa essas ferramentas para clonar genes em vetores para expressão em células hospedeiras (E. coli, levedura).","pt_PT":"Enzimas de restrição tipo II cortam dsDNA em sequências palindrómicas específicas, produzindo extremidades coesivas ou cegas. DNA ligase une os fragmentos. A tecnologia de DNA recombinante usa estas ferramentas para clonar genes em vetores para expressão em células hospedeiras (E. coli, levedura)."}},
  { id: 'dc-mcat-0164', deck_id: 'deck-mcat', sort_order: 164, front: "Southern, Northern, Western Blot", back: "Southern: DNA separated by gel electrophoresis, transferred to membrane, probed with labeled DNA. Northern: same but for RNA. Western: protein separated by SDS-PAGE, transferred, detected by antibody. 'SNoW DRoP' = South DNA, North RNA, West Protein." , front_translations: {"es":"Southern, Northern, Western Blot","de":"Southern-, Northern-, Western-Blot","fr":"Southern, Northern, Western Blot","tr":"Southern, Northern, Western Blot","nl":"Southern-, Northern-, Western-blot","ru":"Саузерн-, Нозерн-, Вестерн-блоттинг","zh":"Southern、Northern、Western印迹","pt_BR":"Southern, Northern, Western Blot","pt_PT":"Southern, Northern, Western Blot"}, back_translations: {"es":"Southern: DNA separado por eletroforese en gel, transferido para membrana, sondado con DNA marcado. Northern: el mismo, pero para RNA. Western: proteína separada por SDS-PAGE, transferida, detectada por anticorpo. 'SNoW DRoP' = South DNA, North RNA, West Protein.","de":"Southern: DNA durch Gelelektrophorese getrennt, auf Membran übertragen, mit markierter DNA-Sonde hybridisiert. Northern: dasselbe, aber für RNA. Western: Protein durch SDS-PAGE getrennt, übertragen, mit Antikörper nachgewiesen. 'SNoW DRoP' = South DNA, North RNA, West Protein.","fr":"Southern : ADN séparé par électrophorèse sur gel, transféré sur membrane, sondé avec de l'ADN marqué. Northern : idem mais pour l'ARN. Western : protéine séparée par SDS-PAGE, transférée, détectée par anticorps. 'SNoW DRoP' = South DNA, North RNA, West Protein.","tr":"Southern: DNA jel elektroforezi ile ayrılır, membrana transfer edilir, işaretli DNA ile problanır. Northern: aynısı ama RNA için. Western: protein SDS-PAGE ile ayrılır, transfer edilir, antikor ile tespit edilir. 'SNoW DRoP' = South DNA, North RNA, West Protein.","nl":"Southern: DNA gescheiden door gelelektroforese, overgebracht op membraan, geprobed met gelabeld DNA. Northern: hetzelfde maar voor RNA. Western: eiwit gescheiden door SDS-PAGE, overgebracht, gedetecteerd met antilichaam. 'SNoW DRoP' = South DNA, North RNA, West Protein.","ru":"Саузерн: ДНК разделяется гель-электрофорезом, переносится на мембрану, гибридизируется с меченым ДНК-зондом. Нозерн: то же, но для РНК. Вестерн: белок разделяется SDS-PAGE, переносится, детектируется антителом. 'SNoW DRoP' = South DNA, North RNA, West Protein.","zh":"Southern：DNA经凝胶电泳分离、转移至膜上、用标记DNA探针杂交。Northern：同样方法但用于RNA。Western：蛋白质经SDS-PAGE分离、转移、用抗体检测。'SNoW DRoP' = South DNA, North RNA, West Protein。","pt_BR":"Southern: DNA separado por eletroforese em gel, transferido para membrana, sondado com DNA marcado. Northern: o mesmo, mas para RNA. Western: proteína separada por SDS-PAGE, transferida, detectada por anticorpo. 'SNoW DRoP' = South DNA, North RNA, West Protein.","pt_PT":"Southern: DNA separado por eletroforese em gel, transferido para membrana, sondado com DNA marcado. Northern: o mesmo, mas para RNA. Western: proteína separada por SDS-PAGE, transferida, detetada por anticorpo. 'SNoW DRoP' = South DNA, North RNA, West Protein."}},
  { id: 'dc-mcat-0165', deck_id: 'deck-mcat', sort_order: 165, front: "ELISA (Enzyme-Linked Immunosorbent Assay)", back: "Uses antibodies and enzyme-linked detection to quantify an antigen in a sample. Types: direct, indirect, sandwich (most sensitive). The enzyme produces a color change proportional to antigen concentration. Used to detect HIV antibodies, hormones, and drugs." , front_translations: {"es":"ELISA (Ensaio de Imunoabsorción Enzimática)","de":"ELISA (Enzyme-Linked Immunosorbent Assay)","fr":"ELISA (Enzyme-Linked Immunosorbent Assay)","tr":"ELISA (Enzyme-Linked Immunosorbent Assay)","nl":"ELISA (Enzyme-Linked Immunosorbent Assay)","ru":"ELISA (иммуноферментный анализ)","zh":"ELISA（酶联免疫吸附测定）","pt_BR":"ELISA (Ensaio de Imunoabsorção Enzimática)","pt_PT":"ELISA (Ensaio de Imunoabsorção Enzimática)"}, back_translations: {"es":"Usa anticorpos y detección acoplada a enzimas para quantificar un antígeno en una amostra. Tipos: direto, indireto, sanduíche (más sensible). La enzima produce una cambio de cor proporcional a la concentración del antígeno. Usado para detectar anticorpos anti-HIV, hormonas y drogas.","de":"Verwendet Antikörper und enzymgekoppelte Detektion zur Quantifizierung eines Antigens in einer Probe. Typen: direkt, indirekt, Sandwich (am empfindlichsten). Das Enzym erzeugt einen Farbumschlag proportional zur Antigenkonzentration. Wird zum Nachweis von HIV-Antikörpern, Hormonen und Medikamenten verwendet.","fr":"Utilise des anticorps et une détection couplée à une enzyme pour quantifier un antigène dans un échantillon. Types : direct, indirect, sandwich (le plus sensible). L'enzyme produit un changement de couleur proportionnel à la concentration d'antigène. Utilisé pour détecter les anticorps anti-VIH, les hormones et les médicaments.","tr":"Bir örnekteki antijeni kantitatif olarak belirlemek için antikor ve enzim bağlı dedeksiyon kullanır. Türler: direkt, indirekt, sandviç (en hassas). Enzim, antijen konsantrasyonuyla orantılı bir renk değişimi üretir. HIV antikorları, hormonlar ve ilaçları tespit etmek için kullanılır.","nl":"Gebruikt antilichamen en enzym-gekoppelde detectie om een antigeen in een monster te kwantificeren. Types: direct, indirect, sandwich (meest gevoelig). Het enzym produceert een kleurverandering evenredig met de antigeenconcentratie. Gebruikt om HIV-antilichamen, hormonen en drugs te detecteren.","ru":"Использует антитела и ферментно-связанную детекцию для количественного определения антигена в образце. Типы: прямой, непрямой, сэндвич (наиболее чувствительный). Фермент даёт изменение цвета, пропорциональное концентрации антигена. Применяется для обнаружения антител к ВИЧ, гормонов и лекарств.","zh":"使用抗体和酶联检测来定量样品中的抗原。类型：直接法、间接法、夹心法（最灵敏）。酶产生与抗原浓度成正比的颜色变化。用于检测HIV抗体、激素和药物。","pt_BR":"Usa anticorpos e detecção acoplada a enzimas para quantificar um antígeno em uma amostra. Tipos: direto, indireto, sanduíche (mais sensível). A enzima produz uma mudança de cor proporcional à concentração do antígeno. Usado para detectar anticorpos anti-HIV, hormônios e drogas.","pt_PT":"Usa anticorpos e deteção acoplada a enzimas para quantificar um antigénio numa amostra. Tipos: direto, indireto, sanduíche (mais sensível). A enzima produz uma mudança de cor proporcional à concentração do antigénio. Usado para detetar anticorpos anti-VIH, hormonas e fármacos."}},
  { id: 'dc-mcat-0166', deck_id: 'deck-mcat', sort_order: 166, front: "Carboxylic Acid Derivatives Reactivity", back: "Acyl chloride > Anhydride > Ester > Amide (decreasing reactivity in nucleophilic acyl substitution). Better leaving group = more reactive. Acid chlorides are made from carboxylic acids + thionyl chloride or PCl₅. All can be hydrolyzed to the parent acid." , front_translations: {"es":"Reatividad de los Derivados de Ácidos Carboxílicos","de":"Reaktivität von Carbonsäurederivaten","fr":"Réactivité des dérivés d'acides carboxyliques","tr":"Karboksilik Asit Türevlerinin Reaktivitesi","nl":"Reactiviteit van carbonzuurderivaten","ru":"Реакционная способность производных карбоновых кислот","zh":"羧酸衍生物的反应活性","pt_BR":"Reatividade dos Derivados de Ácidos Carboxílicos","pt_PT":"Reatividade dos Derivados de Ácidos Carboxílicos"}, back_translations: {"es":"Cloreto de acila > Anidrido > Éster > Amida (reatividad decrescente en la substituición nucleofílica acílica). Melhor grupo de saída = más reativo. Cloretos de ácido son feitos de ácidos carboxílicos + cloreto de tionila o PCl₅. Todos pueden ser hidrolisados al ácido original.","de":"Acylchlorid > Anhydrid > Ester > Amid (abnehmende Reaktivität bei nukleophiler Acylsubstitution). Bessere Abgangsgruppe = reaktiver. Säurechloride werden aus Carbonsäuren + Thionylchlorid oder PCl₅ hergestellt. Alle können zur Ausgangssäure hydrolysiert werden.","fr":"Chlorure d'acyle > Anhydride > Ester > Amide (réactivité décroissante en substitution nucléophile sur acyle). Meilleur groupe partant = plus réactif. Les chlorures d'acide sont préparés à partir d'acides carboxyliques + chlorure de thionyle ou PCl₅. Tous peuvent être hydrolysés en acide parent.","tr":"Açil klorür > Anhidrit > Ester > Amid (nükleofilik açil sübstitüsyonunda azalan reaktivite). Daha iyi ayrılan grup = daha reaktif. Asit klorürleri karboksilik asitler + tionil klorür veya PCl₅'ten yapılır. Hepsi ana aside hidrolize edilebilir.","nl":"Acylchloride > Anhydride > Ester > Amide (afnemende reactiviteit bij nucleofiele acylsubstitutie). Betere vertrekkende groep = reactiever. Zuurchloriden worden gemaakt van carbonzuren + thionylchloride of PCl₅. Allemaal hydrolyseerbaar tot het oorspronkelijke zuur.","ru":"Ацилхлорид > Ангидрид > Сложный эфир > Амид (убывающая реакционная способность в нуклеофильном ацильном замещении). Лучшая уходящая группа = более реакционноспособен. Хлорангидриды получают из карбоновых кислот + тионилхлорид или PCl₅. Все могут быть гидролизованы до исходной кислоты.","zh":"酰氯 > 酸酐 > 酯 > 酰胺（亲核酰基取代反应活性递减）。离去基团越好 = 反应活性越高。酰氯由羧酸 + 亚硫酰氯或PCl₅制备。所有衍生物均可水解为母体酸。","pt_BR":"Cloreto de acila > Anidrido > Éster > Amida (reatividade decrescente na substituição nucleofílica acílica). Melhor grupo de saída = mais reativo. Cloretos de ácido são feitos de ácidos carboxílicos + cloreto de tionila ou PCl₅. Todos podem ser hidrolisados ao ácido original.","pt_PT":"Cloreto de acilo > Anidrido > Éster > Amida (reatividade decrescente na substituição nucleofílica acílica). Melhor grupo de saída = mais reativo. Cloretos de ácido são feitos de ácidos carboxílicos + cloreto de tionilo ou PCl₅. Todos podem ser hidrolisados ao ácido original."}},
  { id: 'dc-mcat-0167', deck_id: 'deck-mcat', sort_order: 167, front: "Oxidation States of Carbon in Organic Compounds", back: "Most reduced: CH₄ (C = -4). Increasingly oxidized: CH₃OH (alcohol, -2) → RCHO (aldehyde, 0) → RCOOH (carboxylic acid, +2) → CO₂ (+4). Moving toward carboxylic acid = oxidation (gain of O or loss of H)." , front_translations: {"es":"Estados de Oxidación del Carbono en Compostos Organicos","de":"Oxidationsstufen von Kohlenstoff in organischen Verbindungen","fr":"États d'oxydation du carbone dans les composés organiques","tr":"Organik Bileşiklerde Karbonun Oksidasyon Durumları","nl":"Oxidatietoestanden van koolstof in organische verbindingen","ru":"Степени окисления углерода в органических соединениях","zh":"有机化合物中碳的氧化态","pt_BR":"Estados de Oxidação do Carbono em Compostos Orgânicos","pt_PT":"Estados de Oxidação do Carbono em Compostos Orgânicos"}, back_translations: {"es":"Más reduzido: CH₄ (C = -4). Cada vez más oxidado: CH₃OH (álcool, -2) → RCHO (aldeído, 0) → RCOOH (ácido carboxílico, +2) → CO₂ (+4). En dirección al ácido carboxílico = oxidación (ganho de El o perda de H).","de":"Am stärksten reduziert: CH₄ (C = -4). Zunehmend oxidiert: CH₃OH (Alkohol, -2) → RCHO (Aldehyd, 0) → RCOOH (Carbonsäure, +2) → CO₂ (+4). Richtung Carbonsäure = Oxidation (Gewinn von O oder Verlust von H).","fr":"Le plus réduit : CH₄ (C = -4). De plus en plus oxydé : CH₃OH (alcool, -2) → RCHO (aldéhyde, 0) → RCOOH (acide carboxylique, +2) → CO₂ (+4). Aller vers l'acide carboxylique = oxydation (gain de O ou perte de H).","tr":"En indirgenmiş: CH₄ (C = -4). Giderek oksitlenmiş: CH₃OH (alkol, -2) → RCHO (aldehit, 0) → RCOOH (karboksilik asit, +2) → CO₂ (+4). Karboksilik aside doğru gitmek = oksidasyon (O kazanımı veya H kaybı).","nl":"Meest gereduceerd: CH₄ (C = -4). Toenemend geoxideerd: CH₃OH (alcohol, -2) → RCHO (aldehyde, 0) → RCOOH (carbonzuur, +2) → CO₂ (+4). Richting carbonzuur = oxidatie (winst van O of verlies van H).","ru":"Наиболее восстановлен: CH₄ (C = -4). Возрастающее окисление: CH₃OH (спирт, -2) → RCHO (альдегид, 0) → RCOOH (карбоновая кислота, +2) → CO₂ (+4). Движение к карбоновой кислоте = окисление (присоединение O или потеря H).","zh":"最还原态：CH₄（C = -4）。逐渐氧化：CH₃OH（醇，-2）→ RCHO（醛，0）→ RCOOH（羧酸，+2）→ CO₂（+4）。向羧酸方向 = 氧化（得O或失H）。","pt_BR":"Mais reduzido: CH₄ (C = -4). Cada vez mais oxidado: CH₃OH (álcool, -2) → RCHO (aldeído, 0) → RCOOH (ácido carboxílico, +2) → CO₂ (+4). Em direção ao ácido carboxílico = oxidação (ganho de O ou perda de H).","pt_PT":"Mais reduzido: CH₄ (C = -4). Cada vez mais oxidado: CH₃OH (álcool, -2) → RCHO (aldeído, 0) → RCOOH (ácido carboxílico, +2) → CO₂ (+4). Em direção ao ácido carboxílico = oxidação (ganho de O ou perda de H)."}},
  { id: 'dc-mcat-0168', deck_id: 'deck-mcat', sort_order: 168, front: "Spectroscopy: ¹H NMR Interpretation", back: "Chemical shift (δ, ppm): indicates electronic environment. Splitting: n equivalent neighbors → n+1 peaks (n+1 rule). Integration: proportional to number of protons. Downfield (high δ): deshielded (near electronegative atoms or π systems). TMS = reference (0 ppm)." , front_translations: {"es":"Espectroscopia: Interpretación de ¹H RMN","de":"Spektroskopie: ¹H NMR Interpretation","fr":"Spectroscopie : interprétation de la RMN ¹H","tr":"Spektroskopi: ¹H NMR Yorumlama","nl":"Spectroscopie: ¹H NMR-interpretatie","ru":"Спектроскопия: интерпретация ¹H ЯМР","zh":"波谱学：¹H NMR解析","pt_BR":"Espectroscopia: Interpretação de ¹H RMN","pt_PT":"Espectroscopia: Interpretação de ¹H RMN"}, back_translations: {"es":"Deslocamento químico (δ, ppm): indica el ambiente electrónico. Desdobramento: n vizinhos equivalentes → n+1 picos (regra n+1). Integración: proporcional al número de protones. Campo bajo (δ alto): desblindado (perto de átomos eletronegativos o sistemas π). TMS = referencia (0 ppm).","de":"Chemische Verschiebung (δ, ppm): zeigt die elektronische Umgebung an. Aufspaltung: n äquivalente Nachbarn → n+1 Peaks (n+1-Regel). Integration: proportional zur Anzahl der Protonen. Tieffeld (hohes δ): entschirmt (nahe elektronegativer Atome oder π-Systeme). TMS = Referenz (0 ppm).","fr":"Déplacement chimique (δ, ppm) : indique l'environnement électronique. Éclatement : n voisins équivalents → n+1 pics (règle n+1). Intégration : proportionnelle au nombre de protons. Champ faible (δ élevé) : déblindé (près d'atomes électronégatifs ou de systèmes π). TMS = référence (0 ppm).","tr":"Kimyasal kayma (δ, ppm): elektronik çevreyi gösterir. Yarılma: n eşdeğer komşu → n+1 pik (n+1 kuralı). İntegrasyon: proton sayısıyla orantılı. Düşük alan (yüksek δ): perdesi kaldırılmış (elektronegatif atomlara veya π sistemlerine yakın). TMS = referans (0 ppm).","nl":"Chemische verschuiving (δ, ppm): geeft de elektronische omgeving aan. Splitsing: n equivalente buren → n+1 pieken (n+1-regel). Integratie: evenredig met het aantal protonen. Laagveld (hoog δ): ontschermd (nabij elektronegatieve atomen of π-systemen). TMS = referentie (0 ppm).","ru":"Химический сдвиг (δ, м.д.): указывает на электронное окружение. Расщепление: n эквивалентных соседей → n+1 пик (правило n+1). Интеграция: пропорциональна числу протонов. Слабое поле (высокий δ): дезэкранированный (вблизи электроотрицательных атомов или π-систем). TMS = эталон (0 м.д.).","zh":"化学位移（δ，ppm）：表示电子环境。裂分：n个等价邻位→n+1个峰（n+1规则）。积分：与质子数成正比。低场（高δ）：去屏蔽（靠近电负性原子或π体系）。TMS = 参考（0 ppm）。","pt_BR":"Deslocamento químico (δ, ppm): indica o ambiente eletrônico. Desdobramento: n vizinhos equivalentes → n+1 picos (regra n+1). Integração: proporcional ao número de prótons. Campo baixo (δ alto): desblindado (perto de átomos eletronegativos ou sistemas π). TMS = referência (0 ppm).","pt_PT":"Desvio químico (δ, ppm): indica o ambiente eletrónico. Desdobramento: n vizinhos equivalentes → n+1 picos (regra n+1). Integração: proporcional ao número de protões. Campo baixo (δ alto): desblindado (perto de átomos eletronegativos ou sistemas π). TMS = referência (0 ppm)."}},
  { id: 'dc-mcat-0169', deck_id: 'deck-mcat', sort_order: 169, front: "Keto-Enol Tautomerism", back: "A rapid equilibrium between a keto form (C=O with α-H) and an enol form (C=C with OH). The keto form usually predominates. Tautomerism is catalyzed by acid or base. Enols are important intermediates in many biological reactions." , front_translations: {"es":"Tautomeria Ceto-Enólica","de":"Keto-Enol-Tautomerie","fr":"Tautomérie céto-énolique","tr":"Keto-Enol Tautomerizmi","nl":"Keto-enol-tautomerie","ru":"Кето-енольная таутомерия","zh":"酮-烯醇互变异构","pt_BR":"Tautomeria Ceto-Enólica","pt_PT":"Tautomeria Ceto-Enólica"}, back_translations: {"es":"Un equilíbrio rápido entre a forma ceto (C=El con α-H) y a forma enol (C=C con OH). La forma ceto generalmente predomina. La tautomeria es catalisada por ácido o base. Enóis son intermediários importantes en muchas reacciones biológicas.","de":"Ein schnelles Gleichgewicht zwischen einer Ketoform (C=O mit α-H) und einer Enolform (C=C mit OH). Die Ketoform überwiegt normalerweise. Tautomerie wird durch Säure oder Base katalysiert. Enole sind wichtige Zwischenprodukte in vielen biologischen Reaktionen.","fr":"Un équilibre rapide entre une forme céto (C=O avec α-H) et une forme énol (C=C avec OH). La forme céto prédomine généralement. La tautomérie est catalysée par un acide ou une base. Les énols sont des intermédiaires importants dans de nombreuses réactions biologiques.","tr":"Keto formu (α-H ile C=O) ve enol formu (OH ile C=C) arasında hızlı bir denge. Keto formu genellikle baskındır. Tautomerizm asit veya baz tarafından katalize edilir. Enoller birçok biyolojik reaksiyonda önemli ara ürünlerdir.","nl":"Een snel evenwicht tussen een ketovorm (C=O met α-H) en een enolvorm (C=C met OH). De ketovorm overheerst meestal. Tautomerie wordt gekatalyseerd door zuur of base. Enolen zijn belangrijke tussenproducten in veel biologische reacties.","ru":"Быстрое равновесие между кето-формой (C=O с α-H) и енольной формой (C=C с OH). Кето-форма обычно преобладает. Таутомерия катализируется кислотой или основанием. Енолы — важные промежуточные вещества во многих биологических реакциях.","zh":"酮式（带α-H的C=O）与烯醇式（带OH的C=C）之间的快速平衡。酮式通常占优势。互变异构由酸或碱催化。烯醇是许多生物反应中的重要中间体。","pt_BR":"Um equilíbrio rápido entre a forma ceto (C=O com α-H) e a forma enol (C=C com OH). A forma ceto geralmente predomina. A tautomeria é catalisada por ácido ou base. Enóis são intermediários importantes em muitas reações biológicas.","pt_PT":"Um equilíbrio rápido entre a forma ceto (C=O com α-H) e a forma enol (C=C com OH). A forma ceto geralmente predomina. A tautomeria é catalisada por ácido ou base. Enóis são intermediários importantes em muitas reações biológicas."}},
  { id: 'dc-mcat-0170', deck_id: 'deck-mcat', sort_order: 170, front: "Claisen Condensation", back: "A condensation between two esters (or an ester and a ketone — Claisen-Schmidt) using a strong base. Forms a β-keto ester. The biological equivalent is thiolase in β-oxidation (two acetyl-CoA units condense to form acetoacetyl-CoA)." , front_translations: {"es":"Condensación de Claisen","de":"Claisen-Kondensation","fr":"Condensation de Claisen","tr":"Claisen Kondensasyonu","nl":"Claisen-condensatie","ru":"Конденсация Кляйзена","zh":"Claisen缩合反应","pt_BR":"Condensação de Claisen","pt_PT":"Condensação de Claisen"}, back_translations: {"es":"Una condensación entre de los ésteres (o un éster y una cetona — Claisen-Schmidt) usando una base fuerte. Forma un β-cetoéster. El equivalente biológico es a tiolase en la β-oxidación (de los unidades de acetil-CoA condensam para formar acetoacetil-CoA).","de":"Eine Kondensation zwischen zwei Estern (oder einem Ester und einem Keton — Claisen-Schmidt) unter Verwendung einer starken Base. Bildet einen β-Ketoester. Das biologische Äquivalent ist die Thiolase in der β-Oxidation (zwei Acetyl-CoA-Einheiten kondensieren zu Acetoacetyl-CoA).","fr":"Condensation entre deux esters (ou un ester et une cétone — Claisen-Schmidt) en présence d'une base forte. Forme un β-cétoester. L'équivalent biologique est la thiolase de la β-oxydation (deux unités d'acétyl-CoA condensent pour former l'acétoacétyl-CoA).","tr":"İki ester (veya bir ester ve bir keton — Claisen-Schmidt) arasında güçlü bir baz kullanılarak gerçekleştirilen kondensasyon. Bir β-keto ester oluşturur. Biyolojik karşılığı β-oksidasyondaki tiolazdır (iki asetil-CoA birimi yoğunlaşarak asetoasetil-CoA oluşturur).","nl":"Een condensatie tussen twee esters (of een ester en een keton — Claisen-Schmidt) met een sterke base. Vormt een β-ketoester. Het biologische equivalent is thiolase in de β-oxidatie (twee acetyl-CoA-eenheden condenseren tot acetoacetyl-CoA).","ru":"Конденсация между двумя сложными эфирами (или эфиром и кетоном — Кляйзена-Шмидта) с использованием сильного основания. Образует β-кетоэфир. Биологический эквивалент — тиолаза в β-окислении (две единицы ацетил-CoA конденсируются в ацетоацетил-CoA).","zh":"两个酯（或一个酯和一个酮——Claisen-Schmidt反应）在强碱作用下的缩合反应。生成β-酮酯。其生物学等价物是β-氧化中的硫解酶（两个乙酰-CoA单元缩合形成乙酰乙酰-CoA）。","pt_BR":"Uma condensação entre dois ésteres (ou um éster e uma cetona — Claisen-Schmidt) usando uma base forte. Forma um β-cetoéster. O equivalente biológico é a tiolase na β-oxidação (duas unidades de acetil-CoA condensam para formar acetoacetil-CoA).","pt_PT":"Uma condensação entre dois ésteres (ou um éster e uma cetona — Claisen-Schmidt) usando uma base forte. Forma um β-cetoéster. O equivalente biológico é a tiolase na β-oxidação (duas unidades de acetil-CoA condensam para formar acetoacetil-CoA)."}},
  { id: 'dc-mcat-0171', deck_id: 'deck-mcat', sort_order: 171, front: "Diels-Alder Reaction", back: "A [4+2] cycloaddition between a diene (in s-cis conformation) and a dienophile (electron-poor alkene). Forms a six-membered ring. Stereospecific: syn addition, endo rule. Important in natural product synthesis." , front_translations: {"es":"Reación de Diels-Alder","de":"Diels-Alder-Reaktion","fr":"Réaction de Diels-Alder","tr":"Diels-Alder Reaksiyonu","nl":"Diels-Alder-reactie","ru":"Реакция Дильса-Альдера","zh":"Diels-Alder反应","pt_BR":"Reação de Diels-Alder","pt_PT":"Reação de Diels-Alder"}, back_translations: {"es":"Una cicloadición [4+2] entre un dieno (en conformación s-cis) y un dienófilo (alceno pobre en electrones). Forma un anel de seis membros. Estereoespecífica: adición sin, regra endo. Importante en la síntese de productos naturais.","de":"Eine [4+2]-Cycloaddition zwischen einem Dien (in s-cis-Konformation) und einem Dienophil (elektronenarmes Alken). Bildet einen Sechsring. Stereospezifisch: syn-Addition, Endo-Regel. Wichtig in der Naturstoffsynthese.","fr":"Une cycloaddition [4+2] entre un diène (en conformation s-cis) et un diénophile (alcène pauvre en électrons). Forme un cycle à six chaînons. Stéréospécifique : addition syn, règle endo. Importante en synthèse de produits naturels.","tr":"Bir dien (s-cis konformasyonunda) ile bir dienofil (elektron fakiri alken) arasındaki [4+2] siklokatılma reaksiyonu. Altı üyeli halka oluşturur. Stereospesifik: sin katılma, endo kuralı. Doğal ürün sentezinde önemlidir.","nl":"Een [4+2]-cycloadditie tussen een dieen (in s-cis-conformatie) en een dienofiel (elektronenarm alkeen). Vormt een zesring. Stereospecifiek: syn-additie, endo-regel. Belangrijk in de synthese van natuurproducten.","ru":"Циклоприсоединение [4+2] между диеном (в s-цис-конформации) и диенофилом (электронодефицитный алкен). Образует шестичленное кольцо. Стереоспецифична: син-присоединение, эндо-правило. Важна в синтезе природных соединений.","zh":"[4+2]环加成反应，发生在二烯（s-顺式构象）和亲二烯体（缺电子烯烃）之间。形成六元环。立体专一性：顺式加成，内型规则。在天然产物合成中很重要。","pt_BR":"Uma cicloadição [4+2] entre um dieno (em conformação s-cis) e um dienófilo (alceno pobre em elétrons). Forma um anel de seis membros. Estereoespecífica: adição sin, regra endo. Importante na síntese de produtos naturais.","pt_PT":"Uma cicloadição [4+2] entre um dieno (em conformação s-cis) e um dienófilo (alceno pobre em eletrões). Forma um anel de seis membros. Estereoespecífica: adição sin, regra endo. Importante na síntese de produtos naturais."}},
  { id: 'dc-mcat-0172', deck_id: 'deck-mcat', sort_order: 172, front: "Free Radical Reactions", back: "Three stages: initiation (homolytic bond cleavage by heat/light → radicals), propagation (radical reacts with substrate, generating new radicals), termination (two radicals combine → no new radicals). Halogenation of alkanes is a free radical reaction." , front_translations: {"es":"Reaciones de Radicais Livres","de":"Radikalische Reaktionen","fr":"Réactions radicalaires","tr":"Serbest Radikal Reaksiyonları","nl":"Vrije-radicaalreacties","ru":"Свободнорадикальные реакции","zh":"自由基反应","pt_BR":"Reações de Radicais Livres","pt_PT":"Reações de Radicais Livres"}, back_translations: {"es":"Tres etapas: iniciación (clivaje homolítica por calor/luz → radicais), propagación (radical reage con substrato, generando nuevos radicais), terminación (de los radicais se combinam → sin nuevos radicais). La halogenación de alcanos es una reacción de radicais livres.","de":"Drei Stufen: Initiierung (homolytische Bindungsspaltung durch Wärme/Licht → Radikale), Kettenwachstum (Radikal reagiert mit Substrat, erzeugt neue Radikale), Abbruch (zwei Radikale kombinieren → keine neuen Radikale). Die Halogenierung von Alkanen ist eine radikalische Reaktion.","fr":"Trois étapes : initiation (clivage homolytique par chaleur/lumière → radicaux), propagation (le radical réagit avec le substrat, générant de nouveaux radicaux), terminaison (deux radicaux se combinent → plus de nouveaux radicaux). L'halogénation des alcanes est une réaction radicalaire.","tr":"Üç aşama: başlatma (ısı/ışıkla homolitik bağ kırılması → radikaller), ilerleme (radikal substratla reaksiyona girer, yeni radikaller üretir), sonlanma (iki radikal birleşir → yeni radikal oluşmaz). Alkanların halojenasyonu serbest radikal reaksiyonudur.","nl":"Drie stadia: initiatie (homolytische bindingsbreuk door warmte/licht → radicalen), propagatie (radicaal reageert met substraat, genereert nieuwe radicalen), terminatie (twee radicalen combineren → geen nieuwe radicalen). Halogenering van alkanen is een vrije-radicaalreactie.","ru":"Три стадии: инициирование (гомолитический разрыв связи под действием тепла/света → радикалы), рост цепи (радикал реагирует с субстратом, образуя новые радикалы), обрыв (два радикала соединяются → новые радикалы не образуются). Галогенирование алканов — свободнорадикальная реакция.","zh":"三个阶段：引发（热/光引起均裂 → 自由基）、增长（自由基与底物反应，产生新自由基）、终止（两个自由基结合 → 不再产生新自由基）。烷烃的卤代反应是自由基反应。","pt_BR":"Três estágios: iniciação (clivagem homolítica por calor/luz → radicais), propagação (radical reage com substrato, gerando novos radicais), terminação (dois radicais se combinam → sem novos radicais). A halogenação de alcanos é uma reação de radicais livres.","pt_PT":"Três estágios: iniciação (clivagem homolítica por calor/luz → radicais), propagação (radical reage com substrato, gerando novos radicais), terminação (dois radicais combinam-se → sem novos radicais). A halogenação de alcanos é uma reação de radicais livres."}},
  { id: 'dc-mcat-0173', deck_id: 'deck-mcat', sort_order: 173, front: "Polarity and Solubility", back: "Like dissolves like: polar solvents (water) dissolve polar/ionic substances; nonpolar solvents (hexane) dissolve nonpolar substances. Amphipathic molecules (soaps, phospholipids) have both polar and nonpolar regions and act as emulsifiers." , front_translations: {"es":"Polaridad y Solubilidad","de":"Polarität und Löslichkeit","fr":"Polarité et solubilité","tr":"Polarite ve Çözünürlük","nl":"Polariteit en oplosbaarheid","ru":"Полярность и растворимость","zh":"极性与溶解性","pt_BR":"Polaridade e Solubilidade","pt_PT":"Polaridade e Solubilidade"}, back_translations: {"es":"Semelhante dissolve semelhante: disolventes polares (agua) dissolvem sustancias polares/ionicas; disolventes apolares (hexano) dissolvem sustancias apolares. Moléculas anfipáticas (sabões, fosfolipídios) tienen regiones polares y apolares y actúan como emulsificantes.","de":"Gleiches löst Gleiches: Polare Lösungsmittel (Wasser) lösen polare/ionische Substanzen; unpolare Lösungsmittel (Hexan) lösen unpolare Substanzen. Amphipathische Moleküle (Seifen, Phospholipide) haben sowohl polare als auch unpolare Bereiche und wirken als Emulgatoren.","fr":"Le semblable dissout le semblable : les solvants polaires (eau) dissolvent les substances polaires/ioniques ; les solvants apolaires (hexane) dissolvent les substances apolaires. Les molécules amphipathiques (savons, phospholipides) ont des régions polaires et apolaires et agissent comme émulsifiants.","tr":"Benzer benzeri çözer: polar çözücüler (su) polar/iyonik maddeleri çözer; apolar çözücüler (hekzan) apolar maddeleri çözer. Amfipatik moleküller (sabunlar, fosfolipidler) hem polar hem apolar bölgelere sahiptir ve emülgatör olarak işlev görür.","nl":"Gelijk lost gelijk op: polaire oplosmiddelen (water) lossen polaire/ionische stoffen op; apolaire oplosmiddelen (hexaan) lossen apolaire stoffen op. Amfipathische moleculen (zepen, fosfolipiden) hebben zowel polaire als apolaire gebieden en werken als emulgatoren.","ru":"Подобное растворяется в подобном: полярные растворители (вода) растворяют полярные/ионные вещества; неполярные растворители (гексан) растворяют неполярные вещества. Амфипатические молекулы (мыла, фосфолипиды) имеют полярные и неполярные участки и действуют как эмульгаторы.","zh":"相似相溶：极性溶剂（水）溶解极性/离子物质；非极性溶剂（己烷）溶解非极性物质。两亲性分子（肥皂、磷脂）同时具有极性和非极性区域，起乳化剂作用。","pt_BR":"Semelhante dissolve semelhante: solventes polares (água) dissolvem substâncias polares/iônicas; solventes apolares (hexano) dissolvem substâncias apolares. Moléculas anfipáticas (sabões, fosfolipídios) têm regiões polares e apolares e atuam como emulsificantes.","pt_PT":"Semelhante dissolve semelhante: solventes polares (água) dissolvem substâncias polares/iónicas; solventes apolares (hexano) dissolvem substâncias apolares. Moléculas anfipáticas (sabões, fosfolípidos) têm regiões polares e apolares e atuam como emulsionantes."}},
  { id: 'dc-mcat-0174', deck_id: 'deck-mcat', sort_order: 174, front: "Resonance and Stability", back: "Resonance structures delocalize electrons, stabilizing the molecule. More resonance contributors = greater stability. Carboxylate anion (2 equivalent structures) is more stable than an alkoxide (1 structure). Benzene's 6-π electron delocalization confers aromatic stability." , front_translations: {"es":"Ressonancia y Estabilidad","de":"Resonanz und Stabilität","fr":"Résonance et stabilité","tr":"Rezonans ve Kararlılık","nl":"Resonantie en stabiliteit","ru":"Резонанс и стабильность","zh":"共振与稳定性","pt_BR":"Ressonância e Estabilidade","pt_PT":"Ressonância e Estabilidade"}, back_translations: {"es":"Estruturas de ressonancia deslocalizam electrones, estabilizando a molécula. Más contribuintes de ressonancia = mayor estabilidad. El anion carboxilato (2 estructuras equivalentes) es más estable que un alcóxido (1 estructura). La deslocalización de los 6 electrones π del benzeno confere estabilidad aromática.","de":"Resonanzstrukturen delokalisieren Elektronen und stabilisieren das Molekül. Mehr Resonanzbeiträge = größere Stabilität. Das Carboxylat-Anion (2 äquivalente Strukturen) ist stabiler als ein Alkoxid (1 Struktur). Die Delokalisierung der 6 π-Elektronen des Benzols verleiht aromatische Stabilität.","fr":"Les structures de résonance délocalisent les électrons, stabilisant la molécule. Plus de contributeurs de résonance = plus grande stabilité. L'anion carboxylate (2 structures équivalentes) est plus stable qu'un alcoolate (1 structure). La délocalisation des 6 électrons π du benzène confère la stabilité aromatique.","tr":"Rezonans yapıları elektronları delokalize ederek molekülü stabilize eder. Daha fazla rezonans katkısı = daha büyük kararlılık. Karboksilat anyonu (2 eşdeğer yapı) bir alkoksitten (1 yapı) daha kararlıdır. Benzenin 6 π-elektron delokalizasyonu aromatik kararlılık sağlar.","nl":"Resonantiestructuren delokaliseren elektronen en stabiliseren het molecuul. Meer resonantiebijdragen = grotere stabiliteit. Het carboxylaat-anion (2 equivalente structuren) is stabieler dan een alkoxide (1 structuur). De 6-π-elektronendelokalisatie van benzeen verleent aromatische stabiliteit.","ru":"Резонансные структуры делокализуют электроны, стабилизируя молекулу. Больше резонансных структур = большая стабильность. Карбоксилат-анион (2 эквивалентные структуры) стабильнее алкоксида (1 структура). Делокализация 6 π-электронов бензола обеспечивает ароматическую стабильность.","zh":"共振结构使电子离域，从而稳定分子。共振贡献体越多 = 稳定性越大。羧酸根阴离子（2个等价结构）比醇盐（1个结构）更稳定。苯的6个π电子离域赋予芳香稳定性。","pt_BR":"Estruturas de ressonância deslocalizam elétrons, estabilizando a molécula. Mais contribuintes de ressonância = maior estabilidade. O ânion carboxilato (2 estruturas equivalentes) é mais estável que um alcóxido (1 estrutura). A deslocalização dos 6 elétrons π do benzeno confere estabilidade aromática.","pt_PT":"Estruturas de ressonância deslocalizam eletrões, estabilizando a molécula. Mais contribuintes de ressonância = maior estabilidade. O anião carboxilato (2 estruturas equivalentes) é mais estável que um alcóxido (1 estrutura). A deslocalização dos 6 eletrões π do benzeno confere estabilidade aromática."}},
  { id: 'dc-mcat-0175', deck_id: 'deck-mcat', sort_order: 175, front: "Magnetism and MRI", back: "MRI uses powerful magnetic fields to align hydrogen nuclei (protons), which are then perturbed by radiofrequency pulses. As they relax back, they emit signals used to construct images. T1 (fat bright) and T2 (fluid bright) are relaxation parameters. No ionizing radiation." , front_translations: {"es":"Magnetismo y MRI","de":"Magnetismus und MRI","fr":"Magnétisme et IRM","tr":"Manyetizma ve MRI","nl":"Magnetisme en MRI","ru":"Магнетизм и MRI","zh":"磁性与MRI","pt_BR":"Magnetismo e MRI","pt_PT":"Magnetismo e MRI"}, back_translations: {"es":"La MRI usa campos magnéticos potentes para alinhar núcleos de hidrógeno (protones), que son entonces perturbados por pulsos de radiofrequencia. Ao relaxarem, emitem señales usados para construir imajes. T1 (gordura brilhante) y T2 (líquido brilhante) son parametros de relaxación. Sin radiación ionizante.","de":"MRI verwendet starke Magnetfelder, um Wasserstoffkerne (Protonen) auszurichten, die dann durch Hochfrequenzimpulse gestört werden. Bei der Relaxation senden sie Signale aus, die zur Bilderzeugung verwendet werden. T1 (Fett hell) und T2 (Flüssigkeit hell) sind Relaxationsparameter. Keine ionisierende Strahlung.","fr":"L'IRM utilise des champs magnétiques puissants pour aligner les noyaux d'hydrogène (protons), qui sont ensuite perturbés par des impulsions radiofréquence. Lors de leur relaxation, ils émettent des signaux utilisés pour construire des images. T1 (graisse brillante) et T2 (liquide brillant) sont des paramètres de relaxation. Pas de rayonnement ionisant.","tr":"MRI, güçlü manyetik alanlar kullanarak hidrojen çekirdeklerini (protonları) hizalar, ardından radyofrekans darbeleriyle bozulurlar. Geri gevşerken görüntü oluşturmak için kullanılan sinyaller yayarlar. T1 (yağ parlak) ve T2 (sıvı parlak) gevşeme parametreleridir. İyonlaştırıcı radyasyon yoktur.","nl":"MRI gebruikt krachtige magneetvelden om waterstofkernen (protonen) uit te lijnen, die vervolgens verstoord worden door radiofrequentiepulsen. Tijdens relaxatie zenden ze signalen uit die gebruikt worden om beelden te construeren. T1 (vet helder) en T2 (vloeistof helder) zijn relaxatieparameters. Geen ioniserende straling.","ru":"MRI использует мощные магнитные поля для выравнивания ядер водорода (протонов), которые затем возмущаются радиочастотными импульсами. При релаксации они испускают сигналы для построения изображений. T1 (жир яркий) и T2 (жидкость яркая) — параметры релаксации. Без ионизирующего излучения.","zh":"MRI使用强磁场使氢原子核（质子）排列，然后用射频脉冲扰动它们。当它们弛豫回来时发出信号用于构建图像。T1（脂肪亮）和T2（液体亮）是弛豫参数。无电离辐射。","pt_BR":"A MRI usa campos magnéticos potentes para alinhar núcleos de hidrogênio (prótons), que são então perturbados por pulsos de radiofrequência. Ao relaxarem, emitem sinais usados para construir imagens. T1 (gordura brilhante) e T2 (líquido brilhante) são parâmetros de relaxação. Sem radiação ionizante.","pt_PT":"A MRI usa campos magnéticos potentes para alinhar núcleos de hidrogénio (protões), que são então perturbados por pulsos de radiofrequência. Ao relaxarem, emitem sinais usados para construir imagens. T1 (gordura brilhante) e T2 (líquido brilhante) são parâmetros de relaxação. Sem radiação ionizante."}},
  { id: 'dc-mcat-0176', deck_id: 'deck-mcat', sort_order: 176, front: "Surface Tension and Lung Compliance", back: "Surface tension of alveolar fluid tends to collapse alveoli. Surfactant (dipalmitoylphosphatidylcholine, produced by type II pneumocytes) reduces surface tension, increasing lung compliance and preventing alveolar collapse. Deficient in premature infants (NRDS)." , front_translations: {"es":"Tensão Superficial y Complacencia Pulmonar","de":"Oberflächenspannung und Lungencompliance","fr":"Tension de surface et compliance pulmonaire","tr":"Yüzey Gerilimi ve Akciğer Kompliansı","nl":"Oppervlaktespanning en longcompliantie","ru":"Поверхностное натяжение и податливость лёгких","zh":"表面张力与肺顺应性","pt_BR":"Tensão Superficial e Complacência Pulmonar","pt_PT":"Tensão Superficial e Complacência Pulmonar"}, back_translations: {"es":"La tensão superficial del líquido alveolar tende a colapsar los alvéolos. El surfactante (dipalmitoilfosfatidilcolina, producido por pneumócitos tipo II) reduce a tensão superficial, aumenta a complacencia pulmonar y previene el colapso alveolar. Deficiente en prematuros (NRDS).","de":"Die Oberflächenspannung der Alveolarflüssigkeit neigt dazu, die Alveolen kollabieren zu lassen. Surfactant (Dipalmitoylphosphatidylcholin, produziert von Typ-II-Pneumozyten) reduziert die Oberflächenspannung, erhöht die Lungencompliance und verhindert den Alveolarkollaps. Fehlt bei Frühgeborenen (NRDS).","fr":"La tension de surface du liquide alvéolaire tend à faire collaber les alvéoles. Le surfactant (dipalmitoylphosphatidylcholine, produit par les pneumocytes de type II) réduit la tension de surface, augmente la compliance pulmonaire et empêche le collapsus alvéolaire. Déficient chez les prématurés (NRDS).","tr":"Alveolar sıvının yüzey gerilimi alveolleri çökertme eğilimindedir. Sürfaktan (dipalmitoilfosfatidilkolin, tip II pnömositler tarafından üretilir) yüzey gerilimini azaltır, akciğer kompliansını artırır ve alveolar çökmeyi önler. Prematüre bebeklerde eksiktir (NRDS).","nl":"Oppervlaktespanning van alveolair vocht neigt ertoe alveoli te laten collaberen. Surfactant (dipalmitoylfosfatidylcholine, geproduceerd door type II-pneumocyten) vermindert de oppervlaktespanning, verhoogt de longcompliantie en voorkomt alveolaire collaps. Deficiënt bij premature zuigelingen (NRDS).","ru":"Поверхностное натяжение альвеолярной жидкости стремится коллапсировать альвеолы. Сурфактант (дипальмитоилфосфатидилхолин, вырабатывается пневмоцитами II типа) снижает поверхностное натяжение, увеличивает податливость лёгких и предотвращает коллапс альвеол. Дефицитен у недоношенных (NRDS).","zh":"肺泡液的表面张力倾向于使肺泡塌陷。表面活性物质（二棕榈酰磷脂酰胆碱，由II型肺泡细胞产生）降低表面张力，增加肺顺应性并防止肺泡塌陷。早产儿缺乏（NRDS）。","pt_BR":"A tensão superficial do líquido alveolar tende a colapsar os alvéolos. O surfactante (dipalmitoilfosfatidilcolina, produzido por pneumócitos tipo II) reduz a tensão superficial, aumenta a complacência pulmonar e previne o colapso alveolar. Deficiente em prematuros (NRDS).","pt_PT":"A tensão superficial do líquido alveolar tende a colapsar os alvéolos. O surfactante (dipalmitoilfosfatidilcolina, produzido por pneumócitos tipo II) reduz a tensão superficial, aumenta a complacência pulmonar e previne o colapso alveolar. Deficiente em prematuros (NRDS)."}},
  { id: 'dc-mcat-0177', deck_id: 'deck-mcat', sort_order: 177, front: "Laplace's Law (Pressure-Volume)", back: "P = 2T/r (sphere). The pressure required to keep a sphere inflated is inversely proportional to its radius. Small alveoli (r) would tend to collapse into larger ones unless surfactant reduces T disproportionately in smaller alveoli." , front_translations: {"es":"Ley de Laplace (Presión-Volume)","de":"Laplace-Gesetz (Druck-Volumen)","fr":"Loi de Laplace (Pression-Volume)","tr":"Laplace Yasası (Basınç-Hacim)","nl":"Wet van Laplace (Druk-Volume)","ru":"Закон Лапласа (давление-объём)","zh":"拉普拉斯定律（压力-容积）","pt_BR":"Lei de Laplace (Pressão-Volume)","pt_PT":"Lei de Laplace (Pressão-Volume)"}, back_translations: {"es":"P = 2T/r (esfera). La presión necesaria para mantener una esfera inflada es inversamente proporcional al su raio. Alvéolos pequeños (r) tenderiam a colapsar en los mayores, a menos que el surfactante reduza T desproporcionalmente en los alvéolos menores.","de":"P = 2T/r (Kugel). Der Druck, der nötig ist, um eine Kugel aufgeblasen zu halten, ist umgekehrt proportional zu ihrem Radius. Kleine Alveolen (r) würden ohne Surfactant, das T in kleineren Alveolen überproportional reduziert, in größere kollabieren.","fr":"P = 2T/r (sphère). La pression nécessaire pour maintenir une sphère gonflée est inversement proportionnelle à son rayon. Les petites alvéoles (r) auraient tendance à se collaber dans les plus grandes, sauf si le surfactant réduit T de façon disproportionnée dans les petites alvéoles.","tr":"P = 2T/r (küre). Bir küreyi şişik tutmak için gereken basınç yarıçapıyla ters orantılıdır. Küçük alveoller (r), sürfaktan küçük alveollerde T'yi orantısız şekilde azaltmazsa büyük alveollere çökme eğiliminde olurdu.","nl":"P = 2T/r (bol). De druk die nodig is om een bol opgeblazen te houden, is omgekeerd evenredig met de straal. Kleine alveoli (r) zouden neigen te collaberen in grotere, tenzij surfactant T onevenredig vermindert in kleinere alveoli.","ru":"P = 2T/r (сфера). Давление, необходимое для поддержания сферы в раздутом состоянии, обратно пропорционально её радиусу. Малые альвеолы (r) коллапсировали бы в более крупные, если бы сурфактант не снижал T непропорционально в малых альвеолах.","zh":"P = 2T/r（球体）。维持球体膨胀所需的压力与其半径成反比。小肺泡（r）会倾向于塌陷入大肺泡，除非表面活性物质在较小肺泡中不成比例地降低T。","pt_BR":"P = 2T/r (esfera). A pressão necessária para manter uma esfera inflada é inversamente proporcional ao seu raio. Alvéolos pequenos (r) tenderiam a colapsar nos maiores, a menos que o surfactante reduza T desproporcionalmente nos alvéolos menores.","pt_PT":"P = 2T/r (esfera). A pressão necessária para manter uma esfera insuflada é inversamente proporcional ao seu raio. Os alvéolos pequenos (r) tenderiam a colapsar nos maiores, a menos que o surfactante reduza T desproporcionalmente nos alvéolos menores."}},
  { id: 'dc-mcat-0178', deck_id: 'deck-mcat', sort_order: 178, front: "Electrophoresis: SDS-PAGE", back: "Proteins denatured with SDS (gives uniform negative charge proportional to size) then separated by size through polyacrylamide gel in an electric field. Smaller proteins migrate faster. Followed by Western blot or Coomassie staining." , front_translations: {"es":"Eletroforese: SDS-PAGE","de":"Elektrophorese: SDS-PAGE","fr":"Électrophorèse : SDS-PAGE","tr":"Elektroforez: SDS-PAGE","nl":"Elektroforese: SDS-PAGE","ru":"Электрофорез: SDS-PAGE","zh":"电泳：SDS-PAGE","pt_BR":"Eletroforese: SDS-PAGE","pt_PT":"Eletroforese: SDS-PAGE"}, back_translations: {"es":"Proteínas desnaturadas con SDS (confere carga negativa uniforme proporcional al tamaño) son separadas por tamaño a través de gel de poliacrilamida en campo eléctrico. Proteínas menores migram más rápido. Seguido por Western blot o coloración con Coomassie.","de":"Proteine werden mit SDS denaturiert (verleiht einheitliche negative Ladung proportional zur Größe) und dann nach Größe durch Polyacrylamidgel im elektrischen Feld getrennt. Kleinere Proteine wandern schneller. Gefolgt von Western Blot oder Coomassie-Färbung.","fr":"Les protéines dénaturées avec du SDS (charge négative uniforme proportionnelle à la taille) sont séparées par taille à travers un gel de polyacrylamide dans un champ électrique. Les petites protéines migrent plus vite. Suivi d'un Western blot ou d'une coloration au bleu de Coomassie.","tr":"Proteinler SDS ile denatüre edilir (boyuta orantılı tekdüze negatif yük verir) ve ardından elektrik alanında poliakrilamid jel içinden boyuta göre ayrılır. Küçük proteinler daha hızlı göç eder. Western blot veya Coomassie boyama ile takip edilir.","nl":"Eiwitten gedenatureerd met SDS (geeft uniforme negatieve lading evenredig met grootte) worden vervolgens op grootte gescheiden door polyacrylamidegel in een elektrisch veld. Kleinere eiwitten migreren sneller. Gevolgd door Western blot of Coomassie-kleuring.","ru":"Белки денатурируют с помощью SDS (придаёт равномерный отрицательный заряд пропорционально размеру), затем разделяют по размеру в полиакриламидном геле в электрическом поле. Меньшие белки мигрируют быстрее. Далее — вестерн-блот или окрашивание Кумасси.","zh":"蛋白质用SDS变性（赋予与大小成比例的均匀负电荷），然后在电场中通过聚丙烯酰胺凝胶按大小分离。较小的蛋白质迁移更快。随后进行Western blot或考马斯亮蓝染色。","pt_BR":"Proteínas desnaturadas com SDS (confere carga negativa uniforme proporcional ao tamanho) são separadas por tamanho através de gel de poliacrilamida em campo elétrico. Proteínas menores migram mais rápido. Seguido por Western blot ou coloração com Coomassie.","pt_PT":"Proteínas desnaturadas com SDS (confere carga negativa uniforme proporcional ao tamanho) são separadas por tamanho através de gel de poliacrilamida em campo elétrico. Proteínas menores migram mais rápido. Seguido por Western blot ou coloração com Coomassie."}},
  { id: 'dc-mcat-0179', deck_id: 'deck-mcat', sort_order: 179, front: "Thin Layer Chromatography (TLC)", back: "Separates compounds by polarity on a silica-coated plate. Mobile phase (solvent) travels up by capillary action. Rf = distance moved by compound / distance moved by solvent front. Polar compounds have low Rf on normal-phase silica." , front_translations: {"es":"Cromatografia en Camada Delgada (TLC)","de":"Dünnschichtchromatographie (TLC)","fr":"Chromatographie sur couche mince (CCM)","tr":"İnce Tabaka Kromatografisi (TLC)","nl":"Dunnelaagchromatografie (TLC)","ru":"Тонкослойная хроматография (TLC)","zh":"薄层色谱法（TLC）","pt_BR":"Cromatografia em Camada Delgada (TLC)","pt_PT":"Cromatografia em Camada Fina (TLC)"}, back_translations: {"es":"Separa compuestos por polaridad en una placa revestida de sílica. La fase móvel (disolvente) sobe por acción capilar. Rf = distancia percorrida por el compuesto / distancia percorrida por la frente del disolvente. Compostos polares tienen Rf bajo en sílica de fase normal.","de":"Trennt Verbindungen nach Polarität auf einer mit Kieselgel beschichteten Platte. Die mobile Phase (Lösungsmittel) steigt durch Kapillarwirkung auf. Rf = Wanderungsstrecke der Verbindung / Wanderungsstrecke der Lösungsmittelfront. Polare Verbindungen haben niedrige Rf-Werte auf Normalphasen-Kieselgel.","fr":"Sépare les composés par polarité sur une plaque recouverte de silice. La phase mobile (solvant) monte par capillarité. Rf = distance parcourue par le composé / distance parcourue par le front de solvant. Les composés polaires ont un Rf faible en phase normale sur silice.","tr":"Bileşikleri silika kaplı bir plaka üzerinde polariteye göre ayırır. Mobil faz (çözücü) kapiler etkiyle yükselir. Rf = bileşiğin aldığı mesafe / çözücü cephesinin aldığı mesafe. Polar bileşikler normal fazlı silikada düşük Rf değerine sahiptir.","nl":"Scheidt verbindingen op polariteit op een met silica gecoate plaat. De mobiele fase (oplosmiddel) stijgt door capillaire werking. Rf = afgelegde afstand door verbinding / afgelegde afstand door oplosmiddelfront. Polaire verbindingen hebben een lage Rf op normale-fase silica.","ru":"Разделяет соединения по полярности на пластине, покрытой силикагелем. Подвижная фаза (растворитель) поднимается за счёт капиллярного эффекта. Rf = расстояние, пройденное соединением / расстояние, пройденное фронтом растворителя. Полярные соединения имеют низкий Rf на нормально-фазном силикагеле.","zh":"在硅胶涂层板上按极性分离化合物。流动相（溶剂）通过毛细作用上升。Rf = 化合物移动距离 / 溶剂前沿移动距离。极性化合物在正相硅胶上Rf值低。","pt_BR":"Separa compostos por polaridade em uma placa revestida de sílica. A fase móvel (solvente) sobe por ação capilar. Rf = distância percorrida pelo composto / distância percorrida pela frente do solvente. Compostos polares têm Rf baixo em sílica de fase normal.","pt_PT":"Separa compostos por polaridade numa placa revestida de sílica. A fase móvel (solvente) sobe por ação capilar. Rf = distância percorrida pelo composto / distância percorrida pela frente do solvente. Compostos polares têm Rf baixo em sílica de fase normal."}},
  { id: 'dc-mcat-0180', deck_id: 'deck-mcat', sort_order: 180, front: "Isoelectric Focusing", back: "Electrophoretic technique separating proteins by their isoelectric point (pI) in a pH gradient. Proteins migrate until they reach the pH equal to their pI and stop (net charge = 0). Used to identify protein isoforms and in proteomics." , front_translations: {"es":"Focalización Isoelétrica","de":"Isoelektrische Fokussierung","fr":"Focalisation isoélectrique","tr":"İzoelektrik Odaklama","nl":"Iso-elektrische focussering","ru":"Изоэлектрическое фокусирование","zh":"等电聚焦","pt_BR":"Focalização Isoelétrica","pt_PT":"Focagem Isoelétrica"}, back_translations: {"es":"Técnica eletroforética que separa proteínas por el su punto isoelétrico (pI) en un gradiente de pH. As proteínas migram hasta atingir el pH igual al su pI y param (carga líquida = 0). Usada para identificar isoformas proteicas y en proteomica.","de":"Elektrophoretische Technik, die Proteine nach ihrem isoelektrischen Punkt (pI) in einem pH-Gradienten trennt. Proteine wandern, bis sie den pH erreichen, der ihrem pI entspricht, und stoppen (Nettoladung = 0). Wird zur Identifizierung von Proteinisoformen und in der Proteomik verwendet.","fr":"Technique électrophorétique séparant les protéines selon leur point isoélectrique (pI) dans un gradient de pH. Les protéines migrent jusqu'à atteindre le pH égal à leur pI et s'arrêtent (charge nette = 0). Utilisée pour identifier les isoformes protéiques et en protéomique.","tr":"Proteinleri pH gradyanında izoelektrik noktalarına (pI) göre ayıran elektroforetik teknik. Proteinler pI'lerine eşit pH'ye ulaşana kadar göç eder ve durur (net yük = 0). Protein izoformlarını tanımlamak ve proteomikte kullanılır.","nl":"Elektroforetische techniek die eiwitten scheidt op hun iso-elektrisch punt (pI) in een pH-gradiënt. Eiwitten migreren tot ze de pH bereiken die gelijk is aan hun pI en stoppen (nettolading = 0). Gebruikt om eiwitisovormen te identificeren en in proteomics.","ru":"Электрофоретический метод разделения белков по их изоэлектрической точке (pI) в градиенте pH. Белки мигрируют до pH, равного их pI, и останавливаются (суммарный заряд = 0). Используется для идентификации изоформ белков и в протеомике.","zh":"在pH梯度中按等电点（pI）分离蛋白质的电泳技术。蛋白质迁移至pH等于其pI处停止（净电荷 = 0）。用于鉴定蛋白质异构体和蛋白质组学研究。","pt_BR":"Técnica eletroforética que separa proteínas pelo seu ponto isoelétrico (pI) em um gradiente de pH. As proteínas migram até atingir o pH igual ao seu pI e param (carga líquida = 0). Usada para identificar isoformas proteicas e em proteômica.","pt_PT":"Técnica eletroforética que separa proteínas pelo seu ponto isoelétrico (pI) num gradiente de pH. As proteínas migram até atingir o pH igual ao seu pI e param (carga líquida = 0). Usada para identificar isoformas proteicas e em proteómica."}},
  { id: 'dc-mcat-0181', deck_id: 'deck-mcat', sort_order: 181, front: "Cystic Fibrosis Pathophysiology", back: "Autosomal recessive mutation in CFTR gene (most common: ΔF508). CFTR is a Cl⁻ channel; dysfunction → thick, sticky mucus in lungs and digestive tract. Features: chronic respiratory infections, pancreatic insufficiency, infertility (males). Sweat chloride test >60 mEq/L is diagnostic." , front_translations: {"es":"Fibrose Cística – Fisiopatologia","de":"Mukoviszidose – Pathophysiologie","fr":"Mucoviscidose – Physiopathologie","tr":"Kistik Fibrozis Patofizyolojisi","nl":"Cystische fibrose – Pathofysiologie","ru":"Муковисцидоз — патофизиология","zh":"囊性纤维化病理生理学","pt_BR":"Fibrose Cística – Fisiopatologia","pt_PT":"Fibrose Quística – Fisiopatologia"}, back_translations: {"es":"Mutación autossomica recessiva en el gen CFTR (más comum: ΔF508). CFTR es un canal de Cl⁻; disfunción → muco espesso y pegajoso en los pulmones y trato digestivo. Características: infecciones respiratórias cronicas, insuficiencia pancreática, infertilidad (hombres). Teste de cloreto en el suor >60 mEq/L es diagnóstico.","de":"Autosomal-rezessive Mutation im CFTR-Gen (häufigste: ΔF508). CFTR ist ein Cl⁻-Kanal; Dysfunktion → dicker, klebriger Schleim in Lunge und Verdauungstrakt. Merkmale: chronische Atemwegsinfektionen, Pankreasinsuffizienz, Infertilität (Männer). Schweißchloridtest >60 mEq/L ist diagnostisch.","fr":"Mutation autosomique récessive du gène CFTR (la plus fréquente : ΔF508). CFTR est un canal Cl⁻ ; dysfonction → mucus épais et collant dans les poumons et le tube digestif. Caractéristiques : infections respiratoires chroniques, insuffisance pancréatique, infertilité (hommes). Test de chlorure sudoral >60 mEq/L est diagnostique.","tr":"CFTR geninde otozomal resesif mutasyon (en yaygın: ΔF508). CFTR bir Cl⁻ kanalıdır; disfonksiyon → akciğerlerde ve sindirim sisteminde kalın, yapışkan mukus. Bulgular: kronik solunum yolu enfeksiyonları, pankreas yetmezliği, infertilite (erkekler). Ter klorür testi >60 mEq/L tanısaldır.","nl":"Autosomaal recessieve mutatie in het CFTR-gen (meest voorkomend: ΔF508). CFTR is een Cl⁻-kanaal; disfunctie → dik, kleverig slijm in longen en spijsverteringskanaal. Kenmerken: chronische luchtweginfecties, pancreasinsufficiëntie, infertiliteit (mannen). Zweetchloridetest >60 mEq/L is diagnostisch.","ru":"Аутосомно-рецессивная мутация гена CFTR (наиболее частая: ΔF508). CFTR — канал Cl⁻; дисфункция → густая, вязкая слизь в лёгких и пищеварительном тракте. Проявления: хронические респираторные инфекции, панкреатическая недостаточность, бесплодие (мужчины). Хлорид пота >60 мЭкв/л — диагностический критерий.","zh":"CFTR基因的常染色体隐性突变（最常见：ΔF508）。CFTR是Cl⁻通道；功能障碍 → 肺和消化道中的粘稠黏液。特征：慢性呼吸道感染、胰腺功能不全、不育（男性）。汗液氯化物测试 >60 mEq/L可诊断。","pt_BR":"Mutação autossômica recessiva no gene CFTR (mais comum: ΔF508). CFTR é um canal de Cl⁻; disfunção → muco espesso e pegajoso nos pulmões e trato digestivo. Características: infecções respiratórias crônicas, insuficiência pancreática, infertilidade (homens). Teste de cloreto no suor >60 mEq/L é diagnóstico.","pt_PT":"Mutação autossómica recessiva no gene CFTR (mais comum: ΔF508). CFTR é um canal de Cl⁻; disfunção → muco espesso e pegajoso nos pulmões e trato digestivo. Características: infeções respiratórias crónicas, insuficiência pancreática, infertilidade (homens). Teste de cloreto no suor >60 mEq/L é diagnóstico."}},
  { id: 'dc-mcat-0182', deck_id: 'deck-mcat', sort_order: 182, front: "Huntington's Disease", back: "Autosomal dominant neurodegenerative disease caused by CAG trinucleotide repeat expansion in HTT gene (>36 repeats) → toxic polyglutamine huntingtin protein. Loss of GABAergic neurons in the striatum. Chorea, dementia, psychiatric symptoms. Onset typically 30–50 years." , front_translations: {"es":"Doença de Huntington","de":"Chorea Huntington","fr":"Maladie de Huntington","tr":"Huntington Hastalığı","nl":"Ziekte van Huntington","ru":"Болезнь Хантингтона","zh":"亨廷顿病","pt_BR":"Doença de Huntington","pt_PT":"Doença de Huntington"}, back_translations: {"es":"Doença neurodegenerativa autossomica dominante causada por expansão de repeticiones trinucleotídicas CAG en el gen HTT (>36 repeticiones) → proteína huntingtina poliglutamina tóxica. Perda de neuronas GABAérgicos en el estriado. Coreia, demencia, síntomas psiquiátricos. Início típicamente 30–50 anos.","de":"Autosomal-dominante neurodegenerative Erkrankung durch CAG-Trinukleotid-Repeat-Expansion im HTT-Gen (>36 Repeats) → toxisches Polyglutamin-Huntingtin-Protein. Verlust GABAerger Neuronen im Striatum. Chorea, Demenz, psychiatrische Symptome. Beginn typischerweise 30–50 Jahre.","fr":"Maladie neurodégénérative autosomique dominante causée par l'expansion de répétitions trinucléotidiques CAG dans le gène HTT (>36 répétitions) → protéine huntingtine polyglutamine toxique. Perte de neurones GABAergiques dans le striatum. Chorée, démence, symptômes psychiatriques. Début typiquement 30–50 ans.","tr":"HTT genindeki CAG trinükleotid tekrar genişlemesinin (>36 tekrar) neden olduğu otozomal dominant nörodejeneratif hastalık → toksik poliglutamin huntingtin proteini. Striatumda GABAerjik nöron kaybı. Kore, demans, psikiyatrik semptomlar. Başlangıç tipik olarak 30–50 yaş.","nl":"Autosomaal dominante neurodegeneratieve ziekte veroorzaakt door CAG-trinucleotide-repeat-expansie in het HTT-gen (>36 herhalingen) → toxisch polyglutamine-huntingtine-eiwit. Verlies van GABAerge neuronen in het striatum. Chorea, dementie, psychiatrische symptomen. Begin typisch 30–50 jaar.","ru":"Аутосомно-доминантное нейродегенеративное заболевание, вызванное экспансией тринуклеотидных повторов CAG в гене HTT (>36 повторов) → токсичный полиглутаминовый белок хантингтин. Потеря ГАМКергических нейронов в стриатуме. Хорея, деменция, психиатрические симптомы. Начало обычно в 30–50 лет.","zh":"由HTT基因中CAG三核苷酸重复扩增（>36次重复）引起的常染色体显性神经退行性疾病 → 有毒的多聚谷氨酰胺亨廷顿蛋白。纹状体GABA能神经元丧失。舞蹈症、痴呆、精神症状。通常30-50岁发病。","pt_BR":"Doença neurodegenerativa autossômica dominante causada por expansão de repetições trinucleotídicas CAG no gene HTT (>36 repetições) → proteína huntingtina poliglutamina tóxica. Perda de neurônios GABAérgicos no estriado. Coreia, demência, sintomas psiquiátricos. Início tipicamente 30–50 anos.","pt_PT":"Doença neurodegenerativa autossómica dominante causada por expansão de repetições trinucleotídicas CAG no gene HTT (>36 repetições) → proteína huntingtina poliglutamina tóxica. Perda de neurónios GABAérgicos no estriado. Coreia, demência, sintomas psiquiátricos. Início tipicamente 30–50 anos."}},
  { id: 'dc-mcat-0183', deck_id: 'deck-mcat', sort_order: 183, front: "Phenylketonuria (PKU)", back: "Autosomal recessive deficiency of phenylalanine hydroxylase (PAH) → phenylalanine accumulates → converted to phenylketones (neurotoxic). Presents with intellectual disability, seizures, musty odor. Detected on newborn screening; treated with low-phenylalanine diet." , front_translations: {"es":"Fenilcetonúria (PKU)","de":"Phenylketonurie (PKU)","fr":"Phénylcétonurie (PKU)","tr":"Fenilketonüri (PKU)","nl":"Fenylketonurie (PKU)","ru":"Фенилкетонурия (PKU)","zh":"苯丙酮尿症（PKU）","pt_BR":"Fenilcetonúria (PKU)","pt_PT":"Fenilcetonúria (PKU)"}, back_translations: {"es":"Deficiencia autossomica recessiva de fenilalanina hidroxilase (PAH) → fenilalanina acumula → convertida en fenilcetonas (neurotóxicas). Se presenta con deficiencia intelectual, convulsões, odor de mofo. Detectada en la triaje neonatal; tratada con dieta pobre en fenilalanina.","de":"Autosomal-rezessiver Mangel an Phenylalaninhydroxylase (PAH) → Phenylalanin akkumuliert → wird zu Phenylketonen umgewandelt (neurotoxisch). Zeigt sich durch geistige Behinderung, Krampfanfälle, muffigen Geruch. Wird im Neugeborenenscreening erkannt; Behandlung mit phenylalaninarmer Diät.","fr":"Déficit autosomique récessif en phénylalanine hydroxylase (PAH) → accumulation de phénylalanine → convertie en phénylcétones (neurotoxiques). Se manifeste par un retard intellectuel, des convulsions, une odeur de moisi. Détectée au dépistage néonatal ; traitée par régime pauvre en phénylalanine.","tr":"Fenilalanin hidroksilaz (PAH) otozomal resesif eksikliği → fenilalanin birikir → fenilketonlara dönüşür (nörotoksik). Zihinsel engellilik, nöbetler, küf kokusu ile kendini gösterir. Yenidoğan taramasında saptanır; düşük fenilalaninli diyetle tedavi edilir.","nl":"Autosomaal recessieve deficiëntie van fenylalaninehydroxylase (PAH) → fenylalanine hoopt op → omgezet in fenylketonen (neurotoxisch). Presenteert zich met verstandelijke beperking, epileptische aanvallen, muffige geur. Gedetecteerd bij neonatale screening; behandeld met fenylalaninearm dieet.","ru":"Аутосомно-рецессивный дефицит фенилаланингидроксилазы (PAH) → накопление фенилаланина → превращается в фенилкетоны (нейротоксичные). Проявляется умственной отсталостью, судорогами, затхлым запахом. Выявляется при неонатальном скрининге; лечение — диета с низким содержанием фенилаланина.","zh":"苯丙氨酸羟化酶（PAH）的常染色体隐性缺乏 → 苯丙氨酸积累 → 转化为苯丙酮（具有神经毒性）。表现为智力障碍、癫痫发作、霉味。通过新生儿筛查发现；以低苯丙氨酸饮食治疗。","pt_BR":"Deficiência autossômica recessiva de fenilalanina hidroxilase (PAH) → fenilalanina acumula → convertida em fenilcetonas (neurotóxicas). Apresenta-se com deficiência intelectual, convulsões, odor de mofo. Detectada na triagem neonatal; tratada com dieta pobre em fenilalanina.","pt_PT":"Deficiência autossómica recessiva de fenilalanina hidroxilase (PAH) → fenilalanina acumula → convertida em fenilcetonas (neurotóxicas). Apresenta-se com deficiência intelectual, convulsões, odor a bolor. Detetada no rastreio neonatal; tratada com dieta pobre em fenilalanina."}},
  { id: 'dc-mcat-0184', deck_id: 'deck-mcat', sort_order: 184, front: "Lysosomal Storage Diseases", back: "Caused by deficiencies in lysosomal hydrolases → accumulation of substrates. Examples: Gaucher's (glucocerebrosidase; most common), Tay-Sachs (hexosaminidase A; cherry-red spot), Niemann-Pick (sphingomyelinase), Hurler syndrome (α-L-iduronidase)." , front_translations: {"es":"Doenças de Armazenamento Lisossomico","de":"Lysosomale Speicherkrankheiten","fr":"Maladies lysosomales de surcharge","tr":"Lizozomal Depo Hastalıkları","nl":"Lysosomale stapelingsziekten","ru":"Лизосомные болезни накопления","zh":"溶酶体贮积症","pt_BR":"Doenças de Armazenamento Lisossômico","pt_PT":"Doenças de Armazenamento Lisossómico"}, back_translations: {"es":"Causadas por deficiencias de hidrolases lisossomicas → acúmulo de substratos. Exemplos: Gaucher (glicocerebrosidase; más comum), Tay-Sachs (hexosaminidase A; mancha rojo-cereja), Niemann-Pick (esfingomielinase), síndrome de Hurler (α-L-iduronidase).","de":"Verursacht durch Defizite lysosomaler Hydrolasen → Substratakkumulation. Beispiele: Gaucher (Glukozerebrosidase; häufigste), Tay-Sachs (Hexosaminidase A; kirschroter Fleck), Niemann-Pick (Sphingomyelinase), Hurler-Syndrom (α-L-Iduronidase).","fr":"Causées par des déficits en hydrolases lysosomales → accumulation de substrats. Exemples : Gaucher (glucocérébrosidase ; la plus fréquente), Tay-Sachs (hexosaminidase A ; tache rouge cerise), Niemann-Pick (sphingomyélinase), syndrome de Hurler (α-L-iduronidase).","tr":"Lizozomal hidrolaz eksikliklerinden kaynaklanır → substrat birikimi. Örnekler: Gaucher (glukoserebrosidaz; en yaygın), Tay-Sachs (heksozaminidaz A; kiraz kırmızısı leke), Niemann-Pick (sfingomiyelinaz), Hurler sendromu (α-L-iduronidaz).","nl":"Veroorzaakt door deficiënties in lysosomale hydrolasen → ophoping van substraten. Voorbeelden: Gaucher (glucocerebrosidase; meest voorkomend), Tay-Sachs (hexosaminidase A; kersenrode vlek), Niemann-Pick (sfingomyelinase), syndroom van Hurler (α-L-iduronidase).","ru":"Вызваны дефицитом лизосомных гидролаз → накопление субстратов. Примеры: болезнь Гоше (глюкоцереброзидаза; самая частая), Тея-Сакса (гексозаминидаза А; вишнёво-красное пятно), Ниманна-Пика (сфингомиелиназа), синдром Гурлер (α-L-идуронидаза).","zh":"由溶酶体水解酶缺乏引起 → 底物积累。例如：戈谢病（葡萄糖脑苷脂酶；最常见）、Tay-Sachs病（己糖胺酶A；樱桃红斑）、尼曼-匹克病（鞘磷脂酶）、Hurler综合征（α-L-艾杜糖醛酸酶）。","pt_BR":"Causadas por deficiências de hidrolases lisossômicas → acúmulo de substratos. Exemplos: Gaucher (glicocerebrosidase; mais comum), Tay-Sachs (hexosaminidase A; mancha vermelho-cereja), Niemann-Pick (esfingomielinase), síndrome de Hurler (α-L-iduronidase).","pt_PT":"Causadas por deficiências de hidrolases lisossómicas → acumulação de substratos. Exemplos: Gaucher (glicocerebrosidase; mais comum), Tay-Sachs (hexosaminidase A; mancha vermelho-cereja), Niemann-Pick (esfingomielinase), síndrome de Hurler (α-L-iduronidase)."}},
  { id: 'dc-mcat-0185', deck_id: 'deck-mcat', sort_order: 185, front: "Insulin Signaling Pathway", back: "Insulin binds RTK (insulin receptor) → autophosphorylation of tyrosine residues → IRS-1 phosphorylation → PI3K activation → Akt phosphorylation → GLUT4 translocation to membrane (↑ glucose uptake), glycogen synthesis, protein synthesis, and anti-apoptosis." , front_translations: {"es":"Via de Sinalización de la Insulina","de":"Insulin-Signalweg","fr":"Voie de signalisation de l'insuline","tr":"İnsülin Sinyal Yolağı","nl":"Insulinesignaleringsroute","ru":"Сигнальный путь инсулина","zh":"胰岛素信号通路","pt_BR":"Via de Sinalização da Insulina","pt_PT":"Via de Sinalização da Insulina"}, back_translations: {"es":"La insulina liga-se al RTK (receptor de insulina) → autofosforilación de resíduos de tirosina → fosforilación de IRS-1 → ativación de PI3K → fosforilación de Akt → translocación de GLUT4 para a membrana (↑ captación de glicose), síntese de glicogenio, síntese proteica y anti-apoptose.","de":"Insulin bindet an RTK (Insulinrezeptor) → Autophosphorylierung von Tyrosinresten → IRS-1-Phosphorylierung → PI3K-Aktivierung → Akt-Phosphorylierung → GLUT4-Translokation zur Membran (↑ Glukoseaufnahme), Glykogensynthese, Proteinsynthese und Anti-Apoptose.","fr":"L'insuline se lie au RTK (récepteur de l'insuline) → autophosphorylation des résidus tyrosine → phosphorylation d'IRS-1 → activation de PI3K → phosphorylation d'Akt → translocation de GLUT4 à la membrane (↑ captation du glucose), synthèse du glycogène, synthèse protéique et anti-apoptose.","tr":"İnsülin RTK'ya (insülin reseptörü) bağlanır → tirozin kalıntılarının otofosforilasyonu → IRS-1 fosforilasyonu → PI3K aktivasyonu → Akt fosforilasyonu → GLUT4'ün membrana translokasyonu (↑ glukoz alımı), glikojen sentezi, protein sentezi ve anti-apoptoz.","nl":"Insuline bindt aan RTK (insulinereceptor) → autofosforylering van tyrosineresiduen → IRS-1-fosforylering → PI3K-activering → Akt-fosforylering → GLUT4-translocatie naar membraan (↑ glucoseopname), glycogeensynthese, eiwitsynthese en anti-apoptose.","ru":"Инсулин связывается с RTK (рецептор инсулина) → аутофосфорилирование тирозиновых остатков → фосфорилирование IRS-1 → активация PI3K → фосфорилирование Akt → транслокация GLUT4 к мембране (↑ поглощение глюкозы), синтез гликогена, синтез белка и антиапоптоз.","zh":"胰岛素与RTK（胰岛素受体）结合 → 酪氨酸残基自磷酸化 → IRS-1磷酸化 → PI3K激活 → Akt磷酸化 → GLUT4转位至细胞膜（↑葡萄糖摄取）、糖原合成、蛋白质合成和抗凋亡。","pt_BR":"A insulina liga-se ao RTK (receptor de insulina) → autofosforilação de resíduos de tirosina → fosforilação de IRS-1 → ativação de PI3K → fosforilação de Akt → translocação de GLUT4 para a membrana (↑ captação de glicose), síntese de glicogênio, síntese proteica e anti-apoptose.","pt_PT":"A insulina liga-se ao RTK (recetor de insulina) → autofosforilação de resíduos de tirosina → fosforilação de IRS-1 → ativação de PI3K → fosforilação de Akt → translocação de GLUT4 para a membrana (↑ captação de glicose), síntese de glicogénio, síntese proteica e anti-apoptose."}},
  { id: 'dc-mcat-0186', deck_id: 'deck-mcat', sort_order: 186, front: "Notch Signaling", back: "A cell-cell contact signaling pathway. Ligand (Delta/Jagged) on one cell binds Notch receptor on adjacent cell → γ-secretase cleaves Notch intracellular domain (NICD) → NICD enters nucleus → activates target genes. Critical in cell fate determination and development." , front_translations: {"es":"Sinalización Notch","de":"Notch-Signalweg","fr":"Voie de signalisation Notch","tr":"Notch Sinyal Yolağı","nl":"Notch-signaleringsroute","ru":"Сигнальный путь Notch","zh":"Notch信号通路","pt_BR":"Sinalização Notch","pt_PT":"Sinalização Notch"}, back_translations: {"es":"Via de sinalización por contato célula-célula. El ligante (Delta/Jagged) en una célula liga-se al receptor Notch en la célula adjacente → γ-secretase cliva el domínio intracelular de Notch (NICD) → NICD entra en el núcleo → ativa genes-alvo. Crítico en la determinación del destino celular y desarrollo.","de":"Ein Zell-Zell-Kontakt-Signalweg. Ligand (Delta/Jagged) auf einer Zelle bindet an Notch-Rezeptor auf benachbarter Zelle → γ-Sekretase spaltet die intrazelluläre Notch-Domäne (NICD) → NICD gelangt in den Zellkern → aktiviert Zielgene. Entscheidend für Zellschicksalsbestimmung und Entwicklung.","fr":"Voie de signalisation par contact cellule-cellule. Le ligand (Delta/Jagged) sur une cellule se lie au récepteur Notch sur la cellule adjacente → la γ-sécrétase clive le domaine intracellulaire de Notch (NICD) → NICD entre dans le noyau → active les gènes cibles. Essentiel dans la détermination du destin cellulaire et le développement.","tr":"Hücre-hücre teması sinyal yolağı. Bir hücredeki ligand (Delta/Jagged) komşu hücredeki Notch reseptörüne bağlanır → γ-sekretaz Notch hücre içi alanını (NICD) keser → NICD çekirdeğe girer → hedef genleri aktive eder. Hücre kader belirlenmesi ve gelişim için kritik öneme sahiptir.","nl":"Een cel-celcontact-signaleringsroute. Ligand (Delta/Jagged) op één cel bindt aan Notch-receptor op aangrenzende cel → γ-secretase klieft het intracellulaire Notch-domein (NICD) → NICD gaat de kern in → activeert doelgenen. Cruciaal voor cellotsbestemming en ontwikkeling.","ru":"Сигнальный путь межклеточного контакта. Лиганд (Delta/Jagged) на одной клетке связывает рецептор Notch на соседней клетке → γ-секретаза расщепляет внутриклеточный домен Notch (NICD) → NICD входит в ядро → активирует гены-мишени. Критически важен для определения клеточной судьбы и развития.","zh":"细胞-细胞接触信号通路。一个细胞上的配体（Delta/Jagged）结合相邻细胞上的Notch受体 → γ-分泌酶切割Notch胞内结构域（NICD）→ NICD进入细胞核 → 激活靶基因。对细胞命运决定和发育至关重要。","pt_BR":"Via de sinalização por contato célula-célula. O ligante (Delta/Jagged) em uma célula liga-se ao receptor Notch na célula adjacente → γ-secretase cliva o domínio intracelular de Notch (NICD) → NICD entra no núcleo → ativa genes-alvo. Crítico na determinação do destino celular e desenvolvimento.","pt_PT":"Via de sinalização por contacto célula-célula. O ligando (Delta/Jagged) numa célula liga-se ao recetor Notch na célula adjacente → γ-secretase cliva o domínio intracelular de Notch (NICD) → NICD entra no núcleo → ativa genes-alvo. Crítico na determinação do destino celular e desenvolvimento."}},
  { id: 'dc-mcat-0187', deck_id: 'deck-mcat', sort_order: 187, front: "Wnt Signaling", back: "Wnt ligand binds Frizzled receptor → inhibits destruction complex → β-catenin accumulates → enters nucleus → activates target genes (cell proliferation, differentiation). Dysregulated Wnt signaling is common in colorectal cancer (APC mutation)." , front_translations: {"es":"Sinalización Wnt","de":"Wnt-Signalweg","fr":"Voie de signalisation Wnt","tr":"Wnt Sinyal Yolağı","nl":"Wnt-signaleringsroute","ru":"Сигнальный путь Wnt","zh":"Wnt信号通路","pt_BR":"Sinalização Wnt","pt_PT":"Sinalização Wnt"}, back_translations: {"es":"El ligante Wnt liga-se al receptor Frizzled → inibe el complexo de destrucción → β-catenina acumula → entra en el núcleo → ativa genes-alvo (proliferación celular, diferenciación). La sinalización Wnt desregulada es comum en el cancer colorretal (mutación APC).","de":"Wnt-Ligand bindet an Frizzled-Rezeptor → hemmt den Destruktionskomplex → β-Catenin akkumuliert → gelangt in den Zellkern → aktiviert Zielgene (Zellproliferation, Differenzierung). Dysregulierte Wnt-Signalgebung ist häufig bei Darmkrebs (APC-Mutation).","fr":"Le ligand Wnt se lie au récepteur Frizzled → inhibe le complexe de destruction → β-caténine s'accumule → entre dans le noyau → active les gènes cibles (prolifération cellulaire, différenciation). La signalisation Wnt dérégulée est fréquente dans le cancer colorectal (mutation APC).","tr":"Wnt ligandı Frizzled reseptörüne bağlanır → yıkım kompleksini inhibe eder → β-katenin birikir → çekirdeğe girer → hedef genleri aktive eder (hücre proliferasyonu, farklılaşma). Düzensiz Wnt sinyali kolorektal kanserde yaygındır (APC mutasyonu).","nl":"Wnt-ligand bindt aan Frizzled-receptor → remt het destructiecomplex → β-catenine accumuleert → gaat de kern in → activeert doelgenen (celproliferatie, differentiatie). Ontregelde Wnt-signalering is veel voorkomend bij colorectaal carcinoom (APC-mutatie).","ru":"Лиганд Wnt связывает рецептор Frizzled → ингибирует комплекс деструкции → β-катенин накапливается → входит в ядро → активирует гены-мишени (пролиферация, дифференцировка клеток). Дисрегуляция Wnt-сигналинга характерна для колоректального рака (мутация APC).","zh":"Wnt配体结合Frizzled受体 → 抑制降解复合物 → β-连环蛋白积累 → 进入细胞核 → 激活靶基因（细胞增殖、分化）。Wnt信号通路失调在结直肠癌中常见（APC突变）。","pt_BR":"O ligante Wnt liga-se ao receptor Frizzled → inibe o complexo de destruição → β-catenina acumula → entra no núcleo → ativa genes-alvo (proliferação celular, diferenciação). A sinalização Wnt desregulada é comum no câncer colorretal (mutação APC).","pt_PT":"O ligando Wnt liga-se ao recetor Frizzled → inibe o complexo de destruição → β-catenina acumula → entra no núcleo → ativa genes-alvo (proliferação celular, diferenciação). A sinalização Wnt desregulada é comum no cancro colorretal (mutação APC)."}},
  { id: 'dc-mcat-0188', deck_id: 'deck-mcat', sort_order: 188, front: "Oxidative Stress and Antioxidants", back: "Reactive oxygen species (ROS: superoxide O₂⁻, H₂O₂, hydroxyl radical OH•) damage DNA, lipids, and proteins. Antioxidant defenses: superoxide dismutase (SOD), catalase, glutathione peroxidase (requires NADPH from PPP). Vitamin C, E also antioxidants." , front_translations: {"es":"Estresse Oxidativo y Antioxidantes","de":"Oxidativer Stress und Antioxidantien","fr":"Stress oxydatif et antioxydants","tr":"Oksidatif Stres ve Antioksidanlar","nl":"Oxidatieve stress en antioxidanten","ru":"Окислительный стресс и антиоксиданты","zh":"氧化应激与抗氧化剂","pt_BR":"Estresse Oxidativo e Antioxidantes","pt_PT":"Stress Oxidativo e Antioxidantes"}, back_translations: {"es":"Espécies reativas de oxígeno (ROS: superóxido El₂⁻, H₂El₂, radical hidroxila OH•) danificam DNA, lipídios y proteínas. Defesas antioxidantes: superóxido dismutase (SOD), catalase, glutationa peroxidase (requiere NADPH de la via de las pentoses-fosfato). Vitaminas C y Y también son antioxidantes.","de":"Reaktive Sauerstoffspezies (ROS: Superoxid O₂⁻, H₂O₂, Hydroxylradikal OH•) schädigen DNA, Lipide und Proteine. Antioxidative Abwehr: Superoxiddismutase (SOD), Katalase, Glutathionperoxidase (benötigt NADPH aus dem PPP). Vitamin C und E sind ebenfalls Antioxidantien.","fr":"Les espèces réactives de l'oxygène (ROS : superoxyde O₂⁻, H₂O₂, radical hydroxyle OH•) endommagent l'ADN, les lipides et les protéines. Défenses antioxydantes : superoxyde dismutase (SOD), catalase, glutathion peroxydase (nécessite le NADPH de la voie des pentoses phosphates). Les vitamines C et E sont aussi antioxydantes.","tr":"Reaktif oksijen türleri (ROS: süperoksit O₂⁻, H₂O₂, hidroksil radikali OH•) DNA, lipidler ve proteinlere zarar verir. Antioksidan savunmalar: süperoksit dismutaz (SOD), katalaz, glutatyon peroksidaz (PPP'den NADPH gerektirir). C ve E vitaminleri de antioksidandır.","nl":"Reactieve zuurstofsoorten (ROS: superoxide O₂⁻, H₂O₂, hydroxylradicaal OH•) beschadigen DNA, lipiden en eiwitten. Antioxidantafweer: superoxidedismutase (SOD), katalase, glutathionperoxidase (vereist NADPH uit de PPP). Vitamine C en E zijn ook antioxidanten.","ru":"Активные формы кислорода (АФК: супероксид O₂⁻, H₂O₂, гидроксильный радикал OH•) повреждают ДНК, липиды и белки. Антиоксидантная защита: супероксиддисмутаза (SOD), каталаза, глутатионпероксидаза (требует NADPH из ПФП). Витамины C и E также являются антиоксидантами.","zh":"活性氧（ROS：超氧化物O₂⁻、H₂O₂、羟基自由基OH•）损伤DNA、脂质和蛋白质。抗氧化防御：超氧化物歧化酶（SOD）、过氧化氢酶、谷胱甘肽过氧化物酶（需要PPP提供的NADPH）。维生素C、E也是抗氧化剂。","pt_BR":"Espécies reativas de oxigênio (ROS: superóxido O₂⁻, H₂O₂, radical hidroxila OH•) danificam DNA, lipídios e proteínas. Defesas antioxidantes: superóxido dismutase (SOD), catalase, glutationa peroxidase (requer NADPH da via das pentoses-fosfato). Vitaminas C e E também são antioxidantes.","pt_PT":"Espécies reativas de oxigénio (ROS: superóxido O₂⁻, H₂O₂, radical hidroxilo OH•) danificam DNA, lípidos e proteínas. Defesas antioxidantes: superóxido dismutase (SOD), catalase, glutationa peroxidase (requer NADPH da via das pentoses-fosfato). Vitaminas C e E também são antioxidantes."}},
  { id: 'dc-mcat-0189', deck_id: 'deck-mcat', sort_order: 189, front: "Replication Fork and Telomeres", back: "DNA polymerase can only extend 3' ends; new strand synthesized 5'→3'. Lagging strand requires Okazaki fragments. Each replication shortens chromosomes at ends (end replication problem). Telomerase (reverse transcriptase) adds TTAGGG repeats; active in germ cells and cancer cells." , front_translations: {"es":"Forquilha de Replicación y Telomeros","de":"Replikationsgabel und Telomere","fr":"Fourche de réplication et télomères","tr":"Replikasyon Çatalı ve Telomerler","nl":"Replicatievork en telomeren","ru":"Репликационная вилка и теломеры","zh":"复制叉与端粒","pt_BR":"Forquilha de Replicação e Telômeros","pt_PT":"Forquilha de Replicação e Telómeros"}, back_translations: {"es":"La DNA polimerase só puede estender extremidades 3'; a nueva fita es sintetizada 5'→3'. La fita descontínua requiere fragmentos de Okazaki. Cada replicación encurta las extremidades cromossomicas (problema de replicación terminal). La telomerase (transcriptase reversa) adiciona repeticiones TTAGGG; ativa en células germinativas y cancerosas.","de":"DNA-Polymerase kann nur 3'-Enden verlängern; der neue Strang wird 5'→3' synthetisiert. Der Folgestrang erfordert Okazaki-Fragmente. Jede Replikation verkürzt die Chromosomenenden (Endreplikationsproblem). Telomerase (reverse Transkriptase) fügt TTAGGG-Repeats hinzu; aktiv in Keimzellen und Krebszellen.","fr":"L'ADN polymérase ne peut allonger que les extrémités 3' ; le nouveau brin est synthétisé 5'→3'. Le brin retardé nécessite des fragments d'Okazaki. Chaque réplication raccourcit les extrémités chromosomiques (problème de réplication terminale). La télomérase (transcriptase inverse) ajoute des répétitions TTAGGG ; active dans les cellules germinales et cancéreuses.","tr":"DNA polimeraz yalnızca 3' uçları uzatabilir; yeni zincir 5'→3' yönünde sentezlenir. Geciken zincir Okazaki fragmanları gerektirir. Her replikasyon kromozom uçlarını kısaltır (uç replikasyon problemi). Telomeraz (ters transkriptaz) TTAGGG tekrarları ekler; germ hücrelerinde ve kanser hücrelerinde aktiftir.","nl":"DNA-polymerase kan alleen 3'-uiteinden verlengen; de nieuwe streng wordt 5'→3' gesynthetiseerd. De achterblijvende streng vereist Okazaki-fragmenten. Elke replicatie verkort de chromosoomuiteinden (eindreplicatieprobleem). Telomerase (reverse transcriptase) voegt TTAGGG-herhalingen toe; actief in kiemcellen en kankercellen.","ru":"ДНК-полимераза может удлинять только 3'-концы; новая цепь синтезируется 5'→3'. Отстающая цепь требует фрагментов Оказаки. Каждая репликация укорачивает концы хромосом (проблема концевой репликации). Теломераза (обратная транскриптаза) добавляет повторы TTAGGG; активна в половых и раковых клетках.","zh":"DNA聚合酶只能延伸3'端；新链以5'→3'方向合成。滞后链需要冈崎片段。每次复制都会缩短染色体末端（末端复制问题）。端粒酶（逆转录酶）添加TTAGGG重复序列；在生殖细胞和癌细胞中活跃。","pt_BR":"A DNA polimerase só pode estender extremidades 3'; a nova fita é sintetizada 5'→3'. A fita descontínua requer fragmentos de Okazaki. Cada replicação encurta as extremidades cromossômicas (problema de replicação terminal). A telomerase (transcriptase reversa) adiciona repetições TTAGGG; ativa em células germinativas e cancerosas.","pt_PT":"A DNA polimerase só pode estender extremidades 3'; a nova cadeia é sintetizada 5'→3'. A cadeia descontínua requer fragmentos de Okazaki. Cada replicação encurta as extremidades cromossómicas (problema de replicação terminal). A telomerase (transcriptase reversa) adiciona repetições TTAGGG; ativa em células germinativas e cancerosas."}},
  { id: 'dc-mcat-0190', deck_id: 'deck-mcat', sort_order: 190, front: "X-Inactivation (Lyon Hypothesis)", back: "In female mammals, one X chromosome is randomly inactivated in each somatic cell early in development (forming a Barr body). The inactivated X is transcriptionally silenced by XIST RNA and DNA methylation. Inactivation is clonal; females are mosaics for X-linked traits." , front_translations: {"es":"Inativación del X (Hipótese de Lyon)","de":"X-Inaktivierung (Lyon-Hypothese)","fr":"Inactivation du X (Hypothèse de Lyon)","tr":"X-İnaktivasyonu (Lyon Hipotezi)","nl":"X-inactivatie (Lyon-hypothese)","ru":"Инактивация X-хромосомы (гипотеза Лайон)","zh":"X染色体失活（Lyon假说）","pt_BR":"Inativação do X (Hipótese de Lyon)","pt_PT":"Inativação do X (Hipótese de Lyon)"}, back_translations: {"es":"En mamíferos femeas, un cromossomo X es aleatoriamente inativado en cada célula somática en el início del desarrollo (formando un corpúsculo de Barr). El X inativado es silenciado transcricionalmente por RNA XIST y metilación del DNA. La inativación es clonal; femeas son mosaicos para características ligadas al X.","de":"Bei weiblichen Säugetieren wird in jeder somatischen Zelle früh in der Entwicklung ein X-Chromosom zufällig inaktiviert (Barr-Körperchen). Das inaktivierte X wird durch XIST-RNA und DNA-Methylierung transkriptionell stillgelegt. Die Inaktivierung ist klonal; Weibchen sind Mosaike für X-chromosomale Merkmale.","fr":"Chez les mammifères femelles, un chromosome X est inactivé aléatoirement dans chaque cellule somatique tôt dans le développement (formant un corpuscule de Barr). Le X inactivé est réduit au silence transcriptionnel par l'ARN XIST et la méthylation de l'ADN. L'inactivation est clonale ; les femelles sont des mosaïques pour les traits liés à l'X.","tr":"Dişi memelilerde, gelişimin erken döneminde her somatik hücrede bir X kromozomu rastgele inaktive edilir (Barr cisimciği oluşturur). İnaktive X, XIST RNA ve DNA metilasyonu ile transkripsiyonel olarak susturulur. İnaktivasyon klonaldir; dişiler X'e bağlı özellikler için mozaiklerdir.","nl":"Bij vrouwelijke zoogdieren wordt in elke somatische cel vroeg in de ontwikkeling willekeurig één X-chromosoom geïnactiveerd (vormt een Barr-lichaampje). Het geïnactiveerde X wordt transcriptioneel stilgelegd door XIST-RNA en DNA-methylering. Inactivatie is klonaal; vrouwtjes zijn mozaïeken voor X-gebonden eigenschappen.","ru":"У самок млекопитающих одна X-хромосома случайно инактивируется в каждой соматической клетке на ранних стадиях развития (образуя тельце Барра). Инактивированная X транскрипционно подавляется РНК XIST и метилированием ДНК. Инактивация клональна; самки являются мозаиками по X-сцепленным признакам.","zh":"在雌性哺乳动物中，每个体细胞在发育早期随机失活一条X染色体（形成Barr小体）。失活的X通过XIST RNA和DNA甲基化转录沉默。失活是克隆性的；雌性是X连锁性状的嵌合体。","pt_BR":"Em mamíferos fêmeas, um cromossomo X é aleatoriamente inativado em cada célula somática no início do desenvolvimento (formando um corpúsculo de Barr). O X inativado é silenciado transcricionalmente por RNA XIST e metilação do DNA. A inativação é clonal; fêmeas são mosaicos para características ligadas ao X.","pt_PT":"Em mamíferos fêmeas, um cromossoma X é aleatoriamente inativado em cada célula somática no início do desenvolvimento (formando um corpúsculo de Barr). O X inativado é silenciado transcricionalmente por RNA XIST e metilação do DNA. A inativação é clonal; fêmeas são mosaicos para características ligadas ao X."}},
  { id: 'dc-mcat-0191', deck_id: 'deck-mcat', sort_order: 191, front: "Genomic Imprinting", back: "Some genes are expressed only from the maternally or paternally inherited allele, regulated by DNA methylation patterns set in gametes. Prader-Willi (paternal 15q11 deletion → no paternal copy) and Angelman syndrome (maternal 15q11 deletion → no maternal UBE3A)." , front_translations: {"es":"Imprinting Genomico","de":"Genomische Prägung","fr":"Empreinte génomique","tr":"Genomik Baskılama","nl":"Genomische imprinting","ru":"Геномный импринтинг","zh":"基因组印记","pt_BR":"Imprinting Genômico","pt_PT":"Imprinting Genómico"}, back_translations: {"es":"Alguns genes son expressos solo a partir del alelo herdado maternalmente o paternalmente, regulados por padrões de metilación del DNA estabelecidos en los gametas. Prader-Willi (deleción paterna 15q11 → sin cópia paterna) y síndrome de Angelman (deleción materna 15q11 → sin UBE3A materno).","de":"Einige Gene werden nur vom mütterlich oder väterlich vererbten Allel exprimiert, reguliert durch DNA-Methylierungsmuster, die in Gameten festgelegt werden. Prader-Willi (paternale 15q11-Deletion → keine väterliche Kopie) und Angelman-Syndrom (maternale 15q11-Deletion → kein maternales UBE3A).","fr":"Certains gènes ne sont exprimés qu'à partir de l'allèle hérité de la mère ou du père, régulés par des profils de méthylation de l'ADN établis dans les gamètes. Prader-Willi (délétion paternelle 15q11 → pas de copie paternelle) et syndrome d'Angelman (délétion maternelle 15q11 → pas de UBE3A maternel).","tr":"Bazı genler yalnızca anneden veya babadan kalıtılan alelden eksprese edilir, gametlerde belirlenen DNA metilasyon kalıpları ile düzenlenir. Prader-Willi (paternal 15q11 delesyonu → paternal kopya yok) ve Angelman sendromu (maternal 15q11 delesyonu → maternal UBE3A yok).","nl":"Sommige genen worden alleen tot expressie gebracht vanuit het maternaal of paternaal overgeërfde allel, gereguleerd door DNA-methyleringspatronen vastgelegd in gameten. Prader-Willi (paternale 15q11-deletie → geen paternale kopie) en Angelman-syndroom (maternale 15q11-deletie → geen maternaal UBE3A).","ru":"Некоторые гены экспрессируются только с материнского или отцовского аллеля, регулируемые паттернами метилирования ДНК, установленными в гаметах. Прадера-Вилли (делеция отцовского 15q11 → нет отцовской копии) и синдром Ангельмана (делеция материнского 15q11 → нет материнского UBE3A).","zh":"某些基因仅从母源或父源等位基因表达，由配子中设定的DNA甲基化模式调控。Prader-Willi综合征（父源15q11缺失 → 无父源拷贝）和Angelman综合征（母源15q11缺失 → 无母源UBE3A）。","pt_BR":"Alguns genes são expressos apenas a partir do alelo herdado maternalmente ou paternalmente, regulados por padrões de metilação do DNA estabelecidos nos gametas. Prader-Willi (deleção paterna 15q11 → sem cópia paterna) e síndrome de Angelman (deleção materna 15q11 → sem UBE3A materno).","pt_PT":"Alguns genes são expressos apenas a partir do alelo herdado maternalmente ou paternalmente, regulados por padrões de metilação do DNA estabelecidos nos gâmetas. Prader-Willi (deleção paterna 15q11 → sem cópia paterna) e síndrome de Angelman (deleção materna 15q11 → sem UBE3A materno)."}},
  { id: 'dc-mcat-0192', deck_id: 'deck-mcat', sort_order: 192, front: "Gene Therapy Approaches", back: "Viral vectors (lentivirus, AAV, retrovirus) deliver functional gene copies into patient cells. Ex vivo: cells removed, modified, reinfused (e.g., CAR-T cells). In vivo: vector delivered directly. CRISPR enables precise genome editing. Used for hemophilia, LCA, certain immunodeficiencies." , front_translations: {"es":"Abordajes de Terapia Genica","de":"Gentherapie-Ansätze","fr":"Approches de thérapie génique","tr":"Gen Terapisi Yaklaşımları","nl":"Gentherapiebenaderingen","ru":"Подходы генной терапии","zh":"基因治疗方法","pt_BR":"Abordagens de Terapia Gênica","pt_PT":"Abordagens de Terapia Génica"}, back_translations: {"es":"Vetores virais (lentivírus, AAV, retrovírus) entregam cópias funcionais de genes en las células del paciente. Ex vivo: células removidas, modificadas, reinfundidas (ex.: células CAR-T). In vivo: vetor entregue directamente. CRISPR permite edición genómica precisa. Usado para hemofilia, LCA, certas imunodeficiencias.","de":"Virale Vektoren (Lentivirus, AAV, Retrovirus) liefern funktionelle Genkopien in Patientenzellen. Ex vivo: Zellen entnommen, modifiziert, reinfundiert (z.B. CAR-T-Zellen). In vivo: Vektor direkt verabreicht. CRISPR ermöglicht präzise Genomeditierung. Anwendung bei Hämophilie, LCA, bestimmten Immundefizienzen.","fr":"Les vecteurs viraux (lentivirus, AAV, rétrovirus) délivrent des copies fonctionnelles de gènes dans les cellules du patient. Ex vivo : cellules prélevées, modifiées, réinjectées (ex. cellules CAR-T). In vivo : vecteur administré directement. CRISPR permet l'édition précise du génome. Utilisé pour l'hémophilie, la LCA, certaines immunodéficiences.","tr":"Viral vektörler (lentivirüs, AAV, retrovirüs) fonksiyonel gen kopyalarını hasta hücrelerine iletir. Ex vivo: hücreler alınır, modifiye edilir, geri verilir (örn. CAR-T hücreleri). In vivo: vektör doğrudan uygulanır. CRISPR hassas genom düzenlemesi sağlar. Hemofili, LCA, bazı immün yetmezliklerde kullanılır.","nl":"Virale vectoren (lentivirus, AAV, retrovirus) leveren functionele genkopieën af in patiëntcellen. Ex vivo: cellen verwijderd, gemodificeerd, teruggebracht (bijv. CAR-T-cellen). In vivo: vector direct toegediend. CRISPR maakt nauwkeurige genoombewerking mogelijk. Gebruikt voor hemofilie, LCA, bepaalde immuundeficiënties.","ru":"Вирусные векторы (лентивирус, AAV, ретровирус) доставляют функциональные копии генов в клетки пациента. Ex vivo: клетки извлекают, модифицируют, возвращают (напр., CAR-T-клетки). In vivo: вектор вводят напрямую. CRISPR обеспечивает точное редактирование генома. Применяется при гемофилии, LCA, некоторых иммунодефицитах.","zh":"病毒载体（慢病毒、AAV、逆转录病毒）将功能基因拷贝递送到患者细胞中。体外法：取出细胞、修饰后回输（如CAR-T细胞）。体内法：直接递送载体。CRISPR实现精准基因组编辑。用于血友病、LCA、某些免疫缺陷病。","pt_BR":"Vetores virais (lentivírus, AAV, retrovírus) entregam cópias funcionais de genes nas células do paciente. Ex vivo: células removidas, modificadas, reinfundidas (ex.: células CAR-T). In vivo: vetor entregue diretamente. CRISPR permite edição genômica precisa. Usado para hemofilia, LCA, certas imunodeficiências.","pt_PT":"Vetores virais (lentivírus, AAV, retrovírus) entregam cópias funcionais de genes nas células do paciente. Ex vivo: células removidas, modificadas, reinfundidas (ex.: células CAR-T). In vivo: vetor entregue diretamente. CRISPR permite edição genómica precisa. Usado para hemofilia, LCA, certas imunodeficiências."}},
  { id: 'dc-mcat-0193', deck_id: 'deck-mcat', sort_order: 193, front: "Pharmacokinetics: ADME", back: "Absorption (route of administration, bioavailability, first-pass effect), Distribution (Vd, plasma protein binding), Metabolism (Phase I: CYP450 oxidation; Phase II: conjugation → more water-soluble), Excretion (renal, biliary). These four processes determine drug concentration over time." , front_translations: {"es":"Farmacocinética: ADME","de":"Pharmakokinetik: ADME","fr":"Pharmacocinétique : ADME","tr":"Farmakokinetik: ADME","nl":"Farmacokinetiek: ADME","ru":"Фармакокинетика: ADME","zh":"药代动力学：ADME","pt_BR":"Farmacocinética: ADME","pt_PT":"Farmacocinética: ADME"}, back_translations: {"es":"Absorción (via de administración, biodisponibilidad, efecto de primera passaje), Distribuición (Vd, enlace a proteínas plasmáticas), Metabolismo (Fase I: oxidación CYP450; Fase II: conjugación → más hidrossolúvel), Excreción (renal, biliar). Esses cuatro procesos determinan a concentración del fármaco a lo ancho del tiempo.","de":"Absorption (Verabreichungsweg, Bioverfügbarkeit, First-Pass-Effekt), Distribution (Vd, Plasmaproteinbindung), Metabolismus (Phase I: CYP450-Oxidation; Phase II: Konjugation → wasserlöslicher), Exkretion (renal, biliär). Diese vier Prozesse bestimmen die Wirkstoffkonzentration über die Zeit.","fr":"Absorption (voie d'administration, biodisponibilité, effet de premier passage), Distribution (Vd, liaison aux protéines plasmatiques), Métabolisme (Phase I : oxydation CYP450 ; Phase II : conjugaison → plus hydrosoluble), Excrétion (rénale, biliaire). Ces quatre processus déterminent la concentration du médicament au cours du temps.","tr":"Absorpsiyon (uygulama yolu, biyoyararlanım, ilk geçiş etkisi), Dağılım (Vd, plazma proteini bağlanması), Metabolizma (Faz I: CYP450 oksidasyonu; Faz II: konjugasyon → daha suda çözünür), Atılım (renal, biliyer). Bu dört süreç ilacın zaman içindeki konsantrasyonunu belirler.","nl":"Absorptie (toedieningsweg, biobeschikbaarheid, first-pass-effect), Distributie (Vd, plasma-eiwitbinding), Metabolisme (Fase I: CYP450-oxidatie; Fase II: conjugatie → meer wateroplosbaar), Excretie (renaal, biliair). Deze vier processen bepalen de geneesmiddelconcentratie over de tijd.","ru":"Абсорбция (путь введения, биодоступность, эффект первого прохождения), Распределение (Vd, связывание с белками плазмы), Метаболизм (Фаза I: окисление CYP450; Фаза II: конъюгация → более водорастворимый), Экскреция (почечная, билиарная). Эти четыре процесса определяют концентрацию препарата во времени.","zh":"吸收（给药途径、生物利用度、首过效应）、分布（Vd、血浆蛋白结合）、代谢（I相：CYP450氧化；II相：结合反应 → 更水溶性）、排泄（肾、胆）。这四个过程决定药物随时间的浓度变化。","pt_BR":"Absorção (via de administração, biodisponibilidade, efeito de primeira passagem), Distribuição (Vd, ligação a proteínas plasmáticas), Metabolismo (Fase I: oxidação CYP450; Fase II: conjugação → mais hidrossolúvel), Excreção (renal, biliar). Esses quatro processos determinam a concentração do fármaco ao longo do tempo.","pt_PT":"Absorção (via de administração, biodisponibilidade, efeito de primeira passagem), Distribuição (Vd, ligação a proteínas plasmáticas), Metabolismo (Fase I: oxidação CYP450; Fase II: conjugação → mais hidrossolúvel), Excreção (renal, biliar). Estes quatro processos determinam a concentração do fármaco ao longo do tempo."}},
  { id: 'dc-mcat-0194', deck_id: 'deck-mcat', sort_order: 194, front: "Proton NMR: Number of Signals", back: "Each chemically non-equivalent proton in a molecule gives a distinct NMR signal. Equivalent protons (related by symmetry) give one signal. The number of signals indicates the number of chemically unique proton environments in the molecule." , front_translations: {"es":"RMN de Prótons: Número de Sinais","de":"Protonen-NMR: Anzahl der Signale","fr":"RMN du proton : Nombre de signaux","tr":"Proton NMR: Sinyal Sayısı","nl":"Proton-NMR: Aantal signalen","ru":"Протонный ЯМР: количество сигналов","zh":"质子NMR：信号数目","pt_BR":"RMN de Prótons: Número de Sinais","pt_PT":"RMN de Protões: Número de Sinais"}, back_translations: {"es":"Cada protón quimicamente no equivalente en una molécula dá un señal de RMN distinto. Prótons equivalentes (relacionados por simetría) dão un único señal. El número de señales indica el número de ambientes de protones quimicamente únicos en la molécula.","de":"Jedes chemisch nicht-äquivalente Proton in einem Molekül ergibt ein eigenständiges NMR-Signal. Äquivalente Protonen (durch Symmetrie verwandt) ergeben ein Signal. Die Anzahl der Signale zeigt die Anzahl der chemisch einzigartigen Protonenumgebungen im Molekül an.","fr":"Chaque proton chimiquement non équivalent dans une molécule donne un signal RMN distinct. Les protons équivalents (liés par symétrie) donnent un seul signal. Le nombre de signaux indique le nombre d'environnements protoniques chimiquement uniques dans la molécule.","tr":"Bir moleküldeki kimyasal olarak eşdeğer olmayan her proton ayrı bir NMR sinyali verir. Eşdeğer protonlar (simetri ile ilişkili) tek bir sinyal verir. Sinyal sayısı, moleküldeki kimyasal olarak benzersiz proton ortamlarının sayısını gösterir.","nl":"Elk chemisch niet-equivalent proton in een molecuul geeft een afzonderlijk NMR-signaal. Equivalente protonen (gerelateerd door symmetrie) geven één signaal. Het aantal signalen geeft het aantal chemisch unieke protonomgevingen in het molecuul aan.","ru":"Каждый химически неэквивалентный протон в молекуле даёт отдельный сигнал ЯМР. Эквивалентные протоны (связанные симметрией) дают один сигнал. Число сигналов указывает на количество химически уникальных протонных окружений в молекуле.","zh":"分子中每个化学不等价的质子产生一个独特的NMR信号。等价质子（通过对称性相关）产生一个信号。信号数目表示分子中化学上独特的质子环境数量。","pt_BR":"Cada próton quimicamente não equivalente em uma molécula dá um sinal de RMN distinto. Prótons equivalentes (relacionados por simetria) dão um único sinal. O número de sinais indica o número de ambientes de prótons quimicamente únicos na molécula.","pt_PT":"Cada protão quimicamente não equivalente numa molécula dá um sinal de RMN distinto. Protões equivalentes (relacionados por simetria) dão um único sinal. O número de sinais indica o número de ambientes de protões quimicamente únicos na molécula."}},
  { id: 'dc-mcat-0195', deck_id: 'deck-mcat', sort_order: 195, front: "Mass Spectrometry", back: "Molecules are ionized and fragmented; detected by mass-to-charge ratio (m/z). The molecular ion peak (M⁺) gives molecular weight. Fragmentation patterns reveal structure. Base peak: most abundant fragment. Used to identify unknowns in organic chemistry." , front_translations: {"es":"Espectrometria de Massa","de":"Massenspektrometrie","fr":"Spectrométrie de masse","tr":"Kütle Spektrometrisi","nl":"Massaspectrometrie","ru":"Масс-спектрометрия","zh":"质谱法","pt_BR":"Espectrometria de Massa","pt_PT":"Espectrometria de Massa"}, back_translations: {"es":"As moléculas son ionizadas y fragmentadas; detectadas por la razão masa/carga (m/z). El pico del ion molecular (M⁺) proporciona el peso molecular. Los padrões de fragmentación revelam a estructura. Pico base: fragmento más abundante. Usado para identificar compuestos desconhecidos en química orgánica.","de":"Moleküle werden ionisiert und fragmentiert; Detektion nach Masse-Ladungs-Verhältnis (m/z). Der Molekülionenpeak (M⁺) gibt das Molekulargewicht an. Fragmentierungsmuster zeigen die Struktur. Basispeak: häufigstes Fragment. Wird zur Identifikation unbekannter Verbindungen in der organischen Chemie verwendet.","fr":"Les molécules sont ionisées et fragmentées ; détection par rapport masse/charge (m/z). Le pic de l'ion moléculaire (M⁺) donne la masse moléculaire. Les schémas de fragmentation révèlent la structure. Pic de base : fragment le plus abondant. Utilisée pour identifier les inconnus en chimie organique.","tr":"Moleküller iyonlaştırılır ve parçalanır; kütle/yük oranına (m/z) göre tespit edilir. Moleküler iyon piki (M⁺) moleküler ağırlığı verir. Parçalanma düzenleri yapıyı ortaya koyar. Taban piki: en bol fragment. Organik kimyada bilinmeyenlerin tanımlanmasında kullanılır.","nl":"Moleculen worden geïoniseerd en gefragmenteerd; gedetecteerd op massa-ladingverhouding (m/z). De moleculaire ionenpiek (M⁺) geeft het molecuulgewicht. Fragmentatiepatronen onthullen de structuur. Basispiek: meest voorkomend fragment. Gebruikt om onbekenden in de organische chemie te identificeren.","ru":"Молекулы ионизируются и фрагментируются; детектируются по отношению массы к заряду (m/z). Пик молекулярного иона (M⁺) даёт молекулярную массу. Паттерны фрагментации раскрывают структуру. Базовый пик: наиболее интенсивный фрагмент. Используется для идентификации неизвестных соединений в органической химии.","zh":"分子被电离并碎裂；按质荷比（m/z）检测。分子离子峰（M⁺）给出分子量。碎裂模式揭示结构。基峰：最丰富的碎片。用于有机化学中未知物的鉴定。","pt_BR":"As moléculas são ionizadas e fragmentadas; detectadas pela razão massa/carga (m/z). O pico do íon molecular (M⁺) fornece o peso molecular. Os padrões de fragmentação revelam a estrutura. Pico base: fragmento mais abundante. Usado para identificar compostos desconhecidos em química orgânica.","pt_PT":"As moléculas são ionizadas e fragmentadas; detetadas pela razão massa/carga (m/z). O pico do ião molecular (M⁺) fornece o peso molecular. Os padrões de fragmentação revelam a estrutura. Pico base: fragmento mais abundante. Usado para identificar compostos desconhecidos em química orgânica."}},
  { id: 'dc-mcat-0196', deck_id: 'deck-mcat', sort_order: 196, front: "Acid-Base Properties of Amino Acids", back: "Each amino acid has at least two pKa values: α-NH₃⁺ (pKa ~9) and α-COOH (pKa ~2). Side chain pKa values vary. Below pKa of COOH: fully protonated (+1 charge). Above pKa of NH₃⁺: fully deprotonated (−1 charge). pI = average of relevant pKa values." , front_translations: {"es":"Propriedades Ácido-Base de los Aminoácidos","de":"Säure-Base-Eigenschaften von Aminosäuren","fr":"Propriétés acido-basiques des acides aminés","tr":"Amino Asitlerin Asit-Baz Özellikleri","nl":"Zuur-base-eigenschappen van aminozuren","ru":"Кислотно-основные свойства аминокислот","zh":"氨基酸的酸碱性质","pt_BR":"Propriedades Ácido-Base dos Aminoácidos","pt_PT":"Propriedades Ácido-Base dos Aminoácidos"}, back_translations: {"es":"Cada aminoácido tiene por el menos de los valores de pKa: α-NH₃⁺ (pKa ~9) y α-COOH (pKa ~2). Los valores de pKa de la cadeia lateral variam. Abaixo del pKa del COOH: totalmente protonado (carga +1). Acima del pKa del NH₃⁺: totalmente desprotonado (carga −1). pI = média de los valores de pKa relevantes.","de":"Jede Aminosäure hat mindestens zwei pKa-Werte: α-NH₃⁺ (pKa ~9) und α-COOH (pKa ~2). Die pKa-Werte der Seitenkette variieren. Unter dem pKa der COOH: vollständig protoniert (+1 Ladung). Über dem pKa von NH₃⁺: vollständig deprotoniert (−1 Ladung). pI = Durchschnitt der relevanten pKa-Werte.","fr":"Chaque acide aminé possède au moins deux valeurs de pKa : α-NH₃⁺ (pKa ~9) et α-COOH (pKa ~2). Les valeurs de pKa des chaînes latérales varient. En dessous du pKa du COOH : entièrement protoné (charge +1). Au-dessus du pKa du NH₃⁺ : entièrement déprotoné (charge −1). pI = moyenne des valeurs de pKa pertinentes.","tr":"Her amino asidin en az iki pKa değeri vardır: α-NH₃⁺ (pKa ~9) ve α-COOH (pKa ~2). Yan zincir pKa değerleri değişir. COOH'nin pKa'sının altında: tamamen protonlanmış (+1 yük). NH₃⁺'ün pKa'sının üstünde: tamamen deprotonlanmış (−1 yük). pI = ilgili pKa değerlerinin ortalaması.","nl":"Elk aminozuur heeft minstens twee pKa-waarden: α-NH₃⁺ (pKa ~9) en α-COOH (pKa ~2). pKa-waarden van de zijketen variëren. Onder pKa van COOH: volledig geprotoneerd (+1 lading). Boven pKa van NH₃⁺: volledig gedeprotoneerd (−1 lading). pI = gemiddelde van de relevante pKa-waarden.","ru":"Каждая аминокислота имеет как минимум два значения pKa: α-NH₃⁺ (pKa ~9) и α-COOH (pKa ~2). Значения pKa боковых цепей варьируются. Ниже pKa COOH: полностью протонирована (заряд +1). Выше pKa NH₃⁺: полностью депротонирована (заряд −1). pI = среднее значение соответствующих pKa.","zh":"每种氨基酸至少有两个pKa值：α-NH₃⁺（pKa ~9）和α-COOH（pKa ~2）。侧链pKa值各不相同。低于COOH的pKa：完全质子化（+1电荷）。高于NH₃⁺的pKa：完全去质子化（−1电荷）。pI = 相关pKa值的平均值。","pt_BR":"Cada aminoácido tem pelo menos dois valores de pKa: α-NH₃⁺ (pKa ~9) e α-COOH (pKa ~2). Os valores de pKa da cadeia lateral variam. Abaixo do pKa do COOH: totalmente protonado (carga +1). Acima do pKa do NH₃⁺: totalmente desprotonado (carga −1). pI = média dos valores de pKa relevantes.","pt_PT":"Cada aminoácido tem pelo menos dois valores de pKa: α-NH₃⁺ (pKa ~9) e α-COOH (pKa ~2). Os valores de pKa da cadeia lateral variam. Abaixo do pKa do COOH: totalmente protonado (carga +1). Acima do pKa do NH₃⁺: totalmente desprotonado (carga −1). pI = média dos valores de pKa relevantes."}},
  { id: 'dc-mcat-0197', deck_id: 'deck-mcat', sort_order: 197, front: "Kidney Tubular Secretion and Drug Elimination", back: "Organic anion transporters (OATs) and cation transporters actively secrete drugs into tubular fluid for excretion. Probenecid blocks OATs (reduces penicillin/uric acid secretion). Drug ionization affects reabsorption: ionized forms are trapped in urine (ion trapping)." , front_translations: {"es":"Secreción Tubular Renal y Eliminación de Fármacos","de":"Tubuläre Sekretion der Niere und Arzneimittelelimination","fr":"Sécrétion tubulaire rénale et élimination des médicaments","tr":"Böbrek Tübüler Sekresyonu ve İlaç Eliminasyonu","nl":"Tubulaire secretie in de nier en geneesmiddeleliminatie","ru":"Канальцевая секреция почек и элиминация лекарств","zh":"肾小管分泌与药物消除","pt_BR":"Secreção Tubular Renal e Eliminação de Fármacos","pt_PT":"Secreção Tubular Renal e Eliminação de Fármacos"}, back_translations: {"es":"Transportadores de anions organicos (OATs) y transportadores de cátions secretam ativamente fármacos en el líquido tubular para excreción. El probenecida bloqueia los OATs (reduce a secreción de penicilina/ácido úrico). La ionización del fármaco afecta a reabsorción: formas ionizadas ficam retidas en la urina (aprisionamento ionico).","de":"Organische Anionentransporter (OATs) und Kationentransporter sezernieren aktiv Arzneimittel in die Tubulusflüssigkeit zur Ausscheidung. Probenecid blockiert OATs (reduziert Penicillin-/Harnsäuresekretion). Die Ionisierung von Arzneimitteln beeinflusst die Rückresorption: ionisierte Formen werden im Urin gefangen (Ion Trapping).","fr":"Les transporteurs d'anions organiques (OATs) et les transporteurs de cations sécrètent activement les médicaments dans le liquide tubulaire pour l'excrétion. Le probénécide bloque les OATs (réduit la sécrétion de pénicilline/acide urique). L'ionisation du médicament affecte la réabsorption : les formes ionisées sont piégées dans l'urine (piégeage ionique).","tr":"Organik anyon taşıyıcıları (OATs) ve katyon taşıyıcıları ilaçları aktif olarak tübüler sıvıya salgılayarak atılımı sağlar. Probenesid OATs'ı bloke eder (penisilin/ürik asit sekresyonunu azaltır). İlacın iyonizasyonu geri emilimi etkiler: iyonize formlar idrarda tutulur (iyon yakalama).","nl":"Organische anionentransporters (OATs) en kationentransporters scheiden actief geneesmiddelen uit in de tubulusvloeistof voor excretie. Probenecid blokkeert OATs (vermindert penicilline-/urinezuursecretie). Ionisatie van het geneesmiddel beïnvloedt reabsorptie: geïoniseerde vormen worden vastgehouden in de urine (ion trapping).","ru":"Транспортёры органических анионов (OATs) и катионные транспортёры активно секретируют лекарства в канальцевую жидкость для экскреции. Пробенецид блокирует OATs (снижает секрецию пенициллина/мочевой кислоты). Ионизация лекарства влияет на реабсорбцию: ионизированные формы задерживаются в моче (ионная ловушка).","zh":"有机阴离子转运体（OATs）和阳离子转运体主动将药物分泌到肾小管液中以进行排泄。丙磺舒阻断OATs（减少青霉素/尿酸的分泌）。药物的电离影响重吸收：电离形式被困在尿液中（离子捕获）。","pt_BR":"Transportadores de ânions orgânicos (OATs) e transportadores de cátions secretam ativamente fármacos no líquido tubular para excreção. O probenecida bloqueia os OATs (reduz a secreção de penicilina/ácido úrico). A ionização do fármaco afeta a reabsorção: formas ionizadas ficam retidas na urina (aprisionamento iônico).","pt_PT":"Transportadores de aniões orgânicos (OATs) e transportadores de catiões secretam ativamente fármacos no líquido tubular para excreção. O probenecida bloqueia os OATs (reduz a secreção de penicilina/ácido úrico). A ionização do fármaco afeta a reabsorção: formas ionizadas ficam retidas na urina (aprisionamento iónico)."}},
  { id: 'dc-mcat-0198', deck_id: 'deck-mcat', sort_order: 198, front: "Poverty and Health Outcomes", back: "Low SES is associated with higher rates of cardiovascular disease, diabetes, infections, mental illness, and infant mortality. Mechanisms: limited access to healthcare, poor nutrition, chronic stress (allostatic load), environmental exposures, and reduced health literacy." , front_translations: {"es":"Pobreza y Desfechos de Saúde","de":"Armut und Gesundheitsergebnisse","fr":"Pauvreté et résultats de santé","tr":"Yoksulluk ve Sağlık Sonuçları","nl":"Armoede en gezondheidsuitkomsten","ru":"Бедность и показатели здоровья","zh":"贫困与健康结果","pt_BR":"Pobreza e Desfechos de Saúde","pt_PT":"Pobreza e Resultados de Saúde"}, back_translations: {"es":"Baixo nivel socioeconomico (SES) está associado a mayores taxas de enfermedades cardiovasculares, diabetes, infecciones, enfermedades mentais y mortalidad infantil. Mecanismos: acceso limitado a cuidados de salud, nutrición inadequada, estresse crónico (carga alostática), exposiciones ambientais y baja alfabetización en salud.","de":"Niedriger sozioökonomischer Status (SES) ist mit höheren Raten von Herz-Kreislauf-Erkrankungen, Diabetes, Infektionen, psychischen Erkrankungen und Säuglingssterblichkeit verbunden. Mechanismen: eingeschränkter Zugang zur Gesundheitsversorgung, schlechte Ernährung, chronischer Stress (allostatische Belastung), Umweltexpositionen und reduzierte Gesundheitskompetenz.","fr":"Un faible statut socio-économique (SES) est associé à des taux plus élevés de maladies cardiovasculaires, de diabète, d'infections, de maladies mentales et de mortalité infantile. Mécanismes : accès limité aux soins de santé, mauvaise nutrition, stress chronique (charge allostatique), expositions environnementales et faible littératie en santé.","tr":"Düşük sosyoekonomik durum (SES), daha yüksek kardiyovasküler hastalık, diyabet, enfeksiyon, ruhsal hastalık ve bebek ölüm oranlarıyla ilişkilidir. Mekanizmalar: sağlık hizmetlerine sınırlı erişim, yetersiz beslenme, kronik stres (allostatik yük), çevresel maruziyetler ve düşük sağlık okuryazarlığı.","nl":"Een lage sociaaleconomische status (SES) is geassocieerd met hogere percentages hart- en vaatziekten, diabetes, infecties, psychische aandoeningen en zuigelingensterfte. Mechanismen: beperkte toegang tot gezondheidszorg, slechte voeding, chronische stress (allostatische belasting), blootstelling aan omgevingsfactoren en verminderde gezondheidsgeletterdheid.","ru":"Низкий социально-экономический статус (SES) связан с более высокими показателями сердечно-сосудистых заболеваний, диабета, инфекций, психических расстройств и младенческой смертности. Механизмы: ограниченный доступ к медицинской помощи, плохое питание, хронический стресс (аллостатическая нагрузка), воздействие окружающей среды и низкая медицинская грамотность.","zh":"低社会经济地位（SES）与更高的心血管疾病、糖尿病、感染、精神疾病和婴儿死亡率相关。机制：医疗保健获取受限、营养不良、慢性压力（异稳态负荷）、环境暴露和健康素养低下。","pt_BR":"Baixo nível socioeconômico (SES) está associado a maiores taxas de doenças cardiovasculares, diabetes, infecções, doenças mentais e mortalidade infantil. Mecanismos: acesso limitado a cuidados de saúde, nutrição inadequada, estresse crônico (carga alostática), exposições ambientais e baixa alfabetização em saúde.","pt_PT":"Baixo nível socioeconómico (SES) está associado a maiores taxas de doenças cardiovasculares, diabetes, infeções, doenças mentais e mortalidade infantil. Mecanismos: acesso limitado a cuidados de saúde, nutrição inadequada, stress crónico (carga alostática), exposições ambientais e baixa literacia em saúde."}},
  { id: 'dc-mcat-0199', deck_id: 'deck-mcat', sort_order: 199, front: "Cultural Competence in Medicine", back: "The ability of healthcare providers to understand, communicate with, and effectively interact with patients from diverse cultural backgrounds. Reduces healthcare disparities. Involves awareness of implicit biases and culturally specific health beliefs." , front_translations: {"es":"Competencia Cultural en la Medicina","de":"Kulturelle Kompetenz in der Medizin","fr":"Compétence culturelle en médecine","tr":"Tıpta Kültürel Yeterlilik","nl":"Culturele competentie in de geneeskunde","ru":"Культурная компетентность в медицине","zh":"医学中的文化能力","pt_BR":"Competência Cultural na Medicina","pt_PT":"Competência Cultural na Medicina"}, back_translations: {"es":"La capacidad de los profissionais de salud de compreender, comunicar-se y interagir efetivamente con pacientes de diversas origens culturais. Reduz las disparidades en salud. Envolve a conciencia de vieses implícitos y creencias de salud culturalmente específicas.","de":"Die Fähigkeit von Gesundheitsdienstleistern, Patienten aus verschiedenen kulturellen Hintergründen zu verstehen, mit ihnen zu kommunizieren und effektiv zu interagieren. Reduziert gesundheitliche Ungleichheiten. Beinhaltet das Bewusstsein für implizite Vorurteile und kulturspezifische Gesundheitsüberzeugungen.","fr":"La capacité des professionnels de santé à comprendre, communiquer et interagir efficacement avec des patients de divers horizons culturels. Réduit les disparités en matière de santé. Implique la prise de conscience des biais implicites et des croyances culturelles spécifiques en matière de santé.","tr":"Sağlık hizmeti sunucularının farklı kültürel geçmişlere sahip hastalarla anlama, iletişim kurma ve etkili etkileşim sağlama becerisi. Sağlık eşitsizliklerini azaltır. Örtük önyargıların ve kültüre özgü sağlık inançlarının farkındalığını içerir.","nl":"Het vermogen van zorgverleners om patiënten uit diverse culturele achtergronden te begrijpen, met hen te communiceren en effectief met hen om te gaan. Vermindert gezondheidsverschillen. Omvat bewustzijn van impliciete vooroordelen en cultureel specifieke gezondheidsovertuigingen.","ru":"Способность медицинских работников понимать, общаться и эффективно взаимодействовать с пациентами из различных культурных слоёв. Снижает неравенство в сфере здравоохранения. Включает осознание неявных предубеждений и культурно-специфических представлений о здоровье.","zh":"医疗服务提供者理解、沟通并有效地与来自不同文化背景的患者互动的能力。减少医疗差距。包括对隐性偏见和特定文化健康信念的认识。","pt_BR":"A capacidade dos profissionais de saúde de compreender, comunicar-se e interagir efetivamente com pacientes de diversas origens culturais. Reduz as disparidades em saúde. Envolve a consciência de vieses implícitos e crenças de saúde culturalmente específicas.","pt_PT":"A capacidade dos profissionais de saúde de compreender, comunicar e interagir eficazmente com pacientes de diversas origens culturais. Reduz as disparidades na saúde. Envolve a consciência de vieses implícitos e crenças de saúde culturalmente específicas."}},
  { id: 'dc-mcat-0200', deck_id: 'deck-mcat', sort_order: 200, front: "Stereotype Threat", back: "A situational predicament in which members of a stigmatized group fear confirming a negative stereotype about their group, leading to impaired performance. Steele and Aronson (1995) demonstrated its effect on African-American students' test performance. Highly relevant for health disparities." , front_translations: {"es":"Ameaça del Estereótipo","de":"Stereotype Threat","fr":"Menace du stéréotype","tr":"Stereotip Tehdidi","nl":"Stereotype dreiging","ru":"Угроза стереотипа","zh":"刻板印象威胁","pt_BR":"Ameaça do Estereótipo","pt_PT":"Ameaça do Estereótipo"}, back_translations: {"es":"Un dilema situacional en el qual membros de un grupo estigmatizado temem confirmar un estereótipo negativo sobre su grupo, levando a un rendimiento prejudicado. Steele y Aronson (1995) demonstraram su efecto en el rendimiento en pruebas de estudantes afro-americanos. Altamente relevante para disparidades en salud.","de":"Eine situative Belastung, bei der Mitglieder einer stigmatisierten Gruppe befürchten, ein negatives Stereotyp über ihre Gruppe zu bestätigen, was zu Leistungsbeeinträchtigungen führt. Steele und Aronson (1995) wiesen diesen Effekt bei afroamerikanischen Studierenden in Testleistungen nach. Hochrelevant für gesundheitliche Ungleichheiten.","fr":"Une situation dans laquelle les membres d'un groupe stigmatisé craignent de confirmer un stéréotype négatif concernant leur groupe, entraînant une diminution des performances. Steele et Aronson (1995) ont démontré son effet sur les performances aux tests d'étudiants afro-américains. Très pertinent pour les disparités en santé.","tr":"Damgalanmış bir grubun üyelerinin, grupları hakkındaki olumsuz bir kalıp yargıyı doğrulamaktan korktukları durumsal bir ikilem olup performansın düşmesine yol açar. Steele ve Aronson (1995) bu etkiyi Afrikalı-Amerikalı öğrencilerin sınav performansında göstermiştir. Sağlık eşitsizlikleri için son derece ilgilidir.","nl":"Een situationeel dilemma waarbij leden van een gestigmatiseerde groep vrezen een negatief stereotype over hun groep te bevestigen, wat leidt tot verminderde prestaties. Steele en Aronson (1995) toonden het effect aan op de testprestaties van Afro-Amerikaanse studenten. Zeer relevant voor gezondheidsverschillen.","ru":"Ситуативное состояние, при котором представители стигматизированной группы опасаются подтвердить негативный стереотип о своей группе, что ведёт к снижению результативности. Стил и Аронсон (1995) продемонстрировали этот эффект на успеваемости афроамериканских студентов. Крайне актуально для неравенства в сфере здоровья.","zh":"一种情境困境，受污名化群体的成员担心证实关于其群体的负面刻板印象，从而导致表现受损。Steele和Aronson（1995）证明了其对非裔美国学生考试表现的影响。与健康差距高度相关。","pt_BR":"Um dilema situacional no qual membros de um grupo estigmatizado temem confirmar um estereótipo negativo sobre seu grupo, levando a um desempenho prejudicado. Steele e Aronson (1995) demonstraram seu efeito no desempenho em testes de estudantes afro-americanos. Altamente relevante para disparidades em saúde.","pt_PT":"Um dilema situacional no qual membros de um grupo estigmatizado temem confirmar um estereótipo negativo sobre o seu grupo, levando a um desempenho prejudicado. Steele e Aronson (1995) demonstraram o seu efeito no desempenho em testes de estudantes afro-americanos. Altamente relevante para disparidades na saúde."}},
];
